def _is_public_path(path: str | None) -> bool:
    if not isinstance(path, str):
        return False
    if path in _PUBLIC_EXT_DOC_PATHS:
        return True
    return any(pattern.match(path) for pattern in _PUBLIC_PATH_PATTERNS)


