def _attach_cors_headers(request: Request, response: Response) -> Response:
    origin = request.headers.get("origin")
    normalized_origin = origin.rstrip("/") if isinstance(origin, str) else origin
    regex_allowed = normalized_origin and any(pattern.match(normalized_origin) for pattern in _CORS_ORIGIN_REGEXES)
    if normalized_origin and (
        normalized_origin in _CORS_ORIGINS
        or (not _IS_PROD_ENV and _LOCAL_CORS_REGEX.match(normalized_origin))
        or regex_allowed
    ):
        response.headers.setdefault("Access-Control-Allow-Origin", origin)
        response.headers.setdefault("Access-Control-Allow-Credentials", "true")
        response.headers.setdefault("Access-Control-Allow-Headers", "*")
        response.headers.setdefault("Access-Control-Allow-Methods", "*")
        response.headers.setdefault("Vary", "Origin")
    return response


@app.middleware("http")
async def local_cors_fallback_middleware(request: Request, call_next):
    if request.method == "OPTIONS":
        response = JSONResponse({}, status_code=200)
    else:
        response = await call_next(request)
    return _attach_cors_headers(request, response)


@app.middleware("http")
async def security_headers_middleware(request: Request, call_next):
    response = await call_next(request)
    response.headers.setdefault("X-Content-Type-Options", "nosniff")
    response.headers.setdefault("X-Frame-Options", "DENY")
    response.headers.setdefault("Referrer-Policy", "strict-origin-when-cross-origin")
    response.headers.setdefault("Permissions-Policy", "camera=(self), microphone=(), geolocation=(self)")
    response.headers.setdefault("Cross-Origin-Opener-Policy", "same-origin")
    if _IS_PROD_ENV or request.url.scheme == "https":
        response.headers.setdefault("Strict-Transport-Security", "max-age=31536000; includeSubDomains")
    return response


def _log_db_rtt_once() -> None:
    url = os.getenv("SUPABASE_DB_URL") or os.getenv("DATABASE_URL")
    if not url:
        return
    try:
        parsed = urlparse(url)
        host = parsed.hostname
        port = parsed.port or 5432
        if not host:
            return
        start = time.perf_counter()
        with socket.create_connection((host, port), timeout=1.0):
            pass
        rtt_ms = (time.perf_counter() - start) * 1000
        logger.info("db_rtt host=%s port=%s rtt_ms=%.1f", host, port, rtt_ms)
    except Exception:
        return


