def _legacy_entity_id(entity_id: str) -> str | None:
    if isinstance(entity_id, str) and entity_id.startswith(LEGACY_ENTITY_PREFIX):
        return entity_id[len(LEGACY_ENTITY_PREFIX) :]
    return None


def _get_by_path(data: dict | None, path: str) -> Any:
    if not isinstance(data, dict) or not isinstance(path, str):
        return None
    if path in data:
        return data.get(path)
    cur: Any = data
    for part in path.split("."):
        if isinstance(cur, dict) and part in cur:
            cur = cur.get(part)
        else:
            return None
    return cur


def _resolve_action_templates(value: Any, context: dict | None) -> Any:
    if isinstance(value, dict):
        if set(value.keys()) == {"ref"} and isinstance(value.get("ref"), str):
            ref = value.get("ref")
            ctx = context if isinstance(context, dict) else {}
            record = ctx.get("record") or ctx.get("record_draft") or {}
            if ref == "$record.id":
                return ctx.get("record_id") or _get_by_path(record, "id")
            if ref.startswith("$record."):
                return _get_by_path(record, ref[len("$record.") :])
            return _get_by_path(record, ref)
        return {k: _resolve_action_templates(v, context) for k, v in value.items()}
    if isinstance(value, list):
        return [_resolve_action_templates(v, context) for v in value]
    return value


def _find_record_anywhere(record_id: str) -> tuple[str, dict] | None:
    if not isinstance(record_id, str) or not record_id:
        return None
    if hasattr(generic_records, "_records"):
        buckets = getattr(generic_records, "_records", {})
        for tenant_id, entities in buckets.items():
            for entity_id, records in entities.items():
                record = records.get(record_id)
                if record:
                    return entity_id, {"record_id": record_id, "record": record}
        return None
    with get_conn() as conn:
        row = fetch_one(
            conn,
            """
            select entity_id, data
            from records_generic
            where id=%s
            limit 1
            """,
            [record_id],
            query_name="records_generic.find_anywhere",
        )
        if not row:
            return None
        data = row.get("data")
        if isinstance(data, str):
            try:
                data = json.loads(data)
            except Exception:
                data = {}
        return row.get("entity_id"), {"record_id": record_id, "record": data or {}}


def _candidate_entity_ids(entity_id: str | None) -> list[str]:
    if not isinstance(entity_id, str) or not entity_id:
        return []
    if entity_id.startswith("entity."):
        return [entity_id, entity_id[7:]]
    return [entity_id, f"entity.{entity_id}"]


def _get_record_for_entity_candidates(entity_id: str | None, record_id: str | None) -> tuple[str | None, dict | None]:
    if not isinstance(entity_id, str) or not entity_id or not isinstance(record_id, str) or not record_id:
        return None, None
    seen: set[str] = set()
    for candidate in _candidate_entity_ids(entity_id):
        if candidate in seen:
            continue
        seen.add(candidate)
        existing = generic_records.get(candidate, record_id)
        existing_id, existing_record = _unwrap_store_record(existing if isinstance(existing, dict) else None)
        if isinstance(existing_id, str) and isinstance(existing_record, dict):
            return candidate, {"record_id": existing_id, "record": existing_record}
    fallback = _find_record_anywhere(record_id)
    if isinstance(fallback, tuple) and len(fallback) == 2:
        found_entity_id, existing = fallback
        if _match_entity_id(entity_id, found_entity_id):
            return found_entity_id, existing
    return None, None


def _get_perf_budget_ms(method: str, path: str) -> float | None:
    budgets = {
        ("GET", "/modules"): 300.0,
        ("GET", "/studio2/modules"): 300.0,
        ("GET", "/studio2/registry"): 300.0,
    }
    budget = budgets.get((method, path))
    if budget is not None:
        return budget
    if method == "GET" and path.startswith("/records/"):
        return 300.0
    return None



@app.middleware("http")
async def timing_middleware(request: Request, call_next):
    if not hasattr(request.state, "cache"):
        request.state.cache = {}
    reset_db_ms()
    start = time.perf_counter()
    response = await call_next(request)
    total_ms = (time.perf_counter() - start) * 1000
    auth_ms = getattr(request.state, "auth_ms", 0.0)
    db_ms = get_db_ms()
    db_stats = get_db_stats()
    handler_ms = max(total_ms - auth_ms - db_ms, 0.0)
    route = request.scope.get("route")
    route_name = getattr(route, "name", None) or getattr(request.scope.get("endpoint"), "__name__", None) or "unknown"
    logger.info(
        "%s %s %s route=%s total_ms=%.1f auth_ms=%.1f db_ms=%.1f db_q=%s db_acquire_ms=%.1f db_wire_ms=%.1f db_decode_ms=%.1f handler_ms=%.1f",
        request.method,
        request.url.path,
        response.status_code,
        route_name,
        total_ms,
        auth_ms,
        db_ms,
        db_stats.get("queries", 0),
        db_stats.get("acquire_ms", 0.0),
        db_stats.get("wire_ms", db_stats.get("execute_ms", 0.0)),
        db_stats.get("decode_ms", 0.0),
        handler_ms,
    )
    if total_ms >= REQ_SLOW_MS or db_ms >= REQ_DB_SLOW_MS:
        logger.warning(
            "slow_request method=%s path=%s route=%s total_ms=%.1f db_ms=%.1f status=%s",
            request.method,
            request.url.path,
            route_name,
            total_ms,
            db_ms,
            response.status_code,
        )
    budget_ms = _get_perf_budget_ms(request.method, request.url.path)
    if budget_ms is not None and total_ms > budget_ms:
        logger.warning(
            "perf_budget_exceeded method=%s path=%s total_ms=%.1f budget_ms=%.1f",
            request.method,
            request.url.path,
            total_ms,
            budget_ms,
        )
    if db_stats.get("queries", 0) > 1:
        logger.warning("db_queries=%s", get_db_query_log())
    if IS_DEV:
        response.headers["X-Req-MS"] = f"{total_ms:.1f}"
        response.headers["X-DB-MS"] = f"{db_ms:.1f}"
        response.headers["X-Queries"] = str(db_stats.get("queries", 0))
        response.headers["X-DB-Wire-MS"] = f"{db_stats.get('wire_ms', 0.0):.1f}"
        response.headers["X-DB-Decode-MS"] = f"{db_stats.get('decode_ms', 0.0):.1f}"
        response.headers["X-Route"] = route_name
    return response


@app.exception_handler(Exception)
async def unhandled_exception_handler(request: Request, exc: Exception):
    logger.exception("unhandled_exception path=%s", request.url.path)
    detail = {"error": str(exc)} if not _IS_PROD_ENV else None
    return _error_response("INTERNAL_ERROR", "Unexpected server error", detail=detail, status=500)


