@app.get("/ops/db_ping")
async def db_ping() -> dict:
    start = time.perf_counter()
    with get_conn() as conn:
        fetch_one(conn, "select 1 as ok", query_name="ops.db_ping")
    elapsed_ms = (time.perf_counter() - start) * 1000
    return {"ok": True, "ms": round(elapsed_ms, 2)}


def _error_response(
    code: str,
    message: str,
    path: str | None = None,
    detail: dict | None = None,
    status: int = 400,
    headers: dict | None = None,
) -> JSONResponse:
    body = {
        "ok": False,
        "errors": [{"code": code, "message": message, "path": path, "detail": detail}],
        "warnings": [],
    }
    return JSONResponse(jsonable_encoder(body), status_code=status, headers=headers)


def _ok_response(payload: dict, warnings: list | None = None, status: int = 200, headers: dict | None = None) -> JSONResponse:
    resolved_warnings = warnings
    if resolved_warnings is None:
        payload_warnings = payload.get("warnings") if isinstance(payload, dict) else None
        resolved_warnings = payload_warnings if isinstance(payload_warnings, list) else []
    payload_errors = payload.get("errors") if isinstance(payload, dict) else None
    resolved_errors = payload_errors if isinstance(payload_errors, list) else []
    body = {"ok": True, **payload, "errors": resolved_errors, "warnings": resolved_warnings or []}
    return JSONResponse(jsonable_encoder(body), status_code=status, headers=headers)


def _perf_now() -> float:
    return time.perf_counter()


def _perf_ms(start: float) -> float:
    return max(0.0, (time.perf_counter() - start) * 1000.0)


def _server_timing_header(metrics: list[tuple[str, float]]) -> dict[str, str]:
    parts: list[str] = []
    for name, duration_ms in metrics:
        if not isinstance(name, str) or not name:
            continue
        try:
            duration = float(duration_ms)
        except Exception:
            continue
        parts.append(f"{name};dur={duration:.1f}")
    if not parts:
        return {}
    return {"Server-Timing": ", ".join(parts)}


def _ext_api_pagination_meta(*, limit: int, offset: int = 0, next_cursor: str | None = None) -> dict:
    return {
        "limit": limit,
        "offset": offset,
        "next_cursor": next_cursor,
        "has_more": bool(next_cursor),
    }


def _ext_api_paginate(items: list[dict], *, limit: int = 50, offset: int = 0, cursor: str | None = None) -> tuple[list[dict], dict]:
    limit_cap = max(1, min(int(limit or 50), 200))
    if isinstance(cursor, str) and cursor.strip():
        try:
            offset_val = max(0, int(cursor.strip()))
        except Exception:
            raise ValueError("cursor must be an integer offset")
    else:
        offset_val = max(0, int(offset or 0))
    sliced = items[offset_val : offset_val + limit_cap]
    next_cursor = str(offset_val + limit_cap) if len(items) > offset_val + limit_cap else None
    return sliced, _ext_api_pagination_meta(limit=limit_cap, offset=offset_val, next_cursor=next_cursor)


def _set_ext_api_rate_limit_headers(
    response: Response | None,
    *,
    remaining: int,
    limited: bool = False,
    window_seconds: int | None = None,
) -> None:
    if response is None:
        return
    window = max(1, int(window_seconds or EXT_API_RATE_LIMIT_WINDOW_SECONDS))
    response.headers["X-RateLimit-Limit"] = str(EXT_API_RATE_LIMIT_MAX_REQUESTS)
    response.headers["X-RateLimit-Remaining"] = str(max(0, remaining))
    response.headers["X-RateLimit-Window-Seconds"] = str(window)
    if limited:
        response.headers["Retry-After"] = str(window)


def _issue(code: str, message: str, path: str | None = None) -> dict:
    return {"code": code, "message": message, "path": path}


def _actor_event_meta(actor: dict | None) -> dict | None:
    if not isinstance(actor, dict):
        return None
    actor_id = actor.get("user_id") or actor.get("id")
    if not actor_id:
        return None
    role = actor.get("role")
    roles = [role] if isinstance(role, str) else []
    return {"id": actor_id, "roles": roles}


def _matching_triggers(manifest: dict, event: str, entity_id: str | None, action_id: str | None, status_field: str | None) -> list[dict]:
    triggers = manifest.get("triggers") if isinstance(manifest, dict) else None
    if not isinstance(triggers, list):
        return []
    matched = []
    for trig in triggers:
        if not isinstance(trig, dict):
            continue
        if trig.get("event") != event:
            continue
        if event in {"record.created", "record.updated", "workflow.status_changed"}:
            if entity_id and trig.get("entity_id") != entity_id:
                continue
            if trig.get("status_field") and status_field and trig.get("status_field") != status_field:
                continue
        if event == "action.clicked":
            if action_id and trig.get("action_id") != action_id:
                continue
        matched.append(trig)
    return matched


def _emit_triggers(
    request: Request,
    module_id: str,
    manifest: dict,
    event: str,
    payload: dict,
    *,
    entity_id: str | None = None,
    action_id: str | None = None,
    status_field: str | None = None,
) -> None:
    if not isinstance(manifest, dict):
        return
    module = _get_module(request, module_id)
    manifest_hash = module.get("current_hash") if isinstance(module, dict) else None
    if not isinstance(manifest_hash, str):
        return
    module_slug = (manifest.get("module") or {}).get("id")
    if not isinstance(module_slug, str) or not module_slug:
        module_slug = module_id
    actor = getattr(request.state, "actor", None) if request is not None and hasattr(request, "state") else None
    meta = {
        "module_id": module_id,
        "manifest_hash": manifest_hash,
        "actor": _actor_event_meta(actor),
        "org_id": actor.get("workspace_id") if isinstance(actor, dict) else None,
        "trace_id": request.headers.get("x-request-id") if hasattr(request, "headers") else None,
    }

    def _derive_namespaced_event() -> str:
        if event == "action.clicked" and action_id:
            return f"{module_slug}.action.{action_id}.clicked"
        if event == "workflow.status_changed":
            return f"{module_slug}.workflow.status_changed"
        if event in {"record.created", "record.updated"}:
            return f"{module_slug}.{event}"
        return f"{module_slug}.{event}"

    namespaced_event = _derive_namespaced_event()
    base_event_payload = {**payload, "event": event}
    _emit_external_webhook_subscriptions(event, base_event_payload, meta)
    if namespaced_event and namespaced_event != event:
        _emit_external_webhook_subscriptions(namespaced_event, {**payload, "event": namespaced_event}, meta)

    try:
        emitted_base = make_event(event, base_event_payload, meta)
        event_bus.publish(emitted_base)
        _handle_automation_event(emitted_base)
        if namespaced_event and namespaced_event != event:
            namespaced_payload = {**payload, "event": namespaced_event}
            emitted_ns = make_event(namespaced_event, namespaced_payload, meta)
            event_bus.publish(emitted_ns)
            _handle_automation_event(emitted_ns)
    except Exception as exc:
        logger.warning("trigger_emit_failed module_id=%s event=%s error=%s", module_id, event, exc)

    triggers = _matching_triggers(manifest, event, entity_id, action_id, status_field)
    if not triggers:
        return

    for trig in triggers:
        name = trig.get("id") or event
        if name in {event, namespaced_event}:
            continue
        event_payload = {
            **payload,
            "event": name,
            "trigger_id": trig.get("id"),
        }
        try:
            emitted = make_event(name, event_payload, meta)
            event_bus.publish(emitted)
            _handle_automation_event(emitted)
        except Exception as exc:
            logger.warning("trigger_emit_failed module_id=%s event=%s error=%s", module_id, event, exc)


def _handle_automation_event(event: dict) -> None:
    try:
        handle_automation_event(automation_store, job_store, event)
    except Exception as exc:
        logger.warning("automation_event_failed error=%s", exc)


def _event_matches_pattern(event_name: str, pattern: str) -> bool:
    candidate = str(event_name or "").strip()
    matcher = str(pattern or "").strip()
    if not candidate or not matcher:
        return False
    if matcher == "*":
        return True
    if matcher.endswith("*"):
        return candidate.startswith(matcher[:-1])
    return candidate == matcher


def _emit_external_webhook_subscriptions(event_name: str, payload: dict, meta: dict | None = None) -> None:
    if not external_webhook_subscription_store or not job_store:
        return
    try:
        subscriptions = external_webhook_subscription_store.list(status="active", limit=1000)
    except Exception as exc:
        logger.warning("external_webhooks_list_failed event=%s error=%s", event_name, exc)
        return
    for subscription in subscriptions:
        pattern = subscription.get("event_pattern")
        if not isinstance(pattern, str) or not _event_matches_pattern(event_name, pattern):
            continue
        try:
            job_store.enqueue(
                {
                    "type": "external.webhook.deliver",
                    "payload": {
                        "subscription_id": subscription.get("id"),
                        "event": event_name,
                        "payload": payload or {},
                        "meta": meta or {},
                    },
                    "idempotency_key": f"external_webhook:{subscription.get('id')}:{event_name}:{uuid.uuid4()}",
                }
            )
        except Exception as exc:
            logger.warning("external_webhook_enqueue_failed subscription_id=%s event=%s error=%s", subscription.get("id"), event_name, exc)


_ACTOR_CACHE: dict[str, dict] = {}
_ACTOR_CACHE_TTL_S = max(0.0, float(os.getenv("OCTO_ACTOR_CACHE_TTL", "5") or "5"))


def _actor_cache_key(request: Request, user: dict) -> str | None:
    user_id = user.get("id")
    if not isinstance(user_id, str) or not user_id:
        return None
    workspace_header = request.headers.get("X-Workspace-Id") or ""
    claims = user.get("claims") if isinstance(user.get("claims"), dict) else {}
    claims_fingerprint = hashlib.sha256(
        json.dumps(
            {
                "iat": claims.get("iat"),
                "app_metadata": claims.get("app_metadata") or claims.get("app_meta_data"),
                "user_metadata": claims.get("user_metadata") or claims.get("user_meta_data"),
                "role": claims.get("role"),
                "email": user.get("email"),
            },
            sort_keys=True,
            default=str,
        ).encode("utf-8")
    ).hexdigest()
    return f"{user_id}:{workspace_header}:{claims_fingerprint}"


def _actor_cache_get(cache_key: str | None) -> dict | None:
    if not cache_key or _ACTOR_CACHE_TTL_S <= 0:
        return None
    entry = _ACTOR_CACHE.get(cache_key)
    if not isinstance(entry, dict):
        return None
    if time.time() - float(entry.get("ts") or 0) > _ACTOR_CACHE_TTL_S:
        _ACTOR_CACHE.pop(cache_key, None)
        return None
    actor = entry.get("actor")
    return copy.deepcopy(actor) if isinstance(actor, dict) else None


def _actor_cache_set(cache_key: str | None, actor: dict) -> dict:
    if cache_key and _ACTOR_CACHE_TTL_S > 0:
        _ACTOR_CACHE[cache_key] = {"ts": time.time(), "actor": copy.deepcopy(actor)}
    return actor


def _actor_cache_invalidate(workspace_id: str | None = None, user_id: str | None = None) -> None:
    if not workspace_id and not user_id:
        _ACTOR_CACHE.clear()
        return
    workspace_marker = f":{workspace_id}:" if isinstance(workspace_id, str) and workspace_id else None
    for key, entry in list(_ACTOR_CACHE.items()):
        actor = entry.get("actor") if isinstance(entry, dict) else None
        if not isinstance(actor, dict):
            _ACTOR_CACHE.pop(key, None)
            continue
        if user_id and actor.get("user_id") == user_id:
            _ACTOR_CACHE.pop(key, None)
            continue
        if workspace_id and (
            actor.get("workspace_id") == workspace_id
            or any(isinstance(item, dict) and item.get("workspace_id") == workspace_id for item in actor.get("workspaces") or [])
            or (workspace_marker and workspace_marker in key)
        ):
            _ACTOR_CACHE.pop(key, None)


def _resolve_actor(request: Request) -> dict | JSONResponse:
    cached_actor = getattr(request.state, "actor", None)
    if isinstance(cached_actor, dict):
        return cached_actor
    api_credential = getattr(request.state, "api_credential", None)
    if isinstance(api_credential, dict) and api_credential.get("org_id"):
        workspace_id = str(api_credential.get("org_id"))
        return {
            "user_id": None,
            "email": None,
            "role": "api",
            "workspace_role": "api",
            "platform_role": "standard",
            "workspace_id": workspace_id,
            "workspaces": [{"workspace_id": workspace_id, "role": "api", "workspace_name": workspace_id}],
            "claims": {},
            "actor_type": "api_credential",
            "api_credential_id": api_credential.get("id"),
            "api_credential_name": api_credential.get("name"),
            "api_scopes": api_credential.get("scopes") or [],
        }
    user = getattr(request.state, "user", None)
    if os.getenv("OCTO_DISABLE_AUTH", "").strip().lower() in ("1", "true", "yes"):
        if not user or not user.get("id"):
            workspace_header = request.headers.get("X-Workspace-Id")
            workspace_id = workspace_header.strip() if isinstance(workspace_header, str) and workspace_header.strip() else "default"
            workspace_name = "Default" if workspace_id == "default" else workspace_id
            return {
                "user_id": "test-user",
                "email": "test@example.com",
                "role": "admin",
                "workspace_role": "admin",
                "platform_role": "superadmin",
                "workspace_id": workspace_id,
                "workspaces": [{"workspace_id": workspace_id, "role": "admin", "workspace_name": workspace_name}],
                "claims": {},
            }
    if not user or not user.get("id"):
        return _error_response("AUTH_REQUIRED", "Authenticated user required", status=401)
    if not USE_DB:
        return {
            "user_id": user.get("id"),
            "email": user.get("email"),
            "role": "admin",
            "workspace_role": "admin",
            "platform_role": "superadmin",
            "workspace_id": "default",
            "workspaces": [{"workspace_id": "default", "role": "admin", "workspace_name": "Default"}],
            "claims": user.get("claims"),
        }
    user_id = user.get("id")
    set_db_user_id(user_id)
    actor_cache_key = _actor_cache_key(request, user)
    cached_actor = _actor_cache_get(actor_cache_key)
    if cached_actor is not None:
        return cached_actor
    platform_role = get_platform_role(user_id)
    managed_account_state = _managed_account_state_from_claims(user.get("claims"))
    auto_workspace_allowed = _workspace_auto_create_allowed_from_claims(user.get("claims"))
    auth_user = _find_auth_user_row_by_id(user_id)
    if auth_user:
        live_managed_account_state = _managed_account_state_from_metadata(auth_user.get("app_metadata"))
        if live_managed_account_state != managed_account_state:
            managed_account_state = live_managed_account_state
    user_email = user.get("email")
    if isinstance(user_email, str) and user_email:
        try:
            claimed_invites = claim_workspace_invites_for_email(user_id, user_email)
            if claimed_invites:
                with suppress(Exception):
                    _supabase_set_auto_workspace_creation(user_id, enabled=False)
                auto_workspace_allowed = False
        except Exception:
            pass
    memberships = list_memberships(user_id)
    user_workspaces = list_user_workspaces(user_id)
    workspace_header = request.headers.get("X-Workspace-Id")
    if not memberships:
        if auth_user:
            auto_workspace_allowed = _workspace_auto_create_allowed_from_metadata(auth_user.get("app_metadata"))
        if not auto_workspace_allowed:
            return _error_response(
                "WORKSPACE_REQUIRED",
                "User is not assigned to a workspace",
                status=403,
            )
        workspace_id = create_workspace_for_user(user)
        memberships = list_memberships(user_id)
        user_workspaces = list_user_workspaces(user_id)
        role = "admin"
        return _actor_cache_set(actor_cache_key, {
            "user_id": user_id,
            "email": user.get("email"),
            "role": role,
            "workspace_role": role,
            "platform_role": platform_role,
            "workspace_id": workspace_id,
            "workspaces": user_workspaces,
            "managed_account_state": managed_account_state,
            "claims": user.get("claims"),
        })
    if workspace_header:
        membership = get_membership(user_id, workspace_header)
        if not membership and platform_role != "superadmin":
            return _error_response("WORKSPACE_FORBIDDEN", "User is not a member of this workspace", "X-Workspace-Id", status=403)
        if membership:
            role = membership.get("role") or "member"
        elif workspace_exists(workspace_header):
            role = "admin"
        else:
            return _error_response("WORKSPACE_NOT_FOUND", "Workspace does not exist", "X-Workspace-Id", status=404)
        workspace_id = workspace_header
    elif len(memberships) == 1:
        workspace_id = memberships[0].get("workspace_id")
        role = memberships[0].get("role") or "member"
    else:
        preferred_workspace = next(
            (
                item
                for item in (user_workspaces or [])
                if isinstance(item, dict) and isinstance(item.get("workspace_id"), str) and item.get("workspace_id")
            ),
            None,
        )
        if preferred_workspace:
            workspace_id = preferred_workspace.get("workspace_id")
            role = preferred_workspace.get("role") or ("admin" if platform_role == "superadmin" else "member")
        elif platform_role == "superadmin":
            all_workspaces = list_all_workspaces()
            if not all_workspaces:
                return _error_response("WORKSPACE_NOT_FOUND", "No workspaces exist yet", status=404)
            workspace_id = all_workspaces[0].get("workspace_id")
            role = "admin"
        else:
            workspace_id = memberships[0].get("workspace_id")
            role = memberships[0].get("role") or "member"
    return _actor_cache_set(actor_cache_key, {
        "user_id": user_id,
        "email": user.get("email"),
        "role": role,
        "workspace_role": role,
        "platform_role": platform_role,
        "workspace_id": workspace_id,
        "workspaces": user_workspaces,
        "managed_account_state": managed_account_state,
        "claims": user.get("claims"),
    })


