def _workspace_ids_for_actor(actor: dict | None) -> list[str]:
    seen: set[str] = set()
    ordered: list[str] = []

    def _push(value: Any) -> None:
        if not isinstance(value, str):
            return
        normalized = value.strip()
        if not normalized or normalized in seen:
            return
        seen.add(normalized)
        ordered.append(normalized)

    _push(get_org_id())
    if isinstance(actor, dict):
        _push(actor.get("workspace_id"))
        for item in actor.get("workspaces") or []:
            if isinstance(item, dict):
                _push(item.get("workspace_id"))
    return ordered


def _get_attachment_for_actor(actor: dict | None, attachment_id: str) -> tuple[dict | None, str | None]:
    attachment = attachment_store.get_attachment(attachment_id)
    return (attachment, get_org_id()) if attachment else (None, None)


def _uploaded_file_too_large(data: bytes | bytearray | None) -> bool:
    try:
        return len(data or b"") > max(1, _MAX_UPLOAD_BYTES)
    except Exception:
        return True


def _invalidate_access_runtime_caches(workspace_id: str | None = None, user_id: str | None = None) -> None:
    invalidate_access_policy_cache(workspace_id, user_id)
    _actor_cache_invalidate(workspace_id, user_id)
    _cache_invalidate("modules")
    _cache_invalidate("registry_list")
    _cache_invalidate("manifest")
    _response_cache.clear()


def _access_policy_for_actor(actor: dict | None) -> dict:
    if not isinstance(actor, dict):
        return {
            "profile_ids": [],
            "profiles": [],
            "module_access": {},
            "entity_access": {},
            "entity_scope_rules": {},
            "field_access": {},
            "action_access": {},
        }
    if actor.get("platform_role") == "superadmin":
        return {
            "profile_ids": [],
            "profiles": [],
            "module_access": {},
            "entity_access": {},
            "entity_scope_rules": {},
            "field_access": {},
            "action_access": {},
        }
    cached = actor.get("_access_policy")
    if isinstance(cached, dict):
        return cached
    workspace_id = actor.get("workspace_id") or get_org_id()
    user_id = actor.get("user_id")
    policy = compile_workspace_user_access_policy(workspace_id, user_id)
    actor["_access_policy"] = policy
    return policy


def _module_visible_for_actor(actor: dict | None, module_id: str) -> bool:
    if not isinstance(module_id, str) or not module_id:
        return False
    policy = _access_policy_for_actor(actor)
    decision = policy.get("module_access", {}).get(module_id)
    if decision == "hidden":
        return False
    wildcard = policy.get("module_access", {}).get("*")
    if wildcard == "hidden":
        return False
    return True


def _entity_base_access_level(actor: dict | None) -> str:
    if _has_capability(actor, "records.write"):
        return "write"
    if _has_capability(actor, "records.read"):
        return "read"
    return "none"


def _entity_access_level_for_actor(actor: dict | None, module_id: str | None, entity_id: str | None) -> str:
    normalized_entity = _normalize_entity_id(entity_id)
    base_level = _entity_base_access_level(actor)
    policy = _access_policy_for_actor(actor)
    rule = None
    if isinstance(normalized_entity, str):
        rule = policy.get("entity_access", {}).get(normalized_entity)
    if not isinstance(rule, str):
        rule = policy.get("entity_access", {}).get("*")
    if not isinstance(rule, str):
        return base_level
    if _ENTITY_ACCESS_ORDER.get(rule, -1) < _ENTITY_ACCESS_ORDER.get(base_level, -1):
        return rule
    return base_level


def _record_scope_access_level_for_actor(actor: dict | None, module_id: str | None, entity_id: str | None, record: dict | None) -> str:
    normalized_entity = _normalize_entity_id(entity_id)
    base_level = _entity_access_level_for_actor(actor, module_id, normalized_entity)
    if base_level == "none":
        return "none"
    policy = _access_policy_for_actor(actor)
    scoped_rules = []
    entity_scope_rules = policy.get("entity_scope_rules", {}) if isinstance(policy, dict) else {}
    if isinstance(normalized_entity, str):
        scoped_rules.extend(entity_scope_rules.get(normalized_entity) or [])
    scoped_rules.extend(entity_scope_rules.get("*") or [])
    if not scoped_rules:
        return base_level
    actor_ctx = _actor_domain_context(actor)
    matched_levels: list[str] = []
    for rule in scoped_rules:
        if not isinstance(rule, dict):
            continue
        condition = rule.get("condition")
        access_level = rule.get("access_level")
        if not isinstance(condition, dict) or not isinstance(access_level, str):
            continue
        try:
            if eval_condition(condition, {"record": record or {}, "actor": actor_ctx}):
                matched_levels.append(access_level)
        except Exception:
            continue
    if not matched_levels:
        return "none"
    if "none" in matched_levels:
        scoped_level = "none"
    elif "read" in matched_levels:
        scoped_level = "read"
    elif "write" in matched_levels:
        scoped_level = "write"
    else:
        scoped_level = "none"
    if _ENTITY_ACCESS_ORDER.get(scoped_level, -1) < _ENTITY_ACCESS_ORDER.get(base_level, -1):
        return scoped_level
    return base_level


def _record_visible_for_actor(actor: dict | None, module_id: str | None, entity_id: str | None, record: dict | None) -> bool:
    return _record_scope_access_level_for_actor(actor, module_id, entity_id, record) != "none"


def _record_write_allowed_for_actor(actor: dict | None, module_id: str | None, entity_id: str | None, record: dict | None) -> bool:
    return _record_scope_access_level_for_actor(actor, module_id, entity_id, record) == "write"


def _entity_allowed_field_ids_for_actor(actor: dict | None, module_id: str | None, entity_def: dict | None) -> set[str] | None:
    if not isinstance(entity_def, dict):
        return None
    cache_holder = actor if isinstance(actor, dict) else None
    entity_id = entity_def.get("id")
    cache_key = None
    if isinstance(entity_id, str) and entity_id:
        cache_key = f"{module_id or ''}:{entity_id}"
    if cache_holder is not None and isinstance(cache_key, str):
        cached = cache_holder.setdefault("_allowed_field_ids", {}).get(cache_key)
        if isinstance(cached, set) or cached is None:
            return cached
    allowed_fields: set[str] = set()
    hidden_present = False
    for field in entity_def.get("fields") or []:
        field_id = field.get("id") if isinstance(field, dict) else None
        if not isinstance(field_id, str) or not field_id:
            continue
        if _field_access_level_for_actor(actor, module_id, entity_id, field_id) == "hidden":
            hidden_present = True
            continue
        allowed_fields.add(field_id)
    result = allowed_fields if hidden_present else None
    if cache_holder is not None and isinstance(cache_key, str):
        cache_holder.setdefault("_allowed_field_ids", {})[cache_key] = result
    return result


def _mask_record_with_allowed_fields(record: dict | None, allowed_fields: set[str] | None) -> dict | None:
    if not isinstance(record, dict) or allowed_fields is None:
        return record
    masked = {}
    for key, value in record.items():
        if key == "id" or key in allowed_fields:
            masked[key] = value
    return masked


def _filter_record_items_for_actor(actor: dict | None, module_id: str | None, entity_def: dict | None, items: list[dict] | None) -> list[dict]:
    if not isinstance(entity_def, dict) or not isinstance(items, list):
        return []
    entity_id = entity_def.get("id")
    requires_scope_filter = _actor_has_entity_scope_rules(actor, entity_id)
    allowed_fields = _entity_allowed_field_ids_for_actor(actor, module_id, entity_def)
    if not requires_scope_filter and allowed_fields is None:
        return items
    filtered: list[dict] = []
    for item in items:
        if not isinstance(item, dict):
            continue
        record = item.get("record")
        if not isinstance(record, dict):
            continue
        if requires_scope_filter and not _record_visible_for_actor(actor, module_id, entity_id, record):
            continue
        filtered.append(
            {
                "record_id": item.get("record_id"),
                "record": _mask_record_with_allowed_fields(record, allowed_fields),
            }
        )
    return filtered


def _field_access_level_for_actor(actor: dict | None, module_id: str | None, entity_id: str | None, field_id: str | None) -> str:
    normalized_entity = _normalize_entity_id(entity_id)
    entity_access = _entity_access_level_for_actor(actor, module_id, normalized_entity)
    if entity_access == "none":
        return "hidden"
    base_level = "write" if entity_access == "write" else "read"
    policy = _access_policy_for_actor(actor)
    field_rule = None
    if isinstance(field_id, str) and field_id:
        field_rule = policy.get("field_access", {}).get(field_id)
        if not isinstance(field_rule, str):
            field_rule = policy.get("field_access", {}).get(f"{normalized_entity}:{field_id}")
    if not isinstance(field_rule, str):
        field_rule = policy.get("field_access", {}).get("*")
    if not isinstance(field_rule, str):
        return base_level
    if _FIELD_ACCESS_ORDER.get(field_rule, -1) < _FIELD_ACCESS_ORDER.get(base_level, -1):
        return field_rule
    return base_level


def _action_visible_for_actor(actor: dict | None, module_id: str | None, action_id: str | None) -> bool:
    if not isinstance(action_id, str) or not action_id:
        return True
    policy = _access_policy_for_actor(actor)
    action_rules = policy.get("action_access", {})
    for key in (f"{module_id}:{action_id}" if isinstance(module_id, str) and module_id else None, action_id, "*"):
        if not isinstance(key, str):
            continue
        if action_rules.get(key) == "hidden":
            return False
    return True


def _mask_record_for_actor(actor: dict | None, module_id: str | None, entity_def: dict | None, record: dict | None) -> dict | None:
    if not isinstance(record, dict) or not isinstance(entity_def, dict):
        return record
    return _mask_record_with_allowed_fields(record, _entity_allowed_field_ids_for_actor(actor, module_id, entity_def))


def _entity_access_denied_response(actor: dict | None, module_id: str | None, entity_id: str | None, *, write: bool = False) -> JSONResponse | None:
    access_level = _entity_access_level_for_actor(actor, module_id, entity_id)
    if access_level == "none":
        return _error_response("FORBIDDEN", "Entity access denied", "entity_id", status=403)
    if write and access_level != "write":
        return _error_response("FORBIDDEN", "Entity write access denied", "entity_id", status=403)
    return None


def _field_write_policy_errors(
    actor: dict | None,
    module_id: str | None,
    entity_def: dict | None,
    data: dict | None,
    *,
    allow_system_fields: bool = False,
    system_field_ids: set[str] | None = None,
) -> list[dict]:
    if not isinstance(entity_def, dict) or not isinstance(data, dict):
        return []
    entity_id = entity_def.get("id")
    errors: list[dict] = []
    for key in data.keys():
        if key == "id":
            continue
        field_access = _field_access_level_for_actor(actor, module_id, entity_id, key)
        if (allow_system_fields or (isinstance(system_field_ids, set) and key in system_field_ids)) and field_access in {"hidden", "read"}:
            continue
        if field_access != "write":
            errors.append(
                {
                    "code": "FIELD_FORBIDDEN",
                    "message": "Field is not writable for this user",
                    "path": key,
                    "detail": {"field_id": key, "access": field_access},
                }
            )
    return errors


def _record_access_denied_response(
    request: Request,
    actor: dict | None,
    entity_id: str,
    record_id: str,
    *,
    write: bool = False,
) -> JSONResponse | None:
    found = _find_entity_def(request, entity_id)
    if not found:
        return _error_response("ENTITY_NOT_FOUND", "Entity not found", "entity_id", status=404)
    module_id, entity_def, _manifest = found
    denied = _entity_access_denied_response(actor, module_id, entity_def.get("id"), write=write)
    if denied:
        return denied
    stored = generic_records.get(_normalize_entity_id(entity_def.get("id") or entity_id), record_id)
    if not stored:
        return _error_response("RECORD_NOT_FOUND", "Record not found", "record_id", status=404)
    record = stored.get("record") if isinstance(stored, dict) else None
    if not isinstance(record, dict):
        record = stored if isinstance(stored, dict) else {}
    if write:
        if not _record_write_allowed_for_actor(actor, module_id, entity_def.get("id"), record):
            return _error_response("FORBIDDEN", "Record write access denied", "record_id", status=403)
    elif not _record_visible_for_actor(actor, module_id, entity_def.get("id"), record):
        return _error_response("FORBIDDEN", "Record access denied", "record_id", status=403)
    return None


def _is_admin_actor(actor: dict | None) -> bool:
    if not isinstance(actor, dict):
        return False
    if actor.get("platform_role") == "superadmin":
        return True
    return (actor.get("workspace_role") or actor.get("role")) == "admin"


def _document_sequences_for_entity(entity_id: str | None, *, active_only: bool = False) -> list[dict]:
    if not isinstance(entity_id, str) or not entity_id:
        return []
    return [
        item
        for item in list_document_sequences(entity_id=entity_id, active_only=active_only)
        if isinstance(item, dict) and item.get("number_field_id")
    ]


def _sequence_error_response(exc: SequenceError) -> JSONResponse:
    return _error_response(exc.code, exc.message, exc.path, detail=exc.detail, status=exc.status)


def _document_numbering_write_errors(actor: dict | None, entity_def: dict | None, existing_record: dict | None, data: dict | None) -> list[dict]:
    if not isinstance(entity_def, dict) or not isinstance(data, dict):
        return []
    entity_id = entity_def.get("id")
    if not isinstance(entity_id, str) or not entity_id:
        return []
    is_admin = _is_admin_actor(actor)
    errors: list[dict] = []
    for definition in _document_sequences_for_entity(entity_id):
        field_id = definition.get("number_field_id")
        if not isinstance(field_id, str) or field_id not in data:
            continue
        existing_value = existing_record.get(field_id) if isinstance(existing_record, dict) else None
        incoming_value = data.get(field_id)
        if incoming_value == existing_value:
            continue
        has_assigned_number = isinstance(existing_value, str) and existing_value.strip()
        if definition.get("allow_admin_override") is True and is_admin:
            continue
        if has_assigned_number and definition.get("lock_after_assignment", True) is False:
            continue
        if has_assigned_number and definition.get("lock_after_assignment", True):
            errors.append(
                {
                    "code": "NUMBER_LOCKED",
                    "message": "Document number is locked after assignment.",
                    "path": field_id,
                    "detail": {"field_id": field_id, "sequence_code": definition.get("code")},
                }
            )
        else:
            errors.append(
                {
                    "code": "NUMBER_MANAGED",
                    "message": "Document number is managed by the numbering engine.",
                    "path": field_id,
                    "detail": {"field_id": field_id, "sequence_code": definition.get("code")},
                }
            )
    return errors


def _sequence_should_assign(
    definition: dict,
    workflow: dict | None,
    before_record: dict | None,
    after_record: dict | None,
    lifecycle_event: str,
) -> bool:
    if not isinstance(definition, dict) or not isinstance(after_record, dict):
        return False
    field_id = definition.get("number_field_id")
    if isinstance(field_id, str) and isinstance(after_record.get(field_id), str) and after_record.get(field_id).strip():
        return False
    assign_on = definition.get("assign_on") or "create"
    if assign_on == "create":
        return lifecycle_event == "create"
    if assign_on == "save":
        return lifecycle_event in {"create", "save"}
    if assign_on == "custom":
        return False
    status_field = workflow.get("status_field") if isinstance(workflow, dict) else None
    if not isinstance(status_field, str):
        return False
    before_status = before_record.get(status_field) if isinstance(before_record, dict) else None
    after_status = after_record.get(status_field)
    if before_status == after_status or after_status in (None, ""):
        return False
    trigger_status_values = definition.get("trigger_status_values") if isinstance(definition.get("trigger_status_values"), list) else []
    if trigger_status_values:
        return after_status in trigger_status_values
    normalized = str(after_status).strip().lower()
    if assign_on == "confirm":
        return normalized in {"confirmed", "confirm", "accepted", "approved"}
    if assign_on == "issue":
        return normalized in {"issued", "issue"}
    return False


def _apply_document_numbering_after_write(
    request: Request,
    entity_def: dict | None,
    record_id: str | None,
    before_record: dict | None,
    after_record: dict | None,
    actor: dict | None,
    manifest: dict | None,
    *,
    lifecycle_event: str,
) -> dict | None:
    if not isinstance(entity_def, dict) or not isinstance(record_id, str) or not isinstance(after_record, dict):
        return after_record
    entity_id = entity_def.get("id")
    if not isinstance(entity_id, str) or not entity_id:
        return after_record
    workflow = _find_entity_workflow(manifest, entity_id) if isinstance(manifest, dict) else None
    assigned = False
    next_record = dict(after_record)
    for definition in _document_sequences_for_entity(entity_id, active_only=True):
        if not _sequence_should_assign(definition, workflow, before_record, next_record, lifecycle_event):
            continue
        assigned_number = assign_document_number(
            definition,
            record_id,
            next_record,
            actor=actor,
            event_label=definition.get("assign_on") if isinstance(definition.get("assign_on"), str) else lifecycle_event,
        )
        field_id = definition.get("number_field_id")
        if isinstance(field_id, str) and assigned_number and next_record.get(field_id) != assigned_number:
            next_record[field_id] = assigned_number
            assigned = True
    if not assigned:
        return after_record
    persisted = _update_record_with_computed_fields(
        request,
        entity_id,
        entity_def,
        record_id,
        next_record,
        before_record=before_record,
    )
    return persisted.get("record") if isinstance(persisted, dict) and isinstance(persisted.get("record"), dict) else next_record


def _document_numbering_assignment_errors(
    entity_def: dict | None,
    before_record: dict | None,
    after_record: dict | None,
    manifest: dict | None,
    *,
    lifecycle_event: str,
) -> list[dict]:
    if not isinstance(entity_def, dict) or not isinstance(after_record, dict):
        return []
    entity_id = entity_def.get("id")
    if not isinstance(entity_id, str) or not entity_id:
        return []
    workflow = _find_entity_workflow(manifest, entity_id) if isinstance(manifest, dict) else None
    errors: list[dict] = []
    for definition in _document_sequences_for_entity(entity_id, active_only=True):
        if not _sequence_should_assign(definition, workflow, before_record, after_record, lifecycle_event):
            continue
        try:
            preview_document_number(definition, context={"record": after_record})
        except SequenceError as exc:
            errors.append(
                {
                    "code": exc.code,
                    "message": exc.message,
                    "path": exc.path or definition.get("number_field_id"),
                    "detail": exc.detail or {"sequence_code": definition.get("code")},
                }
            )
    return errors


def _filter_manifest_for_actor(manifest: dict, module_id: str, actor: dict | None, manifest_hash: str | None = None) -> dict | None:
    if not _module_visible_for_actor(actor, module_id):
        return None
    cache_key = None
    if isinstance(manifest_hash, str) and manifest_hash:
        cache_key = f"filtered:{get_org_id()}:{module_id}:{manifest_hash}:{_access_policy_hash(actor)}"
        cached = _cache_get("manifest", cache_key)
        if isinstance(cached, dict):
            return cached
    policy = _access_policy_for_actor(actor)
    if _has_capability(actor, "records.write") and isinstance(policy, dict):
        unrestricted = True
        for key in ("module_access", "entity_access", "entity_scope_rules", "field_access", "action_access"):
            value = policy.get(key)
            if isinstance(value, dict) and value:
                unrestricted = False
                break
        if unrestricted:
            out = manifest if isinstance(manifest, dict) else {}
            if isinstance(cache_key, str):
                _cache_set("manifest", out, cache_key)
            return out
    out = copy.deepcopy(manifest if isinstance(manifest, dict) else {})
    entities = out.get("entities") if isinstance(out.get("entities"), list) else []
    visible_entities: set[str] = set()
    visible_fields: set[str] = set()
    readonly_fields: set[str] = set()
    filtered_entities: list[dict] = []
    for entity in entities:
        if not isinstance(entity, dict):
            continue
        entity_id = _normalize_entity_id(entity.get("id"))
        entity_access = _entity_access_level_for_actor(actor, module_id, entity_id)
        if entity_access == "none":
            continue
        entity_copy = copy.deepcopy(entity)
        fields = entity_copy.get("fields") if isinstance(entity_copy.get("fields"), list) else []
        managed_number_fields = {
            item.get("number_field_id")
            for item in _document_sequences_for_entity(entity_id, active_only=True)
            if isinstance(item, dict) and isinstance(item.get("number_field_id"), str)
        }
        filtered_fields: list[dict] = []
        for field in fields:
            if not isinstance(field, dict):
                continue
            field_id = field.get("id")
            if not isinstance(field_id, str) or not field_id:
                continue
            field_access = _field_access_level_for_actor(actor, module_id, entity_id, field_id)
            if field_access == "hidden":
                continue
            field_copy = copy.deepcopy(field)
            if field_access != "write":
                field_copy["readonly"] = True
                readonly_fields.add(field_id)
            if field_id in managed_number_fields:
                field_copy["readonly"] = True
                readonly_fields.add(field_id)
            visible_fields.add(field_id)
            filtered_fields.append(field_copy)
        entity_copy["fields"] = filtered_fields
        filtered_entities.append(entity_copy)
        visible_entities.add(entity_id)
    out["entities"] = filtered_entities

    filtered_views: list[dict] = []
    visible_view_ids: set[str] = set()
    for view in out.get("views") or []:
        if not isinstance(view, dict):
            continue
        view_entity = view.get("entity") or view.get("entity_id") or view.get("entityId")
        if isinstance(view_entity, str) and _normalize_entity_id(view_entity) not in visible_entities:
            continue
        view_copy = copy.deepcopy(view)
        kind = view_copy.get("kind") or view_copy.get("type")
        if kind == "list":
            columns = view_copy.get("columns") if isinstance(view_copy.get("columns"), list) else []
            view_copy["columns"] = [
                col
                for col in columns
                if isinstance(col, dict) and isinstance(col.get("field_id"), str) and col.get("field_id") in visible_fields
            ]
            header = view_copy.get("header") if isinstance(view_copy.get("header"), dict) else None
            if header and isinstance(header.get("search"), dict):
                search_fields = header["search"].get("fields")
                if isinstance(search_fields, list):
                    header["search"]["fields"] = [field_id for field_id in search_fields if isinstance(field_id, str) and field_id in visible_fields]
        elif kind == "form":
            sections = view_copy.get("sections") if isinstance(view_copy.get("sections"), list) else []
            filtered_sections: list[dict] = []
            visible_section_ids: set[str] = set()
            for section in sections:
                if not isinstance(section, dict):
                    continue
                fields = section.get("fields") if isinstance(section.get("fields"), list) else []
                next_fields = [field_id for field_id in fields if isinstance(field_id, str) and field_id in visible_fields]
                has_line_editor = isinstance(section.get("line_editor"), dict) or isinstance(section.get("lineEditor"), dict)
                if not next_fields and not has_line_editor:
                    continue
                next_section = copy.deepcopy(section)
                if isinstance(next_section.get("fields"), list):
                    next_section["fields"] = next_fields
                for line_editor_key in ("line_editor", "lineEditor"):
                    line_editor = next_section.get(line_editor_key)
                    if not isinstance(line_editor, dict):
                        continue
                    columns = line_editor.get("columns")
                    if isinstance(columns, list):
                        next_columns = []
                        for col in columns:
                            if not (
                                isinstance(col, dict)
                                and isinstance(col.get("field_id"), str)
                                and col.get("field_id") in visible_fields
                            ):
                                continue
                            next_col = copy.deepcopy(col)
                            currency_field = next_col.get("currency_field")
                            if isinstance(currency_field, str) and currency_field not in visible_fields:
                                next_col.pop("currency_field", None)
                            next_columns.append(next_col)
                        line_editor["columns"] = next_columns
                    for map_key in ("item_field_map", "itemFieldMap", "parent_field_map", "parentFieldMap", "defaults", "custom_line_defaults", "customLineDefaults"):
                        mapping = line_editor.get(map_key)
                        if isinstance(mapping, dict):
                            line_editor[map_key] = {key: value for key, value in mapping.items() if isinstance(key, str) and key in visible_fields}
                filtered_sections.append(next_section)
                section_id = next_section.get("id")
                if isinstance(section_id, str) and section_id:
                    visible_section_ids.add(section_id)
            view_copy["sections"] = filtered_sections
            header = view_copy.get("header") if isinstance(view_copy.get("header"), dict) else None
            if header and isinstance(header.get("statusbar"), dict):
                status_field_id = header["statusbar"].get("field_id")
                if not isinstance(status_field_id, str) or status_field_id not in visible_fields:
                    header.pop("statusbar", None)
            if header and isinstance(header.get("tabs"), dict):
                tabs = header["tabs"].get("tabs")
                if isinstance(tabs, list):
                    next_tabs: list[dict] = []
                    for tab in tabs:
                        if not isinstance(tab, dict):
                            continue
                        section_ids = tab.get("sections") if isinstance(tab.get("sections"), list) else []
                        next_section_ids = [section_id for section_id in section_ids if isinstance(section_id, str) and section_id in visible_section_ids]
                        tab_content = tab.get("content") if isinstance(tab.get("content"), list) else []
                        if not next_section_ids and not tab_content:
                            continue
                        next_tab = copy.deepcopy(tab)
                        next_tab["sections"] = next_section_ids
                        next_tabs.append(next_tab)
                    header["tabs"]["tabs"] = next_tabs
                    default_tab = header["tabs"].get("default_tab")
                    if not isinstance(default_tab, str) or default_tab not in {
                        tab.get("id") for tab in next_tabs if isinstance(tab, dict) and isinstance(tab.get("id"), str)
                    }:
                        if next_tabs:
                            header["tabs"]["default_tab"] = next_tabs[0].get("id")
                        else:
                            header.pop("tabs", None)
        view_id = view.get("id")
        if isinstance(view_id, str):
            visible_view_ids.add(view_id)
        filtered_views.append(view_copy)
    out["views"] = filtered_views

    filtered_actions: list[dict] = []
    for action in out.get("actions") or []:
        if not isinstance(action, dict):
            continue
        action_id = action.get("id")
        if isinstance(action_id, str) and not _action_visible_for_actor(actor, module_id, action_id):
            continue
        filtered_actions.append(action)
    out["actions"] = filtered_actions

    app_def = out.get("app")
    if isinstance(app_def, dict):
        defaults = app_def.get("defaults")
        if isinstance(defaults, dict):
            entities_cfg = defaults.get("entities")
            if isinstance(entities_cfg, dict):
                next_entities_cfg = {}
                for key, value in entities_cfg.items():
                    if _normalize_entity_id(key) in visible_entities:
                        next_entities_cfg[key] = value
                defaults["entities"] = next_entities_cfg

    def _filter_node(node: Any) -> Any:
        if isinstance(node, list):
            out_items = []
            for item in node:
                filtered = _filter_node(item)
                if filtered is not None:
                    out_items.append(filtered)
            return out_items
        if isinstance(node, dict):
            field_id = node.get("field_id")
            if isinstance(field_id, str):
                if field_id not in visible_fields:
                    return None
                next_node = copy.deepcopy(node)
                if field_id in readonly_fields:
                    next_node["readonly"] = True
            else:
                next_node = copy.deepcopy(node)
            action_id = next_node.get("action_id")
            if isinstance(action_id, str) and not _action_visible_for_actor(actor, module_id, action_id):
                return None
            if (next_node.get("kind") or next_node.get("type")) == "related_list":
                related_entity = next_node.get("entity_id") or next_node.get("entity")
                if isinstance(related_entity, str) and _normalize_entity_id(related_entity) not in visible_entities:
                    return None
            for key, value in list(next_node.items()):
                if key in {"entities", "views", "actions"}:
                    continue
                if isinstance(value, (list, dict)):
                    next_node[key] = _filter_node(value)
            view_ref = next_node.get("view_id") or next_node.get("view") or next_node.get("target")
            view_ref_id = None
            if isinstance(view_ref, str):
                if view_ref.startswith("view:"):
                    view_ref_id = view_ref[5:]
                elif view_ref.startswith("view."):
                    view_ref_id = view_ref
            if view_ref_id and visible_view_ids and view_ref_id not in visible_view_ids:
                return None
            return next_node
        return node

    for view in out.get("views") or []:
        if not isinstance(view, dict):
            continue
        header = view.get("header") if isinstance(view.get("header"), dict) else None
        tabs_cfg = header.get("tabs") if isinstance(header, dict) and isinstance(header.get("tabs"), dict) else None
        tabs = tabs_cfg.get("tabs") if isinstance(tabs_cfg, dict) else None
        if not isinstance(tabs, list):
            continue
        next_tabs: list[dict] = []
        for tab in tabs:
            if not isinstance(tab, dict):
                continue
            next_tab = copy.deepcopy(tab)
            content = next_tab.get("content")
            if isinstance(content, list):
                next_tab["content"] = _filter_node(content)
            sections = next_tab.get("sections") if isinstance(next_tab.get("sections"), list) else []
            content = next_tab.get("content") if isinstance(next_tab.get("content"), list) else []
            if not sections and not content:
                continue
            next_tabs.append(next_tab)
        tabs_cfg["tabs"] = next_tabs
        default_tab = tabs_cfg.get("default_tab")
        if not isinstance(default_tab, str) or default_tab not in {
            tab.get("id") for tab in next_tabs if isinstance(tab, dict) and isinstance(tab.get("id"), str)
        }:
            if next_tabs:
                tabs_cfg["default_tab"] = next_tabs[0].get("id")
            else:
                header.pop("tabs", None)

    out["pages"] = _filter_node(out.get("pages") or [])
    if isinstance(cache_key, str):
        _cache_set("manifest", copy.deepcopy(out), cache_key)
    return out


def _has_capability(actor: dict | None, capability: str) -> bool:
    if not isinstance(actor, dict):
        return False
    scopes = actor.get("api_scopes")
    if isinstance(scopes, list):
        normalized = {str(item).strip() for item in scopes if isinstance(item, str) and str(item).strip()}
        if "*" in normalized or capability in normalized:
            return True
    if actor.get("platform_role") == "superadmin":
        return True
    role = actor.get("workspace_role") or actor.get("role") or "member"
    return capability in _CAPABILITIES_BY_ROLE.get(role, set())


def _require_capability(actor: dict | None, capability: str, message: str = "Forbidden") -> JSONResponse | None:
    if not _has_capability(actor, capability):
        return _error_response("FORBIDDEN", message, status=403)
    return None


def _actor_permissions(actor: dict | None) -> dict[str, bool]:
    capabilities = (
        "workspace.manage_members",
        "workspace.manage_settings",
        "modules.manage",
        "templates.manage",
        "automations.manage",
        "records.read",
        "records.write",
    )
    return {
        "workspace_manage_members": _has_capability(actor, "workspace.manage_members"),
        "workspace_manage_settings": _has_capability(actor, "workspace.manage_settings"),
        "modules_manage": _has_capability(actor, "modules.manage"),
        "templates_manage": _has_capability(actor, "templates.manage"),
        "automations_manage": _has_capability(actor, "automations.manage"),
        "records_read": _has_capability(actor, "records.read"),
        "records_write": _has_capability(actor, "records.write"),
        "can_manage_workspace": _has_capability(actor, "workspace.manage_settings"),
        "can_manage_members": _has_capability(actor, "workspace.manage_members"),
        "can_manage_modules": _has_capability(actor, "modules.manage"),
        "can_manage_templates": _has_capability(actor, "templates.manage"),
        "can_manage_automations": _has_capability(actor, "automations.manage"),
        "can_read_records": _has_capability(actor, "records.read"),
        "can_write_records": _has_capability(actor, "records.write"),
        "is_superadmin": bool(isinstance(actor, dict) and actor.get("platform_role") == "superadmin"),
    }


def _require_admin(actor: dict | None) -> JSONResponse | None:
    denied = _require_capability(actor, "workspace.manage_settings", "Admin role required")
    if denied:
        return denied
    return None


def _require_superadmin(actor: dict | None, message: str = "Superadmin role required") -> JSONResponse | None:
    if not isinstance(actor, dict) or actor.get("platform_role") != "superadmin":
        return _error_response("FORBIDDEN", message, status=403)
    return None


def _normalize_api_scopes(raw_scopes: Any) -> tuple[list[str], list[str]]:
    if raw_scopes is None:
        return [], []
    if not isinstance(raw_scopes, list):
        return [], ["scopes must be a list of scope strings"]
    scopes: list[str] = []
    invalid: list[str] = []
    seen: set[str] = set()
    for item in raw_scopes:
        if not isinstance(item, str):
            invalid.append(str(item))
            continue
        scope = item.strip()
        if not scope or scope in seen:
            continue
        seen.add(scope)
        if scope not in _API_CREDENTIAL_SCOPES:
            invalid.append(scope)
            continue
        scopes.append(scope)
    return scopes, invalid


def _resolve_api_credential_expiry(body: dict) -> tuple[str | None, JSONResponse | None]:
    expires_at = body.get("expires_at")
    expires_in_days = body.get("expires_in_days")
    if expires_at not in (None, ""):
        if not isinstance(expires_at, str):
            return None, _error_response("EXPIRES_AT_INVALID", "expires_at must be an ISO datetime string", "expires_at", status=400)
        try:
            parsed = datetime.fromisoformat(expires_at.strip().replace("Z", "+00:00")).astimezone(timezone.utc)
        except Exception as exc:
            return None, _error_response(
                "EXPIRES_AT_INVALID",
                "expires_at must be a valid ISO datetime string",
                "expires_at",
                detail={"error": str(exc)},
                status=400,
            )
        return parsed.strftime("%Y-%m-%dT%H:%M:%SZ"), None
    if expires_in_days not in (None, ""):
        try:
            days = int(expires_in_days)
        except Exception:
            return None, _error_response("EXPIRES_IN_DAYS_INVALID", "expires_in_days must be an integer", "expires_in_days", status=400)
        if days <= 0:
            return None, _error_response("EXPIRES_IN_DAYS_INVALID", "expires_in_days must be greater than zero", "expires_in_days", status=400)
        return (datetime.now(timezone.utc) + timedelta(days=days)).strftime("%Y-%m-%dT%H:%M:%SZ"), None
    return None, None


_WORKSPACE_ROLES = {"admin", "member", "readonly", "portal"}
_PLATFORM_ROLES = {"standard", "superadmin"}
_MANAGED_ACCOUNT_STATES = {"staged", "handoff_required", "active"}
_MANAGED_ACCOUNT_FLAG_KEY = "octo_managed_account"
_MANAGED_ACCOUNT_STATE_KEY = "octo_managed_account_state"
_MANAGED_ACCOUNT_WORKSPACE_KEY = "octo_managed_workspace_id"
_MANAGED_ACCOUNT_CREATED_BY_KEY = "octo_managed_created_by"
_AUTO_WORKSPACE_ON_EMPTY_KEY = "octo_auto_workspace_on_empty"
_PASSWORD_HANDOFF_ALLOWED_PATHS = {
    "/access/password-handoff/complete",
}


def _normalize_workspace_role(value: Any) -> str | None:
    if not isinstance(value, str):
        return None
    role = value.strip().lower()
    if role == "owner":
        role = "admin"
    if role in _WORKSPACE_ROLES:
        return role
    return None


def _coerce_json_object(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return dict(value)
    if isinstance(value, str) and value.strip():
        try:
            decoded = json.loads(value)
        except Exception:
            return {}
        if isinstance(decoded, dict):
            return dict(decoded)
    return {}


def _normalize_managed_account_state(value: Any) -> str | None:
    if not isinstance(value, str):
        return None
    normalized = value.strip().lower()
    if normalized in _MANAGED_ACCOUNT_STATES:
        return normalized
    return None


def _managed_account_state_from_metadata(metadata: Any) -> str | None:
    data = _coerce_json_object(metadata)
    return _normalize_managed_account_state(data.get(_MANAGED_ACCOUNT_STATE_KEY))


def _managed_account_state_from_claims(claims: Any) -> str | None:
    if not isinstance(claims, dict):
        return None
    return _managed_account_state_from_metadata(claims.get("app_metadata"))


def _managed_account_state_from_actor(actor: dict | None) -> str | None:
    if not isinstance(actor, dict):
        return None
    return _normalize_managed_account_state(actor.get("managed_account_state"))


def _workspace_auto_create_allowed_from_metadata(metadata: Any) -> bool:
    data = _coerce_json_object(metadata)
    value = data.get(_AUTO_WORKSPACE_ON_EMPTY_KEY)
    if isinstance(value, bool):
        return value
    if isinstance(value, str):
        normalized = value.strip().lower()
        if normalized in {"true", "1", "yes", "on"}:
            return True
        if normalized in {"false", "0", "no", "off"}:
            return False
    return True


def _workspace_auto_create_allowed_from_claims(claims: Any) -> bool:
    if not isinstance(claims, dict):
        return True
    return _workspace_auto_create_allowed_from_metadata(claims.get("app_metadata"))


def _actor_requires_password_handoff(actor: dict | None) -> bool:
    return _managed_account_state_from_actor(actor) == "handoff_required"


def _merge_managed_account_app_metadata(
    existing: Any,
    *,
    state: str,
    workspace_id: str | None = None,
    created_by_user_id: str | None = None,
) -> dict[str, Any]:
    merged = _coerce_json_object(existing)
    merged[_MANAGED_ACCOUNT_FLAG_KEY] = True
    merged[_MANAGED_ACCOUNT_STATE_KEY] = state
    if isinstance(workspace_id, str) and workspace_id.strip():
        merged[_MANAGED_ACCOUNT_WORKSPACE_KEY] = workspace_id.strip()
    if isinstance(created_by_user_id, str) and created_by_user_id.strip():
        merged[_MANAGED_ACCOUNT_CREATED_BY_KEY] = created_by_user_id.strip()
    return merged


def _clear_managed_account_app_metadata(existing: Any) -> dict[str, Any]:
    cleaned = _coerce_json_object(existing)
    cleaned.pop(_MANAGED_ACCOUNT_FLAG_KEY, None)
    cleaned.pop(_MANAGED_ACCOUNT_STATE_KEY, None)
    cleaned.pop(_MANAGED_ACCOUNT_WORKSPACE_KEY, None)
    cleaned.pop(_MANAGED_ACCOUNT_CREATED_BY_KEY, None)
    return cleaned


def _set_workspace_auto_create_app_metadata(existing: Any, *, enabled: bool) -> dict[str, Any]:
    updated = _coerce_json_object(existing)
    updated[_AUTO_WORKSPACE_ON_EMPTY_KEY] = bool(enabled)
    return updated


def _generate_temporary_password(length: int = 16) -> str:
    alphabet = "ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz23456789!@#$%^&*"
    size = max(12, int(length or 0))
    return "".join(secrets.choice(alphabet) for _ in range(size))


def _supabase_admin_headers() -> dict:
    key = (os.getenv("SUPABASE_SERVICE_ROLE_KEY") or "").strip()
    return {"Authorization": f"Bearer {key}", "apikey": key, "Content-Type": "application/json"}


def _supabase_admin_enabled() -> bool:
    return bool((os.getenv("SUPABASE_URL") or "").strip() and (os.getenv("SUPABASE_SERVICE_ROLE_KEY") or "").strip())


def _supabase_invite_user(email: str, redirect_to: str | None = None) -> dict:
    if not _supabase_admin_enabled():
        raise RuntimeError("Supabase service role not configured")
    base = (os.getenv("SUPABASE_URL") or "").strip().rstrip("/")
    payload: dict[str, Any] = {"email": email}
    query = ""
    if isinstance(redirect_to, str) and redirect_to.strip():
        query = f"?redirect_to={urllib.parse.quote(redirect_to.strip(), safe=':/')}"
    req = urllib.request.Request(
        f"{base}/auth/v1/invite{query}",
        data=json.dumps(payload).encode("utf-8"),
        headers=_supabase_admin_headers(),
        method="POST",
    )
    try:
        with urllib.request.urlopen(req, timeout=20) as res:
            return json.loads(res.read().decode("utf-8"))
    except urllib.error.HTTPError as exc:
        body = exc.read().decode("utf-8", errors="ignore")
        raise RuntimeError(f"invite_failed:{exc.code}:{body}") from exc


def _supabase_create_user(
    email: str,
    password: str,
    *,
    email_confirm: bool = True,
    user_metadata: dict[str, Any] | None = None,
) -> dict:
    if not _supabase_admin_enabled():
        raise RuntimeError("Supabase service role not configured")
    base = (os.getenv("SUPABASE_URL") or "").strip().rstrip("/")
    payload: dict[str, Any] = {
        "email": email,
        "password": password,
        "email_confirm": bool(email_confirm),
    }
    if isinstance(user_metadata, dict) and user_metadata:
        payload["user_metadata"] = user_metadata
    req = urllib.request.Request(
        f"{base}/auth/v1/admin/users",
        data=json.dumps(payload).encode("utf-8"),
        headers=_supabase_admin_headers(),
        method="POST",
    )
    try:
        with urllib.request.urlopen(req, timeout=20) as res:
            raw = res.read().decode("utf-8", errors="ignore").strip()
            return json.loads(raw) if raw else {}
    except urllib.error.HTTPError as exc:
        body = exc.read().decode("utf-8", errors="ignore")
        raise RuntimeError(f"create_user_failed:{exc.code}:{body}") from exc


def _supabase_send_recovery(email: str, redirect_to: str | None = None) -> dict:
    if not _supabase_admin_enabled():
        raise RuntimeError("Supabase service role not configured")
    base = (os.getenv("SUPABASE_URL") or "").strip().rstrip("/")
    query = ""
    if isinstance(redirect_to, str) and redirect_to.strip():
        query = f"?redirect_to={urllib.parse.quote(redirect_to.strip(), safe=':/')}"
    payload: dict[str, Any] = {"email": email}
    req = urllib.request.Request(
        f"{base}/auth/v1/recover{query}",
        data=json.dumps(payload).encode("utf-8"),
        headers=_supabase_admin_headers(),
        method="POST",
    )
    try:
        with urllib.request.urlopen(req, timeout=20) as res:
            raw = res.read().decode("utf-8", errors="ignore").strip()
            return json.loads(raw) if raw else {"ok": True}
    except urllib.error.HTTPError as exc:
        body = exc.read().decode("utf-8", errors="ignore")
        raise RuntimeError(f"recover_failed:{exc.code}:{body}") from exc


def _supabase_update_user_email(user_id: str, new_email: str) -> dict:
    return _supabase_update_user(user_id, {"email": new_email})


def _supabase_update_user(user_id: str, attributes: dict[str, Any]) -> dict:
    if not _supabase_admin_enabled():
        raise RuntimeError("Supabase service role not configured")
    base = (os.getenv("SUPABASE_URL") or "").strip().rstrip("/")
    payload: dict[str, Any] = dict(attributes or {})
    req = urllib.request.Request(
        f"{base}/auth/v1/admin/users/{urllib.parse.quote(user_id)}",
        data=json.dumps(payload).encode("utf-8"),
        headers=_supabase_admin_headers(),
        method="PUT",
    )
    try:
        with urllib.request.urlopen(req, timeout=20) as res:
            raw = res.read().decode("utf-8", errors="ignore").strip()
            return json.loads(raw) if raw else {}
    except urllib.error.HTTPError as exc:
        body = exc.read().decode("utf-8", errors="ignore")
        raise RuntimeError(f"update_user_failed:{exc.code}:{body}") from exc


def _default_invite_redirect() -> str:
    explicit = (os.getenv("INVITE_REDIRECT_URL") or "").strip()
    if explicit:
        return explicit
    app_public = (os.getenv("APP_PUBLIC_URL") or "").strip()
    if app_public:
        return app_public.rstrip("/") + "/auth/set-password"
    return "https://app.octodrop.com/auth/set-password"


def _supabase_delete_user(user_id: str) -> None:
    if not _supabase_admin_enabled():
        raise RuntimeError("Supabase service role not configured")
    base = (os.getenv("SUPABASE_URL") or "").strip().rstrip("/")
    req = urllib.request.Request(
        f"{base}/auth/v1/admin/users/{urllib.parse.quote(user_id)}",
        headers=_supabase_admin_headers(),
        method="DELETE",
    )
    try:
        with urllib.request.urlopen(req, timeout=20):
            return
    except urllib.error.HTTPError as exc:
        body = exc.read().decode("utf-8", errors="ignore")
        raise RuntimeError(f"delete_user_failed:{exc.code}:{body}") from exc


def _find_auth_user_id_by_email(email: str) -> str | None:
    if not isinstance(email, str) or "@" not in email:
        return None
    with get_conn() as conn:
        try:
            row = fetch_one(
                conn,
                """
                select id::text as id
                from auth.users
                where lower(email)=lower(%s)
                limit 1
                """,
                [email.strip().lower()],
                query_name="auth_users.find_by_email",
            )
            user_id = (row or {}).get("id")
            return user_id if isinstance(user_id, str) and user_id else None
        except Exception:
            return None


def _find_auth_user_row_by_id(user_id: str) -> dict[str, Any] | None:
    if not isinstance(user_id, str) or not user_id.strip():
        return None
    with get_conn() as conn:
        try:
            row = fetch_one(
                conn,
                """
                select
                  id::text as id,
                  email,
                  raw_app_meta_data,
                  raw_user_meta_data
                from auth.users
                where id::text=%s
                limit 1
                """,
                [user_id.strip()],
                query_name="auth_users.find_by_id",
            )
        except Exception:
            return None
    if not isinstance(row, dict):
        return None
    row = dict(row)
    row["app_metadata"] = _coerce_json_object(row.get("raw_app_meta_data"))
    row["user_metadata"] = _coerce_json_object(row.get("raw_user_meta_data"))
    row["managed_account_state"] = _managed_account_state_from_metadata(row.get("app_metadata"))
    return row


def _supabase_update_managed_account_state(
    user_id: str,
    *,
    state: str,
    workspace_id: str | None = None,
    created_by_user_id: str | None = None,
    password: str | None = None,
    email_confirm: bool | None = None,
) -> dict:
    auth_user = _find_auth_user_row_by_id(user_id)
    if not auth_user:
        raise RuntimeError("auth_user_not_found")
    app_metadata = _merge_managed_account_app_metadata(
        auth_user.get("app_metadata"),
        state=state,
        workspace_id=workspace_id or auth_user.get("app_metadata", {}).get(_MANAGED_ACCOUNT_WORKSPACE_KEY),
        created_by_user_id=created_by_user_id or auth_user.get("app_metadata", {}).get(_MANAGED_ACCOUNT_CREATED_BY_KEY),
    )
    payload: dict[str, Any] = {"app_metadata": app_metadata}
    if isinstance(password, str) and password:
        payload["password"] = password
    if email_confirm is not None:
        payload["email_confirm"] = bool(email_confirm)
    return _supabase_update_user(user_id, payload)


def _supabase_clear_managed_account_state(user_id: str) -> dict:
    auth_user = _find_auth_user_row_by_id(user_id)
    if not auth_user:
        raise RuntimeError("auth_user_not_found")
    app_metadata = _clear_managed_account_app_metadata(auth_user.get("app_metadata"))
    updated = _supabase_update_user(user_id, {"app_metadata": app_metadata})
    _update_auth_user_app_metadata_direct(user_id, app_metadata)
    return updated


def _update_auth_user_app_metadata_direct(user_id: str, app_metadata: dict[str, Any]) -> None:
    if not isinstance(user_id, str) or not user_id.strip() or not isinstance(app_metadata, dict):
        return
    with get_conn() as conn:
        execute(
            conn,
            """
            update auth.users
            set raw_app_meta_data=%s::jsonb
            where id::text=%s
            """,
            [json.dumps(app_metadata), user_id.strip()],
            query_name="auth_users.update_app_metadata_direct",
        )


def _supabase_set_auto_workspace_creation(user_id: str, *, enabled: bool) -> dict:
    auth_user = _find_auth_user_row_by_id(user_id)
    if not auth_user:
        raise RuntimeError("auth_user_not_found")
    app_metadata = _set_workspace_auto_create_app_metadata(auth_user.get("app_metadata"), enabled=enabled)
    return _supabase_update_user(user_id, {"app_metadata": app_metadata})


def _password_handoff_required_response(actor: dict | None, path: str | None) -> JSONResponse | None:
    if not _actor_requires_password_handoff(actor):
        return None
    normalized_path = str(path or "").strip()
    if normalized_path in _PASSWORD_HANDOFF_ALLOWED_PATHS:
        return None
    return _error_response(
        "PASSWORD_CHANGE_REQUIRED",
        "Password change required before accessing the app",
        detail={"redirect_to": "/auth/set-password"},
        status=403,
    )


class ActorContextMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request: Request, call_next):
        if request.method == "OPTIONS" or _is_public_path(request.url.path):
            return await call_next(request)
        actor = _resolve_actor(request)
        if isinstance(actor, JSONResponse):
            return _attach_cors_headers(request, actor)
        handoff_denied = _password_handoff_required_response(actor, request.url.path)
        if handoff_denied:
            return _attach_cors_headers(request, handoff_denied)
        if request.url.path.startswith("/studio2") or request.url.path.startswith("/studio/"):
            denied = _require_capability(actor, "modules.manage", "Admin role required")
            if denied:
                return _attach_cors_headers(request, denied)
        request.state.actor = actor
        token = set_org_id(actor.get("workspace_id") or "default")
        set_db_user_id(actor.get("user_id"))
        started_at = time.perf_counter()
        response = None
        api_request_logged = False
        ext_api_recent_requests = None
        try:
            if (
                request.url.path.startswith("/ext/")
                and isinstance(actor, dict)
                and actor.get("actor_type") == "api_credential"
                and api_request_log_store
                and actor.get("api_credential_id")
            ):
                recent = api_request_log_store.count_recent(
                    str(actor.get("api_credential_id")),
                    window_seconds=EXT_API_RATE_LIMIT_WINDOW_SECONDS,
                )
                ext_api_recent_requests = recent
                if recent >= EXT_API_RATE_LIMIT_MAX_REQUESTS:
                    response = _error_response(
                        "RATE_LIMITED",
                        "External API rate limit exceeded",
                        detail={
                            "window_seconds": EXT_API_RATE_LIMIT_WINDOW_SECONDS,
                            "max_requests": EXT_API_RATE_LIMIT_MAX_REQUESTS,
                        },
                        status=429,
                    )
                    _set_ext_api_rate_limit_headers(
                        response,
                        remaining=0,
                        limited=True,
                        window_seconds=EXT_API_RATE_LIMIT_WINDOW_SECONDS,
                    )
                    try:
                        api_request_log_store.create(
                            {
                                "api_credential_id": actor.get("api_credential_id"),
                                "method": request.method,
                                "path": request.url.path,
                                "status_code": 429,
                                "duration_ms": int((time.perf_counter() - started_at) * 1000),
                                "ip_address": request.client.host if request.client else None,
                                "user_agent": request.headers.get("user-agent"),
                            }
                        )
                        api_request_logged = True
                    except Exception:
                        pass
                    return _attach_cors_headers(request, response)
            response = await call_next(request)
            return response
        finally:
            if (
                request.url.path.startswith("/ext/")
                and isinstance(actor, dict)
                and actor.get("actor_type") == "api_credential"
                and response is not None
            ):
                consumed = 1
                if isinstance(response, Response) and response.status_code == 429:
                    consumed = 0
                recent_count = ext_api_recent_requests if isinstance(ext_api_recent_requests, int) else 0
                _set_ext_api_rate_limit_headers(
                    response,
                    remaining=EXT_API_RATE_LIMIT_MAX_REQUESTS - recent_count - consumed,
                    limited=bool(isinstance(response, Response) and response.status_code == 429),
                    window_seconds=EXT_API_RATE_LIMIT_WINDOW_SECONDS,
                )
            if (
                request.url.path.startswith("/ext/")
                and isinstance(actor, dict)
                and actor.get("actor_type") == "api_credential"
                and api_request_log_store
                and actor.get("api_credential_id")
                and not api_request_logged
            ):
                try:
                    status_code = None
                    try:
                        status_code = response.status_code  # type: ignore[name-defined]
                    except Exception:
                        status_code = 500
                    api_request_log_store.create(
                        {
                            "api_credential_id": actor.get("api_credential_id"),
                            "method": request.method,
                            "path": request.url.path,
                            "status_code": int(status_code or 500),
                            "duration_ms": int((time.perf_counter() - started_at) * 1000),
                            "ip_address": request.client.host if request.client else None,
                            "user_agent": request.headers.get("user-agent"),
                        }
                    )
                except Exception:
                    pass
            set_db_user_id(None)
            reset_org_id(token)


app.add_middleware(
    CORSMiddleware,
    allow_origins=sorted(_CORS_ORIGINS),
    allow_origin_regex=_CORS_ALLOW_ORIGIN_REGEX,
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)
if _TRUSTED_HOSTS:
    app.add_middleware(TrustedHostMiddleware, allowed_hosts=_TRUSTED_HOSTS)
app.add_middleware(ActorContextMiddleware)
if not DISABLE_AUTH:
    if not SUPABASE_URL:
        raise RuntimeError("SUPABASE_URL is required for auth")
    app.add_middleware(SupabaseAuthMiddleware, supabase_url=SUPABASE_URL, audience=SUPABASE_AUD)


def _json_pointer_escape(token: str) -> str:
    return token.replace("~", "~0").replace("/", "~1")


def _path_to_json_pointer(path: str | None) -> str | None:
    if not path or not isinstance(path, str):
        return None
    if path.startswith("$."):
        path = path[2:]
    elif path.startswith("$"):
        path = path[1:]
    if path.startswith("/"):
        return path
    tokens: list[str] = []
    buf = ""
    i = 0
    while i < len(path):
        ch = path[i]
        if ch == ".":
            if buf:
                tokens.append(buf)
                buf = ""
            i += 1
            continue
        if ch == "[":
            if buf:
                tokens.append(buf)
                buf = ""
            j = path.find("]", i)
            if j == -1:
                break
            tokens.append(path[i + 1 : j])
            i = j + 1
            continue
        buf += ch
        i += 1
    if buf:
        tokens.append(buf)
    if not tokens:
        return None
    return "/" + "/".join(_json_pointer_escape(tok) for tok in tokens if tok != "")


def _normalize_validation_entry(entry) -> dict:
    if isinstance(entry, str):
        return {"code": "ERR", "message": entry, "path": None, "json_pointer": None, "detail": None}
    if not isinstance(entry, dict):
        return {"code": "ERR", "message": str(entry), "path": None, "json_pointer": None, "detail": None}
    path = entry.get("json_pointer") or entry.get("path")
    json_pointer = _path_to_json_pointer(path) if path else None
    payload = dict(entry)
    payload["json_pointer"] = json_pointer
    return payload


def _normalize_validation_list(items: list | None) -> list:
    if not items:
        return []
    return [_normalize_validation_entry(item) for item in items]


def _changed_fields(before: dict, after: dict) -> list[str]:
    if not isinstance(before, dict) or not isinstance(after, dict):
        return []
    keys = set(before.keys()) | set(after.keys())
    changed = []
    for key in sorted(keys):
        if before.get(key) != after.get(key):
            changed.append(key)
    return changed


def _validation_response(errors: list, warnings: list, status: int = 400) -> JSONResponse:
    body = {
        "ok": False,
        "errors": _normalize_validation_list(errors),
        "warnings": _normalize_validation_list(warnings),
        "data": None,
    }
    return JSONResponse(jsonable_encoder(body), status_code=status)


def _require_module_enabled(request: Request, module_id: str, label: str) -> tuple[bool, JSONResponse | None]:
    module = _get_module(request, module_id)
    if module is None:
        return False, _error_response("MODULE_NOT_INSTALLED", f"{label} module not installed", "module_id")
    if not module.get("enabled"):
        return False, _error_response("MODULE_DISABLED", f"{label} module is disabled", "module_id")
    return True, None


def _workflow_required_fields(workflow: dict | None, status_value: str | None) -> list[str]:
    if not workflow or not status_value:
        return []
    required: list[str] = []
    for state in workflow.get("states") or []:
        if not isinstance(state, dict):
            continue
        if state.get("id") == status_value:
            fields = state.get("required_fields")
            if isinstance(fields, list):
                required.extend([f for f in fields if isinstance(f, str)])
    required_map = workflow.get("required_fields_by_state")
    if isinstance(required_map, dict):
        fields = required_map.get(status_value)
        if isinstance(fields, list):
            required.extend([f for f in fields if isinstance(f, str)])
    # de-dupe
    return list(dict.fromkeys(required))


def _log_record_validation_errors(
    entity_id: str,
    payload: dict | None,
    errors: list[dict],
    workflow: dict | None = None,
) -> None:
    payload = payload if isinstance(payload, dict) else {}
    missing_required = [err.get("path") for err in errors if err.get("code") == "REQUIRED_FIELD" and err.get("path")]
    status_value = None
    status_field = workflow.get("status_field") if isinstance(workflow, dict) else None
    if isinstance(status_field, str):
        status_value = payload.get(status_field)
    workflow_required = _workflow_required_fields(workflow, status_value) if workflow else []
    logger.warning(
        "record_validation_failed entity_id=%s missing_required=%s workflow_required=%s payload_keys=%s",
        entity_id,
        sorted(set(missing_required)),
        workflow_required,
        sorted(payload.keys()),
    )


def _wrap_db_constraint_error(exc: Exception) -> dict | None:
    diag = getattr(exc, "diag", None)
    constraint = getattr(diag, "constraint_name", None) if diag else None
    table = getattr(diag, "table_name", None) if diag else None
    column = getattr(diag, "column_name", None) if diag else None
    if constraint or table or column:
        return {
            "code": "DB_CONSTRAINT",
            "message": "Database constraint violation",
            "path": None,
            "detail": {"constraint": constraint, "table": table, "column": column},
        }
    return None



def _with_tx(tx_mgr, fn):
    tx = tx_mgr.begin()
    try:
        result = fn(tx)
        tx.commit()
        return result
    except Exception:
        tx.rollback()
        raise


def _req_cache_get(request: Request | None, key: str):
    cache = getattr(request.state, "cache", None) if request is not None and hasattr(request, "state") else None
    if not isinstance(cache, dict):
        return None
    return cache.get(key)


def _req_cache_set(request: Request | None, key: str, value) -> None:
    cache = getattr(request.state, "cache", None) if request is not None and hasattr(request, "state") else None
    if isinstance(cache, dict):
        cache[key] = value


def _get_module(request: Request, module_id: str):
    cache_key = f"module:{module_id}"
    cached = _req_cache_get(request, cache_key)
    if cached is not None:
        return cached
    modules_cached = _cache_get("modules")
    if isinstance(modules_cached, list):
        for item in modules_cached:
            if item.get("module_id") == module_id:
                _req_cache_set(request, cache_key, item)
                return item
    registry_meta_cached = _req_cache_get(request, "registry:list:meta")
    if isinstance(registry_meta_cached, list):
        for item in registry_meta_cached:
            if item.get("module_id") == module_id:
                _req_cache_set(request, cache_key, item)
                return item
    registry_cached = _cache_get("registry_list")
    if isinstance(registry_cached, list):
        for item in registry_cached:
            if item.get("module_id") == module_id:
                _req_cache_set(request, cache_key, item)
                return item
    module = registry.get(module_id)
    _req_cache_set(request, cache_key, module)
    return module


def _get_registry_list(request: Request, *, fresh: bool = False) -> list[dict]:
    cache_key = "registry:list"
    if not fresh:
        cached = _req_cache_get(request, cache_key)
        if cached is not None:
            return cached
        global_cached = _cache_get("registry_list")
        if global_cached is not None:
            _req_cache_set(request, cache_key, global_cached)
            return global_cached
    modules = registry.list()
    if not fresh:
        _req_cache_set(request, cache_key, modules)
        _cache_set("registry_list", modules)
    return modules


class _CachedRegistry:
    def __init__(self, request: Request):
        self._request = request

    def list(self):
        return _get_registry_list(self._request)


def _registry_for_request(request: Request):
    return _CachedRegistry(request)


def _get_head(request: Request, module_id: str) -> str | None:
    cache_key = f"head:{module_id}"
    cached = _req_cache_get(request, cache_key)
    if cached is not None:
        return cached
    record = _get_module(request, module_id)
    head = record.get("current_hash") if record else None
    if head is None:
        head = store.get_head(module_id)
    _req_cache_set(request, cache_key, head)
    return head


def _get_snapshot(request: Request, module_id: str, manifest_hash: str):
    cache_key = f"snapshot:{module_id}:{manifest_hash}"
    cached = _req_cache_get(request, cache_key)
    if cached is not None:
        return cached
    global_cached = _cache_get("manifest", f"{get_org_id()}:{module_id}:{manifest_hash}")
    if global_cached is not None:
        _req_cache_set(request, cache_key, global_cached)
        return global_cached
    manifest = store.get_snapshot(module_id, manifest_hash)
    _req_cache_set(request, cache_key, manifest)
    _cache_set("manifest", manifest, f"{get_org_id()}:{module_id}:{manifest_hash}")
    return manifest


def _dependency_manifest_index(request: Request, overrides: dict[str, dict] | None = None, *, fresh: bool = False) -> dict[str, dict]:
    cache_key = "dependency_manifest_index"
    cached = None if fresh else _req_cache_get(request, cache_key)
    if isinstance(cached, dict):
        base = copy.deepcopy(cached)
    else:
        base = {}
        for module in _get_registry_list(request, fresh=fresh):
            module_id = module.get("module_id")
            manifest_hash = module.get("current_hash")
            if not isinstance(module_id, str) or not module_id or not isinstance(manifest_hash, str) or not manifest_hash:
                continue
            try:
                manifest = _get_snapshot(request, module_id, manifest_hash)
            except Exception:
                continue
            base[module_id] = {
                "module_id": module_id,
                "manifest": manifest if isinstance(manifest, dict) else {},
                "module_key": module_key_from_manifest(manifest if isinstance(manifest, dict) else {}) or module_id,
                "version": module_version_from_manifest(manifest if isinstance(manifest, dict) else {}),
                "enabled": bool(module.get("enabled")),
            }
        if not fresh:
            _req_cache_set(request, cache_key, copy.deepcopy(base))
    if isinstance(overrides, dict):
        for module_id, manifest in overrides.items():
            if not isinstance(module_id, str) or not module_id:
                continue
            manifest_obj = manifest if isinstance(manifest, dict) else {}
            current = base.get(module_id) or {"module_id": module_id, "enabled": False}
            current["manifest"] = manifest_obj
            current["module_key"] = module_key_from_manifest(manifest_obj) or module_id
            current["version"] = module_version_from_manifest(manifest_obj)
            base[module_id] = current
    return base


def _dependency_entity_owner_index(manifest_index: dict[str, dict]) -> dict[str, str]:
    owners: dict[str, str] = {}
    for module_id, info in manifest_index.items():
        owner_key = info.get("module_key")
        if not isinstance(owner_key, str) or not owner_key:
            owner_key = module_id
        manifest = info.get("manifest")
        entities = manifest.get("entities") if isinstance(manifest, dict) else None
        if not isinstance(entities, list):
            continue
        for entity in entities:
            if not isinstance(entity, dict):
                continue
            entity_id = entity.get("id")
            if not isinstance(entity_id, str) or not entity_id:
                continue
            normalized = entity_id if entity_id.startswith("entity.") else f"entity.{entity_id}"
            owners.setdefault(normalized, owner_key)
    return owners


def _validate_dependency_state(
    request: Request,
    module_id: str,
    manifest: dict,
    mode: str,
) -> tuple[list[dict], list[dict]]:
    errors: list[dict] = []
    warnings: list[dict] = []
    manifest_obj = manifest if isinstance(manifest, dict) else {}
    module_key = module_key_from_manifest(manifest_obj) or module_id
    manifest_index = _dependency_manifest_index(request, overrides={module_id: manifest_obj}, fresh=(mode in {"install", "upgrade"}))
    available_versions = {}
    available_enabled = {}
    for _, data in manifest_index.items():
        key = data.get("module_key")
        if not isinstance(key, str) or not key:
            continue
        available_versions[key] = data.get("version")
        available_enabled[key] = bool(data.get("enabled"))
    if mode in {"install", "upgrade"}:
        # A module being installed/upgraded can satisfy other modules even if currently disabled.
        available_enabled[module_key] = True
    req_errors = validate_required_dependencies(
        module_key,
        manifest_obj,
        available_versions=available_versions,
        available_enabled=available_enabled,
        require_enabled=(mode == "enable"),
    )
    if req_errors:
        errors.extend(req_errors)

    manifests_by_key = {}
    for _, data in manifest_index.items():
        key = data.get("module_key")
        if not isinstance(key, str) or not key:
            continue
        manifests_by_key[key] = data.get("manifest") or {}
    graph = build_dependency_graph(manifests_by_key)
    cycle = find_cycle(graph)
    if cycle and module_key in set(cycle):
        errors.append(
            {
                "code": "MODULE_DEPENDENCY_CYCLE",
                "message": "circular module dependency detected",
                "path": "depends_on.required",
                "detail": {"cycle": cycle},
            }
        )

    declared_required = {item.get("module") for item in normalize_depends_on(manifest_obj).get("required", []) if isinstance(item, dict)}
    entity_owners = _dependency_entity_owner_index(manifest_index)
    for ref in collect_external_entity_references(manifest_obj):
        entity_id = ref.get("entity_id")
        if not isinstance(entity_id, str):
            continue
        owner = entity_owners.get(entity_id)
        if not isinstance(owner, str) or owner == module_key:
            continue
        if owner not in declared_required:
            warnings.append(
                {
                    "code": "MODULE_DEPENDENCY_NOT_DECLARED",
                    "message": "external entity reference found without required dependency declaration",
                    "path": ref.get("path"),
                    "detail": {"entity_id": entity_id, "owner_module": owner, "suggested_dependency": owner},
                }
            )
    return errors, warnings


def _enabled_dependents_for_module(request: Request, module_id: str) -> list[dict]:
    manifest_index = _dependency_manifest_index(request)
    target_info = manifest_index.get(module_id) or {}
    target_key = target_info.get("module_key") if isinstance(target_info.get("module_key"), str) else module_id
    manifests_by_key = {}
    for _, data in manifest_index.items():
        key = data.get("module_key")
        if not isinstance(key, str) or not key:
            continue
        manifests_by_key[key] = data.get("manifest") or {}
    graph = build_dependency_graph(manifests_by_key)
    reverse = build_reverse_dependents(graph)
    dependents: list[dict] = []
    dependent_keys = set(reverse.get(target_key, []))
    for dependent_id, info in manifest_index.items():
        dep_key = info.get("module_key")
        if dep_key not in dependent_keys:
            continue
        if not bool(info.get("enabled")):
            continue
        constraint = None
        dep_items = normalize_depends_on(info.get("manifest") if isinstance(info.get("manifest"), dict) else {}).get("required") or []
        for item in dep_items:
            if isinstance(item, dict) and item.get("module") == target_key:
                constraint = item.get("version") if isinstance(item.get("version"), str) else None
                break
        dependents.append({"module_id": dependent_id, "module_key": dep_key, "version_constraint": constraint})
    return sorted(dependents, key=lambda item: item.get("module_id") or "")


def _disable_block_issue(request: Request, module_id: str) -> dict | None:
    enabled_dependents = _enabled_dependents_for_module(request, module_id)
    if not enabled_dependents:
        return None
    return {
        "code": "MODULE_DISABLE_BLOCKED_BY_DEPENDENTS",
        "message": "Cannot disable module while enabled dependents still require it",
        "path": "module_id",
        "detail": {"module_id": module_id, "enabled_dependents": enabled_dependents},
    }


def _filter_records_by_domain(
    items: list[dict],
    domain: dict | None,
    record_context: dict,
    actor_context: dict | None = None,
) -> list[dict]:
    if not domain:
        return items
    filtered = []
    for item in items:
        record = item.get("record") or {}
        try:
            if eval_condition(
                domain,
                {
                    "record": record_context or {},
                    "candidate": record,
                    "actor": actor_context or {},
                },
            ):
                filtered.append(item)
        except Exception:
            continue
    return filtered


def _enforce_lookup_domains(entity: dict, data: dict) -> list[dict]:
    errors: list[dict] = []
    fields = entity.get("fields") or []
    if not isinstance(fields, list):
        return errors
    for field in fields:
        if not isinstance(field, dict):
            continue
        if field.get("type") != "lookup":
            continue
        domain = field.get("domain")
        if not domain:
            continue
        field_id = field.get("id")
        if not isinstance(field_id, str):
            continue
        value = data.get(field_id)
        if not value:
            continue
        target = field.get("entity")
        if not isinstance(target, str) or not target:
            continue
        target_entity = _normalize_entity_id(target)
        candidate = None
        for candidate_entity_id in (
            target_entity,
            target_entity[7:] if isinstance(target_entity, str) and target_entity.startswith("entity.") else None,
            target,
        ):
            if not isinstance(candidate_entity_id, str) or not candidate_entity_id:
                continue
            candidate = generic_records.get(candidate_entity_id, value)
            if candidate:
                break
        if not candidate:
            errors.append(
                {
                    "code": "LOOKUP_TARGET_NOT_FOUND",
                    "message": "Lookup target not found",
                    "path": field_id,
                    "detail": None,
                }
            )
            continue
        try:
            if not eval_condition(domain, {"record": data, "candidate": candidate.get("record") or {}}):
                errors.append(
                    {
                        "code": "LOOKUP_DOMAIN_VIOLATION",
                        "message": "Lookup selection does not match domain",
                        "path": field_id,
                        "detail": None,
                    }
                )
        except Exception:
            errors.append(
                {
                    "code": "LOOKUP_DOMAIN_VIOLATION",
                    "message": "Lookup selection does not match domain",
                    "path": field_id,
                    "detail": None,
                }
            )
    return errors


def _add_chatter_entry(entity_id: str, record_id: str, entry_type: str, body: str, actor: dict | None) -> None:
    try:
        chatter_store.add(entity_id, record_id, entry_type, body, actor)
    except Exception:
        return


def _activity_view_config(manifest: dict, entity_id: str) -> dict | None:
    views = manifest.get("views") if isinstance(manifest, dict) else None
    if not isinstance(views, list):
        return None
    normalized_entity = _normalize_entity_id(entity_id)
    for view in views:
        if not isinstance(view, dict):
            continue
        vtype = view.get("kind") or view.get("type")
        if vtype != "form":
            continue
        view_entity = _normalize_entity_id(view.get("entity") or view.get("entity_id") or view.get("entityId"))
        if view_entity != normalized_entity:
            continue
        activity = view.get("activity")
        if isinstance(activity, dict) and activity.get("enabled") is True:
            return activity
    return None


def _format_activity_value(value):
    if value is None:
        return "empty"
    if isinstance(value, bool):
        return "Yes" if value else "No"
    if isinstance(value, list):
        if not value:
            return "empty"
        return ", ".join([str(v) for v in value])
    if isinstance(value, dict):
        if "label" in value and value.get("label"):
            return str(value.get("label"))
        if "id" in value and value.get("id"):
            return str(value.get("id"))
        return json.dumps(value, default=str)
    text = str(value)
    return text if text != "" else "empty"


def _format_activity_field_value(field: dict | None, value: Any, lookup_cache: dict[tuple[str, str, str], str | None] | None = None) -> str:
    if not isinstance(field, dict):
        return _format_activity_value(value)
    field_type = field.get("type")
    if field_type == "enum":
        enum_label = _enum_label_for_value(field, value)
        if isinstance(enum_label, str) and enum_label.strip():
            return enum_label
    if field_type == "lookup" and isinstance(value, str) and value.strip():
        target_entity = field.get("entity")
        display_field = field.get("display_field")
        if isinstance(target_entity, str) and isinstance(display_field, str):
            cache_key = (target_entity, display_field, value)
            if isinstance(lookup_cache, dict) and cache_key in lookup_cache:
                cached = lookup_cache.get(cache_key)
                if isinstance(cached, str) and cached.strip():
                    return cached
            label = _lookup_label(target_entity, display_field, value)
            if isinstance(lookup_cache, dict):
                lookup_cache[cache_key] = label
            if isinstance(label, str) and label.strip():
                return label
    return _format_activity_value(value)


def _collect_activity_changes(
    entity_def: dict,
    before_record: dict,
    after_record: dict,
    tracked_fields: list[str] | None = None,
) -> list[dict]:
    fields = entity_def.get("fields") if isinstance(entity_def, dict) else None
    field_by_id = {}
    if isinstance(fields, list):
        for field in fields:
            if isinstance(field, dict) and isinstance(field.get("id"), str):
                field_by_id[field["id"]] = field
    candidates = tracked_fields or sorted(field_by_id.keys())
    changes: list[dict] = []
    lookup_cache: dict[tuple[str, str, str], str | None] = {}
    for field_id in candidates:
        if not isinstance(field_id, str):
            continue
        before_val = before_record.get(field_id)
        after_val = after_record.get(field_id)
        if before_val == after_val:
            continue
        field_def = field_by_id.get(field_id) or {}
        label = field_def.get("label") or field_id
        changes.append(
            {
                "field": field_id,
                "label": label,
                "from": _format_activity_field_value(field_def, before_val, lookup_cache),
                "to": _format_activity_field_value(field_def, after_val, lookup_cache),
            }
        )
    return changes


def _activity_add_event(
    entity_id: str | None,
    record_id: str | None,
    event_type: str,
    payload: dict | None,
    actor: dict | None = None,
) -> dict | None:
    if not isinstance(entity_id, str) or not entity_id:
        return None
    if not isinstance(record_id, str) or not record_id:
        return None
    try:
        return activity_store.add_event(
            _normalize_entity_id(entity_id),
            record_id,
            event_type,
            payload or {},
            actor=actor,
        )
    except Exception:
        logger.exception("activity_event_add_failed entity_id=%s record_id=%s event_type=%s", entity_id, record_id, event_type)
        return None


def _activity_add_record_created_event(entity_def: dict, record_id: str, record: dict, actor: dict | None = None) -> None:
    display_field = entity_def.get("display_field") if isinstance(entity_def, dict) else None
    display_value = record.get(display_field) if isinstance(display_field, str) and isinstance(record, dict) else None
    payload = {
        "action": "record_created",
        "message": f"Record created{f': {display_value}' if display_value else ''}.",
        "record_label": _format_activity_value(display_value) if display_value is not None else None,
        "created_fields": sorted([key for key in record.keys() if isinstance(key, str)]),
    }
    _activity_add_event(entity_def.get("id"), record_id, "system", payload, actor=actor)


def _activity_add_status_change_event(
    entity_def: dict,
    record_id: str,
    status_field: str,
    before_value: Any,
    after_value: Any,
    actor: dict | None = None,
) -> None:
    label = status_field
    for field in entity_def.get("fields") if isinstance(entity_def, dict) else []:
        if isinstance(field, dict) and field.get("id") == status_field:
            label = field.get("label") or status_field
            break
    payload = {
        "action": "status_changed",
        "message": f"{label} changed from {_format_activity_value(before_value)} to {_format_activity_value(after_value)}.",
        "field": status_field,
        "label": label,
        "from": _format_activity_value(before_value),
        "to": _format_activity_value(after_value),
    }
    _activity_add_event(entity_def.get("id"), record_id, "system", payload, actor=actor)


def _activity_add_action_event(
    entity_id: str | None,
    record_id: str | None,
    action_id: str | None,
    action_label: str | None,
    action_kind: str | None,
    actor: dict | None = None,
    extra_payload: dict | None = None,
) -> None:
    if not isinstance(record_id, str) or not record_id:
        return
    payload = {
        "action": "action_executed",
        "message": f"Action executed: {action_label or action_id or action_kind or 'Action'}.",
        "action_id": action_id,
        "action_label": action_label or action_id or action_kind or "Action",
        "action_kind": action_kind,
    }
    if isinstance(extra_payload, dict):
        payload.update(extra_payload)
    _activity_add_event(entity_id, record_id, "system", payload, actor=actor)


def _activity_add_attachment_event(
    entity_id: str | None,
    record_id: str | None,
    attachment: dict | None,
    *,
    action: str,
    purpose: str | None = None,
    actor: dict | None = None,
) -> dict | None:
    if not isinstance(attachment, dict):
        return None
    filename = attachment.get("filename") or "Attachment"
    payload = {
        "action": action,
        "message": f"{'Removed' if action == 'removed' else 'Added'} attachment: {filename}.",
        "attachment_id": attachment.get("id"),
        "filename": filename,
        "mime_type": attachment.get("mime_type"),
        "size": attachment.get("size"),
        "purpose": purpose or "default",
    }
    return _activity_add_event(entity_id, record_id, "attachment", payload, actor=actor)


def _compile_manifest(manifest: dict) -> dict:
    entities = manifest.get("entities") if isinstance(manifest, dict) else None
    views = manifest.get("views") if isinstance(manifest, dict) else None
    actions = manifest.get("actions") if isinstance(manifest, dict) else None
    transformations = manifest.get("transformations") if isinstance(manifest, dict) else None
    entity_by_id: dict = {}
    view_by_id: dict = {}
    field_by_entity: dict = {}
    action_by_id: dict = {}
    transformation_by_key: dict = {}
    if isinstance(entities, list):
        for entity in entities:
            if not isinstance(entity, dict):
                continue
            entity_id = entity.get("id")
            if not isinstance(entity_id, str):
                continue
            entity_by_id[entity_id] = entity
            fields = entity.get("fields")
            if isinstance(fields, list):
                field_map = {}
                for field in fields:
                    if isinstance(field, dict) and isinstance(field.get("id"), str):
                        field_map[field["id"]] = field
                field_by_entity[entity_id] = field_map
    if isinstance(views, list):
        for view in views:
            if isinstance(view, dict) and isinstance(view.get("id"), str):
                view_by_id[view["id"]] = view
    if isinstance(actions, list):
        for action in actions:
            if isinstance(action, dict) and isinstance(action.get("id"), str):
                action_by_id[action["id"]] = action
    if isinstance(transformations, list):
        for transformation in transformations:
            if isinstance(transformation, dict) and isinstance(transformation.get("key"), str):
                transformation_by_key[transformation["key"]] = transformation
    return {
        "entity_by_id": entity_by_id,
        "field_by_entity": field_by_entity,
        "view_by_id": view_by_id,
        "action_by_id": action_by_id,
        "transformation_by_key": transformation_by_key,
    }


def _validate_patch_payload(entity: dict, patch: dict, existing: dict, workflow: dict | None = None) -> tuple[list[dict], dict]:
    errors: list[dict] = []
    if not isinstance(patch, dict):
        return [
            {
                "code": "INVALID_PAYLOAD",
                "message": "Patch must be an object",
                "path": None,
                "detail": None,
            }
        ], {}
    fields = entity.get("fields") or []
    if isinstance(fields, dict):
        field_list = []
        for field_id, field_def in fields.items():
            if isinstance(field_def, dict):
                field_list.append({"id": field_id, **field_def})
            else:
                field_list.append({"id": field_id})
        fields = field_list
    field_by_id = {f.get("id"): f for f in fields if f.get("id")}

    def _add_error(code: str, message: str, path: str | None = None, detail: dict | None = None):
        errors.append({"code": code, "message": message, "path": path, "detail": detail})

    for key in patch.keys():
        if key == "id":
            continue
        if key not in field_by_id:
            _add_error("UNKNOWN_FIELD", f"Unknown field: {key}", path=key)

    for field_id, val in patch.items():
        if field_id == "id":
            continue
        field = field_by_id.get(field_id)
        if not field:
            continue
        ftype = field.get("type")
        if val is None:
            continue
        if ftype in ("string", "text", "rich_text"):
            if not isinstance(val, str):
                _add_error("TYPE_MISMATCH", f"{field_id} must be a string", path=field_id)
        elif ftype in {"number", "currency"}:
            if not isinstance(val, (int, float)) or isinstance(val, bool):
                _add_error("TYPE_MISMATCH", f"{field_id} must be a number", path=field_id)
        elif ftype == "boolean" or ftype == "bool":
            if not isinstance(val, bool):
                _add_error("TYPE_MISMATCH", f"{field_id} must be a boolean", path=field_id)
        elif ftype == "enum":
            allowed = _enum_values(field)
            if val not in allowed:
                _add_error("INVALID_ENUM", f"{field_id} must be one of {allowed}", path=field_id)
        elif ftype == "date":
            if not isinstance(val, str):
                _add_error("TYPE_MISMATCH", f"{field_id} must be a date string", path=field_id)
            else:
                try:
                    date.fromisoformat(val)
                except Exception:
                    _add_error("INVALID_DATE", f"{field_id} must be YYYY-MM-DD", path=field_id)
        elif ftype == "datetime":
            if not isinstance(val, str):
                _add_error("TYPE_MISMATCH", f"{field_id} must be a datetime string", path=field_id)
            else:
                try:
                    datetime.fromisoformat(val.replace("Z", "+00:00"))
                except Exception:
                    _add_error("INVALID_DATETIME", f"{field_id} must be ISO8601", path=field_id)
        elif ftype == "uuid":
            if not isinstance(val, str) or not _is_uuid(val):
                _add_error("TYPE_MISMATCH", f"{field_id} must be a UUID", path=field_id)
        elif ftype == "lookup":
            if not isinstance(val, str):
                _add_error("TYPE_MISMATCH", f"{field_id} must be a string", path=field_id)
        elif ftype == "tags":
            if not isinstance(val, list):
                _add_error("TYPE_MISMATCH", f"{field_id} must be a list", path=field_id)

    if workflow:
        status_field = workflow.get("status_field")
        status_value = None
        if isinstance(status_field, str) and status_field in patch:
            status_value = patch.get(status_field)
        elif isinstance(status_field, str):
            status_value = existing.get(status_field)
        if status_field and status_value is not None:
            states = [s.get("id") for s in workflow.get("states") or [] if isinstance(s, dict)]
            if status_value not in states:
                _add_error("INVALID_STATUS", f"{status_field} must be one of {states}", path=status_field)

    if errors:
        return errors, {}
    updated = dict(existing)
    updated.update(patch)
    return [], updated


def _get_installed_manifest(request: Request, module_id: str) -> tuple[dict | None, dict | None]:
    module = _get_module(request, module_id)
    if not module:
        return None, None
    if not module.get("enabled"):
        return module, None
    manifest_hash = module.get("current_hash")
    if not manifest_hash:
        return module, None
    cache_key = f"{get_org_id()}:{module_id}:{manifest_hash}"
    cached = _cache_get("manifest", cache_key)
    if cached is not None:
        return module, cached
    try:
        manifest = _get_snapshot(request, module_id, manifest_hash)
    except Exception:
        return module, None
    _cache_set("manifest", manifest, cache_key)
    return module, manifest


def _manifest_parse_target(target: str | None) -> tuple[str | None, str | None]:
    if not isinstance(target, str) or not target:
        return None, None
    if target.startswith("page:"):
        return "page", target.split("page:", 1)[1]
    if target.startswith("view:"):
        return "view", target.split("view:", 1)[1]
    return None, None


def _manifest_find_page_by_id(manifest: dict, page_id: str | None) -> dict | None:
    if not isinstance(page_id, str) or not page_id:
        return None
    pages = manifest.get("pages") if isinstance(manifest, dict) else None
    if not isinstance(pages, list):
        return None
    return next((page for page in pages if isinstance(page, dict) and page.get("id") == page_id), None)


def _manifest_find_first_view_modes_block(blocks: list | None) -> dict | None:
    if not isinstance(blocks, list):
        return None
    for block in blocks:
        if not isinstance(block, dict):
            continue
        if block.get("kind") == "view_modes":
            return block
        nested = block.get("content")
        found = _manifest_find_first_view_modes_block(nested if isinstance(nested, list) else None)
        if found:
            return found
        items = block.get("items")
        if isinstance(items, list):
            for item in items:
                if not isinstance(item, dict):
                    continue
                found = _manifest_find_first_view_modes_block(item.get("content") if isinstance(item.get("content"), list) else None)
                if found:
                    return found
        tabs = block.get("tabs")
        if isinstance(tabs, list):
            for tab in tabs:
                if not isinstance(tab, dict):
                    continue
                found = _manifest_find_first_view_modes_block(tab.get("content") if isinstance(tab.get("content"), list) else None)
                if found:
                    return found
    return None


def _manifest_contains_block_kind(blocks: list | None, kinds: set[str] | list[str] | tuple[str, ...]) -> bool:
    if not isinstance(blocks, list):
        return False
    wanted = {str(kind).strip() for kind in kinds if isinstance(kind, str) and str(kind).strip()}
    if not wanted:
        return False
    for block in blocks:
        if not isinstance(block, dict):
            continue
        if str(block.get("kind") or "").strip() in wanted:
            return True
        nested = block.get("content")
        if _manifest_contains_block_kind(nested if isinstance(nested, list) else None, wanted):
            return True
        items = block.get("items")
        if isinstance(items, list):
            for item in items:
                if not isinstance(item, dict):
                    continue
                if _manifest_contains_block_kind(item.get("content") if isinstance(item.get("content"), list) else None, wanted):
                    return True
        tabs = block.get("tabs")
        if isinstance(tabs, list):
            for tab in tabs:
                if not isinstance(tab, dict):
                    continue
                if _manifest_contains_block_kind(tab.get("content") if isinstance(tab.get("content"), list) else None, wanted):
                    return True
    return False


def _manifest_default_query_for_page(manifest: dict, page_id: str | None) -> str:
    page = _manifest_find_page_by_id(manifest, page_id)
    block = _manifest_find_first_view_modes_block(page.get("content") if isinstance(page, dict) else None)
    if not isinstance(block, dict):
        return ""
    params: dict[str, str] = {}
    modes = block.get("modes") if isinstance(block.get("modes"), list) else []
    default_mode = block.get("default_mode") if isinstance(block.get("default_mode"), str) and block.get("default_mode") else None
    if not default_mode and modes and isinstance(modes[0], dict):
        default_mode = modes[0].get("mode") if isinstance(modes[0].get("mode"), str) else None
    if isinstance(default_mode, str) and default_mode:
        params["mode"] = default_mode
    default_filter_id = block.get("default_filter_id")
    if isinstance(default_filter_id, str) and default_filter_id:
        params["filter"] = default_filter_id
    active_mode = next((mode for mode in modes if isinstance(mode, dict) and mode.get("mode") == default_mode), None)
    group_by = None
    if isinstance(active_mode, dict):
        active_group = active_mode.get("default_group_by")
        if isinstance(active_group, str) and active_group:
            group_by = active_group
    if not group_by:
        block_group = block.get("default_group_by")
        if isinstance(block_group, str) and block_group:
            group_by = block_group
    if isinstance(group_by, str) and group_by:
        params["group_by"] = group_by
    return urllib.parse.urlencode(params)


def _studio2_normalize_view_target(target: Any) -> str | None:
    if not isinstance(target, str) or not target.strip():
        return None
    value = target.strip()
    return value.split("view:", 1)[1] if value.startswith("view:") else value


def _studio2_is_basic_list_page_block(block: Any, list_view_id: str) -> bool:
    if not isinstance(block, dict):
        return False
    kind = block.get("kind")
    if kind == "view":
        return (
            _studio2_normalize_view_target(block.get("target")) == list_view_id
            or _studio2_normalize_view_target(block.get("source")) == list_view_id
        )
    if kind == "container":
        content = block.get("content") if isinstance(block.get("content"), list) else []
        return bool(content) and all(_studio2_is_basic_list_page_block(item, list_view_id) for item in content)
    return False


def _studio2_build_view_modes_block_for_entity(
    views: list[dict],
    entity_id: str,
    list_view_id: str,
    *,
    existing_block: dict | None = None,
) -> dict:
    mode_by_name: dict[str, dict] = {}
    graph_default_group_by = None
    for view in views:
        if not isinstance(view, dict) or view.get("entity") != entity_id:
            continue
        view_id = view.get("id")
        kind = view.get("kind")
        if not isinstance(view_id, str) or not view_id.strip() or not isinstance(kind, str) or not kind.strip():
            continue
        if kind == "list":
            mode_by_name.setdefault("list", {"mode": "list", "target": f"view:{view_id}"})
            continue
        if kind == "kanban":
            mode_by_name.setdefault("kanban", {"mode": "kanban", "target": f"view:{view_id}"})
            continue
        if kind == "calendar":
            mode_by_name.setdefault("calendar", {"mode": "calendar", "target": f"view:{view_id}"})
            continue
        if kind == "graph":
            mode_by_name.setdefault("graph", {"mode": "graph", "target": f"view:{view_id}"})
            default_cfg = view.get("default") if isinstance(view.get("default"), dict) else {}
            if isinstance(default_cfg.get("group_by"), str) and default_cfg.get("group_by").strip():
                graph_default_group_by = default_cfg.get("group_by").strip()
            continue
        if kind == "pivot":
            mode_by_name.setdefault("pivot", {"mode": "pivot", "target": f"view:{view_id}"})
    if "list" not in mode_by_name:
        mode_by_name["list"] = {"mode": "list", "target": f"view:{list_view_id}"}
    if "graph" in mode_by_name and "pivot" not in mode_by_name:
        pivot_mode = {"mode": "pivot", "target": f"view:{list_view_id}"}
        if isinstance(graph_default_group_by, str) and graph_default_group_by:
            pivot_mode["default_group_by"] = graph_default_group_by
        mode_by_name["pivot"] = pivot_mode
    ordered_modes = ["list", "kanban", "calendar", "graph", "pivot"]
    modes = [copy.deepcopy(mode_by_name[name]) for name in ordered_modes if name in mode_by_name]
    default_mode = (
        existing_block.get("default_mode")
        if isinstance(existing_block, dict)
        and isinstance(existing_block.get("default_mode"), str)
        and existing_block.get("default_mode") in mode_by_name
        else None
    )
    if not isinstance(default_mode, str) or not default_mode:
        default_mode = "list" if "list" in mode_by_name else next(iter(mode_by_name.keys()), "list")
    block = {
        "kind": "view_modes",
        "entity_id": entity_id,
        "default_mode": default_mode,
        "modes": modes,
    }
    if isinstance(existing_block, dict):
        default_filter_id = existing_block.get("default_filter_id")
        if isinstance(default_filter_id, str) and default_filter_id.strip():
            block["default_filter_id"] = default_filter_id.strip()
        default_group_by = existing_block.get("default_group_by")
        if isinstance(default_group_by, str) and default_group_by.strip():
            block["default_group_by"] = default_group_by.strip()
    return block


def _studio2_standard_list_page_content(views: list[dict], entity_id: str, list_view_id: str, existing_page: dict | None = None) -> list[dict]:
    existing_block = (
        _manifest_find_first_view_modes_block(existing_page.get("content"))
        if isinstance(existing_page, dict)
        else None
    )
    return [
        {
            "kind": "container",
            "variant": "card",
            "content": [
                _studio2_build_view_modes_block_for_entity(
                    views,
                    entity_id,
                    list_view_id,
                    existing_block=existing_block if isinstance(existing_block, dict) else None,
                )
            ],
        }
    ]


def _studio2_is_basic_form_page_view_block(block: Any, form_view_id: str) -> bool:
    if not isinstance(block, dict):
        return False
    kind = block.get("kind")
    if kind == "view":
        return (
            _studio2_normalize_view_target(block.get("target")) == form_view_id
            or _studio2_normalize_view_target(block.get("source")) == form_view_id
        )
    if kind == "container":
        content = block.get("content") if isinstance(block.get("content"), list) else []
        return bool(content) and all(_studio2_is_basic_form_page_view_block(item, form_view_id) for item in content)
    return False


def _studio2_is_basic_form_page_record_block(block: Any, entity_id: str, form_view_id: str) -> bool:
    if not isinstance(block, dict) or block.get("kind") != "record":
        return False
    if block.get("entity_id") != entity_id:
        return False
    content = block.get("content") if isinstance(block.get("content"), list) else []
    return bool(content) and all(_studio2_is_basic_form_page_view_block(item, form_view_id) for item in content)


def _studio2_default_form_activity_config(entity_id: str, fields: list[dict], existing_activity: dict | None = None) -> dict:
    slug = entity_id[7:] if entity_id.startswith("entity.") else entity_id
    tracked_fields: list[str] = []
    for field in fields:
        if not isinstance(field, dict):
            continue
        fid = field.get("id")
        if not isinstance(fid, str) or not fid.strip():
            continue
        ftype = field.get("type")
        if (
            fid.endswith(".status")
            or fid.endswith(".state")
            or fid.endswith(".stage")
            or ftype == "user"
            or (ftype in {"date", "datetime"} and not fid.endswith(".created_at"))
        ):
            if fid not in tracked_fields:
                tracked_fields.append(fid)
        if len(tracked_fields) >= 6:
            break
    allow_attachments = any(isinstance(field, dict) and field.get("type") == "attachments" for field in fields)
    activity = copy.deepcopy(existing_activity) if isinstance(existing_activity, dict) else {}
    if isinstance(existing_activity, dict) and "enabled" in existing_activity:
        activity["enabled"] = existing_activity.get("enabled") is True
    else:
        activity["enabled"] = True
    activity.setdefault("mode", "tab")
    activity.setdefault("tab_label", "Activity")
    activity.setdefault("tab_label_key", f"{slug}.views.form.activity.tab")
    activity.setdefault("allow_comments", True)
    if allow_attachments:
        activity.setdefault("allow_attachments", True)
    activity.setdefault("show_changes", True)
    if tracked_fields and not isinstance(activity.get("tracked_fields"), list):
        activity["tracked_fields"] = tracked_fields
    return activity


def _studio2_disable_scaffold_form_activity_tabs(manifest: dict) -> dict:
    if not isinstance(manifest, dict):
        return manifest
    views = manifest.get("views") if isinstance(manifest.get("views"), list) else []
    for view in views:
        if not isinstance(view, dict) or view.get("kind") != "form":
            continue
        activity = view.get("activity") if isinstance(view.get("activity"), dict) else {}
        activity["enabled"] = False
        view["activity"] = activity
    manifest["views"] = views
    return manifest


def _studio2_standard_form_page_content(
    entity_id: str,
    form_view_id: str,
    *,
    record_id_query: str = "record",
) -> list[dict]:
    return [
        {
            "kind": "record",
            "entity_id": entity_id,
            "record_id_query": record_id_query,
            "content": [
                {
                    "kind": "grid",
                    "columns": 12,
                    "gap": "md",
                    "items": [
                        {
                            "span": 8,
                            "content": [
                                {
                                    "kind": "container",
                                    "variant": "card",
                                    "content": [{"kind": "view", "target": f"view:{form_view_id}"}],
                                }
                            ],
                        },
                        {
                            "span": 4,
                            "content": [
                                {
                                    "kind": "container",
                                    "variant": "card",
                                    "title": "Activity",
                                    "content": [
                                        {
                                            "kind": "chatter",
                                            "entity_id": entity_id,
                                            "record_ref": "$record.id",
                                        }
                                    ],
                                }
                            ],
                        },
                    ],
                }
            ],
        }
    ]


def _studio2_normalize_list_page_scaffolds(manifest: dict, collect_paths: bool = False):
    if not isinstance(manifest, dict):
        return (manifest, []) if collect_paths else manifest
    views = manifest.get("views") if isinstance(manifest.get("views"), list) else []
    pages = manifest.get("pages") if isinstance(manifest.get("pages"), list) else []
    entities = manifest.get("entities") if isinstance(manifest.get("entities"), list) else []
    page_by_id = {p.get("id"): p for p in pages if isinstance(p, dict) and isinstance(p.get("id"), str)}
    paths_changed: list[str] = []

    for entity in entities:
        if not isinstance(entity, dict):
            continue
        entity_id = entity.get("id")
        if not isinstance(entity_id, str) or not entity_id.startswith("entity."):
            continue
        slug = entity_id[7:]
        list_page_id = f"{slug}.list_page"
        list_view_id = f"{slug}.list"
        page = page_by_id.get(list_page_id)
        if not isinstance(page, dict):
            continue
        original_content = page.get("content") if isinstance(page.get("content"), list) else []
        filtered_content = [
            node
            for node in original_content
            if not _studio2_is_basic_list_page_block(node, list_view_id)
        ]
        has_primary_list_surface = (
            isinstance(_manifest_find_first_view_modes_block(original_content), dict)
            or _manifest_contains_block_kind(original_content, {"document_registry"})
        )
        changed = False
        if has_primary_list_surface:
            if len(filtered_content) != len(original_content):
                page["content"] = filtered_content or _studio2_standard_list_page_content(views, entity_id, list_view_id, page)
                changed = True
        else:
            normalized_content = [
                *_studio2_standard_list_page_content(views, entity_id, list_view_id, page),
                *filtered_content,
            ]
            if normalized_content != original_content:
                page["content"] = normalized_content
                changed = True
        if page.get("header") != {"variant": "none"}:
            page["header"] = {"variant": "none"}
            changed = True
        if changed:
            paths_changed.append(f"/pages/{list_page_id}/content")
            page_by_id[list_page_id] = page

    manifest["pages"] = [page_by_id.get(page.get("id"), page) if isinstance(page, dict) else page for page in pages]
    return (manifest, paths_changed) if collect_paths else manifest


def _module_home_route_from_manifest(module_id: str, manifest: dict) -> str:
    if not isinstance(module_id, str) or not module_id or not isinstance(manifest, dict):
        return ""
    app_def = manifest.get("app") if isinstance(manifest.get("app"), dict) else {}
    target_kind, target_id = _manifest_parse_target(app_def.get("home"))
    if target_kind == "page" and isinstance(target_id, str) and target_id:
        route = f"/apps/{module_id}/page/{target_id}"
        query = _manifest_default_query_for_page(manifest, target_id)
        return f"{route}?{query}" if query else route
    if target_kind == "view" and isinstance(target_id, str) and target_id:
        return f"/apps/{module_id}/view/{target_id}"
    return f"/apps/{module_id}"


def _module_registry_meta_from_manifest(module_id: str, manifest: dict) -> dict[str, str | None]:
    module_def = manifest.get("module") if isinstance(manifest.get("module"), dict) else {}
    description = module_def.get("description") if isinstance(module_def.get("description"), str) and module_def.get("description").strip() else None
    description_key = module_def.get("description_key") if isinstance(module_def.get("description_key"), str) and module_def.get("description_key").strip() else None
    category = module_def.get("category") if isinstance(module_def.get("category"), str) and module_def.get("category").strip() else None
    name_key = module_def.get("name_key") if isinstance(module_def.get("name_key"), str) and module_def.get("name_key").strip() else None
    version = module_version_from_manifest(manifest)
    module_key = module_key_from_manifest(manifest) or module_id
    home_route = _module_home_route_from_manifest(module_id, manifest)
    icon_key = module_def.get("icon_key") or module_def.get("icon")
    if isinstance(icon_key, str):
        icon_key = icon_key.strip() or None
    else:
        icon_key = None
    return {
        "name": _module_name_from_manifest(manifest),
        "name_key": name_key,
        "description": description,
        "description_key": description_key,
        "category": category,
        "module_version": version if isinstance(version, str) and version.strip() else None,
        "module_key": module_key.strip() if isinstance(module_key, str) and module_key.strip() else None,
        "home_route": home_route.strip() if isinstance(home_route, str) and home_route.strip() else None,
        "icon_key": icon_key,
    }


def _registry_meta_fingerprint(modules: list[dict]) -> str:
    parts: list[str] = []
    for module in modules or []:
        if not isinstance(module, dict):
            continue
        parts.append(
            "|".join(
                [
                    str(module.get("module_id") or ""),
                    str(module.get("current_hash") or ""),
                    "1" if module.get("enabled") else "0",
                    str(module.get("name") or ""),
                    str(module.get("description") or ""),
                    str(module.get("category") or ""),
                    str(module.get("module_version") or ""),
                    str(module.get("icon_key") or ""),
                    str(module.get("module_key") or ""),
                    str(module.get("home_route") or ""),
                ]
            )
        )
    return str(abs(hash("||".join(parts))))


def _persist_registry_module_meta(module_id: str, metadata: dict[str, str | None]) -> None:
    if not USE_DB:
        return
    if not isinstance(module_id, str) or not module_id or not isinstance(metadata, dict):
        return
    try:
        with get_conn() as conn:
            execute(
                conn,
                """
                update modules_installed
                set name=coalesce(%s, name),
                    description=coalesce(%s, description),
                    category=coalesce(%s, category),
                    module_version=coalesce(%s, module_version),
                    module_key=coalesce(%s, module_key),
                    home_route=coalesce(%s, home_route),
                    icon_key=coalesce(%s, icon_key),
                    updated_at=%s
                where org_id=%s and module_id=%s
                """,
                [
                    metadata.get("name"),
                    metadata.get("description"),
                    metadata.get("category"),
                    metadata.get("module_version"),
                    metadata.get("module_key"),
                    metadata.get("home_route"),
                    metadata.get("icon_key"),
                    _now(),
                    get_org_id(),
                    module_id,
                ],
                query_name="modules_installed.backfill_meta",
            )
    except Exception:
        logger.warning("modules_meta_backfill_failed module_id=%s", module_id, exc_info=True)


def _get_registry_list_with_meta(request: Request) -> list[dict]:
    cache_key = "registry:list:meta"
    cached_req = _req_cache_get(request, cache_key)
    if isinstance(cached_req, list):
        return cached_req
    modules = _get_registry_list(request)
    fingerprint = f"i18n-v2:{get_org_id()}:{_registry_meta_fingerprint(modules)}"
    cached = _cache_get("registry_list_meta", fingerprint)
    if isinstance(cached, list):
        _req_cache_set(request, cache_key, cached)
        return cached
    enriched = copy.deepcopy(modules)
    for mod in enriched:
        if not isinstance(mod, dict):
            continue
        need_meta = not (
            (isinstance(mod.get("name"), str) and mod.get("name").strip())
            and (isinstance(mod.get("description"), str) and mod.get("description").strip())
            and (isinstance(mod.get("category"), str) and mod.get("category").strip())
            and (isinstance(mod.get("module_version"), str) and mod.get("module_version").strip())
            and (isinstance(mod.get("module_key"), str) and mod.get("module_key").strip())
            and (isinstance(mod.get("home_route"), str) and mod.get("home_route").strip())
        )
        need_meta = need_meta or not (
            (isinstance(mod.get("name_key"), str) and mod.get("name_key").strip())
            and (isinstance(mod.get("description_key"), str) and mod.get("description_key").strip())
        )
        if not need_meta:
            continue
        module_id = mod.get("module_id")
        manifest_hash = mod.get("current_hash")
        if not module_id or not manifest_hash:
            continue
        try:
            manifest = _get_snapshot(request, module_id, manifest_hash)
        except Exception:
            continue
        meta = _module_registry_meta_from_manifest(module_id, manifest)
        changed = False
        for key in ("name", "name_key", "description", "description_key", "category", "module_version", "icon_key", "module_key", "home_route"):
            current = mod.get(key)
            if isinstance(current, str) and current.strip():
                continue
            next_value = meta.get(key)
            if isinstance(next_value, str) and next_value.strip():
                mod[key] = next_value.strip()
                changed = True
        if changed:
            _persist_registry_module_meta(module_id, mod)
    _cache_set("registry_list_meta", enriched, fingerprint)
    _req_cache_set(request, cache_key, enriched)
    return enriched


def _entity_registry_fingerprint(modules: list[dict]) -> str:
    parts: list[str] = []
    for module in modules or []:
        if not isinstance(module, dict):
            continue
        parts.append(
            "|".join(
                [
                    str(module.get("module_id") or ""),
                    str(module.get("current_hash") or ""),
                    "1" if module.get("enabled") else "0",
                ]
            )
        )
    return str(abs(hash("||".join(parts))))


def _get_entity_registry_index(request: Request) -> dict[str, tuple[str, dict, dict]]:
    cache_key = "entity_registry:index"
    cached_req = _req_cache_get(request, cache_key)
    if isinstance(cached_req, dict):
        return cached_req
    modules = _get_registry_list(request)
    fingerprint = f"{get_org_id()}:{_entity_registry_fingerprint(modules)}"
    cached = _cache_get("entity_registry", fingerprint)
    if isinstance(cached, dict):
        _req_cache_set(request, cache_key, cached)
        return cached
    index: dict[str, tuple[str, dict, dict]] = {}
    for module in modules:
        if not isinstance(module, dict) or not module.get("enabled"):
            continue
        module_id = module.get("module_id")
        manifest_hash = module.get("current_hash")
        if not isinstance(module_id, str) or not module_id or not isinstance(manifest_hash, str) or not manifest_hash:
            continue
        try:
            manifest = _get_snapshot(request, module_id, manifest_hash)
        except Exception:
            continue
        for ent in _entities_from_manifest(manifest):
            ent_id = _normalize_entity_id(ent.get("id")) if isinstance(ent, dict) else None
            if isinstance(ent_id, str) and ent_id and ent_id not in index:
                index[ent_id] = (module_id, ent, manifest)
    _cache_set("entity_registry", index, fingerprint)
    _req_cache_set(request, cache_key, index)
    return index


def _resolve_action(manifest: dict, action_id: str) -> dict | None:
    actions = manifest.get("actions") if isinstance(manifest, dict) else None
    if not isinstance(actions, list):
        return None
    for action in actions:
        if isinstance(action, dict) and action.get("id") == action_id:
            return action
    return None


def _find_entity_def(request: Request, entity_id: str) -> tuple[str, dict, dict] | None:
    entity_id = _normalize_entity_id(entity_id)
    cache_id = f"{get_org_id()}:{entity_id}"
    entry = _entity_def_cache.get(cache_id)
    now = time.time()
    if entry and now - entry["ts"] < _CACHE_TTL_S:
        return entry["value"]
    result = _get_entity_registry_index(request).get(entity_id)
    _entity_def_cache[cache_id] = {"value": result, "ts": now}
    return result


def _fetch_records_for_compute(entity_id: str) -> list[dict]:
    normalized = _normalize_entity_id(entity_id)
    try:
        rows = generic_records.list(normalized, limit=1000)
    except TypeError:
        rows = generic_records.list(normalized)
    records: list[dict] = []
    for row in rows if isinstance(rows, list) else []:
        if isinstance(row, dict):
            record = row.get("record") if isinstance(row.get("record"), dict) else row
            if isinstance(record, dict):
                records.append(record)
    return records


def _fetch_record_for_compute(entity_id: str, record_id: str) -> dict | None:
    normalized = _normalize_entity_id(entity_id)
    if not normalized or not isinstance(record_id, str) or not record_id:
        return None
    row = generic_records.get(normalized, record_id)
    if not isinstance(row, dict):
        return None
    record = row.get("record") if isinstance(row.get("record"), dict) else row
    return record if isinstance(record, dict) else None


def _fetch_entity_def_for_compute(entity_id: str) -> dict | None:
    return _find_entity_def_global(entity_id)


def _recompute_record_for_entity(entity_def: dict, record: dict) -> dict:
    if not has_computed_fields(entity_def):
        return dict(record or {})
    records_cache: dict[tuple[str, str | None, str | None], list[dict]] = {}
    record_cache: dict[tuple[str, str], dict | None] = {}

    def fetch_records_cached(entity_id: str, field_id: str | None = None, value: Any = None) -> list[dict]:
        normalized = _normalize_entity_id(entity_id)
        cache_key = (
            normalized or "",
            field_id.strip() if isinstance(field_id, str) and field_id.strip() else None,
            None if value is None else str(value),
        )
        if cache_key in records_cache:
            return records_cache[cache_key]
        if normalized and cache_key[1] is not None:
            try:
                rows = generic_records.list_by_field_value(normalized, cache_key[1], value, limit=1000)
            except TypeError:
                rows = generic_records.list_by_field_value(normalized, cache_key[1], value)
            records = []
            for row in rows if isinstance(rows, list) else []:
                if isinstance(row, dict):
                    item = row.get("record") if isinstance(row.get("record"), dict) else row
                    if isinstance(item, dict):
                        records.append(item)
            records_cache[cache_key] = records
            return records
        records = _fetch_records_for_compute(entity_id)
        records_cache[cache_key] = records
        return records

    def fetch_record_cached(entity_id: str, record_id: str) -> dict | None:
        normalized = _normalize_entity_id(entity_id)
        key = (normalized or "", str(record_id))
        if key not in record_cache:
            record_cache[key] = _fetch_record_for_compute(entity_id, record_id)
        return record_cache[key]

    return recompute_record(
        entity_def,
        record or {},
        fetch_records_cached,
        fetch_record_cached,
        _fetch_entity_def_for_compute,
    )


def _recompute_store_items_for_entity(entity_def: dict, items: list[dict] | None) -> list[dict]:
    if not has_computed_fields(entity_def) or not isinstance(items, list):
        return items if isinstance(items, list) else []
    recomputed_items: list[dict] = []
    for item in items:
        if not isinstance(item, dict):
            recomputed_items.append(item)
            continue
        record_id, record = _unwrap_store_record(item)
        if not isinstance(record, dict):
            recomputed_items.append(item)
            continue
        next_item = dict(item)
        next_item["record"] = _recompute_record_for_entity(entity_def, record)
        if isinstance(record_id, str) and record_id:
            next_item["record_id"] = record_id
        recomputed_items.append(next_item)
    return recomputed_items


def _persist_computed_record(entity_id: str, entity_def: dict, record_id: str, record: dict) -> dict | None:
    recomputed = _recompute_record_for_entity(entity_def, record)
    if recomputed == record:
        return {"record_id": record_id, "record": record}
    try:
        return generic_records.update(entity_id, record_id, recomputed)
    except Exception:
        logger.exception("computed_field_update_failed entity_id=%s record_id=%s", entity_id, record_id)
        return None


def _aggregate_parent_link_fields(where: Any, source_entity_id: str) -> set[str]:
    out: set[str] = set()
    if not isinstance(where, dict):
        return out
    op = str(where.get("op") or "").strip().lower()
    if op == "and":
        for condition in where.get("conditions") or []:
            out.update(_aggregate_parent_link_fields(condition, source_entity_id))
        return out
    if op != "eq":
        return out
    field_id = where.get("field")
    value = where.get("value")
    if not isinstance(field_id, str) or not isinstance(value, dict):
        return out
    if _trimmed_text(value.get("ref")) != "$parent.id":
        return out
    source_slug = _trimmed_text(source_entity_id).split(".")[-1]
    if not source_slug:
        return out
    normalized_field_id = _trimmed_text(field_id)
    if normalized_field_id.startswith(f"{source_slug}."):
        out.add(normalized_field_id)
    return out


def _dependent_parent_ids_for_source_records(entity_def: dict, source_entity_id: str, source_records: list[dict] | None) -> set[str]:
    rows = source_records if isinstance(source_records, list) else []
    if not rows:
        return set()
    normalized_source = _normalize_entity_id(source_entity_id)
    if not normalized_source:
        return set()
    link_fields: set[str] = set()
    for field in _field_list(entity_def):
        compute = field.get("compute") if isinstance(field, dict) else None
        aggregate = compute.get("aggregate") if isinstance(compute, dict) else None
        if not isinstance(aggregate, dict):
            continue
        if _normalize_entity_id(aggregate.get("entity")) != normalized_source:
            continue
        link_fields.update(_aggregate_parent_link_fields(aggregate.get("where"), normalized_source))
    if not link_fields:
        return set()
    parent_ids: set[str] = set()
    for row in rows:
        if not isinstance(row, dict):
            continue
        for field_id in link_fields:
            value = row.get(field_id)
            if isinstance(value, str):
                trimmed = value.strip()
                if trimmed:
                    parent_ids.add(trimmed)
            elif value is not None:
                trimmed = str(value).strip()
                if trimmed:
                    parent_ids.add(trimmed)
    return parent_ids


def _iter_installed_entities(request: Request) -> list[tuple[str, dict, dict]]:
    items: list[tuple[str, dict, dict]] = []
    modules = _get_registry_list(request)
    for module in modules:
        if not isinstance(module, dict) or not module.get("enabled"):
            continue
        module_id = module.get("module_id")
        manifest_hash = module.get("current_hash")
        if not isinstance(module_id, str) or not isinstance(manifest_hash, str):
            continue
        try:
            manifest = _get_snapshot(request, module_id, manifest_hash)
        except Exception:
            continue
        for entity_def in _entities_from_manifest(manifest):
            if isinstance(entity_def, dict) and isinstance(entity_def.get("id"), str):
                items.append((module_id, manifest, entity_def))
    return items


def _recompute_aggregate_dependents(request: Request, source_entity_id: str, source_records: list[dict] | None = None) -> None:
    normalized_source = _normalize_entity_id(source_entity_id)
    for _, _, entity_def in _iter_installed_entities(request):
        entity_id = entity_def.get("id")
        if not isinstance(entity_id, str) or not depends_on_aggregate_entity(entity_def, normalized_source):
            continue
        targeted_parent_ids = _dependent_parent_ids_for_source_records(entity_def, normalized_source, source_records)
        try:
            if targeted_parent_ids:
                rows = []
                for parent_id in sorted(targeted_parent_ids):
                    row = generic_records.get(entity_id, parent_id)
                    if isinstance(row, dict):
                        rows.append(row)
            else:
                try:
                    rows = generic_records.list(entity_id, limit=1000)
                except TypeError:
                    rows = generic_records.list(entity_id)
        except Exception:
            continue
        changed_any = False
        for row in rows if isinstance(rows, list) else []:
            if not isinstance(row, dict):
                continue
            record_id = row.get("record_id") or row.get("id")
            record = row.get("record") if isinstance(row.get("record"), dict) else row
            if not isinstance(record_id, str) or not isinstance(record, dict):
                continue
            updated = _persist_computed_record(entity_id, entity_def, record_id, record)
            if updated and isinstance(updated.get("record"), dict) and updated.get("record") != record:
                changed_any = True
                _resp_cache_invalidate_record(entity_id, record_id)
        if changed_any:
            _resp_cache_invalidate_entity(entity_id)


def _extract_attachment_refs_for_metadata(value: Any) -> list[dict]:
    if isinstance(value, list):
        items: list[dict] = []
        for item in value:
            items.extend(_extract_attachment_refs_for_metadata(item))
        return items
    if isinstance(value, dict):
        return [value]
    if isinstance(value, str) and value:
        return [{"id": value}]
    return []


def _attachment_extension_from_filename(filename: Any) -> str:
    if not isinstance(filename, str):
        return ""
    trimmed = filename.strip()
    if not trimmed or "." not in trimmed:
        return ""
    extension = trimmed.rsplit(".", 1)[-1].strip().lower()
    return extension


def _apply_attachment_metadata_fields(entity_def: dict | None, record: dict | None) -> dict:
    if not isinstance(entity_def, dict) or not isinstance(record, dict):
        return record if isinstance(record, dict) else {}
    fields = entity_def.get("fields") if isinstance(entity_def.get("fields"), list) else []
    field_ids = {
        field.get("id")
        for field in fields
        if isinstance(field, dict) and isinstance(field.get("id"), str) and field.get("id")
    }
    updated = dict(record)
    changed = False
    for field in fields:
        if not isinstance(field, dict) or field.get("type") != "attachments":
            continue
        field_id = field.get("id")
        if not isinstance(field_id, str) or not field_id:
            continue
        prefix = field_id.rsplit(".", 1)[0] if "." in field_id else field_id
        file_name_field = f"{prefix}.file_name"
        file_extension_field = f"{prefix}.file_extension"
        mime_type_field = f"{prefix}.mime_type"
        if not any(meta_field in field_ids for meta_field in (file_name_field, file_extension_field, mime_type_field)):
            continue
        attachments = _extract_attachment_refs_for_metadata(record.get(field_id))
        first_attachment = next((item for item in attachments if isinstance(item, dict)), {})
        filename = first_attachment.get("filename") if isinstance(first_attachment.get("filename"), str) else ""
        mime_type = first_attachment.get("mime_type") if isinstance(first_attachment.get("mime_type"), str) else ""
        extension = _attachment_extension_from_filename(filename)
        if file_name_field in field_ids and updated.get(file_name_field) != filename:
            updated[file_name_field] = filename
            changed = True
        if file_extension_field in field_ids and updated.get(file_extension_field) != extension:
            updated[file_extension_field] = extension
            changed = True
        if mime_type_field in field_ids and updated.get(mime_type_field) != mime_type:
            updated[mime_type_field] = mime_type
            changed = True
    return updated if changed else record


def _create_record_with_computed_fields(request: Request, entity_id: str, entity_def: dict, clean: dict) -> dict:
    payload = _apply_attachment_metadata_fields(entity_def, _recompute_record_for_entity(entity_def, clean))
    record = generic_records.create(entity_id, payload)
    created_record = record.get("record") if isinstance(record, dict) and isinstance(record.get("record"), dict) else payload
    _recompute_aggregate_dependents(request, entity_id, source_records=[created_record])
    return record


def _update_record_with_computed_fields(
    request: Request,
    entity_id: str,
    entity_def: dict,
    record_id: str,
    clean: dict,
    *,
    before_record: dict | None = None,
) -> dict:
    payload = _apply_attachment_metadata_fields(entity_def, _recompute_record_for_entity(entity_def, clean))
    record = generic_records.update(entity_id, record_id, payload)
    updated_record = record.get("record") if isinstance(record, dict) and isinstance(record.get("record"), dict) else payload
    source_records = [row for row in [before_record, updated_record] if isinstance(row, dict)]
    _recompute_aggregate_dependents(request, entity_id, source_records=source_records)
    return record


def _manifest_entity_by_id(manifest: dict) -> dict[str, dict]:
    entities = manifest.get("entities") if isinstance(manifest, dict) else None
    out: dict[str, dict] = {}
    if not isinstance(entities, list):
        return out
    for entity in entities:
        if not isinstance(entity, dict):
            continue
        entity_id = entity.get("id")
        if not isinstance(entity_id, str) or not entity_id:
            continue
        out[entity_id] = entity
        if entity_id.startswith("entity."):
            out[entity_id[len("entity.") :]] = entity
        else:
            out[f"entity.{entity_id}"] = entity
    return out


def _normalize_interface_scope(scope: Any) -> str:
    if isinstance(scope, str) and scope in {"module_only", "global_only", "module_and_global"}:
        return scope
    return "module_and_global"


def _interface_enabled(entry: dict) -> bool:
    enabled = entry.get("enabled")
    if enabled is None:
        return True
    return enabled is True


def _should_include_global_scope(entry: dict) -> bool:
    scope = _normalize_interface_scope(entry.get("scope"))
    return scope in {"global_only", "module_and_global"}


def _interface_entity_id(entry: dict) -> str | None:
    entity_id = entry.get("entity_id")
    if not isinstance(entity_id, str) or not entity_id:
        return None
    return _normalize_entity_id(entity_id)


def _read_interface_list(manifest: dict, kind: str) -> list[dict]:
    interfaces = manifest.get("interfaces") if isinstance(manifest, dict) else None
    if not isinstance(interfaces, dict):
        return []
    items = interfaces.get(kind)
    if not isinstance(items, list):
        return []
    return [item for item in items if isinstance(item, dict)]


def _collect_interface_sources(request: Request, kind: str, actor: dict | None = None) -> list[dict]:
    modules = _get_registry_list(request)
    sources: list[dict] = []
    for module in modules:
        if not isinstance(module, dict) or not module.get("enabled"):
            continue
        module_id = module.get("module_id")
        manifest_hash = module.get("current_hash")
        if not isinstance(module_id, str) or not isinstance(manifest_hash, str):
            continue
        if actor is not None and not _module_visible_for_actor(actor, module_id):
            continue
        try:
            manifest = _get_snapshot(request, module_id, manifest_hash)
        except Exception:
            continue
        entity_by_id = _manifest_entity_by_id(manifest)
        for idx, entry in enumerate(_read_interface_list(manifest, kind)):
            if not _interface_enabled(entry):
                continue
            if not _should_include_global_scope(entry):
                continue
            entity_id = _interface_entity_id(entry)
            if not isinstance(entity_id, str):
                continue
            entity_def = entity_by_id.get(entity_id) or entity_by_id.get(f"entity.{entity_id}") or entity_by_id.get(entity_id[7:] if entity_id.startswith("entity.") else entity_id)
            if not isinstance(entity_def, dict):
                continue
            if actor is not None and _entity_access_level_for_actor(actor, module_id, entity_id) == "none":
                continue
            source_key = f"{module_id}:{kind}:{entity_id}:{idx}"
            sources.append(
                {
                    "source_key": source_key,
                    "kind": kind,
                    "module_id": module_id,
                    "module_name": module.get("name"),
                    "manifest_hash": manifest_hash,
                    "entity_id": entity_id,
                    "entity_label": entity_def.get("label") or entity_id,
                    "display_field": entity_def.get("display_field"),
                    "scope": _normalize_interface_scope(entry.get("scope")),
                    "config": dict(entry),
                }
            )
    return sources


def _to_datetime(value: Any) -> datetime | None:
    if isinstance(value, datetime):
        return value
    if not isinstance(value, str):
        return None
    text = value.strip()
    if not text:
        return None
    try:
        if len(text) == 10 and text.count("-") == 2:
            return datetime.fromisoformat(f"{text}T00:00:00")
        return datetime.fromisoformat(text.replace("Z", "+00:00"))
    except Exception:
        return None


def _records_list_page_all(
    entity_id: str,
    *,
    fields: list[str] | None = None,
    q: str | None = None,
    search_fields: list[str] | None = None,
    cap: int = 1000,
) -> list[dict]:
    out: list[dict] = []
    cursor = None
    remaining = max(1, int(cap or 1000))
    while remaining > 0:
        batch_size = min(remaining, 200)
        items, next_cursor = generic_records.list_page(
            entity_id,
            limit=batch_size,
            cursor=cursor,
            q=q,
            search_fields=search_fields,
            fields=fields,
        )
        items = items if isinstance(items, list) else []
        out.extend(items)
        remaining -= len(items)
        if not next_cursor or len(items) == 0:
            break
        cursor = next_cursor
    return out


_SAFE_SQL_FIELD_RE = re.compile(r"^[A-Za-z0-9._-]+$")
_SAFE_NUMERIC_TEXT_RE = r"^-?(?:\d+)(?:\.\d+)?$"


def _is_safe_sql_field_id(value: str | None) -> bool:
    return isinstance(value, str) and bool(_SAFE_SQL_FIELD_RE.fullmatch(value))


def _actor_has_entity_scope_rules(actor: dict | None, entity_id: str | None) -> bool:
    normalized_entity = _normalize_entity_id(entity_id)
    policy = _access_policy_for_actor(actor)
    entity_scope_rules = policy.get("entity_scope_rules", {}) if isinstance(policy, dict) else {}
    if not isinstance(entity_scope_rules, dict):
        return False
    if isinstance(normalized_entity, str) and entity_scope_rules.get(normalized_entity):
        return True
    return bool(entity_scope_rules.get("*"))


def _records_sql_fast_path_allowed(
    actor: dict | None,
    entity_id: str | None,
    domain: Any = None,
    *,
    allow_simple_domain: bool = False,
) -> bool:
    if domain and not allow_simple_domain:
        return False
    return not _actor_has_entity_scope_rules(actor, entity_id)


def _build_records_generic_sql_where(
    *,
    entity_id: str,
    q: str | None = None,
    search_fields: list[str] | None = None,
) -> tuple[str, list[Any]]:
    q_lower = str(q).strip().lower() if isinstance(q, str) else None
    params: list[Any] = [get_org_id(), entity_id]
    where = "where tenant_id=%s and entity_id=%s"
    if q_lower:
        safe_search_fields = [field_id for field_id in (search_fields or []) if _is_safe_sql_field_id(field_id)]
        if safe_search_fields:
            clauses = []
            for field_id in safe_search_fields:
                clauses.append("lower(data ->> %s) like %s")
                params.extend([field_id, f"{q_lower}%"])
            where += " and (" + " or ".join(clauses) + ")"
        else:
            where += " and (data::text ilike %s)"
            params.append(f"%{q_lower}%")
    return where, params


def _encode_resp_cursor(updated_at: Any, record_id: str) -> str | None:
    if not updated_at or not record_id:
        return None
    if hasattr(updated_at, "strftime"):
        ts = updated_at.strftime("%Y-%m-%dT%H:%M:%SZ")
    else:
        ts = str(updated_at)
    raw = f"{ts}|{record_id}"
    return base64.urlsafe_b64encode(raw.encode("utf-8")).decode("utf-8")


def _decode_resp_cursor(cursor: str | None) -> tuple[str, str] | None:
    if not cursor or not isinstance(cursor, str):
        return None
    try:
        raw = base64.urlsafe_b64decode(cursor.encode("utf-8")).decode("utf-8")
        if "|" not in raw:
            return None
        ts, record_id = raw.split("|", 1)
        if not ts or not record_id:
            return None
        return ts, record_id
    except Exception:
        return None


def _domain_scalar_to_sql_text(value: Any) -> str | None:
    if value is None:
        return ""
    if isinstance(value, bool):
        return "true" if value else "false"
    if isinstance(value, (int, float)):
        return str(value)
    if isinstance(value, (date, datetime)):
        return value.isoformat()
    if isinstance(value, str):
        return value
    return None


def _build_simple_domain_sql_clause(domain: Any) -> tuple[str, list[Any]] | None:
    if not isinstance(domain, dict):
        return None
    op = str(domain.get("op") or "").strip().lower()
    if op == "and":
        conditions = domain.get("conditions")
        if not isinstance(conditions, list) or not conditions:
            return None
        parts: list[str] = []
        params: list[Any] = []
        for condition in conditions:
            built = _build_simple_domain_sql_clause(condition)
            if built is None:
                return None
            sql, sql_params = built
            parts.append(f"({sql})")
            params.extend(sql_params)
        return " and ".join(parts), params
    if op == "or":
        conditions = domain.get("conditions")
        if not isinstance(conditions, list) or not conditions:
            return None
        parts = []
        params: list[Any] = []
        for condition in conditions:
            built = _build_simple_domain_sql_clause(condition)
            if built is None:
                return None
            sql, sql_params = built
            parts.append(f"({sql})")
            params.extend(sql_params)
        return " or ".join(parts), params
    if op == "not":
        condition = domain.get("condition")
        built = _build_simple_domain_sql_clause(condition)
        if built is None:
            return None
        sql, sql_params = built
        return f"not ({sql})", sql_params
    field_id = domain.get("field")
    if not _is_safe_sql_field_id(field_id):
        return None
    if op == "exists":
        return "data ? %s", [field_id]
    raw_value = domain.get("value")
    if op in {"eq", "lt", "lte", "gt", "gte"}:
        scalar = _domain_scalar_to_sql_text(raw_value)
        if scalar is None:
            return None
        if op == "eq":
            return "data @> jsonb_build_object(%s, (%s)::jsonb)", [field_id, json.dumps(raw_value)]
        comparator = {"lt": "<", "lte": "<=", "gt": ">", "gte": ">="}[op]
        return f"coalesce(data ->> %s, '') {comparator} %s", [field_id, scalar]
    if op == "in":
        if not isinstance(raw_value, list) or not raw_value:
            return None
        clauses = []
        params: list[Any] = []
        for item in raw_value:
            scalar = _domain_scalar_to_sql_text(item)
            if scalar is None:
                return None
            clauses.append("data @> jsonb_build_object(%s, (%s)::jsonb)")
            params.extend([field_id, json.dumps(item)])
        return "(" + " or ".join(clauses) + ")", params
    return None


def _records_list_page_with_simple_domain(
    *,
    entity_id: str,
    domain: dict,
    limit: int,
    cursor: str | None = None,
    q: str | None = None,
    search_fields: list[str] | None = None,
    fields: list[str] | None = None,
) -> tuple[list[dict], str | None] | None:
    built_domain = _build_simple_domain_sql_clause(domain)
    if built_domain is None:
        return None
    where, params = _build_records_generic_sql_where(entity_id=entity_id, q=q, search_fields=search_fields)
    domain_sql, domain_params = built_domain
    where += f" and ({domain_sql})"
    params.extend(domain_params)
    decoded = _decode_resp_cursor(cursor)
    if decoded:
        cursor_ts, cursor_id = decoded
        where += " and (updated_at, id) < (%s, %s)"
        params.extend([cursor_ts, cursor_id])
    safe_fields = [field_id for field_id in (fields or []) if _is_safe_sql_field_id(field_id)]
    select_params: list[Any] = []
    if safe_fields:
        parts = []
        for field_id in safe_fields:
            parts.append("%s, data -> %s")
            select_params.extend([field_id, field_id])
        data_expr = f"jsonb_build_object({', '.join(parts)}) as data"
    else:
        data_expr = "data"
    query_params = select_params + params + [limit + 1]
    with get_conn() as conn:
        rows = fetch_all(
            conn,
            f"""
            select id, {data_expr}, updated_at
            from records_generic
            {where}
            order by updated_at desc, id desc
            limit %s
            """,
            query_params,
            query_name="records_generic.list_page_simple_domain",
        )
    next_cursor = None
    if len(rows) > limit:
        tail = rows[limit - 1]
        next_cursor = _encode_resp_cursor(tail.get("updated_at"), str(tail.get("id")))
        rows = rows[:limit]
    items: list[dict] = []
    for row in rows:
        record = copy.deepcopy(row.get("data") or {})
        record_id = str(row.get("id"))
        if isinstance(record, dict):
            record["id"] = record_id
        items.append({"record_id": record_id, "record": record})
    return items, next_cursor


def _aggregate_records_sql_fast(
    *,
    entity_id: str,
    group_by: str,
    measure: str,
    limit: int,
    q: str | None = None,
    search_fields: list[str] | None = None,
) -> list[dict] | None:
    if not _is_safe_sql_field_id(group_by):
        return None
    measure_field = None
    measure_is_sum = False
    if isinstance(measure, str) and measure.startswith("sum:"):
        measure_field = measure.split(":", 1)[1]
        measure_is_sum = True
        if not _is_safe_sql_field_id(measure_field):
            return None
    where, params = _build_records_generic_sql_where(entity_id=entity_id, q=q, search_fields=search_fields)
    query_params: list[Any] = list(params)
    query_params.append(limit)
    query_params.append(group_by)
    if measure_is_sum and measure_field:
        value_sql = (
            "coalesce(sum(case "
            "when nullif(trim(coalesce(base.data ->> %s, '')), '') is null then 0 "
            f"when trim(base.data ->> %s) ~ '{_SAFE_NUMERIC_TEXT_RE}' then (base.data ->> %s)::double precision "
            "else 0 end), 0)"
        )
        query_params.extend([measure_field, measure_field, measure_field])
    else:
        value_sql = "count(*)"
    with get_conn() as conn:
        rows = fetch_all(
            conn,
            f"""
            with base as (
                select id, data, updated_at
                from records_generic
                {where}
                order by updated_at desc, id desc
                limit %s
            )
            select coalesce(base.data ->> %s, '') as key, {value_sql} as value
            from base
            group by 1
            order by 1
            """,
            query_params,
            query_name="records_generic.aggregate_fast",
        )
    out: list[dict] = []
    for row in rows:
        value = row.get("value")
        if measure_is_sum:
            try:
                value = float(value or 0)
            except Exception:
                value = 0.0
        else:
            try:
                value = int(value or 0)
            except Exception:
                value = 0
        out.append({"key": row.get("key") or "", "value": value})
    return out


def _pivot_records_sql_fast(
    *,
    entity_id: str,
    row_group_by: str,
    col_group_by: str | None,
    measure: str,
    limit: int,
    q: str | None = None,
    search_fields: list[str] | None = None,
) -> dict | None:
    if not _is_safe_sql_field_id(row_group_by):
        return None
    if isinstance(col_group_by, str) and col_group_by and not _is_safe_sql_field_id(col_group_by):
        return None
    measure_field = None
    measure_is_sum = False
    if isinstance(measure, str) and measure.startswith("sum:"):
        measure_field = measure.split(":", 1)[1]
        measure_is_sum = True
        if not _is_safe_sql_field_id(measure_field):
            return None
    where, params = _build_records_generic_sql_where(entity_id=entity_id, q=q, search_fields=search_fields)
    query_params: list[Any] = list(params)
    query_params.append(limit)
    query_params.append(row_group_by)
    if isinstance(col_group_by, str) and col_group_by:
        col_key_sql = "coalesce(base.data ->> %s, '')"
        query_params.append(col_group_by)
    else:
        col_key_sql = "''"
    if measure_is_sum and measure_field:
        value_sql = (
            "coalesce(sum(case "
            "when nullif(trim(coalesce(base.data ->> %s, '')), '') is null then 0 "
            f"when trim(base.data ->> %s) ~ '{_SAFE_NUMERIC_TEXT_RE}' then (base.data ->> %s)::double precision "
            "else 0 end), 0)"
        )
        query_params.extend([measure_field, measure_field, measure_field])
    else:
        value_sql = "count(*)::double precision"
    with get_conn() as conn:
        rows = fetch_all(
            conn,
            f"""
            with base as (
                select id, data, updated_at
                from records_generic
                {where}
                order by updated_at desc, id desc
                limit %s
            )
            select
                coalesce(base.data ->> %s, '') as row_key,
                {col_key_sql} as col_key,
                {value_sql} as value
            from base
            group by 1, 2
            order by 1, 2
            """,
            query_params,
            query_name="records_generic.pivot_fast",
        )
    row_keys: list[str] = []
    col_keys: list[str] = []
    matrix: dict[str, dict[str, float]] = {}
    row_totals: dict[str, float] = {}
    col_totals: dict[str, float] = {}
    grand_total = 0.0
    for row in rows:
        row_key = row.get("row_key") or ""
        col_key = row.get("col_key") or ""
        try:
            value = float(row.get("value") or 0)
        except Exception:
            value = 0.0
        if row_key not in matrix:
            matrix[row_key] = {}
            row_keys.append(row_key)
        if col_key not in col_totals:
            col_totals[col_key] = 0.0
            col_keys.append(col_key)
        matrix[row_key][col_key] = value
        row_totals[row_key] = row_totals.get(row_key, 0.0) + value
        col_totals[col_key] = col_totals.get(col_key, 0.0) + value
        grand_total += value
    return {
        "rows": [{"key": key, "label": key} for key in row_keys],
        "cols": [{"key": key, "label": key} for key in col_keys] if col_keys else [{"key": "", "label": ""}],
        "matrix": matrix,
        "row_totals": row_totals,
        "col_totals": col_totals,
        "grand_total": grand_total,
    }


def _dashboard_query_sql_fast(
    *,
    entity_id: str,
    source: dict,
    group_by: str | None,
    measure: str,
    date_field: str | None,
    start: str | None,
    end: str | None,
    limit: int,
    q: str | None = None,
    source_filter: dict | None = None,
) -> dict | None:
    if isinstance(group_by, str) and group_by and not _is_safe_sql_field_id(group_by):
        return None
    effective_measure = measure if isinstance(measure, str) and measure else "count"
    measure_kind = "count"
    measure_field = None
    if effective_measure.startswith("sum:"):
        measure_kind = "sum"
        measure_field = effective_measure.split(":", 1)[1]
    elif effective_measure.startswith("count_distinct:"):
        measure_kind = "count_distinct"
        measure_field = effective_measure.split(":", 1)[1]
    if measure_field and not _is_safe_sql_field_id(measure_field):
        return None
    if isinstance(date_field, str) and date_field and not _is_safe_sql_field_id(date_field):
        return None
    built_filter = _build_simple_domain_sql_clause(source_filter) if isinstance(source_filter, dict) else ("true", [])
    if built_filter is None:
        return None
    filter_sql, filter_params = built_filter
    where, params = _build_records_generic_sql_where(entity_id=entity_id, q=q, search_fields=None)
    query_params: list[Any] = list(params)
    query_params.append(limit)
    outer_conditions = [filter_sql]
    outer_params: list[Any] = list(filter_params)
    if isinstance(date_field, str) and date_field:
        if isinstance(start, str) and start.strip():
            outer_conditions.append("coalesce(base.data ->> %s, '') >= %s")
            outer_params.extend([date_field, start.strip()])
        if isinstance(end, str) and end.strip():
            outer_conditions.append("coalesce(base.data ->> %s, '') <= %s")
            outer_params.extend([date_field, end.strip()])
    outer_where = " and ".join([f"({part})" for part in outer_conditions if isinstance(part, str) and part.strip()]) or "true"
    if not isinstance(group_by, str) or not group_by:
        if measure_kind == "sum" and measure_field:
            select_sql = (
                "coalesce(sum(case "
                "when nullif(trim(coalesce(base.data ->> %s, '')), '') is null then 0 "
                f"when trim(base.data ->> %s) ~ '{_SAFE_NUMERIC_TEXT_RE}' then (base.data ->> %s)::double precision "
                "else 0 end), 0) as value"
            )
            query_params.extend([measure_field, measure_field, measure_field] + outer_params)
        elif measure_kind == "count_distinct" and measure_field:
            select_sql = "count(distinct nullif(trim(coalesce(base.data ->> %s, '')), '')) as value"
            query_params.extend([measure_field] + outer_params)
        else:
            select_sql = "count(*)::bigint as value"
            query_params.extend(outer_params)
        with get_conn() as conn:
            row = fetch_one(
                conn,
                f"""
                with base as (
                    select id, data, updated_at
                    from records_generic
                    {where}
                    order by updated_at desc, id desc
                    limit %s
                )
                select {select_sql}, count(*)::bigint as filtered_count
                from base
                where {outer_where}
                """,
                query_params,
                query_name="records_generic.dashboard_fast_total",
            )
        value = row.get("value") if isinstance(row, dict) else 0
        count = row.get("filtered_count") if isinstance(row, dict) else 0
        try:
            value = float(value or 0) if measure_kind == "sum" else int(value or 0)
        except Exception:
            value = 0.0 if measure_kind == "sum" else 0
        try:
            count = int(count or 0)
        except Exception:
            count = 0
        return {"source": source, "measure": effective_measure if measure_kind != "count" else "count", "value": value, "count": count}
    group_key_sql = "coalesce(base.data ->> %s, '') as key"
    query_params.append(group_by)
    if measure_kind == "sum" and measure_field:
        value_sql = (
            "coalesce(sum(case "
            "when nullif(trim(coalesce(base.data ->> %s, '')), '') is null then 0 "
            f"when trim(base.data ->> %s) ~ '{_SAFE_NUMERIC_TEXT_RE}' then (base.data ->> %s)::double precision "
            "else 0 end), 0) as value"
        )
        query_params.extend([measure_field, measure_field, measure_field] + outer_params)
    elif measure_kind == "count_distinct" and measure_field:
        value_sql = "count(distinct nullif(trim(coalesce(base.data ->> %s, '')), ''))::double precision as value"
        query_params.extend([measure_field] + outer_params)
    else:
        value_sql = "count(*)::double precision as value"
        query_params.extend(outer_params)
    with get_conn() as conn:
        rows = fetch_all(
            conn,
            f"""
            with base as (
                select id, data, updated_at
                from records_generic
                {where}
                order by updated_at desc, id desc
                limit %s
            )
            select {group_key_sql}, {value_sql}
            from base
            where {outer_where}
            group by 1
            order by value desc
            """,
            query_params,
            query_name="records_generic.dashboard_fast_grouped",
        )
        count_row = fetch_one(
            conn,
            f"""
            with base as (
                select id, data, updated_at
                from records_generic
                {where}
                order by updated_at desc, id desc
                limit %s
            )
            select count(*)::bigint as filtered_count
            from base
            where {outer_where}
            """,
            params + [limit] + outer_params,
            query_name="records_generic.dashboard_fast_grouped_count",
        )
    output = []
    for row in rows:
        try:
            value = float(row.get("value") or 0)
        except Exception:
            value = 0.0
        output.append({"key": row.get("key") or "", "value": value})
    try:
        filtered_count = int((count_row or {}).get("filtered_count") or 0)
    except Exception:
        filtered_count = 0
    return {
        "source": source,
        "group_by": group_by,
        "measure": effective_measure,
        "groups": output,
        "count": filtered_count,
    }


def _record_value(record: dict, field_id: str | None):
    if not isinstance(record, dict) or not isinstance(field_id, str) or not field_id:
        return None
    return record.get(field_id)


def _extract_attachment_items(attachment_value: Any) -> list[dict]:
    if attachment_value is None:
        return []
    if isinstance(attachment_value, list):
        out = []
        for item in attachment_value:
            if isinstance(item, dict):
                out.append(item)
            elif isinstance(item, str) and item:
                out.append({"id": item})
        return out
    if isinstance(attachment_value, dict):
        return [attachment_value]
    if isinstance(attachment_value, str) and attachment_value:
        return [{"id": attachment_value}]
    return []


def _find_source_by_key(sources: list[dict], source_key: str | None) -> dict | None:
    if not isinstance(source_key, str) or not source_key:
        return None
    for source in sources:
        if source.get("source_key") == source_key:
            return source
    return None


def _get_compiled_manifest(module_id: str, manifest_hash: str, manifest: dict) -> dict:
    cache_key = f"{get_org_id()}:{module_id}:{manifest_hash}"
    entry = _compiled_cache.get(cache_key)
    now = time.time()
    if entry and now - entry["ts"] < _CACHE_TTL_S:
        return entry["value"]
    compiled = _compile_manifest(manifest)
    _compiled_cache[cache_key] = {"value": compiled, "ts": now}
    return compiled


def _get_compiled_manifest_variant(module_id: str, manifest_hash: str, manifest: dict, variant_key: str) -> dict:
    cache_key = f"{get_org_id()}:{module_id}:{manifest_hash}:{variant_key}"
    entry = _compiled_cache.get(cache_key)
    now = time.time()
    if entry and now - entry["ts"] < _CACHE_TTL_S:
        return entry["value"]
    compiled = _compile_manifest(manifest)
    _compiled_cache[cache_key] = {"value": compiled, "ts": now}
    return compiled


def _cache_get(bucket: str, key: str | None = None):
    now = time.time()
    if key is None:
        # Buckets below must be tenant-scoped. Otherwise module lists leak across workspaces.
        if bucket in {"modules", "studio_modules", "registry_list"}:
            org_id = get_org_id()
            entry = _cache[bucket]
            value_map = entry.get("value")
            ts_map = entry.get("ts")
            if not isinstance(value_map, dict) or not isinstance(ts_map, dict):
                # Migrate old single-tenant shape to per-tenant maps.
                entry["value"] = {}
                entry["ts"] = {}
                return None
            if org_id in value_map and org_id in ts_map and now - float(ts_map[org_id] or 0.0) < _CACHE_TTL_S:
                return value_map[org_id]
            return None
        entry = _cache[bucket]
        if entry["value"] is not None and now - entry["ts"] < _CACHE_TTL_S:
            return entry["value"]
        return None
    entry = _cache[bucket].get(key)
    if entry and now - entry["ts"] < _CACHE_TTL_S:
        return entry["value"]
    return None


def _cache_set(bucket: str, value, key: str | None = None):
    if key is None:
        if bucket in {"modules", "studio_modules", "registry_list"}:
            org_id = get_org_id()
            entry = _cache[bucket]
            if not isinstance(entry.get("value"), dict) or not isinstance(entry.get("ts"), dict):
                entry["value"] = {}
                entry["ts"] = {}
            entry["value"][org_id] = value
            entry["ts"][org_id] = time.time()
            return
        _cache[bucket]["value"] = value
        _cache[bucket]["ts"] = time.time()
    else:
        _cache[bucket][key] = {"value": value, "ts": time.time()}


def _cache_invalidate(bucket: str, key: str | None = None):
    if key is None:
        if "value" in _cache[bucket]:
            if bucket in {"modules", "studio_modules", "registry_list"}:
                _cache[bucket]["value"] = {}
                _cache[bucket]["ts"] = {}
            else:
                _cache[bucket]["value"] = None
                _cache[bucket]["ts"] = 0.0
        else:
            _cache[bucket].clear()
    else:
        _cache[bucket].pop(key, None)
    if bucket in {"manifest", "modules", "registry_list"}:
        _entity_def_cache.clear()
        _cache["entity_registry"].clear()
        _cache["studio2_registry"].clear()
        _cache["studio2_registry_summary"].clear()
        _cache["registry_list_meta"].clear()


def _resp_cache_get(key: str):
    entry = _response_cache.get(key)
    now = time.time()
    if entry and now - entry["ts"] < _RESPONSE_TTL_S:
        return entry["value"]
    return None


def _resp_cache_set(key: str, value):
    _response_cache[key] = {"value": value, "ts": time.time()}


def _resp_cache_invalidate_prefix(prefix: str) -> None:
    for key in list(_response_cache.keys()):
        if key.startswith(prefix):
            _response_cache.pop(key, None)


def _resp_cache_invalidate_entity(entity_id: str) -> None:
    prefix = f"records:list:{get_org_id()}:{entity_id}:"
    _resp_cache_invalidate_prefix(prefix)
    prefix = f"lookup:{get_org_id()}:{entity_id}:"
    _resp_cache_invalidate_prefix(prefix)
    prefix = f"aggregate:{get_org_id()}:{entity_id}:"
    _resp_cache_invalidate_prefix(prefix)
    prefix = f"pivot:{get_org_id()}:{entity_id}:"
    _resp_cache_invalidate_prefix(prefix)
    prefix = f"dashboard_query:{get_org_id()}:"
    marker = f":{entity_id}:"
    for key in list(_response_cache.keys()):
        if key.startswith(prefix) and marker in key:
            _response_cache.pop(key, None)


def _resp_cache_invalidate_record(entity_id: str, record_id: str) -> None:
    _resp_cache_invalidate_prefix(f"records:get:{get_org_id()}:{entity_id}:{record_id}:")
    _resp_cache_invalidate_prefix(f"chatter:{get_org_id()}:{entity_id}:{record_id}:")


def _resp_cache_invalidate_module_bootstrap(module_id: str) -> None:
    if not isinstance(module_id, str) or not module_id:
        return
    prefix = f"bootstrap:{get_org_id()}:"
    marker = f":{module_id}:"
    for key in list(_response_cache.keys()):
        if key.startswith(prefix) and marker in key:
            _response_cache.pop(key, None)


def _prefs_ui_cache_key(org_id: str, user_id: str | None = None) -> str:
    return f"prefs_ui:{str(org_id or '').strip()}:{str(user_id or '').strip()}"


def _invalidate_prefs_ui_runtime_caches(org_id: str) -> None:
    org_key = str(org_id or "").strip()
    if not org_key:
        return
    _cache_invalidate("branding_domains", org_key)
    _resp_cache_invalidate_prefix(f"prefs_ui:{org_key}:")


def _invalidate_module_runtime_caches(module_id: str, *, include_studio_modules: bool = False) -> None:
    _cache_invalidate("modules")
    _cache_invalidate("registry_list")
    _cache_invalidate("manifest")
    if include_studio_modules:
        _cache_invalidate("studio_modules")
    _compiled_cache_invalidate(module_id)
    _resp_cache_invalidate_module_bootstrap(module_id)
    _resp_cache_invalidate_prefix("automations_meta:")
    _resp_cache_invalidate_prefix("interface_sources:")
    _resp_cache_invalidate_prefix("calendar_sources:")
    _resp_cache_invalidate_prefix("document_sources:")
    _resp_cache_invalidate_prefix("dashboard_sources:")


def _domain_hash(domain: dict | None) -> str:
    if not domain:
        return ""
    try:
        payload = json.dumps(domain, sort_keys=True)
    except Exception:
        payload = str(domain)
    return str(abs(hash(payload)))


def _context_hash(ctx: dict | None) -> str:
    if not ctx:
        return ""
    try:
        payload = json.dumps(ctx, sort_keys=True)
    except Exception:
        payload = str(ctx)
    return str(abs(hash(payload)))


def _access_policy_hash(actor: dict | None) -> str:
    policy = _access_policy_for_actor(actor)
    try:
        payload = json.dumps(policy or {}, sort_keys=True)
    except Exception:
        payload = str(policy)
    return str(abs(hash(payload)))


def _actor_domain_context(actor: dict | None) -> dict:
    if not isinstance(actor, dict):
        return {}
    context = {}
    for key in ("user_id", "email", "workspace_id", "workspace_role", "role", "platform_role"):
        value = actor.get(key)
        if isinstance(value, str) and value:
            context[key] = value
    return context


def _compiled_cache_invalidate(module_id: str | None = None):
    if module_id is None:
        _compiled_cache.clear()
        return
    prefix = f"{get_org_id()}:{module_id}:"
    for key in list(_compiled_cache.keys()):
        if key.startswith(prefix):
            _compiled_cache.pop(key, None)


def _module_name_from_manifest(manifest: dict | None) -> str | None:
    if not isinstance(manifest, dict):
        return None
    module_def = manifest.get("module")
    if not isinstance(module_def, dict):
        return None
    name = module_def.get("name")
    if isinstance(name, str) and name.strip():
        return name
    return None


def _begin_module_mutation(module_id: str) -> bool:
    if module_id in _MODULE_MUTATIONS:
        return False
    _MODULE_MUTATIONS.add(module_id)
    return True


def _end_module_mutation(module_id: str) -> None:
    _MODULE_MUTATIONS.discard(module_id)


def _preview_payload(module_id: str, current_hash: str | None, manifest: dict, reason: str, patch_id: str, actor_id: str) -> dict:
    proposed_hash = manifest_hash(manifest)
    warnings = []
    if current_hash == proposed_hash:
        warnings.append({"code": "MODULE_ALREADY_UP_TO_DATE", "message": "Module already up to date", "path": "module_id", "detail": None})
    patch = {
        "patch_id": patch_id,
        "target_module_id": module_id,
        "target_manifest_hash": current_hash,
        "mode": "preview",
        "reason": reason,
        "operations": [],
        "metadata": {"generated_by": {"type": "user", "id": actor_id, "name": ""}},
    }
    preview = {
        "ok": True,
        "errors": [],
        "warnings": warnings,
        "impact": None,
        "resolved_ops": [],
        "diff_summary": {"touched": [], "counts": {"add": 0, "remove": 0, "replace": 0, "move": 0, "copy": 0, "test": 0}},
    }
    return {
        "module_id": module_id,
        "current_hash": current_hash,
        "proposed_hash": proposed_hash,
        "patch": patch,
        "preview": preview,
    }


def _is_valid_module_id(module_id: str) -> bool:
    return bool(re.match(r"^[a-z][a-z0-9_]{2,32}$", module_id))


def _generate_module_id() -> str:
    for _ in range(25):
        candidate = f"module_{uuid.uuid4().hex[:6]}"
        if _is_valid_module_id(candidate) and registry.get(candidate) is None and drafts.get_draft(candidate) is None:
            return candidate
    return f"module_{uuid.uuid4().hex[:6]}"


def _draft_hash(manifest: dict, module_id: str | None = None) -> str:
    # Keep draft/install hash comparison consistent with Studio2 install:
    # sanitize -> ensure_module_id -> ensure_app_home -> normalize_v13 -> validate.
    normalized_input = manifest if isinstance(manifest, dict) else {}
    if isinstance(module_id, str) and module_id:
        normalized_input = _ensure_app_home(_ensure_module_id(_sanitize_manifest(normalized_input), module_id))
        normalized_input, _ = normalize_manifest_v13(normalized_input, module_id=module_id, cache={})
    normalized, _, _ = validate_manifest_raw(
        normalized_input,
        expected_module_id=module_id if isinstance(module_id, str) else None,
    )
    return manifest_hash(normalized)


