def _build_scaffold_single_entity(
    module_id: str,
    module_name: str | None,
    entity_slug: str,
    entity_label: str,
    fields: list[dict],
    nav_label: str | None = None,
    family: str | None = None,
) -> dict:
    name = module_name or module_id.replace("_", " ").replace("-", " ").title() or "New Module"
    entity_id = f"entity.{entity_slug}"
    list_page = f"{entity_slug}.list_page"
    form_page = f"{entity_slug}.form_page"
    list_view = f"{entity_slug}.list"
    form_view = f"{entity_slug}.form"
    kanban_view = f"{entity_slug}.kanban"
    calendar_view = f"{entity_slug}.calendar"
    graph_view = f"{entity_slug}.graph"
    action_id = f"action.{entity_slug}_new"
    nav_label = nav_label or entity_label
    preferred_view_modes = set(_ai_design_family_preferred_view_modes(family or ""))
    default_list_mode = _ai_design_family_default_list_mode(family or "") or "list"

    custom_fields: list[dict] = []
    for field in fields if isinstance(fields, list) else []:
        if not isinstance(field, dict):
            continue
        field_id = field.get("id")
        if field_id in {f"{entity_slug}.id", f"{entity_slug}.created_at"}:
            continue
        custom_fields.append(copy.deepcopy(field))

    base_fields = [
        {"id": f"{entity_slug}.id", "type": "uuid", "label": "ID", "readonly": True},
        {"id": f"{entity_slug}.created_at", "type": "datetime", "label": "Created At", "readonly": True},
    ]
    entity_fields = base_fields + custom_fields
    display_field = _ai_pick_scaffold_display_field(entity_slug, entity_fields)
    if not isinstance(display_field, str):
        display_field = entity_fields[1]["id"] if len(entity_fields) > 1 else entity_fields[0]["id"]
    status_field = next((field for field in entity_fields if isinstance(field, dict) and field.get("id") == f"{entity_slug}.status"), None)
    if status_field is None:
        status_field = next((field for field in entity_fields if isinstance(field, dict) and field.get("type") == "enum"), None)
    if isinstance(status_field, dict):
        status_options = status_field.get("options") if isinstance(status_field.get("options"), list) else []
        default_value = status_field.get("default") if isinstance(status_field.get("default"), str) else None
        if status_options:
            option_values = {
                item.get("value")
                for item in status_options
                if isinstance(item, dict) and isinstance(item.get("value"), str) and item.get("value")
            }
            if not default_value or default_value not in option_values:
                first_value = next(
                    (
                        item.get("value")
                        for item in status_options
                        if isinstance(item, dict) and isinstance(item.get("value"), str) and item.get("value")
                    ),
                    None,
                )
                if isinstance(first_value, str) and first_value:
                    status_field["default"] = first_value
    status_field_id = status_field.get("id") if isinstance(status_field, dict) and isinstance(status_field.get("id"), str) else None
    date_fields = [
        field for field in entity_fields
        if isinstance(field, dict) and field.get("type") in {"date", "datetime"} and isinstance(field.get("id"), str)
    ]
    date_field_id = date_fields[0].get("id") if date_fields else None
    secondary_date_field_id = date_fields[1].get("id") if len(date_fields) > 1 else date_field_id
    form_activity = _studio2_default_form_activity_config(entity_id, entity_fields)

    list_column_ids = _ai_select_scaffold_list_column_ids(
        entity_fields,
        display_field,
        status_field_id,
        family,
        limit=6,
    )
    list_columns = [{"field_id": field_id} for field_id in list_column_ids]
    if not list_columns and isinstance(display_field, str) and display_field:
        list_columns = [{"field_id": display_field}]

    subtitle_fields = _ai_select_scaffold_kanban_subtitle_fields(
        entity_fields,
        display_field,
        status_field_id,
        family,
        limit=2,
    )
    badge_fields = _ai_select_scaffold_kanban_badge_fields(
        entity_fields,
        display_field,
        status_field_id,
        family,
        limit=2,
    )
    search_field_ids = _ai_select_scaffold_search_field_ids(
        entity_fields,
        display_field,
        status_field_id,
        family,
        limit=4,
    )

    filters: list[dict] = []
    default_filter_id = None
    status_options = status_field.get("options") if isinstance(status_field, dict) and isinstance(status_field.get("options"), list) else []
    if status_field_id and status_options:
        preferred_defaults = {"active", "open", "planned", "new", "todo", "in_progress"}
        for option in status_options[:6]:
            if not isinstance(option, dict):
                continue
            value = option.get("value")
            label = option.get("label")
            if not isinstance(value, str) or not isinstance(label, str):
                continue
            filter_id = _marketplace_slugify(value).replace("-", "_") or f"status_{len(filters) + 1}"
            filters.append(
                {
                    "id": filter_id,
                    "label": label,
                    "domain": {"op": "eq", "field": status_field_id, "value": value},
                }
            )
            if default_filter_id is None and value in preferred_defaults:
                default_filter_id = filter_id

    view_modes = [{"mode": "list", "target": f"view:{list_view}"}]
    views: list[dict] = [
        {
            "id": list_view,
            "kind": "list",
            "entity": entity_id,
            "header": {
                "primary_actions": [{"action_id": action_id}],
                "open_record_target": f"page:{form_page}",
                "filters": filters,
                **(
                    {
                        "search": {
                            "enabled": True,
                            "placeholder": f"Search {nav_label}...",
                            "fields": search_field_ids,
                        }
                    }
                    if search_field_ids
                    else {}
                ),
            },
            "columns": list_columns,
            "create_behavior": "open_form",
        },
    ]
    if status_field_id and (not preferred_view_modes or "kanban" in preferred_view_modes):
        view_modes.append({"mode": "kanban", "target": f"view:{kanban_view}", "default_group_by": status_field_id})
        views.append(
            {
                "id": kanban_view,
                "kind": "kanban",
                "entity": entity_id,
                "card": {
                    "title_field": display_field,
                    "subtitle_fields": subtitle_fields[:2],
                    "badge_fields": badge_fields[:2],
                },
            }
        )
    if date_field_id and (not preferred_view_modes or "calendar" in preferred_view_modes):
        view_modes.append({"mode": "calendar", "target": f"view:{calendar_view}"})
        views.append(
            {
                "id": calendar_view,
                "kind": "calendar",
                "entity": entity_id,
                "calendar": {
                    "title_field": display_field,
                    "date_start": date_field_id,
                    "date_end": secondary_date_field_id,
                    "default_scale": "week",
                },
            }
        )
    graph_group_by = status_field_id or date_field_id or display_field
    if not preferred_view_modes or "graph" in preferred_view_modes:
        view_modes.append({"mode": "graph", "target": f"view:{graph_view}"})
    if graph_group_by != display_field and (not preferred_view_modes or "pivot" in preferred_view_modes):
        view_modes.append({"mode": "pivot", "target": f"view:{list_view}", "default_group_by": graph_group_by})
    if not preferred_view_modes or "graph" in preferred_view_modes:
        views.append(
            {
                "id": graph_view,
                "kind": "graph",
                "entity": entity_id,
                "default": {
                    "type": "bar",
                    "group_by": graph_group_by,
                    "measure": "count",
                },
            }
        )

    return {
        "manifest_version": "1.3",
        "module": {"id": module_id, "name": name, "key": module_id, "version": "0.1.0", "description": ""},
        "app": {
            "home": f"page:{list_page}",
            "nav": [{"group": name, "items": [{"label": nav_label, "to": f"page:{list_page}"}]}],
            "defaults": {
                "entity_form_page": f"page:{form_page}",
                "entity_home_page": f"page:{list_page}",
                "entities": {
                    entity_id: {
                        "entity_form_page": f"page:{form_page}",
                        "entity_home_page": f"page:{list_page}",
                    }
                },
            },
        },
        "entities": [
            {
                "id": entity_id,
                "label": entity_label,
                "display_field": display_field,
                "fields": entity_fields,
            }
        ],
        "views": views + [
            {
                "id": form_view,
                "kind": "form",
                "entity": entity_id,
                "header": {
                    "auto_save": True,
                    "save_mode": "top",
                    "title_field": display_field,
                    "auto_save_debounce_ms": 750,
                },
                "activity": form_activity,
                "sections": [
                    {
                        "id": "main",
                        "title": "Details",
                        "fields": [f.get("id") for f in entity_fields if f.get("id")],
                        "layout": "columns",
                        "columns": 2,
                    }
                ],
            },
        ],
        "pages": [
            {
                "id": list_page,
                "title": nav_label,
                "header": {"variant": "none"},
                "layout": "single",
                "content": [
                    {
                        "kind": "container",
                        "variant": "card",
                        "content": [
                            {
                                "kind": "view_modes",
                                "entity_id": entity_id,
                                "default_mode": default_list_mode,
                                "modes": view_modes,
                                **({"default_filter_id": default_filter_id} if isinstance(default_filter_id, str) and default_filter_id else {}),
                            }
                        ],
                    }
                ],
            },
            {
                "id": form_page,
                "title": entity_label,
                "header": {"variant": "none"},
                "layout": "single",
                "content": [
                    {
                        "kind": "record",
                        "entity_id": entity_id,
                        "record_id_query": "record",
                        "content": [
                            {
                                "kind": "grid",
                                "columns": 12,
                                "gap": "md",
                                "items": [
                                    {
                                        "span": 8,
                                        "content": [
                                            {
                                                "kind": "container",
                                                "variant": "card",
                                                "content": [{"kind": "view", "target": f"view:{form_view}"}],
                                            }
                                        ],
                                    },
                                    {
                                        "span": 4,
                                        "content": [
                                            {
                                                "kind": "container",
                                                "title": "Activity",
                                                "variant": "card",
                                                "content": [
                                                    {
                                                        "kind": "chatter",
                                                        "entity_id": entity_id,
                                                        "record_ref": "$record.id",
                                                    }
                                                ],
                                            }
                                        ],
                                    },
                                ],
                            }
                        ],
                    }
                ],
            },
        ],
        "actions": [{"id": action_id, "kind": "open_form", "label": "New", "target": form_view}],
        "relations": [],
    }


def _build_scaffold_template(module_id: str, module_name: str | None, pattern_key: str | None) -> dict:
    key = (pattern_key or "").lower() if pattern_key else ""
    if key == "contacts":
        fields = [
            {"id": "contact.name", "type": "string", "label": "Name", "required": True},
            {"id": "contact.email", "type": "string", "label": "Email"},
            {"id": "contact.phone", "type": "string", "label": "Phone"},
            {"id": "contact.company", "type": "string", "label": "Company"},
            {"id": "contact.tags", "type": "tags", "label": "Tags"},
            {
                "id": "contact.status",
                "type": "enum",
                "label": "Status",
                "default": "active",
                "options": [{"label": "Active", "value": "active"}, {"label": "Inactive", "value": "inactive"}],
            },
        ]
        return _build_scaffold_single_entity(module_id, module_name, "contact", "Contact", fields, nav_label="All Contacts")
    if key == "jobs":
        fields = [
            {"id": "job.title", "type": "string", "label": "Title", "required": True},
            {
                "id": "job.status",
                "type": "enum",
                "label": "Status",
                "default": "new",
                "options": [{"label": "New", "value": "new"}, {"label": "In Progress", "value": "in_progress"}, {"label": "Done", "value": "done"}],
            },
            {"id": "job.due_date", "type": "date", "label": "Due Date"},
            {"id": "job.price", "type": "number", "label": "Price"},
            {"id": "job.notes", "type": "text", "label": "Notes"},
        ]
        return _build_scaffold_single_entity(module_id, module_name, "job", "Job", fields, nav_label="Jobs")
    if key == "todo":
        fields = [
            {"id": "task.title", "type": "string", "label": "Title", "required": True},
            {
                "id": "task.status",
                "type": "enum",
                "label": "Status",
                "default": "todo",
                "options": [{"label": "To Do", "value": "todo"}, {"label": "In Progress", "value": "in_progress"}, {"label": "Done", "value": "done"}],
            },
            {"id": "task.due_date", "type": "date", "label": "Due Date"},
            {"id": "task.notes", "type": "text", "label": "Notes"},
        ]
        return _build_scaffold_single_entity(module_id, module_name, "task", "Task", fields, nav_label="Tasks")
    if key == "inventory":
        fields = [
            {"id": "item.name", "type": "string", "label": "Name", "required": True},
            {"id": "item.sku", "type": "string", "label": "SKU"},
            {"id": "item.qty", "type": "number", "label": "Quantity"},
            {
                "id": "item.status",
                "type": "enum",
                "label": "Status",
                "default": "active",
                "options": [{"label": "Active", "value": "active"}, {"label": "Inactive", "value": "inactive"}],
            },
            {"id": "item.notes", "type": "text", "label": "Notes"},
        ]
        return _build_scaffold_single_entity(module_id, module_name, "item", "Item", fields, nav_label="Items")
    if key == "crm":
        fields = [
            {"id": "lead.title", "type": "string", "label": "Title", "required": True},
            {
                "id": "lead.stage",
                "type": "enum",
                "label": "Stage",
                "default": "new",
                "options": [{"label": "New", "value": "new"}, {"label": "Qualified", "value": "qualified"}, {"label": "Won", "value": "won"}],
            },
            {"id": "lead.value", "type": "number", "label": "Value"},
            {"id": "lead.notes", "type": "text", "label": "Notes"},
        ]
        return _build_scaffold_single_entity(module_id, module_name, "lead", "Lead", fields, nav_label="Leads")
    return _build_v1_empty_template(module_id, module_name)


def _ai_clean_module_name_candidate(raw: str | None) -> str | None:
    if not isinstance(raw, str):
        return None
    label = raw.strip(" .,-\"'")
    if not label:
        return None
    label = re.split(r"[.!?]\s+", label, maxsplit=1)[0].strip(" .,-\"'")
    label = re.sub(
        r"^(?:create|build|make|change|rename)\s+",
        "",
        label,
        flags=re.IGNORECASE,
    ).strip(" .,-\"'")
    label = re.sub(
        r"^(?:me|us)\s+(?:a|an|the)\s+",
        "",
        label,
        flags=re.IGNORECASE,
    ).strip(" .,-\"'")
    label = re.sub(
        r"^(?:me\s+|us\s+)?(?:(?:a|an|the)\s+)?(?:new\s+|simple\s+|small\s+|custom\s+)+",
        "",
        label,
        flags=re.IGNORECASE,
    ).strip(" .,-\"'")
    label = re.sub(
        r"\s+\b(with|for|to|that|which|including|using|where|make|keep|and add|and include)\b\s+.*$",
        "",
        label,
        flags=re.IGNORECASE,
    ).strip(" .,-\"'")
    label = re.sub(r"\s+\bmodule\b$", "", label, flags=re.IGNORECASE).strip(" .,-\"'")
    if label.lower() in {"simple", "new", "module", "app", "me", "me a", "me a new"}:
        return None
    if label and label == label.lower():
        label = label.title()
    return label or None


def _ai_is_overly_generic_module_label(label: str | None) -> bool:
    if not isinstance(label, str) or not label.strip():
        return False
    normalized_tokens = [token for token in re.findall(r"[a-z0-9]+", label.lower()) if token]
    if len(normalized_tokens) < 2:
        return False
    generic_tokens = {
        "job",
        "jobs",
        "task",
        "tasks",
        "lead",
        "leads",
        "quote",
        "quotes",
        "invoice",
        "invoices",
    }
    return all(token in generic_tokens for token in normalized_tokens)


def _ai_extract_scoped_module_name(message: str) -> str | None:
    msg = _ai_focus_request_text(message)
    if not msg:
        return None
    patterns = [
        rf"(?:^|[.!?]\s*)for\s+([a-zA-Z0-9][a-zA-Z0-9 &_.-]{{0,40}}?)(?:,|:|\s+(?:{_AI_SCOPE_ACTION_VERBS_PATTERN})\b)",
        r"(?:^|[.!?]\s*)regarding\s+([a-zA-Z0-9][a-zA-Z0-9 &_.-]{0,40}?)(?:,|:|\s)",
    ]
    for pattern in patterns:
        match = re.search(pattern, msg, flags=re.IGNORECASE)
        if match and isinstance(match.group(1), str):
            label = _ai_clean_module_name_candidate(match.group(1))
            if _ai_is_label_confident(label):
                if re.search(r"\b(?:my|our)\b", label, flags=re.IGNORECASE):
                    continue
                if _ai_is_overly_generic_module_label(label):
                    continue
                return label
    return None


def _ai_infer_module_name_from_purpose(message: str) -> str | None:
    msg = (message or "").strip()
    if not msg:
        return None
    lower = re.sub(r"\s+", " ", msg.lower()).strip()
    family = _ai_detect_new_module_family("", msg)
    family_def = _ai_design_family_definition(family)
    purpose_name_rules = family_def.get("purpose_name_rules") if isinstance(family_def.get("purpose_name_rules"), list) else []
    for rule in purpose_name_rules:
        if not isinstance(rule, dict):
            continue
        tokens = [token for token in (rule.get("match_any") or []) if isinstance(token, str) and token]
        name = rule.get("name") if isinstance(rule.get("name"), str) else None
        if tokens and isinstance(name, str) and name.strip() and any(token in lower for token in tokens):
            return name.strip()
    return _ai_design_family_default_module_name(family)


def _ai_extract_new_module_name(message: str, answer_hints: dict | None = None) -> str | None:

    if isinstance(answer_hints, dict):
        answer_text = answer_hints.get("answer_text")
        answer_looks_like_recipient_selection = bool(
            isinstance(answer_hints.get("recipient_email"), str)
            and answer_hints.get("recipient_email").strip()
        )
        if isinstance(answer_text, str) and answer_text.strip() and not answer_looks_like_recipient_selection:
            explicit_answer_name = _ai_extract_new_module_name(answer_text, answer_hints=None)
            if isinstance(explicit_answer_name, str) and _ai_is_label_confident(explicit_answer_name):
                return explicit_answer_name
        for key in ("module_name", "module_target"):
            value = answer_hints.get(key)
            cleaned = _ai_clean_module_name_candidate(value)
            if isinstance(cleaned, str) and _ai_is_label_confident(cleaned):
                return cleaned
    msg = (message or "").strip()
    if not msg:
        return None
    lowered = msg.lower()
    if re.search(r"\bsoftware\s+(?:engineering\s+)?contracting\s+jobs?\b", lowered):
        return "Software Delivery"
    if re.search(
        r"\b(?:field|attribute|tab|section|view|page|button|workflow|form|list|layout)\b",
        msg,
        flags=re.IGNORECASE,
    ) and re.search(
        r"\b(?:in|into|inside|within|on|to|for)\s+(?:the\s+|my\s+|our\s+)?[a-zA-Z0-9_. -]{1,60}?\s+module\b",
        msg,
        flags=re.IGNORECASE,
    ):
        return None
    rename_match = re.search(
        r"(?:change|rename)\s+(?:[a-zA-Z0-9][a-zA-Z0-9 &_.-]{0,40}?)\s+to\s+[\"']?([a-zA-Z0-9][a-zA-Z0-9 &_.-]{0,40})[\"']?",
        msg,
        flags=re.IGNORECASE,
    )
    if rename_match and isinstance(rename_match.group(1), str):
        label = _ai_clean_module_name_candidate(rename_match.group(1))
        if _ai_is_label_confident(label):
            return label
    patterns = [
        r"(?:called|named)\s+[\"']?([a-zA-Z0-9][a-zA-Z0-9 &_.-]{0,40})[\"']?",
        r"let'?s\s+call\s+it\s+[\"']?([a-zA-Z0-9][a-zA-Z0-9 &_.-]{0,40})[\"']?",
        r"call\s+it\s+[\"']?([a-zA-Z0-9][a-zA-Z0-9 &_.-]{0,40})[\"']?",
        r"(?:create|build|make)\s+(?:me\s+)?(?:a\s+|an\s+|the\s+)?(?:new\s+)?(?:simple\s+)?module\s+(?:for|to manage|for managing)\s+([a-zA-Z0-9][a-zA-Z0-9 &_.-]{0,40})",
        r"(?:create|build|make)\s+(?:me\s+)?(?:a\s+|an\s+|the\s+)?(?:new\s+)?(?:simple\s+)?module\s+(?:to track|for tracking|track)\s+(?!my\b|our\b|the\b)([a-zA-Z0-9][a-zA-Z0-9 &_.-]{0,40})",
        r"(?:create|build|make)(?:\s+(?:a|an|the))?(?:\s+simple)?\s+([a-zA-Z0-9][a-zA-Z0-9 &_.-]{0,40}?)\s+module\b",
        r"(?:create|build|make)\s+(?:me\s+|us\s+|a\s+|an\s+|the\s+|new\s+|simple\s+|small\s+|custom\s+){0,6}([a-zA-Z0-9][a-zA-Z0-9 &_.-]{0,40}?)\s+system\b",
        r"(?:create|build|make)\s+(?:me\s+|us\s+|a\s+|an\s+|the\s+|new\s+|simple\s+|small\s+|custom\s+){0,6}([a-zA-Z0-9][a-zA-Z0-9 &_.-]{0,40}?)\s+workspace\b",
    ]
    for pattern in patterns:
        match = re.search(pattern, msg, flags=re.IGNORECASE)
        if match and isinstance(match.group(1), str):
            label = _ai_clean_module_name_candidate(match.group(1))
            if _ai_is_label_confident(label):
                if re.search(r"\b(?:my|our)\b", label, flags=re.IGNORECASE):
                    continue
                if _ai_is_overly_generic_module_label(label):
                    continue
                return label
    quoted = re.search(r"[\"']([^\"']{1,40})[\"']", msg)
    if quoted and isinstance(quoted.group(1), str):
        label = _ai_clean_module_name_candidate(quoted.group(1))
        if _ai_is_label_confident(label):
            return label
    scoped_name = _ai_extract_scoped_module_name(msg)
    if _ai_is_label_confident(scoped_name):
        return scoped_name
    if "service operations" in lowered:
        return "Service Operations"
    inferred_pattern = _infer_pattern_key(msg)
    if inferred_pattern == "jobs" and re.search(r"\b(system|workspace|platform)\b", lowered):
        return "Job Operations"
    inferred_name = _ai_infer_module_name_from_purpose(msg)
    if _ai_is_label_confident(inferred_name):
        return inferred_name
    return None


def _ai_new_module_id_from_name(module_name: str, module_index: dict[str, dict]) -> str:
    base = re.sub(r"[^a-z0-9_]+", "_", _marketplace_slugify(module_name).replace("-", "_")).strip("_")
    if not base:
        base = "app"
    if not base[0].isalpha():
        base = f"app_{base}"
    if len(base) < 3:
        base = f"{base}_app"
    base = base[:33].rstrip("_") or "app_mod"
    if len(base) < 3:
        base = "app_mod"
    candidate = base
    suffix = 2
    while (
        not _is_valid_module_id(candidate)
        or candidate in module_index
        or registry.get(candidate) is not None
        or drafts.get_draft(candidate) is not None
    ):
        trimmed = base[: max(1, 33 - len(str(suffix)) - 1)].rstrip("_") or "app"
        candidate = f"{trimmed}_{suffix}"
        suffix += 1
    return candidate


def _ai_extract_requested_new_module_labels(
    message: str,
    module_ids: list[str],
    module_index: dict[str, dict],
    answer_hints: dict | None = None,
    *,
    max_targets: int = 4,
) -> list[str]:
    if not isinstance(message, str) or not message.strip():
        return []
    ordered_module_ids = list(dict.fromkeys([*module_ids, *module_index.keys()]))
    labels: list[str] = []
    seen: set[str] = set()

    def _push(candidate: str | None) -> None:
        if len(labels) >= max_targets:
            return
        cleaned = _ai_clean_module_name_candidate(candidate)
        if not _ai_is_label_confident(cleaned):
            return
        normalized = _ai_norm_token(cleaned)
        if not normalized or normalized in seen:
            return
        pending_module_id, _pending_manifest = _ai_find_pending_create_module(answer_hints, cleaned)
        if isinstance(pending_module_id, str) and pending_module_id:
            return
        resolved = _ai_find_module_by_alias(cleaned, ordered_module_ids, module_index)
        if isinstance(resolved, str) and resolved:
            return
        seen.add(normalized)
        labels.append(cleaned if any(ch.isupper() for ch in cleaned) else (_ai_humanize_identifier(cleaned) or cleaned))

    for label in _ai_extract_requested_module_labels(message):
        _push(label)
    for section in _ai_module_outline_sections(message):
        _push(section.get("label") if isinstance(section, dict) else None)
    if not labels:
        _push(_ai_extract_new_module_name(message, answer_hints=answer_hints))
    return labels


def _ai_module_outline_sections(message: str) -> list[dict]:
    if not isinstance(message, str) or not message.strip():
        return []
    clean_message = message.strip()
    header_pattern = re.compile(
        r"(?im)^(?:\s*(?:[-*•]|\d+[.)])\s*)?(?:module\s+\d+\s*:\s*(?P<numbered>.+?)|(?P<named>[A-Za-z][A-Za-z0-9 &/_.-]{1,60}?(?:\s+module)?)\s*:)\s*$"
    )
    ignored_headers = {
        _ai_norm_token(value)
        for value in (
            "build order",
            "implement in this order",
            "do not overbuild",
            "final aim",
            "important",
            "main daily workflow",
            "main weekly workflow",
            "nice to have",
            "only 2 custom modules",
            "overview",
            "requirements",
            "shared module reuse",
            "shared requirements",
            "summary",
            "what not to build",
        )
    }
    headers: list[dict] = []
    for match in header_pattern.finditer(clean_message):
        raw_label = match.group("numbered") if isinstance(match.group("numbered"), str) else match.group("named")
        cleaned = _ai_clean_module_name_candidate(raw_label)
        if not _ai_is_label_confident(cleaned):
            continue
        normalized = _ai_norm_token(cleaned)
        if not normalized or normalized in ignored_headers:
            continue
        label = cleaned if any(ch.isupper() for ch in cleaned) else (_ai_humanize_identifier(cleaned) or cleaned)
        headers.append(
            {
                "label": label,
                "start": match.start(),
                "end": match.end(),
            }
        )
    sections: list[dict] = []
    for idx, item in enumerate(headers):
        section_end = headers[idx + 1]["start"] if idx + 1 < len(headers) else len(clean_message)
        section = clean_message[item["start"] : section_end].strip()
        sections.append(
            {
                "label": item["label"],
                "start": item["start"],
                "end": section_end,
                "text": section,
            }
        )
    return sections


def _ai_scope_create_module_request(message: str, module_name: str) -> str:
    if not isinstance(message, str) or not message.strip():
        return ""
    if not isinstance(module_name, str) or not module_name.strip():
        return message.strip()
    clean_message = message.strip()
    module_sections = _ai_module_outline_sections(clean_message)
    if not module_sections:
        return clean_message
    target_aliases = {alias for alias in _ai_module_alias_candidates(module_name) if alias}
    target_aliases.add(_ai_norm_token(module_name))
    shared_prefix = clean_message[: module_sections[0]["start"]].strip()
    for section in module_sections:
        section_label = section.get("label") if isinstance(section.get("label"), str) else ""
        if _ai_norm_token(section_label) not in target_aliases:
            continue
        section_text = section.get("text") if isinstance(section.get("text"), str) else ""
        if not section_text:
            continue
        if shared_prefix:
            return f"{shared_prefix}\n\n{section_text}".strip()
        return section_text
    return clean_message


def _ai_pick_scaffold_display_field(entity_slug: str, fields: list[dict]) -> str | None:
    preferred_ids = (
        f"{entity_slug}.name",
        f"{entity_slug}.title",
        f"{entity_slug}.full_name",
        f"{entity_slug}.number",
        f"{entity_slug}.code",
        f"{entity_slug}.reference",
    )
    valid_fields = [field for field in fields if isinstance(field, dict)]
    for preferred_id in preferred_ids:
        if any(field.get("id") == preferred_id for field in valid_fields):
            return preferred_id
    for field in valid_fields:
        field_id = field.get("id")
        field_type = field.get("type")
        if not isinstance(field_id, str) or field_id.endswith(".id") or field_id.endswith(".created_at"):
            continue
        if field_type in {"string", "text", "rich_text"}:
            return field_id
    for field in valid_fields:
        field_id = field.get("id")
        if isinstance(field_id, str) and not field_id.endswith(".id") and not field_id.endswith(".created_at"):
            return field_id
    return None


def _ai_singularize_slug(value: str) -> str:
    slug = re.sub(r"[^a-z0-9_]+", "_", (value or "").lower()).strip("_")
    if not slug:
        return "record"
    if slug.endswith("ies") and len(slug) > 3:
        return f"{slug[:-3]}y"
    if slug.endswith("ses") and len(slug) > 3:
        return slug[:-2]
    if slug.endswith("s") and not slug.endswith("ss") and len(slug) > 3:
        return slug[:-1]
    return slug


def _ai_entity_slug_for_module(module_id: str, module_name: str | None = None) -> str:
    if isinstance(module_name, str) and module_name.strip():
        name_slug = _ai_singularize_slug(module_name)
        if isinstance(name_slug, str) and name_slug and name_slug != "record":
            return name_slug
    module_slug = re.sub(r"_[0-9]+$", "", (module_id or "").strip())
    return _ai_singularize_slug(module_slug or module_id)


def _ai_design_primary_entity_for_family(
    module_id: str,
    module_name: str | None,
    message: str,
    family: str,
) -> tuple[str, str]:
    entity_slug = _ai_entity_slug_for_module(module_id, module_name)
    entity_label = module_name.strip() if isinstance(module_name, str) and module_name.strip() else _ai_titleize_slug(entity_slug)
    if family == "field_service":
        lower = f"{module_name or ''} {message or ''}".lower()
        if re.search(r"\bdispatch\b", lower) or re.search(r"\broute (?:board|planning|stops?)\b", lower):
            return "dispatch", "Dispatch"
        if re.search(r"\b(site|service) visits?\b", lower):
            return "site_visit", "Site Visit"
        if re.search(r"\bwork orders?\b", lower):
            return "work_order", "Work Order"
        return entity_slug, entity_label
    if family == "service_desk":
        lower = f"{module_name or ''} {message or ''}".lower()
        if re.search(r"\bcases?\b", lower):
            return "case", "Case"
        return "ticket", "Ticket"
    if family != "fleet":
        return entity_slug, entity_label
    lower = f"{module_name or ''} {message or ''}".lower()
    if re.search(r"\b(vehicle|fleet)\b", lower):
        return "vehicle", "Vehicle"
    if re.search(r"\b(asset|equipment)\b", lower):
        return "asset", "Asset"
    if re.search(r"\btool|tools\b", lower):
        return "tool", "Tool"
    return entity_slug, entity_label


def _ai_default_primary_nav_label(
    module_name: str | None,
    entity_label: str | None,
) -> str:
    if isinstance(entity_label, str) and entity_label.strip():
        return entity_label.strip()
    if isinstance(module_name, str) and module_name.strip():
        return module_name.strip()
    return "Records"


def _ai_titleize_slug(value: str) -> str:
    parts = [part for part in re.split(r"[_\s-]+", value or "") if part]
    return " ".join(part.capitalize() for part in parts) or "Record"


def _ai_extract_status_options(message: str) -> list[dict]:
    msg = (message or "").strip()
    if not msg:
        return []
    patterns = [
        r"\bwith\s+(.+?)\s+(?:statuses|stages)\b",
        r"\bwith\s+(?:status|statuses|stage|stages)\b\s+(.+?)(?:[.;]|$)",
        r"\b(?:statuses|stages)\b\s+(.+?)(?:[.;]|$)",
    ]
    raw = None
    for pattern in patterns:
        match = re.search(pattern, msg, flags=re.IGNORECASE)
        if match and isinstance(match.group(1), str):
            raw = match.group(1)
            break
    if not raw:
        return []
    cleaned = re.sub(r"^\s*flow\s+", "", raw, flags=re.IGNORECASE)
    cleaned = re.sub(r"\band\s+actions?\b.*$", "", cleaned, flags=re.IGNORECASE)
    cleaned = re.sub(r"\band\s+(?:kanban|calendar|chart|graph|pivot|board|view|views)\b.*$", "", cleaned, flags=re.IGNORECASE)
    cleaned = cleaned.strip(" .")
    tokens = [part.strip(" .") for part in re.split(r",|\band\b", cleaned, flags=re.IGNORECASE) if part.strip(" .")]
    options: list[dict] = []
    seen: set[str] = set()
    for token in tokens[:8]:
        value = _marketplace_slugify(token).replace("-", "_").strip("_")
        label = _ai_titleize_slug(value)
        if not value or value in seen:
            continue
        seen.add(value)
        options.append({"label": label, "value": value})
    return options


def _ai_enrich_status_options_from_message(statuses: list[dict], message: str) -> list[dict]:
    merged = [copy.deepcopy(item) for item in statuses if isinstance(item, dict)]
    lower = re.sub(r"\s+", " ", (message or "").lower()).strip()
    if not lower:
        return merged
    seen = {
        item.get("value")
        for item in merged
        if isinstance(item, dict) and isinstance(item.get("value"), str)
    }

    def add(value: str, label: str) -> None:
        if value in seen:
            return
        merged.append({"value": value, "label": label})
        seen.add(value)

    if re.search(r"\bsubmit|submitted|submission\b", lower):
        add("submitted", "Submitted")
    if re.search(r"\breview|under review|reviewing\b", lower):
        add("under_review", "Under Review")
    if re.search(r"\bapprove|approved|approval\b", lower):
        add("approved", "Approved")
    if re.search(r"\breject|rejected|rejecting|decline|declined|declining\b", lower):
        add("rejected", "Rejected")
    if re.search(r"\bcomplete|completed|completion\b", lower):
        add("completed", "Completed")
    return merged


def _ai_append_unique_fields(fields: list[dict], additions: list[dict]) -> list[dict]:
    existing = {
        field.get("id")
        for field in fields
        if isinstance(field, dict) and isinstance(field.get("id"), str)
    }
    for field in additions:
        if not isinstance(field, dict):
            continue
        field_id = field.get("id")
        if not isinstance(field_id, str) or not field_id or field_id in existing:
            continue
        fields.append(field)
        existing.add(field_id)
    return fields


def _ai_design_family_signal_phrases(family_def: dict) -> list[str]:
    ignored = {
        "title",
        "name",
        "notes",
        "note",
        "attachments",
        "attachment",
        "status",
        "owner",
        "created",
        "created at",
        "quantity",
    }
    phrases: list[str] = []

    def push(raw: str | None) -> None:
        if not isinstance(raw, str):
            return
        cleaned = re.sub(r"\s+", " ", raw.replace("_", " ")).strip().lower()
        if not cleaned or cleaned in ignored:
            return
        if len(cleaned) < 6 and " " not in cleaned:
            return
        if cleaned not in phrases:
            phrases.append(cleaned)

    for token in family_def.get("detect_any") if isinstance(family_def.get("detect_any"), list) else []:
        push(token)
    for rule in family_def.get("detect_all") if isinstance(family_def.get("detect_all"), list) else []:
        if isinstance(rule, list):
            for token in rule:
                push(token)
    for rule in family_def.get("purpose_name_rules") if isinstance(family_def.get("purpose_name_rules"), list) else []:
        if not isinstance(rule, dict):
            continue
        for token in rule.get("match_any") if isinstance(rule.get("match_any"), list) else []:
            push(token)
    for field in family_def.get("fields") if isinstance(family_def.get("fields"), list) else []:
        if not isinstance(field, dict):
            continue
        push(field.get("label"))
        push(field.get("suffix"))
    for related in family_def.get("related_entities") if isinstance(family_def.get("related_entities"), list) else []:
        if not isinstance(related, dict):
            continue
        for key in ("entity_label", "nav_label", "related_title", "related_tab_label", "entity_slug"):
            push(related.get(key))
        for field in related.get("fields") if isinstance(related.get("fields"), list) else []:
            if not isinstance(field, dict):
                continue
            push(field.get("label"))
            push(field.get("id"))
    return phrases


def _ai_workspace_design_context_text(module_index: dict[str, dict] | None) -> str:
    if not isinstance(module_index, dict) or not module_index:
        return ""
    parts: list[str] = []
    for info in module_index.values():
        manifest = info.get("manifest") if isinstance(info, dict) and isinstance(info.get("manifest"), dict) else None
        if not isinstance(manifest, dict):
            continue
        module_meta = manifest.get("module") if isinstance(manifest.get("module"), dict) else {}
        if isinstance(module_meta.get("name"), str):
            parts.append(module_meta.get("name"))
        if isinstance(module_meta.get("key"), str):
            parts.append(module_meta.get("key"))
        for entity in manifest.get("entities") if isinstance(manifest.get("entities"), list) else []:
            if not isinstance(entity, dict):
                continue
            if isinstance(entity.get("label"), str):
                parts.append(entity.get("label"))
            if isinstance(entity.get("id"), str):
                parts.append(entity.get("id"))
            for field in entity.get("fields") if isinstance(entity.get("fields"), list) else []:
                if not isinstance(field, dict):
                    continue
                if isinstance(field.get("label"), str):
                    parts.append(field.get("label"))
                if isinstance(field.get("id"), str):
                    parts.append(field.get("id"))
    return re.sub(r"\s+", " ", " ".join(str(part) for part in parts if isinstance(part, str) and part.strip()).lower()).strip()


def _ai_score_new_module_family(module_name: str, message: str, family: str, family_def: dict, workspace_text: str = "") -> tuple[int, int, int]:
    lower = re.sub(r"\s+", " ", f"{module_name} {message}".lower()).strip()
    score = 0
    explicit_hits = 0
    support_hits = 0

    detect_any = family_def.get("detect_any") if isinstance(family_def.get("detect_any"), list) else []
    for token in detect_any:
        if not isinstance(token, str):
            continue
        normalized = token.strip().lower()
        if normalized and normalized in lower:
            score += 10 + min(len(normalized.split()), 3)
            explicit_hits += 1

    detect_all = family_def.get("detect_all") if isinstance(family_def.get("detect_all"), list) else []
    for rule in detect_all:
        tokens = [str(token).strip().lower() for token in rule if isinstance(token, str) and token.strip()] if isinstance(rule, list) else []
        if tokens and all(token in lower for token in tokens):
            score += 14 + len(tokens) * 2
            explicit_hits += 2

    for rule in family_def.get("purpose_name_rules") if isinstance(family_def.get("purpose_name_rules"), list) else []:
        if not isinstance(rule, dict):
            continue
        tokens = [str(token).strip().lower() for token in (rule.get("match_any") or []) if isinstance(token, str) and token.strip()]
        if any(token in lower for token in tokens):
            score += 6
            support_hits += 1

    for phrase in _ai_design_family_signal_phrases(family_def):
        if phrase in lower:
            score += 3
            support_hits += 1
            if workspace_text and phrase in workspace_text and re.search(r"\b(?:our|existing|current|other)\b", lower):
                score += 2
                support_hits += 1

    return score, explicit_hits, support_hits


def _ai_detect_new_module_family(module_name: str, message: str, module_index: dict[str, dict] | None = None) -> str:
    catalog = _ai_design_family_catalog()
    workspace_text = _ai_workspace_design_context_text(module_index)
    best_family = "generic"
    best_tuple = (0, 0, 0)
    for family, family_def in catalog.items():
        if not isinstance(family_def, dict) or family == "generic":
            continue
        score_tuple = _ai_score_new_module_family(module_name, message, family, family_def, workspace_text=workspace_text)
        if score_tuple > best_tuple:
            best_family = family
            best_tuple = score_tuple
    return best_family if best_tuple[0] > 0 else "generic"


def _ai_default_status_options(family: str) -> list[dict]:
    family_def = _ai_design_family_definition(family)
    raw_statuses = family_def.get("statuses") if isinstance(family_def.get("statuses"), list) else []
    statuses = _ai_coerce_design_statuses(raw_statuses, "generic") if raw_statuses else []
    if statuses:
        return statuses
    return [
        {"value": "new", "label": "New"},
        {"value": "in_progress", "label": "In Progress"},
        {"value": "done", "label": "Done"},
    ]


def _ai_module_design_field(field_id: str, field_type: str, label: str, **extra) -> dict:
    field = {"id": field_id, "type": field_type, "label": label}
    for key, value in extra.items():
        if value not in (None, "", [], {}):
            field[key] = value
    return field


def _ai_family_design_fields(entity_slug: str, family: str) -> list[dict]:
    family_def = _ai_design_family_definition(family)
    raw_fields = family_def.get("fields") if isinstance(family_def.get("fields"), list) else []
    normalized: list[dict] = []
    for field in raw_fields:
        if not isinstance(field, dict):
            continue
        suffix = field.get("suffix") if isinstance(field.get("suffix"), str) and field.get("suffix").strip() else None
        field_type = field.get("type") if isinstance(field.get("type"), str) and field.get("type").strip() else None
        label = field.get("label") if isinstance(field.get("label"), str) and field.get("label").strip() else None
        if not suffix or not field_type or not label:
            continue
        extra = {key: copy.deepcopy(value) for key, value in field.items() if key not in {"suffix", "type", "label"}}
        normalized.append(_ai_module_design_field(f"{entity_slug}.{suffix}", field_type, label, **extra))
    return normalized


def _ai_family_design_related_entities(family: str) -> list[dict]:
    family_def = _ai_design_family_definition(family)
    raw_related_entities = family_def.get("related_entities") if isinstance(family_def.get("related_entities"), list) else []
    return [copy.deepcopy(item) for item in raw_related_entities if isinstance(item, dict)]


def _ai_entity_specific_design_fields(entity_slug: str, family: str, message: str) -> list[dict]:
    normalized_entity_slug = entity_slug.strip().lower() if isinstance(entity_slug, str) else ""
    normalized_family = family.strip().lower() if isinstance(family, str) else ""
    if normalized_family == "field_service" and normalized_entity_slug == "dispatch":
        return [
            _ai_module_design_field(f"{entity_slug}.assigned_technician", "string", "Assigned Technician"),
            _ai_module_design_field(f"{entity_slug}.crew_name", "string", "Crew"),
            _ai_module_design_field(f"{entity_slug}.route_name", "string", "Route"),
            _ai_module_design_field(f"{entity_slug}.dispatch_date", "date", "Dispatch Date"),
            _ai_module_design_field(f"{entity_slug}.service_window_start", "datetime", "Service Window Start"),
            _ai_module_design_field(f"{entity_slug}.service_window_end", "datetime", "Service Window End"),
            _ai_module_design_field(f"{entity_slug}.stop_number", "number", "Stop Number"),
            _ai_module_design_field(f"{entity_slug}.dispatch_notes", "text", "Dispatch Notes"),
        ]
    return []


