def _ai_prune_family_specific_generic_fields(family: str, entity_slug: str, fields: list[dict]) -> list[dict]:
    if not isinstance(fields, list) or not fields:
        return []
    normalized_family = family.strip().lower() if isinstance(family, str) else ""
    normalized_entity_slug = entity_slug.strip().lower() if isinstance(entity_slug, str) else ""
    next_fields = [copy.deepcopy(field) for field in fields if isinstance(field, dict)]
    field_ids = {
        str(field.get("id")).strip().lower()
        for field in next_fields
        if isinstance(field.get("id"), str) and str(field.get("id")).strip()
    }
    if normalized_family == "compliance":
        has_specific_expiry_tracking = any(
            field_id.endswith(".insurance_expiry") or field_id.endswith(".next_review_date")
            for field_id in field_ids
        )
        if has_specific_expiry_tracking:
            next_fields = [
                field
                for field in next_fields
                if not (
                    isinstance(field.get("id"), str)
                    and str(field.get("id")).strip().lower().endswith(".due_date")
                )
            ]
    if normalized_family == "field_service":
        has_customer_name = any(field_id.endswith(".customer_name") for field_id in field_ids)
        if has_customer_name:
            next_fields = [
                field
                for field in next_fields
                if not (
                    isinstance(field.get("id"), str)
                    and str(field.get("id")).strip().lower().endswith(".client_name")
                )
            ]
        if normalized_entity_slug == "dispatch":
            next_fields = [
                field
                for field in next_fields
                if not (
                    isinstance(field.get("id"), str)
                    and str(field.get("id")).strip().lower().endswith((
                        ".technician_name",
                        ".scheduled_start",
                        ".scheduled_end",
                        ".completion_notes",
                    ))
                )
            ]
    if normalized_family in {"fleet", "register"}:
        has_service_tracking = any(
            field_id.endswith((
                ".service_due_date",
                ".last_service_date",
                ".service_date",
                ".odometer",
                ".condition",
                ".registration_number",
            ))
            for field_id in field_ids
        )
        if has_service_tracking:
            next_fields = [
                field
                for field in next_fields
                if not (
                    isinstance(field.get("id"), str)
                    and str(field.get("id")).strip().lower().endswith((
                        ".request_type",
                        ".requested_date",
                        ".requester_name",
                        ".approver_name",
                        ".amount",
                    ))
                )
            ]
    if normalized_family == "service_desk":
        has_customer_name = any(field_id.endswith(".customer_name") for field_id in field_ids)
        has_issue_type = any(field_id.endswith(".issue_type") for field_id in field_ids)
        has_sla_fields = any(field_id.endswith(".response_due_at") or field_id.endswith(".resolution_due_at") for field_id in field_ids)
        next_fields = [
            field
            for field in next_fields
            if not (
                isinstance(field.get("id"), str)
                and (
                    (has_issue_type and str(field.get("id")).strip().lower().endswith(".request_type"))
                    or (has_customer_name and str(field.get("id")).strip().lower().endswith(".requester_name"))
                    or (has_sla_fields and str(field.get("id")).strip().lower().endswith(".due_date"))
                    or str(field.get("id")).strip().lower().endswith((
                        ".approver_name",
                        ".amount",
                        ".technician_name",
                        ".scheduled_start",
                        ".scheduled_end",
                        ".service_window_start",
                        ".service_window_end",
                        ".route_name",
                    ))
                )
            )
        ]
    if normalized_family == "incident":
        has_incident_signals = any(
            field_id.endswith((
                ".reported_on",
                ".incident_type",
                ".severity",
                ".root_cause",
                ".follow_up",
                ".corrective_action_owner",
                ".corrective_due_date",
                ".closeout_summary",
                ".closed_on",
            ))
            for field_id in field_ids
        )
        if has_incident_signals:
            next_fields = [
                field
                for field in next_fields
                if not (
                    isinstance(field.get("id"), str)
                    and str(field.get("id")).strip().lower().endswith((
                        ".insurance_expiry",
                        ".safety_docs",
                        ".approved_categories",
                        ".review_notes",
                        ".approval_date",
                        ".next_review_date",
                        ".certificate_reference",
                        ".request_type",
                        ".requested_date",
                        ".requester_name",
                        ".approver_name",
                        ".amount",
                    ))
                )
            ]
    return next_fields


def _ai_module_primary_label(family: str, message: str, entity_slug: str | None = None) -> str:
    normalized_family = family.strip().lower() if isinstance(family, str) else ""
    normalized_entity_slug = entity_slug.strip().lower() if isinstance(entity_slug, str) else ""
    if normalized_family == "field_service":
        if normalized_entity_slug == "dispatch":
            return "Dispatch Reference"
        if normalized_entity_slug == "site_visit":
            return "Visit Reference"
        if normalized_entity_slug == "work_order":
            return "Work Order Number"
    if normalized_family == "service_desk":
        if normalized_entity_slug == "case":
            return "Case Reference"
        return "Ticket Number"
    family_def = _ai_design_family_definition(family)
    primary_label = family_def.get("primary_label") if isinstance(family_def.get("primary_label"), str) else None
    return primary_label.strip() if isinstance(primary_label, str) and primary_label.strip() else "Title"


def _ai_module_design_summary(module_name: str, family: str) -> str:
    family_def = _ai_design_family_definition(family)
    template = family_def.get("summary_template") if isinstance(family_def.get("summary_template"), str) else None
    if isinstance(template, str) and template.strip():
        return template.format(module_name=module_name)
    return f"{module_name} with operational records, priorities, and notes."


def _ai_infer_design_related_entities_from_message(primary_entity_slug: str, message: str) -> list[dict]:
    if not isinstance(primary_entity_slug, str) or not primary_entity_slug or not isinstance(message, str) or not message.strip():
        return []
    lower = re.sub(r"\s+", " ", message.lower()).strip()
    patterns = [
        {
            "tokens": ("maintenance", "service history", "service record", "service records", "repair history", "repair records"),
            "require_any": ("vehicle", "fleet", "asset", "equipment", "tool"),
            "entity_slug": "maintenance_record",
            "entity_label": "Maintenance Record",
            "related_title": "Maintenance Records",
            "related_tab_label": "Maintenance History",
            "fields": [
                {"id": "service_date", "type": "date", "label": "Service Date", "required": True},
                {"id": "service_type", "type": "string", "label": "Service Type", "required": True},
                {"id": "provider_name", "type": "string", "label": "Service Provider"},
                {"id": "odometer", "type": "number", "label": "Odometer"},
                {"id": "cost", "type": "number", "label": "Cost"},
                {"id": "next_due_date", "type": "date", "label": "Next Due Date"},
                {"id": "notes", "type": "text", "label": "Notes"},
                {"id": "attachments", "type": "attachments", "label": "Attachments"},
            ],
        },
        {
            "tokens": ("line item", "line items", "item row", "item rows", "item entry", "item entries"),
            "entity_slug": "line_item",
            "entity_label": "Line Item",
            "related_title": "Line Items",
            "related_tab_label": "Line Items",
            "fields": [
                {"id": "description", "type": "string", "label": "Description", "required": True},
                {"id": "quantity", "type": "number", "label": "Quantity"},
                {"id": "unit_price", "type": "number", "label": "Unit Price"},
                {"id": "line_total", "type": "number", "label": "Line Total"},
                {"id": "notes", "type": "text", "label": "Notes"},
            ],
        },
        {
            "tokens": ("subtask", "subtasks", "checklist item", "checklist items", "task item", "task items"),
            "entity_slug": "subtask",
            "entity_label": "Subtask",
            "related_title": "Subtasks",
            "related_tab_label": "Subtasks",
            "fields": [
                {"id": "title", "type": "string", "label": "Title", "required": True},
                {"id": "status", "type": "enum", "label": "Status", "options": [{"label": "Not Started", "value": "not_started"}, {"label": "In Progress", "value": "in_progress"}, {"label": "Done", "value": "done"}]},
                {"id": "owner_id", "type": "user", "label": "Owner"},
                {"id": "due_date", "type": "date", "label": "Due Date"},
                {"id": "notes", "type": "text", "label": "Notes"},
            ],
        },
        {
            "tokens": ("segment", "segments", "leg", "legs", "trip leg", "trip legs", "itinerary leg", "itinerary legs", "stop", "stops"),
            "entity_slug": "segment",
            "entity_label": "Segment",
            "related_title": "Segments",
            "related_tab_label": "Segments",
            "fields": [
                {"id": "title", "type": "string", "label": "Title", "required": True},
                {"id": "start_date", "type": "date", "label": "Start Date"},
                {"id": "end_date", "type": "date", "label": "End Date"},
                {"id": "location", "type": "string", "label": "Location"},
                {"id": "notes", "type": "text", "label": "Notes"},
            ],
        },
    ]
    inferred: list[dict] = []
    seen: set[str] = set()
    for pattern in patterns:
        require_any = pattern.get("require_any") if isinstance(pattern.get("require_any"), (list, tuple)) else []
        if require_any and not any(isinstance(token, str) and token in lower for token in require_any):
            continue
        if not any(token in lower for token in pattern["tokens"]):
            continue
        entity_slug = pattern.get("entity_slug")
        if not isinstance(entity_slug, str) or not entity_slug or entity_slug == primary_entity_slug or entity_slug in seen:
            continue
        inferred.append(
            {
                "entity_slug": entity_slug,
                "entity_label": pattern.get("entity_label"),
                "nav_label": pattern.get("related_title"),
                "related_title": pattern.get("related_title"),
                "related_tab_label": pattern.get("related_tab_label"),
                "fields": copy.deepcopy(pattern.get("fields") or []),
            }
        )
        seen.add(entity_slug)
    return inferred[:3]


def _ai_design_lookup_display_field(entity_def: dict | None) -> str | None:
    if not isinstance(entity_def, dict):
        return None
    fields = entity_def.get("fields") if isinstance(entity_def.get("fields"), list) else []
    preferred_suffixes = ("name", "title", "label", "sku", "code", "number")
    for suffix in preferred_suffixes:
        for field in fields:
            if not isinstance(field, dict):
                continue
            field_id = field.get("id") if isinstance(field.get("id"), str) and field.get("id").strip() else None
            field_type = field.get("type") if isinstance(field.get("type"), str) and field.get("type").strip() else ""
            if not isinstance(field_id, str) or field_type not in {"string", "text", "rich_text", "enum"}:
                continue
            if field_id.split(".")[-1] == suffix:
                return field_id
    for field in fields:
        if not isinstance(field, dict):
            continue
        field_id = field.get("id") if isinstance(field.get("id"), str) and field.get("id").strip() else None
        field_type = field.get("type") if isinstance(field.get("type"), str) and field.get("type").strip() else ""
        if isinstance(field_id, str) and field_type in {"string", "text", "rich_text", "enum"}:
            return field_id
    return None


def _ai_find_workspace_lookup_target(
    module_index: dict[str, dict] | None,
    *,
    module_terms: tuple[str, ...],
    entity_terms: tuple[str, ...],
) -> dict | None:
    if not isinstance(module_index, dict) or not module_index:
        return None
    best_match: dict | None = None
    best_score = 0
    for module_id, info in module_index.items():
        if not isinstance(module_id, str) or not isinstance(info, dict):
            continue
        manifest = info.get("manifest") if isinstance(info.get("manifest"), dict) else {}
        module_def = manifest.get("module") if isinstance(manifest.get("module"), dict) else {}
        module_name = module_def.get("name") if isinstance(module_def.get("name"), str) and module_def.get("name").strip() else module_id
        module_text = f"{module_id} {module_name}".lower()
        module_score = 0
        for idx, term in enumerate(module_terms):
            if term in module_text:
                module_score += max(2, 5 - idx)
        for entity in manifest.get("entities") if isinstance(manifest.get("entities"), list) else []:
            if not isinstance(entity, dict):
                continue
            entity_id = entity.get("id") if isinstance(entity.get("id"), str) and entity.get("id").strip() else None
            entity_label = entity.get("label") if isinstance(entity.get("label"), str) and entity.get("label").strip() else None
            if not isinstance(entity_id, str):
                continue
            entity_text = f"{entity_id} {entity_label or ''}".lower()
            score = module_score
            for idx, term in enumerate(entity_terms):
                if term in entity_text:
                    score += max(2, 4 - idx)
            field_ids = [
                field.get("id")
                for field in (entity.get("fields") or [])
                if isinstance(field, dict) and isinstance(field.get("id"), str)
            ]
            field_suffixes = {field_id.split(".")[-1] for field_id in field_ids}
            if "sku" in field_suffixes:
                score += 2
            if field_suffixes.intersection({"name", "title", "label"}):
                score += 1
            display_field = _ai_design_lookup_display_field(entity)
            if score > best_score and isinstance(display_field, str) and display_field:
                best_score = score
                best_match = {
                    "entity_id": entity_id,
                    "entity_label": entity_label or _ai_titleize_slug(entity_id.split(".")[-1]),
                    "display_field": display_field,
                }
    return copy.deepcopy(best_match) if isinstance(best_match, dict) and best_score > 0 else None


