@app.post("/studio2/agent/chat/stream")
async def studio2_agent_chat_stream(request: Request) -> StreamingResponse:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_superadmin(actor, "Studio AI is currently limited to superadmins")
    if denied:
        return denied
    body = await _safe_json(request)
    if not isinstance(body, dict):
        body = {}
    module_id = body.get("module_id")
    message = body.get("message")
    if not isinstance(module_id, str) or not isinstance(message, str):
        return _error_response("AGENT_INVALID", "module_id and message required", "module_id")

    request_id = request.headers.get("x-request-id") if hasattr(request, "headers") else None
    request_id_value = request_id or str(uuid.uuid4())
    queue: asyncio.Queue[str] = asyncio.Queue()
    done_event = asyncio.Event()

    def _sink(frame: str) -> None:
        queue.put_nowait(frame)

    progress = AgentProgress(
        request_id=request_id_value,
        module_id=module_id,
        stream_debug=STUDIO2_AGENT_STREAM_DEBUG,
        sink=_sink,
    )

    async def _run() -> None:
        try:
            result = await _studio2_agent_chat_run(request, body, progress=progress, include_progress=True)
            if isinstance(result, JSONResponse):
                payload = json.loads(result.body)
            else:
                payload = result
            if isinstance(payload, dict) and not payload.get("ok"):
                progress.emit(
                    "stopped",
                    "stop",
                    None,
                    {"stop_reason": "validation_error", "final_error_counts": {}},
                )
            progress.emit(
                "final_done",
                "done",
                None,
                {"final_payload": payload},
            )
            progress.emit(
                "done",
                "done",
                None,
                {"final_payload": payload, "progress": progress.to_progress_list()},
            )
            logger.info("studio2_agent_stream_done request_id=%s module_id=%s", request_id_value, module_id)
        except Exception as exc:
            progress.emit(
                "stopped",
                "stop",
                None,
                {"stop_reason": "exception", "error": str(exc)},
            )
            progress.emit(
                "final_done",
                "done",
                None,
                {
                    "final_payload": {
                        "ok": False,
                        "errors": [{"code": "STREAM_ERROR", "message": str(exc)}],
                        "warnings": [],
                    }
                },
            )
            progress.emit(
                "done",
                "done",
                None,
                {
                    "final_payload": {
                        "ok": False,
                        "errors": [{"code": "STREAM_ERROR", "message": str(exc)}],
                        "warnings": [],
                    }
                },
            )
        finally:
            done_event.set()

    async def event_generator():
        task = asyncio.create_task(_run())
        try:
            while True:
                try:
                    frame = await asyncio.wait_for(queue.get(), timeout=15.0)
                    yield frame
                except asyncio.TimeoutError:
                    yield ": ping\n\n"
                if done_event.is_set() and queue.empty():
                    break
        finally:
            if not task.done():
                task.cancel()
            with suppress(asyncio.CancelledError):
                await task

    headers = {"Cache-Control": "no-cache", "Connection": "keep-alive", "X-Accel-Buffering": "no"}
    return StreamingResponse(event_generator(), media_type="text/event-stream", headers=headers)


def _artifact_ai_progress_payload(result: dict | JSONResponse) -> dict:
    if isinstance(result, JSONResponse):
        try:
            return json.loads(result.body)
        except Exception:
            return {
                "ok": False,
                "errors": [{"code": "STREAM_ERROR", "message": "Invalid stream response"}],
                "warnings": [],
            }
    if isinstance(result, dict):
        return result
    return {
        "ok": False,
        "errors": [{"code": "STREAM_ERROR", "message": "Invalid stream response"}],
        "warnings": [],
    }


def _artifact_ai_progress_validation_counts(validation: dict | None) -> dict:
    source = validation if isinstance(validation, dict) else {}
    errors = source.get("errors") if isinstance(source.get("errors"), list) else []
    warnings = source.get("warnings") if isinstance(source.get("warnings"), list) else []
    undefined = source.get("undefined") if isinstance(source.get("undefined"), list) else []
    total_errors = len(errors)
    return {
        "total": total_errors,
        "warnings": len(warnings),
        "undefined": len(undefined),
        "compiled_ok": bool(source.get("compiled_ok")) and total_errors == 0,
    }


async def _artifact_ai_plan_stream_response(
    request: Request,
    artifact_id: str,
    body: dict,
    *,
    artifact_kind: str,
    run_fn,
) -> StreamingResponse:
    request_id = request.headers.get("x-request-id") if hasattr(request, "headers") else None
    request_id_value = request_id or str(uuid.uuid4())
    queue: asyncio.Queue[str] = asyncio.Queue()
    done_event = asyncio.Event()

    def _sink(frame: str) -> None:
        queue.put_nowait(frame)

    progress = AgentProgress(
        request_id=request_id_value,
        module_id=artifact_id,
        stream_debug=STUDIO2_AGENT_STREAM_DEBUG,
        sink=_sink,
    )

    async def _run() -> None:
        try:
            progress.emit(
                "run_started",
                "start",
                None,
                {"artifact_kind": artifact_kind, "artifact_id": artifact_id},
            )
            result = await run_fn(progress)
            payload = _artifact_ai_progress_payload(result)
            if isinstance(payload, dict) and not payload.get("ok"):
                progress.emit(
                    "stopped",
                    "stop",
                    None,
                    {
                        "stop_reason": "error",
                        "artifact_kind": artifact_kind,
                        "artifact_id": artifact_id,
                    },
                )
            progress.emit(
                "final_done",
                "done",
                None,
                {"final_payload": payload},
            )
            progress.emit(
                "done",
                "done",
                None,
                {"final_payload": payload, "progress": progress.to_progress_list()},
            )
        except Exception as exc:
            progress.emit(
                "stopped",
                "stop",
                None,
                {
                    "stop_reason": "exception",
                    "artifact_kind": artifact_kind,
                    "artifact_id": artifact_id,
                    "error": str(exc),
                },
            )
            error_payload = {
                "ok": False,
                "errors": [{"code": "STREAM_ERROR", "message": str(exc)}],
                "warnings": [],
            }
            progress.emit(
                "final_done",
                "done",
                None,
                {"final_payload": error_payload},
            )
            progress.emit(
                "done",
                "done",
                None,
                {"final_payload": error_payload, "progress": progress.to_progress_list()},
            )
        finally:
            done_event.set()

    async def event_generator():
        task = asyncio.create_task(_run())
        try:
            while True:
                try:
                    frame = await asyncio.wait_for(queue.get(), timeout=15.0)
                    yield frame
                except asyncio.TimeoutError:
                    yield ": ping\n\n"
                if done_event.is_set() and queue.empty():
                    break
        finally:
            if not task.done():
                task.cancel()
            with suppress(asyncio.CancelledError):
                await task

    headers = {"Cache-Control": "no-cache", "Connection": "keep-alive", "X-Accel-Buffering": "no"}
    return StreamingResponse(event_generator(), media_type="text/event-stream", headers=headers)


@app.get("/studio/modules/{module_id}")
async def studio_get_draft(module_id: str) -> dict:
    draft = drafts.get_draft(module_id)
    installed = registry.get(module_id)
    installed_manifest = None
    if installed and installed.get("current_hash"):
        try:
            installed_manifest = store.get_snapshot(module_id, installed.get("current_hash"))
        except Exception:
            installed_manifest = None
    draft_hash = None
    if draft and isinstance(draft.get("manifest"), dict):
        draft_hash = _draft_hash(draft.get("manifest"), module_id=module_id)
    installed_hash = installed.get("current_hash") if installed else None
    payload = {"draft": draft, "installed": installed, "installed_manifest": installed_manifest, "draft_hash": draft_hash, "installed_hash": installed_hash}
    if draft is None and installed is None:
        return _error_response("MODULE_NOT_FOUND", "Module not found", "module_id", status=404)
    return _ok_response({"data": payload})


