def _studio2_message_likely_requires_entity_target(message: str) -> bool:
    if not isinstance(message, str) or not message.strip():
        return False
    return bool(
        re.search(
            r"\b(field|attribute|tab|section|form|list|view|page|button|workflow|status|action|rename|remove|delete|move|required|visible|hide|show|display)\b",
            message,
            flags=re.IGNORECASE,
        )
    )


def _studio2_message_likely_targets_existing_field(message: str) -> bool:
    if not isinstance(message, str) or not message.strip():
        return False
    if re.search(r"\b(?:add|create|make)\s+(?:a\s+|an\s+|the\s+)?(?:new\s+)?(?:field|attribute)\b", message, flags=re.IGNORECASE):
        return False
    return bool(
        re.search(
            r"\b(rename|remove|delete|move|reposition|convert|change\s+type|make|required|optional|hide|show|display|persist|save)\b",
            message,
            flags=re.IGNORECASE,
        )
    )


def _studio2_message_likely_requires_tab_target(message: str) -> bool:
    if not isinstance(message, str) or not message.strip():
        return False
    return bool(
        re.search(
            r"\b(tab|section)\b.*\b(add|create|move|place|put|show|display|organize|group)\b|\b(add|create|move|place|put|show|display|organize|group)\b.*\b(tab|section)\b",
            message,
            flags=re.IGNORECASE,
        )
    )


def _studio2_message_likely_requires_section_target(message: str) -> bool:
    if not isinstance(message, str) or not message.strip():
        return False
    return bool(
        re.search(
            r"\b(section)\b.*\b(add|create|move|place|put|show|display|organize|group)\b|\b(add|create|move|place|put|show|display|organize|group)\b.*\b(section)\b",
            message,
            flags=re.IGNORECASE,
        )
    )


def _studio2_message_likely_requires_view_target(message: str) -> bool:
    if not isinstance(message, str) or not message.strip():
        return False
    return bool(
        re.search(
            r"\b(view|kanban|calendar|graph|pivot|list)\b.*\b(change|update|edit|redesign|rework|fix|adjust|show|display|configure)\b|\b(change|update|edit|redesign|rework|fix|adjust|show|display|configure)\b.*\b(view|kanban|calendar|graph|pivot|list)\b",
            message,
            flags=re.IGNORECASE,
        )
    )


def _studio2_message_likely_requires_page_target(message: str) -> bool:
    if not isinstance(message, str) or not message.strip():
        return False
    return bool(
        re.search(
            r"\b(page)\b.*\b(change|update|edit|redesign|rework|fix|adjust|show|display|configure|add)\b|\b(change|update|edit|redesign|rework|fix|adjust|show|display|configure|add)\b.*\b(page)\b",
            message,
            flags=re.IGNORECASE,
        )
    )


def _studio2_apply_scoped_hints_and_slots(
    message: str,
    manifest: dict | None,
    build_spec: dict | None,
    answer_hints: dict | None = None,
) -> tuple[dict | None, dict, list[str], list[str], list[str], dict | None]:
    next_build_spec = copy.deepcopy(build_spec) if isinstance(build_spec, dict) else {}
    next_hints = copy.deepcopy(answer_hints) if isinstance(answer_hints, dict) else {}
    assumptions: list[str] = []
    advisories: list[str] = []
    questions: list[str] = []
    question_meta: dict | None = None
    manifest = manifest if isinstance(manifest, dict) else {}
    entities = [entity for entity in (manifest.get("entities") or []) if isinstance(entity, dict)]
    entity_ids = [entity.get("id") for entity in entities if isinstance(entity.get("id"), str) and entity.get("id")]
    selected_entity_id = next_hints.get("selected_entity_id") if isinstance(next_hints.get("selected_entity_id"), str) and next_hints.get("selected_entity_id").strip() else None
    if isinstance(selected_entity_id, str):
        selected_entity_id = selected_entity_id.strip()
        if selected_entity_id not in entity_ids:
            selected_entity_id = None
    build_spec_entities = next_build_spec.get("entities") if isinstance(next_build_spec.get("entities"), list) else []
    build_spec_entity_ids = [
        item.get("id")
        for item in build_spec_entities
        if isinstance(item, dict) and isinstance(item.get("id"), str) and item.get("id")
    ]
    explicit_entities = _studio2_match_explicit_entities(message, manifest)

    resolved_entity_id = selected_entity_id
    if not resolved_entity_id and len(build_spec_entity_ids) == 1:
        resolved_entity_id = build_spec_entity_ids[0]
    if not resolved_entity_id and len(explicit_entities) == 1:
        resolved_entity_id = explicit_entities[0]
    if not resolved_entity_id and len(entity_ids) == 1:
        resolved_entity_id = entity_ids[0]
        entity_label = _ai_humanize_identifier((resolved_entity_id or "").split(".")[-1]) or resolved_entity_id
        assumptions.append(f"Targeting the only entity in this module: {entity_label}.")

    if resolved_entity_id and not build_spec_entity_ids:
        next_build_spec["entities"] = [{"id": resolved_entity_id}]
    if resolved_entity_id:
        next_hints["selected_entity_id"] = resolved_entity_id

    if (
        not resolved_entity_id
        and len(entity_ids) > 1
        and _studio2_message_likely_requires_entity_target(message)
    ):
        prompt = "Which entity should this change target?"
        questions = [prompt]
        question_meta = {
            "kind": "decision_slot",
            "slot_kind": "studio_entity_choice",
            "slot_id": "studio_entity_choice",
            "prompt": prompt,
            "label": prompt,
            "why_needed": "This module has more than one entity, so the target entity needs to be explicit before Studio AI can build the update safely.",
            "hint_field": "selected_entity_id",
            "allow_free_text": True,
            "decision_slots": [
                {
                    "slot_id": "studio_entity_choice",
                    "slot_kind": "studio_entity_choice",
                    "prompt": prompt,
                    "label": prompt,
                    "why_needed": "This module has more than one entity, so the target entity needs to be explicit before Studio AI can build the update safely.",
                    "hint_field": "selected_entity_id",
                    "allow_free_text": True,
                    "options": _studio2_entity_choice_options(manifest),
                }
            ],
        }
        return next_build_spec, next_hints, assumptions, advisories, questions, question_meta

    resolved_tab_target = next_hints.get("tab_target") if isinstance(next_hints.get("tab_target"), str) and next_hints.get("tab_target").strip() else None
    explicit_tabs = _studio2_match_explicit_tabs(message, manifest, selected_entity_id=resolved_entity_id)
    tab_options = _studio2_tab_choice_options(manifest, selected_entity_id=resolved_entity_id)
    if not resolved_tab_target and len(explicit_tabs) == 1:
        resolved_tab_target = explicit_tabs[0]
        next_hints["tab_target"] = resolved_tab_target
    elif (
        not resolved_tab_target
        and len(tab_options) == 1
        and _studio2_message_likely_requires_tab_target(message)
    ):
        resolved_tab_target = tab_options[0].get("value") if isinstance(tab_options[0].get("value"), str) else None
        if isinstance(resolved_tab_target, str) and resolved_tab_target:
            next_hints["tab_target"] = resolved_tab_target
            tab_label = tab_options[0].get("label") if isinstance(tab_options[0].get("label"), str) else resolved_tab_target
            assumptions.append(f"Targeting the only available tab: {tab_label}.")
    elif (
        not resolved_tab_target
        and len(tab_options) > 1
        and _studio2_message_likely_requires_tab_target(message)
    ):
        prompt = "Which tab should this change target?"
        questions = [prompt]
        question_meta = {
            "kind": "decision_slot",
            "slot_kind": "studio_tab_choice",
            "slot_id": "studio_tab_choice",
            "prompt": prompt,
            "label": prompt,
            "why_needed": "This form has more than one tab, so Studio AI needs the exact placement target before it can build the change safely.",
            "hint_field": "tab_target",
            "allow_free_text": True,
            "decision_slots": [
                {
                    "slot_id": "studio_tab_choice",
                    "slot_kind": "studio_tab_choice",
                    "prompt": prompt,
                    "label": prompt,
                    "why_needed": "This form has more than one tab, so Studio AI needs the exact placement target before it can build the change safely.",
                    "hint_field": "tab_target",
                    "allow_free_text": True,
                    "options": tab_options,
                }
            ],
        }
        return next_build_spec, next_hints, assumptions, advisories, questions, question_meta

    resolved_section_target = next_hints.get("planned_section_id") if isinstance(next_hints.get("planned_section_id"), str) and next_hints.get("planned_section_id").strip() else None
    explicit_sections = _studio2_match_explicit_sections(
        message,
        manifest,
        selected_entity_id=resolved_entity_id,
        tab_target=resolved_tab_target,
    )
    section_options = _studio2_section_choice_options(
        manifest,
        selected_entity_id=resolved_entity_id,
        tab_target=resolved_tab_target,
    )
    if not resolved_section_target and len(explicit_sections) == 1:
        resolved_section_target = explicit_sections[0]
        next_hints["planned_section_id"] = resolved_section_target
    elif (
        not resolved_section_target
        and len(section_options) == 1
        and _studio2_message_likely_requires_section_target(message)
    ):
        resolved_section_target = section_options[0].get("value") if isinstance(section_options[0].get("value"), str) else None
        if isinstance(resolved_section_target, str) and resolved_section_target:
            next_hints["planned_section_id"] = resolved_section_target
            section_label = section_options[0].get("label") if isinstance(section_options[0].get("label"), str) else resolved_section_target
            assumptions.append(f"Targeting the only matching section: {section_label}.")
    elif (
        not resolved_section_target
        and len(section_options) > 1
        and _studio2_message_likely_requires_section_target(message)
    ):
        prompt = "Which section should this change target?"
        questions = [prompt]
        question_meta = {
            "kind": "decision_slot",
            "slot_kind": "studio_section_choice",
            "slot_id": "studio_section_choice",
            "prompt": prompt,
            "label": prompt,
            "why_needed": "This form layout has more than one matching section, so Studio AI needs the exact section before it can place the change safely.",
            "hint_field": "planned_section_id",
            "allow_free_text": True,
            "decision_slots": [
                {
                    "slot_id": "studio_section_choice",
                    "slot_kind": "studio_section_choice",
                    "prompt": prompt,
                    "label": prompt,
                    "why_needed": "This form layout has more than one matching section, so Studio AI needs the exact section before it can place the change safely.",
                    "hint_field": "planned_section_id",
                    "allow_free_text": True,
                    "options": section_options,
                }
            ],
        }
        return next_build_spec, next_hints, assumptions, advisories, questions, question_meta

    resolved_page_target = next_hints.get("planned_page_id") if isinstance(next_hints.get("planned_page_id"), str) and next_hints.get("planned_page_id").strip() else None
    if not resolved_page_target:
        page_target_hint = next_hints.get("page_target") if isinstance(next_hints.get("page_target"), str) and next_hints.get("page_target").strip() else None
        if isinstance(page_target_hint, str):
            resolved_page_target = page_target_hint.strip()
    explicit_pages = _studio2_match_explicit_pages(message, manifest, selected_entity_id=resolved_entity_id)
    page_options = _studio2_page_choice_options(manifest, selected_entity_id=resolved_entity_id)
    if not resolved_page_target and len(explicit_pages) == 1:
        resolved_page_target = explicit_pages[0]
        next_hints["planned_page_id"] = resolved_page_target
        next_hints["page_target"] = resolved_page_target
        if not isinstance(next_hints.get("planned_view_id"), str) or not next_hints.get("planned_view_id"):
            page_match = next((item for item in page_options if item.get("value") == resolved_page_target), None)
            if isinstance(page_match, dict):
                page_hints = page_match.get("hints") if isinstance(page_match.get("hints"), dict) else {}
                if isinstance(page_hints.get("planned_view_id"), str) and page_hints.get("planned_view_id").strip():
                    next_hints["planned_view_id"] = page_hints.get("planned_view_id").strip()
    elif (
        not resolved_page_target
        and len(page_options) == 1
        and _studio2_message_likely_requires_page_target(message)
    ):
        resolved_page_target = page_options[0].get("value") if isinstance(page_options[0].get("value"), str) else None
        if isinstance(resolved_page_target, str) and resolved_page_target:
            page_hints = page_options[0].get("hints") if isinstance(page_options[0].get("hints"), dict) else {}
            next_hints.update({key: value for key, value in page_hints.items() if isinstance(value, str) and value.strip()})
            page_label = page_options[0].get("label") if isinstance(page_options[0].get("label"), str) else resolved_page_target
            assumptions.append(f"Targeting the only matching page: {page_label}.")
    elif (
        not resolved_page_target
        and len(page_options) > 1
        and _studio2_message_likely_requires_page_target(message)
    ):
        prompt = "Which page should this change target?"
        questions = [prompt]
        question_meta = {
            "kind": "decision_slot",
            "slot_kind": "studio_page_choice",
            "slot_id": "studio_page_choice",
            "prompt": prompt,
            "label": prompt,
            "why_needed": "This module has more than one matching page, so Studio AI needs the exact page before it can build the change safely.",
            "hint_field": "planned_page_id",
            "allow_free_text": True,
            "decision_slots": [
                {
                    "slot_id": "studio_page_choice",
                    "slot_kind": "studio_page_choice",
                    "prompt": prompt,
                    "label": prompt,
                    "why_needed": "This module has more than one matching page, so Studio AI needs the exact page before it can build the change safely.",
                    "hint_field": "planned_page_id",
                    "allow_free_text": True,
                    "options": page_options,
                }
            ],
        }
        return next_build_spec, next_hints, assumptions, advisories, questions, question_meta

    resolved_view_target = next_hints.get("planned_view_id") if isinstance(next_hints.get("planned_view_id"), str) and next_hints.get("planned_view_id").strip() else None
    explicit_views = _studio2_match_explicit_views(message, manifest, selected_entity_id=resolved_entity_id)
    view_options = _studio2_view_choice_options(manifest, selected_entity_id=resolved_entity_id)
    if not resolved_view_target and len(explicit_views) == 1:
        resolved_view_target = explicit_views[0]
        next_hints["planned_view_id"] = resolved_view_target
    elif (
        not resolved_view_target
        and len(view_options) == 1
        and _studio2_message_likely_requires_view_target(message)
    ):
        resolved_view_target = view_options[0].get("value") if isinstance(view_options[0].get("value"), str) else None
        if isinstance(resolved_view_target, str) and resolved_view_target:
            view_hints = view_options[0].get("hints") if isinstance(view_options[0].get("hints"), dict) else {}
            next_hints.update({key: value for key, value in view_hints.items() if isinstance(value, str) and value.strip()})
            view_label = view_options[0].get("label") if isinstance(view_options[0].get("label"), str) else resolved_view_target
            assumptions.append(f"Targeting the only matching view: {view_label}.")
    elif (
        not resolved_view_target
        and len(view_options) > 1
        and _studio2_message_likely_requires_view_target(message)
        and not _studio2_message_likely_requires_page_target(message)
    ):
        prompt = "Which view should this change target?"
        questions = [prompt]
        question_meta = {
            "kind": "decision_slot",
            "slot_kind": "studio_view_choice",
            "slot_id": "studio_view_choice",
            "prompt": prompt,
            "label": prompt,
            "why_needed": "This module has more than one matching view, so Studio AI needs the exact view before it can build the change safely.",
            "hint_field": "planned_view_id",
            "allow_free_text": True,
            "decision_slots": [
                {
                    "slot_id": "studio_view_choice",
                    "slot_kind": "studio_view_choice",
                    "prompt": prompt,
                    "label": prompt,
                    "why_needed": "This module has more than one matching view, so Studio AI needs the exact view before it can build the change safely.",
                    "hint_field": "planned_view_id",
                    "allow_free_text": True,
                    "options": view_options,
                }
            ],
        }
        return next_build_spec, next_hints, assumptions, advisories, questions, question_meta

    resolved_field_target = None
    raw_field_target = next_hints.get("field_target") if isinstance(next_hints.get("field_target"), str) and next_hints.get("field_target").strip() else None
    raw_field_id = next_hints.get("field_id") if isinstance(next_hints.get("field_id"), str) and next_hints.get("field_id").strip() else None
    if isinstance(raw_field_target, str):
        resolved_field_target = raw_field_target.strip()
    elif isinstance(raw_field_id, str):
        resolved_field_target = raw_field_id.strip()

    field_ref = None
    if not resolved_field_target and _studio2_message_likely_targets_existing_field(message):
        field_ref = _ai_extract_field_label(message, answer_hints=next_hints)
        if not (isinstance(field_ref, str) and field_ref.strip()):
            fallback_patterns = [
                r"\brename\s+(?:the\s+)?([a-zA-Z0-9 _.-]{1,80}?)\s+field\b",
                r"\b(?:remove|delete)\s+(?:the\s+)?([a-zA-Z0-9 _.-]{1,80}?)\s+field\b",
                r"\bmove\s+(?:the\s+)?([a-zA-Z0-9 _.-]{1,80}?)\s+field\b",
                r"\bchange\s+the\s+type\s+of\s+(?:the\s+)?([a-zA-Z0-9 _.-]{1,80}?)\s+field\b",
                r"\bmake\s+(?:the\s+)?([a-zA-Z0-9 _.-]{1,80}?)\s+field\s+(?:required|optional)\b",
                r"\b(?:hide|show)\s+(?:the\s+)?([a-zA-Z0-9 _.-]{1,80}?)\s+field\b",
            ]
            for pattern in fallback_patterns:
                match = re.search(pattern, message, flags=re.IGNORECASE)
                if match and isinstance(match.group(1), str) and match.group(1).strip():
                    field_ref = match.group(1).strip()
                    break
        if isinstance(field_ref, str) and field_ref.strip():
            candidates = _studio2_field_choice_candidates(manifest, field_ref)
            if len(candidates) == 1:
                resolved_hints = candidates[0].get("hints") if isinstance(candidates[0].get("hints"), dict) else {}
                next_hints.update(resolved_hints)
                resolved_field_target = resolved_hints.get("field_target") if isinstance(resolved_hints.get("field_target"), str) else None
                field_label = resolved_hints.get("field_label") if isinstance(resolved_hints.get("field_label"), str) else field_ref
                advisories.append(f"Using the existing field '{field_label}' for this change.")
            elif len(candidates) > 1:
                prompt = "Which field should this change target?"
                questions = [prompt]
                question_meta = {
                    "kind": "decision_slot",
                    "slot_kind": "studio_field_choice",
                    "slot_id": "studio_field_choice",
                    "prompt": prompt,
                    "label": prompt,
                    "why_needed": "More than one field matches the current request, so Studio AI needs the exact field before it can build the update safely.",
                    "hint_field": "field_target",
                    "allow_free_text": True,
                    "decision_slots": [
                        {
                            "slot_id": "studio_field_choice",
                            "slot_kind": "studio_field_choice",
                            "prompt": prompt,
                            "label": prompt,
                            "why_needed": "More than one field matches the current request, so Studio AI needs the exact field before it can build the update safely.",
                            "hint_field": "field_target",
                            "allow_free_text": True,
                            "options": candidates,
                        }
                    ],
                }
                return next_build_spec, next_hints, assumptions, advisories, questions, question_meta

    if resolved_field_target and not isinstance(next_hints.get("field_target"), str):
        next_hints["field_target"] = resolved_field_target
    if resolved_field_target and not isinstance(next_hints.get("field_id"), str):
        next_hints["field_id"] = resolved_field_target

    return next_build_spec, next_hints, assumptions, advisories, questions, question_meta


def _studio2_validate_call_references(manifest: dict | None, call: dict) -> list[dict]:
    if not isinstance(call, dict):
        return []
    contract = _studio2_manifest_reference_contract(manifest)
    entity_ids = set(contract.get("entity_ids") or [])
    field_ids_by_entity = contract.get("field_ids_by_entity") if isinstance(contract.get("field_ids_by_entity"), dict) else {}
    errors: list[dict] = []
    tool = _studio2_normalize_tool_name(call.get("tool"))
    entity_id = call.get("entity_id") or call.get("args", {}).get("entity_id")

    def add_error(path: str, message: str, detail: dict | None = None) -> None:
        errors.append({"code": "CALL_INVALID", "message": message, "path": path, "detail": detail or {}})

    if tool in {"ensure_entity_pages", "ensure_actions_for_status"}:
        if not isinstance(entity_id, str) or not entity_id:
            add_error("calls.entity_id", f"{tool} requires entity_id")
        elif entity_id not in entity_ids:
            add_error("calls.entity_id", f"{tool} requires an existing entity_id", {"entity_id": entity_id})
    elif tool == "ensure_workflow":
        workflow = call.get("workflow") or call.get("args", {}).get("workflow")
        if isinstance(workflow, dict):
            workflow_entity = workflow.get("entity")
            status_field = workflow.get("status_field")
            if isinstance(workflow_entity, str) and workflow_entity:
                if workflow_entity not in entity_ids:
                    add_error("calls.workflow.entity", "workflow.entity must reference an existing entity", {"entity_id": workflow_entity})
                elif isinstance(status_field, str) and status_field:
                    valid_fields = {
                        item
                        for item in (field_ids_by_entity.get(workflow_entity) or [])
                        if isinstance(item, str) and item
                    }
                    if valid_fields and status_field not in valid_fields:
                        add_error(
                            "calls.workflow.status_field",
                            "workflow.status_field must reference an existing field on the workflow entity",
                            {"entity_id": workflow_entity, "status_field": status_field},
                        )
    elif tool == "ensure_ui_pattern":
        pattern = call.get("pattern") or call.get("args", {}).get("pattern")
        page_ids = set(contract.get("page_ids") or [])
        if isinstance(pattern, dict):
            pattern_kind = pattern.get("kind") if isinstance(pattern.get("kind"), str) else pattern.get("pattern")
            if isinstance(pattern_kind, str) and pattern_kind.strip().lower() in {"dashboard_page", "dashboard_stat_cards"}:
                pattern_page_id = pattern.get("page_id")
                pattern_entity_id = pattern.get("entity_id")
                if not isinstance(pattern_page_id, str) or not pattern_page_id:
                    add_error("calls.pattern.page_id", "dashboard_page pattern requires page_id")
                elif pattern_page_id not in page_ids:
                    add_error("calls.pattern.page_id", "dashboard_page pattern must reference an existing page", {"page_id": pattern_page_id})
                if not isinstance(pattern_entity_id, str) or not pattern_entity_id:
                    add_error("calls.pattern.entity_id", "dashboard_page pattern requires entity_id")
                elif pattern_entity_id not in entity_ids:
                    add_error("calls.pattern.entity_id", "dashboard_page pattern must reference an existing entity", {"entity_id": pattern_entity_id})
    return errors


async def _studio2_agent_chat_run(
    request: Request,
    body: dict,
    progress: AgentProgress | None = None,
    include_progress: bool = False,
) -> dict:
    if not _openai_configured():
        return _openai_not_configured()
    reset_db_ms()
    request_id = request.headers.get("x-request-id") if hasattr(request, "headers") else None
    module_id = body.get("module_id") if isinstance(body, dict) else None
    message = body.get("message") if isinstance(body, dict) else None
    draft_text = body.get("draft_text") if isinstance(body.get("draft_text"), str) else None
    chat_history = body.get("chat_history") if isinstance(body, dict) else None
    answer_hints = body.get("hints") if isinstance(body.get("hints"), dict) else {}
    user_hint_count = _artifact_ai_progress_user_hint_count(answer_hints)
    requested_focus = _studio2_agent_focus(body.get("focus") if isinstance(body, dict) else None, message)
    if not isinstance(module_id, str) or not isinstance(message, str):
        return _error_response("AGENT_INVALID", "module_id and message required", "module_id")
    if len(message) > 4000:
        return _error_response("AGENT_MESSAGE_TOO_LONG", "message too long", "message")

    request_id_value = request_id or str(uuid.uuid4())
    if include_progress and progress is None:
        progress = AgentProgress(request_id=request_id_value, module_id=module_id, stream_debug=STUDIO2_AGENT_STREAM_DEBUG)
    if progress:
        progress.emit(
            "run_started",
            "start",
            None,
            {
                "message_len": len(message or ""),
                "has_build_spec": isinstance(body.get("build_spec"), dict),
                "planner_model": STUDIO2_PLANNER_MODEL,
                "builder_model": STUDIO2_BUILDER_MODEL,
            },
        )

    registry_summary = _studio2_build_registry_summary(request)
    registry_header = _studio2_registry_header(registry_summary)
    registry_text = json.dumps(registry_header, separators=(",", ":"))
    pattern_memory = _load_pattern_memory()
    patterns = pattern_memory.get("patterns") if isinstance(pattern_memory, dict) else {}
    pattern_key = _infer_pattern_key(message, module_id)
    pattern_hint = patterns.get(pattern_key) if isinstance(patterns, dict) and pattern_key else None

    system_pack = _load_prompt_pack("system.md")
    contract_pack = _load_prompt_pack("manifest_contract_v1_3.md")
    ui_pack = _load_prompt_pack("ui_rules.md")
    patch_protocol = _load_prompt_pack("patch_protocol.md")
    system_text = "\n\n".join([system_pack, contract_pack, ui_pack, patch_protocol]).strip()

    history = []
    if isinstance(chat_history, list):
        for item in chat_history[-6:]:
            if not isinstance(item, dict):
                continue
            role = item.get("role")
            text = item.get("text")
            if role in {"user", "assistant"} and isinstance(text, str):
                history.append({"role": role, "content": text[:800]})

    base_draft = drafts.get_draft(module_id)
    base_manifest = _studio2_get_target_manifest(request, module_id, draft_text)
    if not isinstance(base_manifest, dict) or not base_manifest:
        if base_draft and isinstance(base_draft.get("manifest"), dict):
            base_manifest = base_draft.get("manifest")
        else:
            _installed_module, installed_manifest = _get_installed_manifest(request, module_id)
            if isinstance(installed_manifest, dict):
                base_manifest = installed_manifest
            else:
                base_manifest = _studio2_seed_manifest_for_brief(
                    module_id,
                    message,
                    answer_hints=answer_hints,
                    pattern_key=pattern_key,
                )
    base_manifest = _ensure_app_home(_ensure_module_id(_sanitize_manifest(base_manifest or {}), module_id))

    actor = getattr(request.state, "user", None)
    created_by = actor.get("email") if isinstance(actor, dict) else None
    ctx = AgentContext(
        module_id=module_id,
        user_id=created_by,
        registry_snapshot=registry_header,
        base_manifest=copy.deepcopy(base_manifest),
        working_manifest=copy.deepcopy(base_manifest),
        request_id=request_id_value,
    )

    build_spec = body.get("build_spec") if isinstance(body, dict) else None
    wall_start = time.perf_counter()
    planner_ms = 0.0
    openai_total_ms = 0.0
    if not isinstance(build_spec, dict):
        planner_pack = _load_prompt_pack("planner.md")
        planner_system = "\n\n".join([planner_pack, contract_pack]).strip()
        planner_context = {
            "module_id": module_id,
            "module_summary": _studio2_prompt_manifest_summary(ctx.base_manifest),
            "reference_contract": _studio2_manifest_reference_contract(ctx.base_manifest),
            "authoring_contract": _shared_module_authoring_contract(),
            "answer_hints": answer_hints,
            "registry": registry_header if len(registry_text.encode("utf-8")) <= STUDIO2_MAX_REGISTRY_BYTES else {"modules": []},
            "pattern": {"key": pattern_key, "data": pattern_hint} if pattern_hint else None,
            "history": history,
            "requested_focus": requested_focus,
        }
        planner_text = json.dumps(planner_context, separators=(",", ":"))
        planner_messages = [
            {"role": "system", "content": planner_system},
            {"role": "user", "content": message},
            {"role": "user", "content": f"context.json\n```json\n{planner_text}\n```"},
        ]
        if progress:
            progress.emit("stage_started", "planning", None, {"stage": "planning"})
            progress.emit("planner_started", "planning", None, {"model": STUDIO2_PLANNER_MODEL})
        planner_start = time.perf_counter()
        try:
            planner_resp = _openai_chat_completion(planner_messages, model=STUDIO2_PLANNER_MODEL)
        except Exception as exc:
            return _error_response("OPENAI_ERROR", "Planner request failed", detail={"error": str(exc)}, status=502)
        planner_ms = (time.perf_counter() - planner_start) * 1000
        openai_total_ms += planner_ms
        planner_choices = planner_resp.get("choices") or []
        planner_content = planner_choices[0].get("message", {}).get("content") if planner_choices else None
        if not planner_content:
            return _error_response("OPENAI_EMPTY", "Planner returned empty response", status=502)
        build_spec, spec_diag = _extract_build_spec_from_response(planner_content)
        if not isinstance(build_spec, dict):
            return _error_response("PLANNER_PARSE_FAILED", "Planner response parse failed", detail=spec_diag)

    build_spec, scoped_answer_hints, slot_assumptions, slot_advisories, slot_questions, slot_question_meta = _studio2_apply_scoped_hints_and_slots(
        message,
        ctx.base_manifest,
        build_spec,
        answer_hints=answer_hints,
    )
    decision_slots = _ai_normalize_required_decision_slots(slot_question_meta, slot_questions)

    build_spec_hash = _hash_json(build_spec) if isinstance(build_spec, dict) else None
    if progress and isinstance(build_spec, dict):
        progress.emit(
            "planner_result",
            "planning",
            None,
            {
                "build_spec_hash": build_spec_hash,
                "build_spec_summary": summarize_build_spec(build_spec),
                "pattern_key": pattern_key,
            },
        )
        progress.emit("stage_done", "planning", None, {"stage": "planning"})
        progress.emit("planner_done", "planning", None, {"stage": "planning"})

    if slot_questions:
        stop_reason = "decision_required"
        build_spec_summary = summarize_build_spec(build_spec) if isinstance(build_spec, dict) else []
        summary_text = "I have a draft plan for this module, but I need one choice before I can build the update."
        if isinstance(build_spec_summary, list) and build_spec_summary:
            summary_text = f"{build_spec_summary[0]} I need one choice before I can build the update."
        plan_payload = {
            "summary": summary_text,
            "assumptions": [item for item in slot_assumptions if isinstance(item, str) and item.strip()],
            "advisories": [
                *[item for item in slot_advisories if isinstance(item, str) and item.strip()],
                *[
                    item
                    for item in (build_spec_summary[1:] if isinstance(build_spec_summary, list) else [])
                    if isinstance(item, str) and item.strip()
                ],
            ],
            "required_questions": [item for item in slot_questions if isinstance(item, str) and item.strip()],
            "required_question_meta": slot_question_meta if isinstance(slot_question_meta, dict) else None,
            "decision_slots": decision_slots,
        }
        if progress:
            progress.emit(
                "stopped",
                "stop",
                None,
                {
                    "stop_reason": stop_reason,
                    "best_iter": 0,
                    "final_error_counts": {"schema": 0, "strict": 0, "completeness": 0},
                },
            )
        payload = {
            "assistant_message": summary_text,
            "plan": plan_payload,
            "notes": summary_text,
            "request_prompt": message,
            "requested_focus": requested_focus,
            "calls": [],
            "ops_by_module": [],
            "drafts": {},
            "validation": {
                "errors": [],
                "warnings": [],
                "strict_errors": [],
                "completeness_errors": [],
                "design_warnings": [],
            },
            "stop_reason": stop_reason,
            "iterations": 0,
            "timing_summary": {
                "total_ms": round((time.perf_counter() - wall_start) * 1000, 2),
                "openai_total_ms": round(openai_total_ms, 2),
                "db_ms": 0.0,
                "db_q": 0,
                "per_iter": [],
            },
            "persisted_draft_id": None,
            "best_iteration_index": 0,
            "last_build_spec_hash": build_spec_hash,
        }
        if include_progress and progress:
            payload["progress"] = progress.to_progress_list()
        return _ok_response({"data": payload})

    # Agent loop runs fully in-memory; persistence happens once after convergence/stop.
    plan_payload: dict | None = None
    notes_text: str | None = None
    last_validation = {"errors": [], "warnings": [], "strict": [], "completeness": [], "design": []}
    best_iteration: dict | None = None
    stop_reason = None
    ops_count = 0
    prev_error_counts: list[int] = []
    prev_strict_fp: str | None = None
    strict_repeat = 0
    planner_repeat = 0
    prev_build_spec_hash: str | None = None
    best_index = 0
    prev_manifest_hash: str | None = None
    prev_error_fp: str | None = None

    is_new = base_draft is None and _get_module(request, module_id) is None
    narrow_field_add_request = _studio2_message_is_narrow_field_add(message)
    form_placement_requested = _studio2_message_requests_form_placement(message)
    initial_manifest_hash = _hash_json(ctx.working_manifest)
    inherited_completeness_issue_fps: set[str] = set()
    if not is_new:
        baseline_normalized, baseline_errors, _baseline_warnings = validate_manifest_raw(
            copy.deepcopy(ctx.working_manifest),
            expected_module_id=module_id,
        )
        if not baseline_errors:
            inherited_completeness_issue_fps = {
                _validation_issue_fingerprint(issue)
                for issue in _studio2_completeness_check(baseline_normalized)
            }

    for attempt in range(MAX_AGENT_ITERS):
        iter_start = time.perf_counter()
        manifest_before = copy.deepcopy(ctx.working_manifest)
        manifest_before_hash = _hash_json(ctx.working_manifest)

        summary_cache = ctx.cache.setdefault("summary_by_hash", {})
        summary = summary_cache.get(manifest_before_hash)
        if summary is None:
            summary = _studio2_prompt_manifest_summary(ctx.working_manifest)
            summary_cache[manifest_before_hash] = summary

        errors_fp = _fingerprint_errors(last_validation["errors"]) if last_validation["errors"] else ""
        snippet_cache = ctx.cache.setdefault("snippets", {})
        snippet_key = f"{manifest_before_hash}:{errors_fp}"
        snippets = snippet_cache.get(snippet_key)
        if snippets is None:
            snippets = _extract_error_snippets(ctx.working_manifest, last_validation["errors"])
            snippet_cache[snippet_key] = snippets

        context = {
            "module_id": module_id,
            "module_summaries": {module_id: summary},
            "reference_contract": _studio2_manifest_reference_contract(ctx.working_manifest),
            "authoring_contract": _shared_module_authoring_contract(),
            "build_spec": build_spec,
            "answer_hints": scoped_answer_hints,
            "errors": {module_id: last_validation["errors"]},
            "warnings": {module_id: last_validation["warnings"]},
            "design_warnings": {module_id: last_validation["design"]},
            "snippets": {module_id: snippets},
            "registry": registry_header if len(registry_text.encode("utf-8")) <= STUDIO2_MAX_REGISTRY_BYTES else {"modules": []},
            "history": history,
            "pattern": {"key": pattern_key, "data": pattern_hint} if pattern_hint else None,
            "requested_focus": requested_focus,
        }
        linked = ctx.cache.get("linked_manifests")
        if isinstance(linked, dict) and linked:
            context["linked_manifests"] = linked
        context_text = json.dumps(context, separators=(",", ":"))
        if len(context_text.encode("utf-8")) > STUDIO2_MAX_CONTEXT_BYTES:
            context["registry"] = {"modules": []}
            context["snippets"] = {}
            context_text = json.dumps(context, separators=(",", ":"))
        if len(context_text.encode("utf-8")) > STUDIO2_MAX_CONTEXT_BYTES:
            context.pop("linked_manifests", None)
            context_text = json.dumps(context, separators=(",", ":"))

        constraints = (
            "Return strict JSON only. Include plan + calls (tool calls only). No prose. "
            "Do NOT include ops or ops_by_module. "
            "Allowed tools: ensure_entity, ensure_entity_pages, ensure_nav, ensure_actions_for_status, "
            "ensure_relation, ensure_workflow, ensure_ui_pattern, read_manifest. "
            "calls schema: [{\"tool\":\"<allowed>\",\"module_id\":\"<target>\",\"args\":{...}}]. "
            "Do NOT invent tool names. If unsure, choose ensure_entity + ensure_entity_pages + ensure_nav. "
            "Use context.reference_contract as the source of truth for existing entity ids, field ids, view ids, page ids, action ids, and workflow ids in this module. "
            "Use context.authoring_contract as the source of truth for the current module UX scaffold. "
            "Use context.answer_hints as resolved user choices when they are present; do not override them or ask for them again. "
            "Use context.authoring_contract.domain_heuristics to model real business structure, especially when deciding between single-entity vs header/line records, approval workflows, or operational lifecycle fields. "
            "For a narrow request like adding one field to an existing form, preserve the current module structure and avoid ensure_entity_pages or ensure_nav unless pages or navigation are genuinely missing. "
            "When list-header search is useful, wire it with real searchable field ids and a sensible placeholder. "
            "Default create CTAs should use the generic label 'New', not 'New <Entity>'. "
            "Prefer the standard list page card + view_modes pattern and the standard 8/4 form page with a separate chatter card. "
            "For existing dashboard page requests, you may use ensure_ui_pattern with pattern "
            "{\"kind\":\"dashboard_page\",\"page_id\":\"<existing page>\",\"entity_id\":\"<existing entity>\",\"request_summary\":\"<original request>\"} "
            "so the shared backend can generate manifest-backed stat cards. "
            "If you need a new entity or field, create it with ensure_entity before using tools that require it to already exist. "
            "If validation includes MANIFEST_* schema errors, you MUST emit at least one tool call. "
            "Workflow schema (required): workflows[] items MUST include id, entity, status_field, states; "
            "states MUST be array of objects: [{\"id\":\"draft\",\"label\":\"Draft\"}, ...]. "
            "Do NOT output states as strings."
        )
        focus_instruction = _studio2_agent_focus_instruction(requested_focus)
        if focus_instruction:
            constraints = f"{constraints} {focus_instruction}"
        task_template = _load_prompt_pack("task.md")
        task_text = task_template.replace("{{message}}", message).replace("{{constraints}}", constraints)

        messages = [
            {"role": "system", "content": system_text},
            *history,
            {"role": "user", "content": f"context.json\n```json\n{context_text}\n```"},
            {"role": "user", "content": f"task.md\n```\n{task_text}\n```"},
        ]

        target_bytes = len(json.dumps(summary, separators=(",", ":")).encode("utf-8"))
        tokens_est = int(sum(len(m.get("content", "")) for m in messages) / 4)
        logger.info(
            "studio2_agent registry_summary_bytes=%s target_manifest_bytes=%s messages_tokens_estimate=%s model=%s base_url=%s",
            len(registry_text.encode("utf-8")),
            target_bytes,
            tokens_est,
            STUDIO2_BUILDER_MODEL,
            OPENAI_BASE_URL,
        )
        if STUDIO2_AGENT_DEBUG:
            msg_len = len(message or "")
            logger.info("studio2_agent prompt_debug message_len=%s errors_count=%s", msg_len, len(last_validation["errors"]))
        if STUDIO2_AGENT_LOG_PAYLOAD:
            trimmed_messages = []
            for msg in messages:
                role = msg.get("role")
                content = msg.get("content", "")
                snippet = content[:800]
                trimmed_messages.append({"role": role, "content": snippet, "truncated": len(content) > 800})
            logger.info("studio2_agent payload_preview=%s", json.dumps(trimmed_messages))

        if progress:
            progress.emit("stage_started", "building", attempt, {"stage": "building"})
            progress.emit("builder_started", "building", attempt, {"model": STUDIO2_BUILDER_MODEL})
        builder_start = time.perf_counter()
        try:
            response = _openai_chat_completion(messages, model=STUDIO2_BUILDER_MODEL)
        except urllib.error.HTTPError as exc:
            try:
                payload = exc.read().decode("utf-8")
            except Exception:
                payload = None
            if STUDIO2_AGENT_DEBUG:
                logger.warning("studio2_agent openai_http_error status=%s body=%s", exc.code, payload)
            return _error_response("OPENAI_ERROR", "OpenAI request failed", detail={"status": exc.code, "body": payload}, status=502)
        except urllib.error.URLError as exc:
            if STUDIO2_AGENT_DEBUG:
                logger.warning("studio2_agent openai_url_error error=%s", str(exc))
            return _error_response("OPENAI_TIMEOUT", "OpenAI request timed out", detail={"error": str(exc)}, status=504)
        except Exception as exc:
            if STUDIO2_AGENT_DEBUG:
                logger.warning("studio2_agent openai_error error=%s", str(exc))
            return _error_response("OPENAI_ERROR", "OpenAI request failed", detail={"error": str(exc)}, status=502)
        builder_ms = (time.perf_counter() - builder_start) * 1000
        openai_total_ms += builder_ms

        choices = response.get("choices") or []
        content = choices[0].get("message", {}).get("content") if choices else None
        if not content:
            return _error_response("OPENAI_EMPTY", "OpenAI returned empty response", status=502)

        plan_ops, diagnostics = _extract_patch_ops_from_response(content)
        if not isinstance(plan_ops, dict):
            return _error_response("AGENT_PARSE_FAILED", "agent response parse failed", detail=diagnostics)

        plan_payload = plan_ops.get("plan") if isinstance(plan_ops.get("plan"), dict) else None
        notes_text = plan_ops.get("notes") if isinstance(plan_ops.get("notes"), str) else None
        tool_ops = plan_ops.get("ops")
        calls = plan_ops.get("calls")
        if tool_ops is not None and isinstance(tool_ops, list):
            calls = tool_ops
        if calls is None:
            calls = []
        if not isinstance(calls, list):
            return _error_response("AGENT_SCHEMA_INVALID", "calls must be list", "calls")

        ops_by_module = plan_ops.get("ops_by_module")
        if ops_by_module is None:
            ops_by_module = []
        if not isinstance(ops_by_module, list):
            return _error_response("AGENT_SCHEMA_INVALID", "ops_by_module required", "ops_by_module")
        if _studio2_contains_patch_ops(plan_ops):
            last_validation = {
                "errors": [
                    {
                        "code": "AGENT_OPS_DISABLED_FOR_STUDIO2",
                        "message": "Patch ops are disabled for Studio2; use tools only",
                        "path": "ops",
                        "detail": {"hint": "Use tools; ops are disabled"},
                    }
                ],
                "warnings": [],
                "strict": [],
                "completeness": [],
                "design": [],
            }
            stop_reason = "invalid"
            if progress:
                progress.emit("stage_started", "validating", attempt, {"stage": "validating"})
                progress.emit(
                    "validate_result",
                    "validating",
                    attempt,
                    {
                        "error_counts": {"schema": 1, "strict": 0, "completeness": 0, "total": 1},
                        "top_errors": top_errors(last_validation["errors"]),
                        "warnings_count": 0,
                        "design_warnings_count": 0,
                    },
                )
                progress.emit("stage_done", "validating", attempt, {"stage": "validating"})
            break

        prev_total_errors = _count_errors(last_validation["errors"], last_validation["strict"], last_validation["completeness"])
        if prev_total_errors > 0 and len(calls) == 0:
            hint = "No tool calls were produced. You must emit at least one allowed tool call when errors exist."
            last_validation = {
                "errors": [
                    {
                        "code": "AGENT_NO_TOOL_CALLS",
                        "message": hint,
                        "path": "calls",
                        "detail": {"hint": hint},
                    }
                ],
                "warnings": [],
                "strict": [],
                "completeness": [],
                "design": [],
            }
            best_iteration = {
                "index": attempt,
                "manifest": copy.deepcopy(ctx.working_manifest),
                "total_errors": 1,
                "strict_errors": 0,
                "completeness_errors": 0,
                "validation": last_validation,
                "calls": [],
                "ops_by_module": [],
            }
            best_index = attempt
            stop_reason = "no_effect"
            if notes_text:
                if hint not in notes_text:
                    notes_text = f"{notes_text.strip()} {hint}".strip()
            else:
                notes_text = hint
            if progress:
                progress.emit("stage_started", "validating", attempt, {"stage": "validating"})
                progress.emit(
                    "validate_result",
                    "validating",
                    attempt,
                    {
                        "error_counts": {"schema": 1, "strict": 0, "completeness": 0, "total": 1},
                        "top_errors": top_errors(last_validation["errors"]),
                        "warnings_count": 0,
                        "design_warnings_count": 0,
                    },
                )
                progress.emit("stage_done", "validating", attempt, {"stage": "validating"})
            break

        planned_ops_count = sum(len(entry.get("ops", [])) for entry in ops_by_module if isinstance(entry, dict))
        tools_used = sorted({call.get("tool") for call in calls if isinstance(call, dict) and call.get("tool")})
        if progress:
            progress.emit(
                "builder_result",
                "building",
                attempt,
                {
                    "plan_summary": summarize_plan(plan_payload, notes_text),
                    "ops_count": planned_ops_count,
                    "tools_used": tools_used,
                    "calls_preview": preview_calls(calls, STUDIO2_AGENT_STREAM_DEBUG),
                },
            )
            progress.emit("stage_done", "building", attempt, {"stage": "building"})
            progress.emit("builder_done", "building", attempt, {"stage": "building"})

        apply_start = time.perf_counter()
        if progress:
            progress.emit("stage_started", "applying", attempt, {"stage": "applying"})
            progress.emit("apply_started", "applying", attempt, {})
        applied_ops = []
        applied_calls = []
        local_errors: list[dict] = []

        for call in calls:
            if not isinstance(call, dict):
                local_errors.append({"code": "CALL_INVALID", "message": "call must be object", "path": "calls"})
                continue
            tool = _studio2_normalize_tool_name(call.get("tool"))
            call_module_id = call.get("module_id") or call.get("args", {}).get("module_id")
            entity_id = call.get("entity_id") or call.get("args", {}).get("entity_id")
            entity_def = call.get("entity") or call.get("args", {}).get("entity")
            relation_def = call.get("relation") or call.get("args", {}).get("relation")
            workflow_def = call.get("workflow") or call.get("args", {}).get("workflow")
            pattern_def = call.get("pattern") or call.get("args", {}).get("pattern")
            if tool not in {
                "ensure_entity",
                "ensure_entity_pages",
                "ensure_nav",
                "ensure_actions_for_status",
                "ensure_relation",
                "ensure_workflow",
                "ensure_ui_pattern",
                "read_manifest",
            }:
                local_errors.append({"code": "CALL_INVALID", "message": "unknown tool", "path": "calls.tool", "detail": {"tool": tool}})
                continue
            if tool != "read_manifest" and call_module_id != module_id:
                local_errors.append({"code": "CALL_INVALID", "message": "module_id mismatch", "path": "calls.module_id"})
                continue
            if (
                narrow_field_add_request
                and not is_new
                and tool in {"ensure_entity_pages", "ensure_nav"}
            ):
                continue
            ref_errors = _studio2_validate_call_references(ctx.working_manifest, call)
            if ref_errors:
                local_errors.extend(ref_errors)
                continue
            base = ctx.working_manifest
            if tool == "ensure_entity":
                if isinstance(entity_def, dict):
                    target_entity_id = entity_def.get("id") if isinstance(entity_def.get("id"), str) else None
                    existing_field_ids: set[str] = set()
                    if isinstance(target_entity_id, str):
                        existing_entity = next(
                            (
                                entity
                                for entity in (base.get("entities") or [])
                                if isinstance(entity, dict) and entity.get("id") == target_entity_id
                            ),
                            None,
                        )
                        if isinstance(existing_entity, dict):
                            existing_field_ids = {
                                field.get("id")
                                for field in (existing_entity.get("fields") or [])
                                if isinstance(field, dict) and isinstance(field.get("id"), str)
                            }
                    base = _studio2_tool_ensure_entity_def(base, entity_def)
                    if isinstance(target_entity_id, str):
                        added_field_ids = [
                            field.get("id")
                            for field in (entity_def.get("fields") or [])
                            if isinstance(field, dict)
                            and isinstance(field.get("id"), str)
                            and field.get("id") not in existing_field_ids
                        ]
                        if added_field_ids and (form_placement_requested or isinstance(scoped_answer_hints.get("planned_section_id"), str) or isinstance(scoped_answer_hints.get("tab_target"), str)):
                            base = _studio2_place_new_fields_in_form(
                                base,
                                target_entity_id,
                                added_field_ids,
                                answer_hints=scoped_answer_hints,
                                message=message,
                            )
                elif isinstance(entity_id, str):
                    base = _studio2_tool_ensure_entity(base, entity_id)
                else:
                    local_errors.append({"code": "CALL_INVALID", "message": "entity_id or entity required", "path": "calls.entity_id"})
                    continue
                base = _studio2_enforce_architecture(base)
            elif tool == "ensure_entity_pages":
                if not isinstance(entity_id, str):
                    local_errors.append({"code": "CALL_INVALID", "message": "entity_id required", "path": "calls.entity_id"})
                    continue
                base = _studio2_tool_ensure_entity_pages(base, entity_id)
            elif tool == "ensure_nav":
                base = _studio2_tool_ensure_nav(base)
            elif tool == "ensure_actions_for_status":
                base = _studio2_tool_ensure_status_actions(base, entity_id if isinstance(entity_id, str) else None)
            elif tool == "ensure_relation":
                if not isinstance(relation_def, dict):
                    local_errors.append({"code": "CALL_INVALID", "message": "relation required", "path": "calls.relation"})
                    continue
                result = _studio2_tool_ensure_relation(base, relation_def)
                if isinstance(result, dict) and result.get("ok") is False:
                    local_errors.append(
                        {
                            "code": "CALL_INVALID",
                            "message": result.get("reason", "relation rejected"),
                            "path": "calls.relation",
                            "detail": {"missing": result.get("missing")},
                        }
                    )
                    continue
                base = result if isinstance(result, dict) else base
            elif tool == "ensure_workflow":
                if not isinstance(workflow_def, dict):
                    local_errors.append({"code": "CALL_INVALID", "message": "workflow required", "path": "calls.workflow"})
                    continue
                result = _studio2_tool_ensure_workflow(base, workflow_def)
                if isinstance(result, dict) and result.get("ok") is False:
                    local_errors.append(
                        {
                            "code": "CALL_INVALID",
                            "message": result.get("reason", "workflow rejected"),
                            "path": "calls.workflow",
                            "detail": {"hint": result.get("hint")},
                        }
                    )
                    continue
                if isinstance(result, dict) and isinstance(result.get("manifest"), dict):
                    base = result.get("manifest")
                elif isinstance(result, dict):
                    base = result
            elif tool == "ensure_ui_pattern":
                base = _studio2_tool_ensure_ui_pattern(base, pattern_def if isinstance(pattern_def, dict) else None)
            elif tool == "read_manifest":
                if not isinstance(call_module_id, str) or not call_module_id:
                    local_errors.append({"code": "CALL_INVALID", "message": "module_id required", "path": "calls.module_id"})
                    continue
                level = call.get("level") or call.get("args", {}).get("level")
                result = _studio2_read_manifest_payload(request, call_module_id, level if isinstance(level, str) else None)
                cache = ctx.cache.setdefault("linked_manifests", {})
                if isinstance(cache, dict) and result.get("ok"):
                    cache[call_module_id] = result
                elif not result.get("ok"):
                    local_errors.append(
                        {
                            "code": "CALL_INVALID",
                            "message": result.get("error", {}).get("message", "read_manifest failed"),
                            "path": "calls.module_id",
                        }
                    )
                applied_calls.append(call)
                continue
            ctx.working_manifest = base
            applied_calls.append(call)

        for entry in ops_by_module:
            if not isinstance(entry, dict):
                local_errors.append({"code": "OPS_INVALID", "message": "ops_by_module entry invalid", "path": "ops_by_module"})
                continue
            mod_id = entry.get("module_id")
            ops = entry.get("ops")
            if not isinstance(mod_id, str) or not isinstance(ops, list):
                local_errors.append({"code": "OPS_INVALID", "message": "module_id and ops required", "path": "ops_by_module"})
                continue
            if mod_id != module_id:
                local_errors.append({"code": "OPS_CROSS_MODULE_FORBIDDEN", "message": "cross-module ops not enabled", "path": "ops_by_module"})
                continue
            guard_errors = _studio2_guard_ops(mod_id, ops, is_new)
            if guard_errors:
                local_errors.extend(guard_errors)
                continue
            applied = _studio2_apply_ops(ctx.working_manifest, ops)
            if not applied.get("ok"):
                local_errors.extend(applied.get("errors", []))
                continue
            updated_manifest = applied.get("manifest")
            if isinstance(updated_manifest, dict):
                updated_manifest = _ensure_app_home(_ensure_module_id(_sanitize_manifest(updated_manifest), mod_id))
                updated_manifest = _studio2_enforce_architecture(updated_manifest)
            ctx.working_manifest = updated_manifest
            applied_ops.append({"module_id": mod_id, "ops": applied.get("resolved_ops", [])})

        normalization_warnings: list[dict] = []
        if not local_errors:
            normalize_cache = ctx.cache.setdefault("normalize_cache", {})
            ctx.working_manifest, normalization_warnings = normalize_manifest_v13(
                ctx.working_manifest, module_id=module_id, cache=normalize_cache
            )

        apply_ops_ms = (time.perf_counter() - apply_start) * 1000
        ops_count = sum(len(entry.get("ops", [])) for entry in applied_ops)
        diff_summary = diff_manifest(manifest_before, ctx.working_manifest)
        if progress:
            progress.emit(
                "apply_result",
                "applying",
                attempt,
                {
                    "changed": manifest_before_hash != diff_summary.get("manifest_hash"),
                    "diff_summary": {
                        "entities_added": diff_summary.get("entities_added"),
                        "pages_added": diff_summary.get("pages_added"),
                        "views_added": diff_summary.get("views_added"),
                        "actions_added": diff_summary.get("actions_added"),
                        "nav_changes": diff_summary.get("nav_changes"),
                        "relations_added": diff_summary.get("relations_added"),
                        "workflows_added": diff_summary.get("workflows_added"),
                    },
                    "manifest_hash": diff_summary.get("manifest_hash"),
                },
            )
            progress.emit("stage_done", "applying", attempt, {"stage": "applying"})
            progress.emit("apply_done", "applying", attempt, {"stage": "applying"})

        validate_start = time.perf_counter()
        if progress:
            progress.emit("stage_started", "validating", attempt, {"stage": "validating"})
            progress.emit("validate_started", "validating", attempt, {})
        validation_errors = []
        validation_warnings = []
        strict_errors_all = []
        completeness_issues = []
        design_warnings = []
        inherited_completeness_issues = []
        if not local_errors:
            _, errors, warnings = validate_manifest_raw(ctx.working_manifest, expected_module_id=module_id)
            if errors:
                for err in errors:
                    entry = _normalize_validation_entry(err)
                    entry["module_id"] = module_id
                    validation_errors.append(entry)
            strict_errors = _studio2_strict_validate(ctx.working_manifest, expected_module_id=module_id)
            if strict_errors:
                for err in strict_errors:
                    entry = _normalize_validation_entry(err)
                    entry["module_id"] = module_id
                    validation_errors.append(entry)
                    strict_errors_all.append(entry)
            if warnings:
                for warn in warnings:
                    entry = _normalize_validation_entry(warn)
                    entry["module_id"] = module_id
                    validation_warnings.append(entry)
            if normalization_warnings:
                for warn in normalization_warnings:
                    entry = _normalize_validation_entry(warn)
                    entry["module_id"] = module_id
                    validation_warnings.append(entry)
            for warn in _studio2_design_warnings(ctx.working_manifest):
                entry = _normalize_validation_entry(warn)
                entry["module_id"] = module_id
                design_warnings.append(entry)
            if not errors:
                for issue in _studio2_completeness_check(ctx.working_manifest):
                    entry = _normalize_validation_entry(issue)
                    entry["module_id"] = module_id
                    completeness_issues.append(entry)
            if (
                inherited_completeness_issue_fps
                and _hash_json(ctx.working_manifest) != initial_manifest_hash
                and completeness_issues
            ):
                current_completeness = []
                for issue in completeness_issues:
                    if _validation_issue_fingerprint(issue) in inherited_completeness_issue_fps:
                        inherited_completeness_issues.append(issue)
                    else:
                        current_completeness.append(issue)
                completeness_issues = current_completeness
                for issue in inherited_completeness_issues:
                    validation_warnings.append(
                        {
                            "code": f"INHERITED_{issue.get('code') or 'COMPLETENESS_ISSUE'}",
                            "message": issue.get("message") or "Inherited completeness issue",
                            "path": issue.get("path"),
                            "json_pointer": issue.get("json_pointer"),
                            "detail": {
                                "inherited": True,
                                "module_id": module_id,
                                "original_code": issue.get("code"),
                            },
                            "module_id": module_id,
                        }
                    )
        validate_ms = (time.perf_counter() - validate_start) * 1000

        last_validation = {
            "errors": validation_errors if not local_errors else local_errors,
            "warnings": validation_warnings,
            "strict": strict_errors_all,
            "completeness": completeness_issues,
            "design": design_warnings,
        }

        if local_errors:
            call_invalid = [err for err in local_errors if err.get("code") == "CALL_INVALID"]
            if call_invalid:
                last_validation["errors"] = list(local_errors) + [
                    {
                        "code": "CALL_INVALID_HINT",
                        "message": "Unknown tool. Allowed tools are: ensure_entity, ensure_entity_pages, ensure_nav, ensure_actions_for_status, ensure_relation, ensure_workflow, ensure_ui_pattern, read_manifest.",
                        "path": "calls.tool",
                    }
                ]

        total_errors = _count_errors(last_validation["errors"], last_validation["strict"], last_validation["completeness"])
        strict_fp = _fingerprint_errors(last_validation["strict"]) if last_validation["strict"] else ""
        completeness_fp = _fingerprint_errors(last_validation["completeness"]) if last_validation["completeness"] else ""
        ops_fp = _hash_json({"calls": applied_calls, "ops": applied_ops})
        manifest_after_hash = _hash_json(ctx.working_manifest)
        error_fp = _fingerprint_errors(
            (last_validation["errors"] or []) + (last_validation["strict"] or []) + (last_validation["completeness"] or [])
        )

        if total_errors == 0 and manifest_after_hash == manifest_before_hash:
            warn_count = len(last_validation.get("warnings", [])) + len(last_validation.get("design", []))
            if warn_count > 0:
                notes_text = "No changes applied. Warnings are advisory."

        if progress:
            progress.emit(
                "validate_result",
                "validating",
                attempt,
                {
                    "error_counts": {
                        "schema": len(last_validation["errors"]),
                        "strict": len(last_validation["strict"]),
                        "completeness": len(last_validation["completeness"]),
                        "total": total_errors,
                    },
                    "top_errors": top_errors(last_validation["errors"] or last_validation["strict"] or last_validation["completeness"]),
                    "warnings_count": len(last_validation["warnings"]),
                    "design_warnings_count": len(last_validation["design"]),
                },
            )
            progress.emit("stage_done", "validating", attempt, {"stage": "validating"})
            progress.emit("validate_done", "validating", attempt, {"stage": "validating"})

        iter_log = {
            "iteration": attempt + 1,
            "planner_ms": round(planner_ms, 2) if attempt == 0 else 0.0,
            "builder_ms": round(builder_ms, 2),
            "apply_ops_ms": round(apply_ops_ms, 2),
            "validate_ms": round(validate_ms, 2),
            "iter_total_ms": round((time.perf_counter() - iter_start) * 1000, 2),
            "error_counts": {
                "schema": len(last_validation["errors"]),
                "strict": len(last_validation["strict"]),
                "completeness": len(last_validation["completeness"]),
                "total": total_errors,
            },
            "build_spec_hash": build_spec_hash,
            "ops_count": ops_count,
            "ops_fingerprint": ops_fp,
            "strict_fingerprint": strict_fp,
            "completeness_fingerprint": completeness_fp,
        }
        ctx.stats["iteration_logs"].append(iter_log)
        logger.info(
            "studio2_agent_iter request_id=%s module_id=%s iter=%s total_errors=%s strict_errors=%s completeness_errors=%s",
            ctx.request_id,
            module_id,
            attempt + 1,
            total_errors,
            len(last_validation["strict"]),
            len(last_validation["completeness"]),
        )
        if progress:
            progress.emit(
                "iter_timing",
                "metrics",
                attempt,
                {
                    "planner_ms": iter_log.get("planner_ms"),
                    "builder_ms": iter_log.get("builder_ms"),
                    "apply_ms": iter_log.get("apply_ops_ms"),
                    "validate_ms": iter_log.get("validate_ms"),
                    "iter_total_ms": iter_log.get("iter_total_ms"),
                },
            )

        current_iter_state = {
            "index": attempt,
            "manifest": copy.deepcopy(ctx.working_manifest),
            "total_errors": total_errors,
            "strict_errors": len(last_validation["strict"]),
            "completeness_errors": len(last_validation["completeness"]),
            "validation": last_validation,
            "calls": applied_calls,
            "ops_by_module": applied_ops,
        }
        best_iteration = _update_best_iteration(best_iteration, current_iter_state)
        best_index = best_iteration["index"] if best_iteration else 0

        if total_errors == 0:
            stop_reason = "pass"
            break

        only_call_invalid = False
        if local_errors and all(err.get("code") == "CALL_INVALID" for err in local_errors):
            only_call_invalid = True

        if attempt >= 1 and not only_call_invalid:
            if manifest_after_hash == prev_manifest_hash and error_fp == prev_error_fp:
                stop_reason = "no_effect"
                break

        prev_error_counts.append(total_errors)
        if len(prev_error_counts) >= 3:
            if prev_error_counts[-1] >= prev_error_counts[-2] >= prev_error_counts[-3]:
                stop_reason = "no_progress"
                break

        if strict_fp:
            if strict_fp == prev_strict_fp:
                strict_repeat += 1
            else:
                strict_repeat = 0
            prev_strict_fp = strict_fp
            if strict_repeat >= 1:
                stop_reason = "repeated_errors"
                break

        if build_spec_hash:
            if build_spec_hash == prev_build_spec_hash:
                planner_repeat += 1
            else:
                planner_repeat = 0
            prev_build_spec_hash = build_spec_hash
            if planner_repeat >= 1 and attempt >= 1:
                if manifest_after_hash == prev_manifest_hash and error_fp == prev_error_fp:
                    stop_reason = "planner_repeat"
                    break

        if attempt == MAX_AGENT_ITERS - 1:
            stop_reason = "max_iters"
            break

        prev_manifest_hash = manifest_after_hash
        prev_error_fp = error_fp

    if stop_reason is None:
        stop_reason = "max_iters"

    if progress:
        progress.emit(
            "stopped",
            "stop",
            None,
            {
                "stop_reason": stop_reason,
                "best_iter": best_index,
                "final_error_counts": {
                    "schema": len(last_validation.get("errors", [])),
                    "strict": len(last_validation.get("strict", [])),
                    "completeness": len(last_validation.get("completeness", [])),
                },
            },
        )

    final_state = best_iteration if best_iteration else {
        "index": 0,
        "manifest": ctx.working_manifest,
        "validation": last_validation,
        "calls": [],
        "ops_by_module": [],
        "total_errors": _count_errors(last_validation["errors"], last_validation["strict"], last_validation["completeness"]),
        "strict_errors": len(last_validation["strict"]),
        "completeness_errors": len(last_validation["completeness"]),
    }

    ops_with_meta = list(final_state.get("ops_by_module") or [])
    ops_with_meta.append(
        {
            "meta": {
                "build_spec_hash": build_spec_hash,
                "iterations": len(ctx.stats["iteration_logs"]),
                "stop_reason": stop_reason,
                "ops_applied_count": ops_count,
                "timing_summary": ctx.stats["iteration_logs"],
            }
        }
    )

    draft_version = drafts.create_draft_version(
        module_id,
        final_state["manifest"],
        note=f"ai: {message[:120]} stop:{stop_reason}",
        created_by=created_by,
        parent_version_id=None,
        ops_applied=ops_with_meta,
        validation_errors=final_state["validation"].get("errors"),
    )

    db_stats = get_db_stats()
    db_q = len(get_db_query_log())
    total_ms = (time.perf_counter() - wall_start) * 1000
    summary_log = {
        "request_id": ctx.request_id,
        "module_id": module_id,
        "iterations": len(ctx.stats["iteration_logs"]),
        "stop_reason": stop_reason,
        "total_ms": round(total_ms, 2),
        "openai_total_ms": round(openai_total_ms, 2),
        "db_ms": round(db_stats.get("execute_ms", 0.0), 2),
        "db_q": db_q,
        "final_errors": final_state["total_errors"],
    }
    logger.info("studio2_agent_summary %s", json.dumps(summary_log))

    payload = {
        "assistant_message": notes_text or "",
        "plan": plan_payload,
        "notes": notes_text,
        "request_prompt": message,
        "requested_focus": requested_focus,
        "calls": final_state.get("calls", []),
        "ops_by_module": final_state.get("ops_by_module", []),
        "drafts": {module_id: final_state["manifest"]},
        "validation": {
            "errors": final_state["validation"].get("errors", []),
            "warnings": final_state["validation"].get("warnings", []),
            "strict_errors": final_state["validation"].get("strict", []),
            "completeness_errors": final_state["validation"].get("completeness", []),
            "design_warnings": final_state["validation"].get("design", []),
        },
        "stop_reason": stop_reason,
        "iterations": len(ctx.stats["iteration_logs"]),
        "timing_summary": {
            "total_ms": round(total_ms, 2),
            "openai_total_ms": round(openai_total_ms, 2),
            "db_ms": round(db_stats.get("execute_ms", 0.0), 2),
            "db_q": db_q,
            "per_iter": ctx.stats["iteration_logs"],
        },
        "persisted_draft_id": draft_version.get("id"),
        "best_iteration_index": best_index,
        "last_build_spec_hash": build_spec_hash,
    }
    if include_progress and progress:
        payload["progress"] = progress.to_progress_list()

    return _ok_response({"data": payload})


@app.post("/studio2/agent/plan")
async def studio2_agent_plan(request: Request) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_superadmin(actor, "Studio AI is currently limited to superadmins")
    if denied:
        return denied
    if not _openai_configured():
        return _openai_not_configured()
    body = await _safe_json(request)
    message = body.get("message") if isinstance(body, dict) else None
    module_id = body.get("module_id") if isinstance(body, dict) else None
    requested_focus = _studio2_agent_focus(body.get("focus") if isinstance(body, dict) else None, message)
    if not isinstance(message, str):
        return _error_response("AGENT_INVALID", "message required", "message")
    registry_summary = _studio2_build_registry_summary(request)
    registry_header = _studio2_registry_header(registry_summary)
    registry_text = json.dumps(registry_header, separators=(",", ":"))
    pattern_memory = _load_pattern_memory()
    patterns = pattern_memory.get("patterns") if isinstance(pattern_memory, dict) else {}
    pattern_key = _infer_pattern_key(message, module_id if isinstance(module_id, str) else None)
    pattern_hint = patterns.get(pattern_key) if isinstance(patterns, dict) and pattern_key else None
    base_manifest = _studio2_seed_manifest_for_brief(
        module_id or "new_module",
        message,
        answer_hints=None,
        pattern_key=pattern_key,
    )
    context = {
        "module_id": module_id,
        "module_summary": _studio2_prompt_manifest_summary(base_manifest),
        "authoring_contract": _shared_module_authoring_contract(),
        "registry": registry_header if len(registry_text.encode("utf-8")) <= STUDIO2_MAX_REGISTRY_BYTES else {"modules": []},
        "pattern": {"key": pattern_key, "data": pattern_hint} if pattern_hint else None,
        "requested_focus": requested_focus,
    }
    context_text = json.dumps(context, separators=(",", ":"))
    planner_pack = _load_prompt_pack("planner.md")
    contract_pack = _load_prompt_pack("manifest_contract_v1_3.md")
    planner_system = "\n\n".join([planner_pack, contract_pack]).strip()
    messages = [
        {"role": "system", "content": planner_system},
        {"role": "user", "content": message},
        {"role": "user", "content": f"context.json\n```json\n{context_text}\n```"},
    ]
    try:
        response = _openai_chat_completion(messages, model=STUDIO2_PLANNER_MODEL)
    except Exception as exc:
        return _error_response("OPENAI_ERROR", "Planner request failed", detail={"error": str(exc)}, status=502)
    choices = response.get("choices") or []
    content = choices[0].get("message", {}).get("content") if choices else None
    if not content:
        return _error_response("OPENAI_EMPTY", "Planner returned empty response", status=502)
    build_spec, diag = _extract_build_spec_from_response(content)
    if not isinstance(build_spec, dict):
        return _error_response("PLANNER_PARSE_FAILED", "Planner response parse failed", detail=diag)
    return _ok_response({"data": {"build_spec": build_spec}})


