def _unwrap_store_record(record: dict | None) -> tuple[str | None, dict | None]:
    if not isinstance(record, dict):
        return None, None
    payload = record.get("record")
    if isinstance(payload, dict):
        rid = record.get("record_id") if isinstance(record.get("record_id"), str) else payload.get("id")
        return rid, payload
    rid = record.get("id") if isinstance(record.get("id"), str) else None
    return rid, record


def _normalize_field_mappings(field_mappings: Any) -> list[dict]:
    if isinstance(field_mappings, list):
        out: list[dict] = []
        for item in field_mappings:
            if isinstance(item, dict):
                out.append(item)
        return out
    if isinstance(field_mappings, dict):
        out = []
        for target_field, spec in field_mappings.items():
            if not isinstance(target_field, str) or not target_field:
                continue
            if isinstance(spec, str):
                out.append({"to": target_field, "from": spec})
                continue
            if isinstance(spec, dict):
                item = {"to": target_field}
                if "from" in spec:
                    item["from"] = spec.get("from")
                if "value" in spec:
                    item["value"] = spec.get("value")
                if "ref" in spec:
                    item["ref"] = spec.get("ref")
                out.append(item)
        return out
    return []


def _transform_numeric_value(value: Any) -> float | int | None:
    if isinstance(value, bool):
        return None
    if isinstance(value, (int, float)):
        return value
    if isinstance(value, str):
        text = value.strip()
        if not text:
            return None
        try:
            return float(text)
        except ValueError:
            return None
    return None


def _transform_value_missing(value: Any) -> bool:
    if value is None:
        return True
    if isinstance(value, str):
        return not value.strip()
    if isinstance(value, (list, dict, set, tuple)):
        return len(value) == 0
    return False


def _resolve_transform_ref(ref: str, source_record: dict, target_record: dict | None, context: dict) -> Any:
    if not isinstance(ref, str) or not ref:
        return None
    if ref == "$today":
        return date.today().isoformat()
    if ref == "$now":
        return _now()
    if ref == "$source.id":
        return source_record.get("id")
    if ref.startswith("$source."):
        return source_record.get(ref[len("$source.") :])
    if ref == "$target.id":
        return (target_record or {}).get("id")
    if ref.startswith("$target."):
        return (target_record or {}).get(ref[len("$target.") :])
    if ref == "$context.record_id":
        return context.get("record_id")
    if ref.startswith("$context.record."):
        record = context.get("record")
        if isinstance(record, dict):
            return record.get(ref[len("$context.record.") :])
    selected_records = context.get("selected_records")
    if isinstance(selected_records, list):
        if ref == "$selection.count":
            return len([item for item in selected_records if isinstance(item, dict)])
        if ref.startswith("$selection.sum."):
            field_id = ref[len("$selection.sum.") :]
            total = 0.0
            matched = False
            for record in selected_records:
                if not isinstance(record, dict):
                    continue
                numeric = _transform_numeric_value(record.get(field_id))
                if numeric is None:
                    continue
                matched = True
                total += float(numeric)
            if not matched:
                return 0
            return int(total) if float(total).is_integer() else total
    return None


def _resolve_mapping_value(mapping: dict, source_record: dict, target_record: dict | None, context: dict) -> tuple[bool, Any]:
    if "from" in mapping:
        field_id = mapping.get("from")
        if not isinstance(field_id, str) or not field_id:
            return False, None
        return True, source_record.get(field_id)
    if "ref" in mapping:
        ref = mapping.get("ref")
        if not isinstance(ref, str) or not ref:
            return False, None
        return True, _resolve_transform_ref(ref, source_record, target_record, context)
    if "value" in mapping:
        return True, mapping.get("value")
    return False, None


def _apply_field_mappings(field_mappings: list[dict], source_record: dict, target_record: dict | None, context: dict) -> tuple[list[dict], dict]:
    errors: list[dict] = []
    mapped: dict = {}
    for idx, mapping in enumerate(field_mappings):
        target_field = mapping.get("to")
        if not isinstance(target_field, str) or not target_field:
            errors.append({"code": "TRANSFORMATION_MAPPING_INVALID", "message": "field mapping.to is required", "path": f"field_mappings[{idx}].to", "detail": None})
            continue
        present, value = _resolve_mapping_value(mapping, source_record, target_record, context)
        if not present:
            errors.append(
                {
                    "code": "TRANSFORMATION_MAPPING_INVALID",
                    "message": "field mapping requires exactly one of from/ref/value",
                    "path": f"field_mappings[{idx}]",
                    "detail": None,
                }
            )
            continue
        mapped[target_field] = value
    return errors, mapped


def _list_entity_records_for_transform(entity_id: str) -> list[dict]:
    if not USE_DB and hasattr(generic_records, "list"):
        try:
            rows = generic_records.list(entity_id)
            out = []
            for row in rows if isinstance(rows, list) else []:
                rid, payload = _unwrap_store_record(row if isinstance(row, dict) else None)
                if rid and isinstance(payload, dict):
                    out.append({"record_id": rid, "record": payload})
            return out
        except Exception:
            return []
    records: list[dict] = []
    cursor = None
    while True:
        items, next_cursor = generic_records.list_page(entity_id, limit=200, cursor=cursor)
        for item in items if isinstance(items, list) else []:
            rid, payload = _unwrap_store_record(item if isinstance(item, dict) else None)
            if rid and isinstance(payload, dict):
                records.append({"record_id": rid, "record": payload})
        if not next_cursor:
            break
        cursor = next_cursor
    return records


def _emit_transform_hook_event(request: Request, module_id: str, manifest: dict, event_name: str, payload: dict) -> None:
    if not isinstance(event_name, str) or not event_name:
        return
    module = _get_module(request, module_id)
    manifest_hash = module.get("current_hash") if isinstance(module, dict) else None
    actor = getattr(request.state, "actor", None)
    meta = {
        "module_id": module_id,
        "manifest_hash": manifest_hash,
        "actor": _actor_event_meta(actor),
        "org_id": actor.get("workspace_id") if isinstance(actor, dict) else None,
        "trace_id": request.headers.get("x-request-id") if hasattr(request, "headers") else None,
    }
    try:
        event_payload = dict(payload or {})
        event_payload["event"] = event_name
        emitted = make_event(event_name, event_payload, meta)
        event_bus.publish(emitted)
        _handle_automation_event(emitted)
    except Exception as exc:
        logger.warning("transform_hook_emit_failed module_id=%s event=%s error=%s", module_id, event_name, exc)


def _render_transform_feed_message(template: str, source_entity_id: str, source_id: str, target_entity_id: str, target_id: str) -> str:
    text = template if isinstance(template, str) and template.strip() else "Transformation completed"
    return (
        text.replace("{source.entity_id}", source_entity_id)
        .replace("{source.id}", source_id)
        .replace("{target.entity_id}", target_entity_id)
        .replace("{target.id}", target_id)
    )


def _run_transform_record_action(
    request: Request,
    module_id: str,
    manifest: dict,
    compiled: dict | None,
    action_id: str,
    action: dict,
    context: dict,
    actor: dict | None,
    phase_ms: dict[str, float],
    action_start: float,
) -> dict:
    transformation_key = action.get("transformation_key")
    if not isinstance(transformation_key, str) or not transformation_key:
        return _error_response("ACTION_INVALID", "transformation_key is required", "transformation_key", status=400)
    transformation = None
    if isinstance(compiled, dict):
        transformation = (compiled.get("transformation_by_key") or {}).get(transformation_key)
    if not isinstance(transformation, dict):
        for item in manifest.get("transformations", []) if isinstance(manifest.get("transformations"), list) else []:
            if isinstance(item, dict) and item.get("key") == transformation_key:
                transformation = item
                break
    if not isinstance(transformation, dict):
        return _error_response("TRANSFORMATION_NOT_FOUND", "Transformation not found", "transformation_key", status=404)

    source_entity_from_action = action.get("entity_id")
    source_entity = transformation.get("source_entity_id")
    if isinstance(source_entity_from_action, str) and source_entity_from_action:
        source_entity = source_entity_from_action
    if not isinstance(source_entity, str) or not source_entity:
        return _error_response("TRANSFORMATION_INVALID", "source_entity_id is required", "source_entity_id", status=400)
    source_entity = _normalize_entity_id(source_entity)
    if isinstance(transformation.get("source_entity_id"), str):
        declared_source = _normalize_entity_id(transformation.get("source_entity_id"))
        if source_entity != declared_source:
            return _error_response("TRANSFORMATION_INVALID", "action.entity_id must match transformation.source_entity_id", "entity_id", status=400)
    target_entity = transformation.get("target_entity_id")
    if not isinstance(target_entity, str) or not target_entity:
        return _error_response("TRANSFORMATION_INVALID", "target_entity_id is required", "target_entity_id", status=400)
    target_entity = _normalize_entity_id(target_entity)

    source_found = _find_entity_def(request, source_entity)
    if not source_found:
        return _error_response("ENTITY_NOT_FOUND", "Source entity not found or disabled", "source_entity_id", status=404)
    target_found = _find_entity_def(request, target_entity)
    if not target_found:
        return _error_response("ENTITY_NOT_FOUND", "Target entity not found or disabled", "target_entity_id", status=404)
    denied = _entity_access_denied_response(actor, source_found[0], source_entity, write=True)
    if denied:
        return denied
    denied = _entity_access_denied_response(actor, target_found[0], target_entity, write=True)
    if denied:
        return denied

    validation_cfg = transformation.get("validation") if isinstance(transformation.get("validation"), dict) else {}
    selection_mode = action.get("selection_mode") if isinstance(action.get("selection_mode"), str) else None
    selected_rows: list[dict] = []
    if selection_mode == "selected_records":
        raw_selected_ids = context.get("selected_ids") if isinstance(context, dict) else None
        if not isinstance(raw_selected_ids, list) or len(raw_selected_ids) == 0:
            return _error_response("ACTION_INVALID", "selected_ids is required", "selected_ids", status=400)
        deduped_ids: list[str] = []
        seen_ids: set[str] = set()
        for item in raw_selected_ids:
            if not isinstance(item, str) or not item or item in seen_ids:
                continue
            seen_ids.add(item)
            deduped_ids.append(item)
        if not deduped_ids:
            return _error_response("ACTION_INVALID", "selected_ids is required", "selected_ids", status=400)
        for idx, selected_id in enumerate(deduped_ids):
            selected_entity_id, existing = _get_record_for_entity_candidates(source_entity, selected_id)
            if not isinstance(selected_entity_id, str) or _normalize_entity_id(selected_entity_id) != source_entity or not existing:
                return _error_response("RECORD_NOT_FOUND", "Selected source record not found", f"selected_ids[{idx}]", status=404)
            selected_record = existing.get("record") if isinstance(existing, dict) else None
            if not isinstance(selected_record, dict):
                return _error_response("RECORD_NOT_FOUND", "Selected source record not found", f"selected_ids[{idx}]", status=404)
            if not _record_visible_for_actor(actor, source_found[0], source_entity, selected_record):
                return _error_response("RECORD_NOT_FOUND", "Selected source record not found", f"selected_ids[{idx}]", status=404)
            if not _record_write_allowed_for_actor(actor, source_found[0], source_entity, selected_record):
                return _error_response("FORBIDDEN", "Source record write access denied", f"selected_ids[{idx}]", status=403)
            selected_rows.append({"record_id": selected_id, "record": selected_record})
    else:
        record_id = context.get("record_id") if isinstance(context, dict) else None
        if not isinstance(record_id, str) or not record_id:
            return _error_response("ACTION_INVALID", "record_id is required", "record_id", status=400)
        source_raw = generic_records.get(source_entity, record_id)
        source_id, source_record = _unwrap_store_record(source_raw)
        if not source_id or not isinstance(source_record, dict):
            return _error_response("RECORD_NOT_FOUND", "Source record not found", "record_id", status=404)
        if not _record_visible_for_actor(actor, source_found[0], source_entity, source_record):
            return _error_response("RECORD_NOT_FOUND", "Source record not found", "record_id", status=404)
        if not _record_write_allowed_for_actor(actor, source_found[0], source_entity, source_record):
            return _error_response("FORBIDDEN", "Source record write access denied", "record_id", status=403)
        selected_rows.append({"record_id": source_id, "record": source_record})

    source_id = selected_rows[0]["record_id"]
    source_record = selected_rows[0]["record"]
    transform_context = dict(context if isinstance(context, dict) else {})
    transform_context["selected_records"] = [row.get("record") for row in selected_rows if isinstance(row.get("record"), dict)]

    required_source_fields = validation_cfg.get("require_source_fields") if isinstance(validation_cfg.get("require_source_fields"), list) else []
    if required_source_fields:
        errors = []
        rows_to_validate = selected_rows if selection_mode == "selected_records" else [selected_rows[0]]
        for idx, row in enumerate(rows_to_validate):
            row_record = row.get("record") if isinstance(row.get("record"), dict) else {}
            row_id = row.get("record_id") if isinstance(row.get("record_id"), str) else None
            for field_id in required_source_fields:
                if not isinstance(field_id, str) or not field_id:
                    continue
                if not _transform_value_missing(row_record.get(field_id)):
                    continue
                path = f"selected_ids[{idx}].{field_id}" if selection_mode == "selected_records" else field_id
                errors.append(
                    {
                        "code": "TRANSFORMATION_SOURCE_REQUIRED",
                        "message": "Required source field is missing",
                        "path": path,
                        "detail": {"record_id": row_id} if row_id else None,
                    }
                )
        if errors:
            return _validation_response(errors, [])

    selected_record_domain = validation_cfg.get("selected_record_domain") if isinstance(validation_cfg.get("selected_record_domain"), dict) else None
    if selection_mode == "selected_records" and selected_record_domain:
        selection_errors = []
        for idx, row in enumerate(selected_rows):
            row_record = row.get("record") if isinstance(row.get("record"), dict) else {}
            if eval_condition(selected_record_domain, {"record": row_record}):
                continue
            selection_errors.append(
                {
                    "code": "TRANSFORMATION_SOURCE_INVALID",
                    "message": "Selected source record does not satisfy transformation requirements",
                    "path": f"selected_ids[{idx}]",
                    "detail": {"record_id": row.get("record_id")},
                }
            )
        if selection_errors:
            return _validation_response(selection_errors, [])

    require_uniform_fields = validation_cfg.get("require_uniform_fields") if isinstance(validation_cfg.get("require_uniform_fields"), list) else []
    if selection_mode == "selected_records" and len(selected_rows) > 1 and require_uniform_fields:
        uniform_errors = []
        for field_id in require_uniform_fields:
            if not isinstance(field_id, str) or not field_id:
                continue
            baseline = selected_rows[0].get("record", {}).get(field_id)
            mismatched_ids = [
                row.get("record_id")
                for row in selected_rows[1:]
                if isinstance(row.get("record"), dict) and row.get("record", {}).get(field_id) != baseline
            ]
            if mismatched_ids:
                uniform_errors.append(
                    {
                        "code": "TRANSFORMATION_SOURCE_MISMATCH",
                        "message": "Selected source records must share the same field value",
                        "path": field_id,
                        "detail": {"record_ids": [selected_rows[0].get("record_id"), *mismatched_ids]},
                    }
                )
        if uniform_errors:
            return _validation_response(uniform_errors, [])

    link_fields = transformation.get("link_fields") if isinstance(transformation.get("link_fields"), dict) else {}
    source_to_target_field = link_fields.get("source_to_target")
    if validation_cfg.get("prevent_if_target_linked") is True and isinstance(source_to_target_field, str):
        already_linked = [
            row
            for row in selected_rows
            if isinstance(row.get("record"), dict) and row.get("record", {}).get(source_to_target_field)
        ]
        if already_linked:
            first_link = already_linked[0].get("record", {}).get(source_to_target_field)
            return _error_response(
                "TRANSFORMATION_ALREADY_LINKED",
                "Source record is already linked to a target record",
                source_to_target_field,
                detail={
                    "target_id": first_link,
                    "record_ids": [row.get("record_id") for row in already_linked if isinstance(row.get("record_id"), str)],
                },
                status=409,
            )

    child_defs = transformation.get("child_mappings") if isinstance(transformation.get("child_mappings"), list) else []
    child_sources: list[dict] = []
    total_source_child_records = 0
    for child_idx, child_def in enumerate(child_defs):
        if not isinstance(child_def, dict):
            return _error_response("TRANSFORMATION_INVALID", "child_mappings entries must be objects", f"child_mappings[{child_idx}]", status=400)
        source_child_entity = child_def.get("source_entity_id")
        source_scope = child_def.get("source_scope") if isinstance(child_def.get("source_scope"), str) else None
        source_link_field = child_def.get("source_link_field")
        if not isinstance(source_child_entity, str):
            return _error_response("TRANSFORMATION_INVALID", "child mapping source_entity_id required", f"child_mappings[{child_idx}]", status=400)
        source_child_entity = _normalize_entity_id(source_child_entity)
        source_child_found = _find_entity_def(request, source_child_entity)
        if not source_child_found:
            return _error_response("ENTITY_NOT_FOUND", "Source child entity not found or disabled", f"child_mappings[{child_idx}].source_entity_id", status=404)
        denied = _entity_access_denied_response(actor, source_child_found[0], source_child_entity, write=False)
        if denied:
            return denied
        if source_scope == "selected_records":
            if source_child_entity != source_entity:
                return _error_response("TRANSFORMATION_INVALID", "selected_records child mappings must use the source entity", f"child_mappings[{child_idx}].source_entity_id", status=400)
            scoped = list(selected_rows)
        else:
            if not isinstance(source_link_field, str):
                return _error_response("TRANSFORMATION_INVALID", "child mapping source_link_field required", f"child_mappings[{child_idx}].source_link_field", status=400)
            source_items = _list_entity_records_for_transform(source_child_entity)
            scoped = [
                item
                for item in source_items
                if isinstance(item.get("record"), dict)
                and item.get("record", {}).get(source_link_field) == source_id
                and _record_visible_for_actor(actor, source_child_found[0], source_child_entity, item.get("record"))
            ]
        total_source_child_records += len(scoped)
        child_sources.append({"def": child_def, "source_entity_id": source_child_entity, "source_records": scoped, "source_found": source_child_found})
    if validation_cfg.get("require_child_records") is True and total_source_child_records == 0 and len(child_defs) > 0:
        return _error_response("TRANSFORMATION_CHILD_REQUIRED", "At least one child record is required", "child_mappings", status=400)

    t0 = time.perf_counter()
    field_mappings = _normalize_field_mappings(transformation.get("field_mappings"))
    map_errors, target_values = _apply_field_mappings(field_mappings, source_record, None, transform_context)
    if map_errors:
        return _validation_response(map_errors, [])
    target_workflow = _find_entity_workflow(target_found[2], target_found[1].get("id"))
    errors, clean_target = _validate_record_payload(target_found[1], target_values, for_create=True, workflow=target_workflow)
    lookup_errors = _validate_lookup_fields(target_found[1], _registry_for_request(request), lambda m_id, m_hash: _get_snapshot(request, m_id, m_hash))
    errors.extend(lookup_errors)
    domain_errors = _enforce_lookup_domains(target_found[1], clean_target if isinstance(clean_target, dict) else {})
    errors.extend(domain_errors)
    errors.extend(
        _field_write_policy_errors(
            actor,
            target_found[0],
            target_found[1],
            clean_target if isinstance(clean_target, dict) else {},
            allow_system_fields=True,
        )
    )
    errors.extend(_document_numbering_write_errors(actor, target_found[1], None, clean_target if isinstance(clean_target, dict) else {}))
    errors.extend(_document_numbering_assignment_errors(target_found[1], None, clean_target if isinstance(clean_target, dict) else {}, target_found[2], lifecycle_event="create"))
    if errors:
        _log_record_validation_errors(target_entity, target_values, errors, target_workflow)
        return _validation_response(errors, [])
    phase_ms["transform_validate_target"] = (time.perf_counter() - t0) * 1000

    t0 = time.perf_counter()
    target_created = _create_record_with_computed_fields(request, target_entity, target_found[1], clean_target)
    target_id, target_record = _unwrap_store_record(target_created if isinstance(target_created, dict) else None)
    if not target_id or not isinstance(target_record, dict):
        return _error_response("TRANSFORMATION_FAILED", "Failed to create target record", "target_entity_id", status=500)
    try:
        target_record = _apply_document_numbering_after_write(
            request,
            target_found[1],
            target_id,
            None,
            target_record,
            actor,
            target_found[2],
            lifecycle_event="create",
        )
    except SequenceError as exc:
        generic_records.delete(target_entity, target_id)
        return _sequence_error_response(exc)
    _resp_cache_invalidate_entity(target_entity)
    _resp_cache_invalidate_module_bootstrap(module_id)
    phase_ms["transform_create_target"] = (time.perf_counter() - t0) * 1000

    created_children: list[tuple[str, str]] = []
    child_created_count = 0
    for child_bundle in child_sources:
        child_def = child_bundle["def"]
        target_child_entity = child_def.get("target_entity_id")
        target_link_field = child_def.get("target_link_field")
        if not isinstance(target_child_entity, str) or not isinstance(target_link_field, str):
            for ent_id, rec_id in created_children:
                generic_records.delete(ent_id, rec_id)
            generic_records.delete(target_entity, target_id)
            return _error_response("TRANSFORMATION_INVALID", "child mapping target_entity_id/target_link_field required", "child_mappings", status=400)
        target_child_entity = _normalize_entity_id(target_child_entity)
        target_child_found = _find_entity_def(request, target_child_entity)
        if not target_child_found:
            for ent_id, rec_id in created_children:
                generic_records.delete(ent_id, rec_id)
            generic_records.delete(target_entity, target_id)
            return _error_response("ENTITY_NOT_FOUND", "Target child entity not found or disabled", "child_mappings.target_entity_id", status=404)
        denied = _entity_access_denied_response(actor, target_child_found[0], target_child_entity, write=True)
        if denied:
            for ent_id, rec_id in created_children:
                generic_records.delete(ent_id, rec_id)
            generic_records.delete(target_entity, target_id)
            return denied
        child_field_mappings = _normalize_field_mappings(child_def.get("field_mappings"))
        for source_child in child_bundle["source_records"]:
            source_child_record = source_child.get("record") if isinstance(source_child.get("record"), dict) else {}
            map_errors, child_values = _apply_field_mappings(child_field_mappings, source_child_record, target_record, transform_context)
            if map_errors:
                for ent_id, rec_id in created_children:
                    generic_records.delete(ent_id, rec_id)
                generic_records.delete(target_entity, target_id)
                return _validation_response(map_errors, [])
            child_values[target_link_field] = target_id
            child_workflow = _find_entity_workflow(target_child_found[2], target_child_found[1].get("id"))
            child_errors, clean_child = _validate_record_payload(target_child_found[1], child_values, for_create=True, workflow=child_workflow)
            child_lookup_errors = _validate_lookup_fields(target_child_found[1], _registry_for_request(request), lambda m_id, m_hash: _get_snapshot(request, m_id, m_hash))
            child_errors.extend(child_lookup_errors)
            child_domain_errors = _enforce_lookup_domains(target_child_found[1], clean_child if isinstance(clean_child, dict) else {})
            child_errors.extend(child_domain_errors)
            child_errors.extend(
                _field_write_policy_errors(
                    actor,
                    target_child_found[0],
                    target_child_found[1],
                    clean_child if isinstance(clean_child, dict) else {},
                    allow_system_fields=True,
                )
            )
            child_errors.extend(_document_numbering_write_errors(actor, target_child_found[1], None, clean_child if isinstance(clean_child, dict) else {}))
            child_errors.extend(_document_numbering_assignment_errors(target_child_found[1], None, clean_child if isinstance(clean_child, dict) else {}, target_child_found[2], lifecycle_event="create"))
            if child_errors:
                for ent_id, rec_id in created_children:
                    generic_records.delete(ent_id, rec_id)
                generic_records.delete(target_entity, target_id)
                _log_record_validation_errors(target_child_entity, child_values, child_errors, child_workflow)
                return _validation_response(child_errors, [])
            created_child = _create_record_with_computed_fields(request, target_child_entity, target_child_found[1], clean_child)
            created_child_id, created_child_record = _unwrap_store_record(created_child if isinstance(created_child, dict) else None)
            if created_child_id:
                try:
                    created_child_record = _apply_document_numbering_after_write(
                        request,
                        target_child_found[1],
                        created_child_id,
                        None,
                        created_child_record if isinstance(created_child_record, dict) else clean_child,
                        actor,
                        target_child_found[2],
                        lifecycle_event="create",
                    )
                except SequenceError as exc:
                    for ent_id, rec_id in created_children:
                        generic_records.delete(ent_id, rec_id)
                    generic_records.delete(target_entity, target_id)
                    generic_records.delete(target_child_entity, created_child_id)
                    return _sequence_error_response(exc)
                created_children.append((target_child_entity, created_child_id))
                child_created_count += 1
        _resp_cache_invalidate_entity(target_child_entity)
        _resp_cache_invalidate_module_bootstrap(module_id)

    source_patch: dict = {}
    if isinstance(source_to_target_field, str) and source_to_target_field:
        source_patch[source_to_target_field] = target_id
    source_update = transformation.get("source_update") if isinstance(transformation.get("source_update"), dict) else {}
    source_update_patch = source_update.get("patch") if isinstance(source_update.get("patch"), dict) else {}
    source_patch.update(source_update_patch)
    updated_source_record = source_record
    if source_patch:
        source_workflow = _find_entity_workflow(source_found[2], source_found[1].get("id"))
        source_updates: list[tuple[str, dict, dict]] = []
        for idx, row in enumerate(selected_rows):
            row_id = row.get("record_id")
            row_record = row.get("record") if isinstance(row.get("record"), dict) else None
            if not isinstance(row_id, str) or not isinstance(row_record, dict):
                continue
            source_patch_errors, merged_source = _validate_patch_payload(source_found[1], source_patch, row_record, workflow=source_workflow)
            source_patch_errors.extend(
                _field_write_policy_errors(
                    actor,
                    source_found[0],
                    source_found[1],
                    source_patch if isinstance(source_patch, dict) else {},
                    allow_system_fields=True,
                )
            )
            source_patch_errors.extend(_document_numbering_write_errors(actor, source_found[1], row_record, merged_source if isinstance(merged_source, dict) else {}))
            source_patch_errors.extend(_document_numbering_assignment_errors(source_found[1], row_record, merged_source if isinstance(merged_source, dict) else {}, source_found[2], lifecycle_event="save"))
            if source_patch_errors:
                for ent_id, rec_id in created_children:
                    generic_records.delete(ent_id, rec_id)
                generic_records.delete(target_entity, target_id)
                for error in source_patch_errors:
                    if isinstance(error, dict) and idx > 0 and isinstance(error.get("path"), str):
                        error["path"] = f"selected_ids[{idx}].{error['path']}"
                return _validation_response(source_patch_errors, [])
            source_updates.append((row_id, row_record, merged_source))
        status_field = (source_workflow or {}).get("status_field")
        for row_id, before_record, merged_source in source_updates:
            updated_source = _update_record_with_computed_fields(request, source_entity, source_found[1], row_id, merged_source)
            _, after_record = _unwrap_store_record(updated_source if isinstance(updated_source, dict) else None)
            after_record = after_record if isinstance(after_record, dict) else merged_source
            try:
                after_record = _apply_document_numbering_after_write(
                    request,
                    source_found[1],
                    row_id,
                    before_record,
                    after_record,
                    actor,
                    source_found[2],
                    lifecycle_event="save",
                )
            except SequenceError as exc:
                return _sequence_error_response(exc)
            if row_id == source_id:
                updated_source_record = after_record
            _resp_cache_invalidate_record(source_entity, row_id)
            changed = _changed_fields(before_record or {}, after_record or {})
            before_snapshot = _automation_record_snapshot(before_record, source_found[1])
            after_snapshot = _automation_record_snapshot(after_record, source_found[1])
            _emit_triggers(
                request,
                module_id,
                manifest,
                "record.updated",
                {
                    "entity_id": source_found[1].get("id"),
                    "record_id": row_id,
                    "changed_fields": changed,
                    "before": before_snapshot,
                    "after": after_snapshot,
                    "user_id": (getattr(request.state, "actor", None) or {}).get("user_id"),
                    "timestamp": _now(),
                },
                entity_id=source_found[1].get("id"),
            )
            if isinstance(status_field, str) and before_record.get(status_field) != (after_record or {}).get(status_field):
                _emit_triggers(
                    request,
                    module_id,
                    manifest,
                    "workflow.status_changed",
                    {
                        "entity_id": source_found[1].get("id"),
                        "record_id": row_id,
                        "changed_fields": [status_field],
                        "from": before_record.get(status_field),
                        "to": (after_record or {}).get(status_field),
                        "before": before_snapshot,
                        "after": after_snapshot,
                        "user_id": (getattr(request.state, "actor", None) or {}).get("user_id"),
                        "timestamp": _now(),
                    },
                    entity_id=source_found[1].get("id"),
                    status_field=status_field,
                )
        _resp_cache_invalidate_entity(source_entity)
        _resp_cache_invalidate_module_bootstrap(module_id)

    target_to_source_field = link_fields.get("target_to_source")
    if isinstance(target_to_source_field, str) and target_to_source_field:
        target_patch_errors, merged_target = _validate_patch_payload(target_found[1], {target_to_source_field: source_id}, target_record, workflow=target_workflow)
        target_patch_errors.extend(
            _field_write_policy_errors(
                actor,
                target_found[0],
                target_found[1],
                {target_to_source_field: source_id},
                allow_system_fields=True,
            )
        )
        target_patch_errors.extend(_document_numbering_write_errors(actor, target_found[1], target_record, merged_target if isinstance(merged_target, dict) else {}))
        target_patch_errors.extend(_document_numbering_assignment_errors(target_found[1], target_record, merged_target if isinstance(merged_target, dict) else {}, target_found[2], lifecycle_event="save"))
        if target_patch_errors:
            for ent_id, rec_id in created_children:
                generic_records.delete(ent_id, rec_id)
            generic_records.delete(target_entity, target_id)
            return _validation_response(target_patch_errors, [])
        before_target_record = target_record if isinstance(target_record, dict) else None
        target_updated = _update_record_with_computed_fields(request, target_entity, target_found[1], target_id, merged_target)
        _, target_record = _unwrap_store_record(target_updated if isinstance(target_updated, dict) else None)
        try:
            target_record = _apply_document_numbering_after_write(
                request,
                target_found[1],
                target_id,
                before_target_record,
                target_record if isinstance(target_record, dict) else merged_target,
                actor,
                target_found[2],
                lifecycle_event="save",
            )
        except SequenceError as exc:
            return _sequence_error_response(exc)
        _resp_cache_invalidate_record(target_entity, target_id)
        _resp_cache_invalidate_entity(target_entity)
        _resp_cache_invalidate_module_bootstrap(module_id)

    activity_cfg = transformation.get("activity") if isinstance(transformation.get("activity"), dict) else {}
    source_record_ids = [row.get("record_id") for row in selected_rows if isinstance(row.get("record_id"), str)]
    if activity_cfg.get("enabled") is not False:
        event_type = activity_cfg.get("event_type") if isinstance(activity_cfg.get("event_type"), str) else "transform"
        targets = activity_cfg.get("targets") if isinstance(activity_cfg.get("targets"), list) else ["source", "target"]
        payload = {
            "transformation_key": transformation_key,
            "source_entity_id": source_entity,
            "source_record_id": source_id,
            "source_record_ids": source_record_ids,
            "target_entity_id": target_entity,
            "target_record_id": target_id,
            "child_created": child_created_count,
        }
        if "source" in targets:
            for source_record_id in source_record_ids:
                try:
                    activity_store.add_event(source_entity, source_record_id, event_type, payload, actor=getattr(request.state, "user", None))
                except Exception:
                    pass
        if "target" in targets:
            try:
                activity_store.add_event(target_entity, target_id, event_type, payload, actor=getattr(request.state, "user", None))
            except Exception:
                pass

    feed_cfg = transformation.get("feed") if isinstance(transformation.get("feed"), dict) else {}
    if feed_cfg.get("enabled") is True:
        targets = feed_cfg.get("targets") if isinstance(feed_cfg.get("targets"), list) else ["source"]
        message = _render_transform_feed_message(feed_cfg.get("message"), source_entity, source_id, target_entity, target_id)
        if "source" in targets:
            for source_record_id in source_record_ids:
                _add_chatter_entry(source_entity, source_record_id, "system", message, getattr(request.state, "user", None))
        if "target" in targets:
            _add_chatter_entry(target_entity, target_id, "system", message, getattr(request.state, "user", None))

    hooks_cfg = transformation.get("hooks") if isinstance(transformation.get("hooks"), dict) else {}
    emit_events = hooks_cfg.get("emit_events") if isinstance(hooks_cfg.get("emit_events"), list) else []
    hook_payload = {
        "transformation_key": transformation_key,
        "source_entity_id": source_entity,
        "source_record_id": source_id,
        "source_record_ids": source_record_ids,
        "target_entity_id": target_entity,
        "target_record_id": target_id,
        "child_created": child_created_count,
        "action_id": action_id,
    }
    for event_name in emit_events:
        if isinstance(event_name, str) and event_name:
            _emit_transform_hook_event(request, module_id, manifest, event_name, hook_payload)

    _emit_triggers(
        request,
        module_id,
        manifest,
        "record.created",
        {
            "entity_id": target_found[1].get("id"),
            "record_id": target_id,
            "changed_fields": sorted((target_record or {}).keys()),
            "record": _automation_record_snapshot(target_record, target_found[1]),
            "user_id": (getattr(request.state, "actor", None) or {}).get("user_id"),
            "timestamp": _now(),
        },
        entity_id=target_found[1].get("id"),
    )
    _emit_triggers(
        request,
        module_id,
        manifest,
        "action.clicked",
        {
            "action_id": action_id,
            "kind": "transform_record",
            "entity_id": target_found[1].get("id"),
            "record_id": target_id,
            "record": _automation_record_snapshot(target_record, target_found[1]),
            "source_record_id": source_id,
            "source_record_ids": source_record_ids,
            "source_entity_id": source_found[1].get("id"),
            "target_entity_id": target_found[1].get("id"),
            "changed_fields": sorted((target_record or {}).keys()),
            "user_id": (getattr(request.state, "actor", None) or {}).get("user_id"),
            "timestamp": _now(),
        },
        action_id=action_id,
    )
    phase_ms["total"] = (time.perf_counter() - action_start) * 1000
    _action_logger.info("action_perf=%s", {"action_id": action_id, "kind": "transform_record", "ms": phase_ms})
    return _ok_response(
        {
            "result": {
                "record_id": target_id,
                "record": _mask_record_for_actor(actor, target_found[0], target_found[1], target_record) if _record_visible_for_actor(actor, target_found[0], target_entity, target_record) else None,
                "entity_id": target_entity,
                "kind": "transform_record",
                "transformation_key": transformation_key,
                "source_record_id": source_id,
                "source_entity_id": source_entity,
                "source_record": _mask_record_for_actor(actor, source_found[0], source_found[1], updated_source_record) if _record_visible_for_actor(actor, source_found[0], source_entity, updated_source_record) else None,
                "source_record_ids": source_record_ids,
                "child_created": child_created_count,
            }
        }
    )


@app.post("/actions/run")
async def run_action(request: Request) -> dict:
    body = await _safe_json(request)
    module_id = body.get("module_id") if isinstance(body, dict) else None
    action_id = body.get("action_id") if isinstance(body, dict) else None
    context = body.get("context") if isinstance(body, dict) else {}
    return _run_action_core(request, module_id, action_id, context)


def _run_action_core(request: Request, module_id: str | None, action_id: str | None, context: dict | None) -> dict:
    action_start = time.perf_counter()
    phase_ms: dict[str, float] = {}
    if not isinstance(module_id, str) or not module_id:
        return _error_response("ACTION_INVALID", "module_id is required", "module_id", status=400)
    if not isinstance(action_id, str) or not action_id:
        return _error_response("ACTION_INVALID", "action_id is required", "action_id", status=400)
    context = context if isinstance(context, dict) else {}
    t0 = time.perf_counter()
    module, manifest = _get_installed_manifest(request, module_id)
    phase_ms["load_manifest"] = (time.perf_counter() - t0) * 1000
    if module is None:
        return _error_response("MODULE_NOT_INSTALLED", "Module not installed", "module_id", status=404)
    if not module.get("enabled"):
        return _error_response("MODULE_DISABLED", "Module is disabled", "module_id", status=400)
    if manifest is None:
        return _error_response("MODULE_NOT_FOUND", "Module manifest not found", "module_id", status=404)
    actor = getattr(request.state, "actor", None)
    if not _module_visible_for_actor(actor, module_id):
        return _error_response("FORBIDDEN", "Module access denied", "module_id", status=403)

    t0 = time.perf_counter()
    manifest_hash = module.get("current_hash") if isinstance(module, dict) else None
    compiled = _get_compiled_manifest(module_id, manifest_hash, manifest) if manifest_hash else None
    action = compiled.get("action_by_id", {}).get(action_id) if isinstance(compiled, dict) else None
    if not action:
        action = _resolve_action(manifest, action_id)
    phase_ms["resolve_action"] = (time.perf_counter() - t0) * 1000
    if not action:
        return _error_response("ACTION_NOT_FOUND", "Action not found", "action_id", status=404)
    if not _action_visible_for_actor(actor, module_id, action_id):
        return _error_response("FORBIDDEN", "Action access denied", "action_id", status=403)
    kind = action.get("kind")
    if kind not in ALLOWED_ACTION_KINDS:
        return _error_response("ACTION_INVALID", "Action kind not allowed", "kind", status=400)
    if kind in {"create_record", "update_record", "bulk_update", "transform_record"}:
        denied = _require_capability(actor, "records.write", "Write access required")
        if denied:
            return denied

    record_context = {}
    if isinstance(context, dict):
        record_context = context.get("record") or context.get("record_draft") or {}
    # Automation/module action steps often provide only entity_id + record_id.
    # Hydrate the current record before evaluating action guards so enabled_when /
    # visible_when behave the same as interactive UI-triggered actions.
    if not isinstance(record_context, dict) or not record_context:
        candidate_entity_id = action.get("entity_id") if isinstance(action.get("entity_id"), str) else None
        candidate_record_id = context.get("record_id") if isinstance(context, dict) else None
        if isinstance(candidate_entity_id, str) and candidate_entity_id:
            candidate_entity_id = _normalize_entity_id(candidate_entity_id)
        if isinstance(candidate_entity_id, str) and candidate_entity_id and isinstance(candidate_record_id, str) and candidate_record_id:
            _, existing_context_record = _get_record_for_entity_candidates(candidate_entity_id, candidate_record_id)
            if isinstance(existing_context_record, dict) and isinstance(existing_context_record.get("record"), dict):
                record_context = existing_context_record.get("record") or {}
    try:
        t0 = time.perf_counter()
        enabled_when = action.get("enabled_when")
        if enabled_when and not eval_condition(enabled_when, {"record": record_context}):
            return _error_response("ACTION_DISABLED", "Action is disabled", "action_id", status=400)
        visible_when = action.get("visible_when")
        if visible_when and not eval_condition(visible_when, {"record": record_context}):
            return _error_response("ACTION_DISABLED", "Action is hidden", "action_id", status=400)
        phase_ms["guard_eval"] = (time.perf_counter() - t0) * 1000
    except Exception:
        return _error_response("ACTION_INVALID", "Action condition failed", "action_id", status=400)

    if kind in {"navigate", "open_form", "refresh"}:
        record_id = context.get("record_id") if isinstance(context, dict) else None
        entity_id = action.get("entity_id") if isinstance(action.get("entity_id"), str) else None
        record_snapshot = None
        if isinstance(entity_id, str) and entity_id:
            entity_id = _normalize_entity_id(entity_id)
        if isinstance(entity_id, str) and entity_id and isinstance(record_id, str) and record_id:
            found_entity_id, existing = _get_record_for_entity_candidates(entity_id, record_id)
            if not isinstance(found_entity_id, str) or not found_entity_id:
                found_entity_id = entity_id
            found = _find_entity_def(request, found_entity_id)
            entity_def = found[1] if found else None
            if isinstance(existing, dict) and isinstance(existing.get("record"), dict):
                record_snapshot = _automation_record_snapshot(existing.get("record"), entity_def)
        _activity_add_action_event(
            entity_id,
            record_id,
            action_id,
            action.get("label") if isinstance(action.get("label"), str) else None,
            kind,
            actor=getattr(request.state, "user", None),
        )
        _emit_triggers(
            request,
            module_id,
            manifest,
            "action.clicked",
            {
                "action_id": action_id,
                "kind": kind,
                "entity_id": entity_id,
                "record_id": record_id,
                "record": record_snapshot,
                "changed_fields": sorted((record_snapshot or {}).get("flat", {}).keys()),
                "user_id": (getattr(request.state, "actor", None) or {}).get("user_id"),
                "timestamp": _now(),
            },
            action_id=action_id,
        )
        return _ok_response({"result": {"kind": kind, "target": action.get("target")}})

    if kind == "transform_record":
        return _run_transform_record_action(
            request=request,
            module_id=module_id,
            manifest=manifest,
            compiled=compiled if isinstance(compiled, dict) else None,
            action_id=action_id,
            action=action,
            context=context,
            actor=actor,
            phase_ms=phase_ms,
            action_start=action_start,
        )

    entity_id = action.get("entity_id")
    if not isinstance(entity_id, str) or not entity_id:
        return _error_response("ACTION_INVALID", "entity_id is required", "entity_id", status=400)
    entity_id = _normalize_entity_id(entity_id)
    found = _find_entity_def(request, entity_id)
    if not found:
        return _error_response("ENTITY_NOT_FOUND", "Entity not found or disabled", "entity_id", status=404)
    entity_def = found[1]
    denied = _entity_access_denied_response(actor, found[0], entity_id, write=(kind in {"create_record", "update_record", "bulk_update", "transform_record"}))
    if denied:
        return denied

    if kind == "create_record":
        t0 = time.perf_counter()
        values = action.get("defaults") if isinstance(action.get("defaults"), dict) else {}
        values = _resolve_action_templates(values, context)
        workflow = _find_entity_workflow(found[2], entity_def.get("id"))
        errors, clean = _validate_record_payload(entity_def, values, for_create=True, workflow=workflow)
        lookup_errors = _validate_lookup_fields(entity_def, _registry_for_request(request), lambda module_id, manifest_hash: _get_snapshot(request, module_id, manifest_hash))
        errors.extend(lookup_errors)
        domain_errors = _enforce_lookup_domains(entity_def, clean if isinstance(clean, dict) else {})
        errors.extend(domain_errors)
        errors.extend(_field_write_policy_errors(actor, found[0], entity_def, clean if isinstance(clean, dict) else {}))
        errors.extend(_document_numbering_write_errors(actor, entity_def, None, clean if isinstance(clean, dict) else {}))
        errors.extend(_document_numbering_assignment_errors(entity_def, None, clean if isinstance(clean, dict) else {}, found[2], lifecycle_event="create"))
        if errors:
            _log_record_validation_errors(entity_id, values, errors, workflow)
            return _validation_response(errors, [])
        phase_ms["validate"] = (time.perf_counter() - t0) * 1000
        t0 = time.perf_counter()
        try:
            record = _create_record_with_computed_fields(request, entity_id, entity_def, clean)
        except Exception as exc:
            constraint = _wrap_db_constraint_error(exc)
            if constraint:
                return _error_response(
                    "RECORD_WRITE_FAILED",
                    "Record create failed due to constraint",
                    "record",
                    detail=constraint.get("detail"),
                    status=400,
                )
            raise
        _add_chatter_entry(entity_id, record["record_id"], "system", "Record created", getattr(request.state, "user", None))
        created_record = record.get("record") if isinstance(record, dict) else None
        created_id = record.get("record_id") if isinstance(record, dict) else None
        if created_id and isinstance(created_record, dict):
            try:
                created_record = _apply_document_numbering_after_write(
                    request,
                    entity_def,
                    created_id,
                    None,
                    created_record,
                    actor,
                    found[2],
                    lifecycle_event="create",
                )
                record["record"] = created_record
            except SequenceError as exc:
                return _sequence_error_response(exc)
            _activity_add_record_created_event(entity_def, created_id, created_record, actor=getattr(request.state, "user", None))
            _activity_add_action_event(
                entity_def.get("id"),
                created_id,
                action_id,
                action.get("label") if isinstance(action.get("label"), str) else None,
                kind,
                actor=getattr(request.state, "user", None),
                extra_payload={"record_created": True},
            )
        _resp_cache_invalidate_entity(entity_id)
        _resp_cache_invalidate_module_bootstrap(module_id)
        phase_ms["write"] = (time.perf_counter() - t0) * 1000
        phase_ms["total"] = (time.perf_counter() - action_start) * 1000
        _action_logger.info("action_perf=%s", {"action_id": action_id, "kind": kind, "ms": phase_ms})
        if created_id and isinstance(created_record, dict):
            created_snapshot = _automation_record_snapshot(created_record, entity_def)
            _emit_triggers(
                request,
                module_id,
                manifest,
                "record.created",
                {
                    "entity_id": entity_def.get("id"),
                    "record_id": created_id,
                    "changed_fields": sorted(created_record.keys()),
                    "record": created_snapshot,
                    "user_id": (getattr(request.state, "actor", None) or {}).get("user_id"),
                    "timestamp": _now(),
                },
                entity_id=entity_def.get("id"),
            )
        _emit_triggers(
            request,
            module_id,
            manifest,
            "action.clicked",
            {
                "action_id": action_id,
                "kind": kind,
                "entity_id": entity_def.get("id"),
                "record_id": created_id,
                "record": created_snapshot if created_id and isinstance(created_record, dict) else None,
                "changed_fields": sorted(created_record.keys()) if isinstance(created_record, dict) else [],
                "user_id": (getattr(request.state, "actor", None) or {}).get("user_id"),
                "timestamp": _now(),
            },
            action_id=action_id,
        )
        return _ok_response({"result": {"record_id": record["record_id"], "record": _mask_record_for_actor(actor, found[0], entity_def, record["record"]), "entity_id": entity_id}})

    patch = action.get("patch") if isinstance(action.get("patch"), dict) else {}
    patch = _resolve_action_templates(patch, context)
    if kind == "update_record":
        t0 = time.perf_counter()
        record_id = context.get("record_id") if isinstance(context, dict) else None
        if not isinstance(record_id, str) or not record_id:
            return _error_response("ACTION_INVALID", "record_id is required", "record_id", status=400)
        found_entity_id, existing = _get_record_for_entity_candidates(entity_id, record_id)
        if not isinstance(found_entity_id, str) or not found_entity_id:
            found_entity_id = entity_id
        if not existing:
            return _error_response("RECORD_NOT_FOUND", "Record not found", "record_id", status=404)
        denied = _entity_access_denied_response(actor, found[0], found_entity_id, write=True)
        if denied:
            return denied
        existing_record = existing.get("record") if isinstance(existing, dict) else None
        if not isinstance(existing_record, dict) or not _record_visible_for_actor(actor, found[0], found_entity_id, existing_record):
            return _error_response("RECORD_NOT_FOUND", "Record not found", "record_id", status=404)
        if not _record_write_allowed_for_actor(actor, found[0], found_entity_id, existing_record):
            return _error_response("FORBIDDEN", "Record write access denied", "record_id", status=403)
        phase_ms["load_record"] = (time.perf_counter() - t0) * 1000
        t0 = time.perf_counter()
        workflow = _find_entity_workflow(found[2], entity_def.get("id"))
        errors, updated = _validate_patch_payload(entity_def, patch, existing_record or {}, workflow=workflow)
        errors.extend(_field_write_policy_errors(actor, found[0], entity_def, patch if isinstance(patch, dict) else {}))
        errors.extend(_document_numbering_write_errors(actor, entity_def, existing_record, updated if isinstance(updated, dict) else {}))
        errors.extend(_document_numbering_assignment_errors(entity_def, existing_record, updated if isinstance(updated, dict) else {}, found[2], lifecycle_event="save"))
        if errors:
            _log_record_validation_errors(entity_id, patch, errors, workflow)
            return _validation_response(errors, [])
        phase_ms["validate"] = (time.perf_counter() - t0) * 1000
        t0 = time.perf_counter()
        target_entity_id = found_entity_id
        try:
            record = _update_record_with_computed_fields(request, target_entity_id, entity_def, record_id, updated)
        except Exception as exc:
            constraint = _wrap_db_constraint_error(exc)
            if constraint:
                return _error_response(
                    "RECORD_WRITE_FAILED",
                    "Record update failed due to constraint",
                    "record",
                    detail=constraint.get("detail"),
                    status=400,
                )
            raise
        after_record = record.get("record") if isinstance(record, dict) else None
        before_record = existing.get("record") if isinstance(existing, dict) else None
        if isinstance(after_record, dict):
            try:
                after_record = _apply_document_numbering_after_write(
                    request,
                    entity_def,
                    record_id,
                    before_record,
                    after_record,
                    actor,
                    found[2],
                    lifecycle_event="save",
                )
                record["record"] = after_record
            except SequenceError as exc:
                return _sequence_error_response(exc)
        _add_chatter_entry(target_entity_id, record_id, "system", "Record updated", getattr(request.state, "user", None))
        _resp_cache_invalidate_record(target_entity_id, record_id)
        _resp_cache_invalidate_entity(target_entity_id)
        _resp_cache_invalidate_module_bootstrap(module_id)
        phase_ms["write"] = (time.perf_counter() - t0) * 1000
        phase_ms["total"] = (time.perf_counter() - action_start) * 1000
        _action_logger.info("action_perf=%s", {"action_id": action_id, "kind": kind, "ms": phase_ms})
        changed = _changed_fields(before_record or {}, after_record or {})
        activity_cfg = _activity_view_config(found[2], entity_def.get("id"))
        if isinstance(after_record, dict) and isinstance(before_record, dict) and isinstance(activity_cfg, dict):
            show_changes = activity_cfg.get("show_changes", True) is not False
            tracked_fields = activity_cfg.get("tracked_fields") if isinstance(activity_cfg.get("tracked_fields"), list) else None
            if show_changes:
                changes = _collect_activity_changes(entity_def, before_record, after_record, tracked_fields=tracked_fields)
                if changes:
                    try:
                        activity_store.add_change(
                            entity_def.get("id"),
                            record_id,
                            changes,
                            actor=getattr(request.state, "user", None),
                        )
                    except Exception:
                        pass
        status_field = (workflow or {}).get("status_field")
        if isinstance(status_field, str) and isinstance(before_record, dict) and isinstance(after_record, dict):
            if before_record.get(status_field) != after_record.get(status_field):
                _activity_add_status_change_event(
                    entity_def,
                    record_id,
                    status_field,
                    before_record.get(status_field),
                    after_record.get(status_field),
                    actor=getattr(request.state, "user", None),
                )
        _activity_add_action_event(
            entity_def.get("id"),
            record_id,
            action_id,
            action.get("label") if isinstance(action.get("label"), str) else None,
            kind,
            actor=getattr(request.state, "user", None),
            extra_payload={"changed_fields": changed},
        )
        if isinstance(after_record, dict):
            before_snapshot = _automation_record_snapshot(before_record, entity_def)
            after_snapshot = _automation_record_snapshot(after_record, entity_def)
            _emit_triggers(
                request,
                module_id,
                manifest,
                "record.updated",
                {
                    "entity_id": entity_def.get("id"),
                    "record_id": record_id,
                    "changed_fields": changed,
                    "before": before_snapshot,
                    "after": after_snapshot,
                    "user_id": (getattr(request.state, "actor", None) or {}).get("user_id"),
                    "timestamp": _now(),
                },
                entity_id=entity_def.get("id"),
            )
            if isinstance(status_field, str) and before_record and before_record.get(status_field) != after_record.get(status_field):
                _emit_triggers(
                    request,
                    module_id,
                    manifest,
                    "workflow.status_changed",
                    {
                        "entity_id": entity_def.get("id"),
                        "record_id": record_id,
                        "changed_fields": [status_field],
                        "from": before_record.get(status_field),
                        "to": after_record.get(status_field),
                        "before": before_snapshot,
                        "after": after_snapshot,
                        "user_id": (getattr(request.state, "actor", None) or {}).get("user_id"),
                        "timestamp": _now(),
                    },
                    entity_id=entity_def.get("id"),
                    status_field=status_field,
                )
        _emit_triggers(
            request,
            module_id,
            manifest,
            "action.clicked",
            {
                "action_id": action_id,
                "kind": kind,
                "entity_id": entity_def.get("id"),
                "record_id": record_id,
                "record": after_snapshot if isinstance(after_record, dict) else None,
                "changed_fields": changed,
                "user_id": (getattr(request.state, "actor", None) or {}).get("user_id"),
                "timestamp": _now(),
            },
            action_id=action_id,
        )
        return _ok_response({"result": {"record_id": record["record_id"], "record": _mask_record_for_actor(actor, found[0], entity_def, record["record"]), "entity_id": entity_id}})

    if kind == "bulk_update":
        t0 = time.perf_counter()
        selected_ids = context.get("selected_ids") if isinstance(context, dict) else None
        if not isinstance(selected_ids, list) or len(selected_ids) == 0:
            return _error_response("ACTION_INVALID", "selected_ids is required", "selected_ids", status=400)
        updated_count = 0
        updated_ids = []
        last_updated_record = None
        for record_id in selected_ids:
            if not isinstance(record_id, str):
                continue
            target_entity_id, existing = _get_record_for_entity_candidates(entity_id, record_id)
            if not isinstance(target_entity_id, str) or not target_entity_id:
                target_entity_id = entity_id
            if not existing:
                continue
            before_record = existing.get("record") if isinstance(existing, dict) else {}
            if not isinstance(before_record, dict) or not _record_visible_for_actor(actor, found[0], target_entity_id, before_record):
                return _error_response("RECORD_NOT_FOUND", "Record not found", "selected_ids", status=404)
            if not _record_write_allowed_for_actor(actor, found[0], target_entity_id, before_record):
                return _error_response("FORBIDDEN", "Record write access denied", "selected_ids", status=403)
            updated = dict(before_record or {})
            updated.update(patch)
            workflow = _find_entity_workflow(found[2], entity_def.get("id"))
            errors, clean = _validate_record_payload(entity_def, updated, for_create=False, workflow=workflow)
            lookup_errors = _validate_lookup_fields(entity_def, _registry_for_request(request), lambda module_id, manifest_hash: _get_snapshot(request, module_id, manifest_hash))
            errors.extend(lookup_errors)
            domain_errors = _enforce_lookup_domains(entity_def, clean if isinstance(clean, dict) else {})
            errors.extend(domain_errors)
            errors.extend(_field_write_policy_errors(actor, found[0], entity_def, patch if isinstance(patch, dict) else {}))
            errors.extend(_document_numbering_write_errors(actor, entity_def, before_record, clean if isinstance(clean, dict) else {}))
            errors.extend(_document_numbering_assignment_errors(entity_def, before_record, clean if isinstance(clean, dict) else {}, found[2], lifecycle_event="save"))
            if errors:
                return _validation_response(errors, [])
            updated_record = _update_record_with_computed_fields(request, target_entity_id, entity_def, record_id, clean)
            _add_chatter_entry(target_entity_id, record_id, "system", "Record updated", getattr(request.state, "user", None))
            updated_count += 1
            updated_ids.append(record_id)
            after_record = updated_record.get("record") if isinstance(updated_record, dict) else None
            if isinstance(after_record, dict):
                try:
                    after_record = _apply_document_numbering_after_write(
                        request,
                        entity_def,
                        record_id,
                        before_record,
                        after_record,
                        actor,
                        found[2],
                        lifecycle_event="save",
                    )
                    updated_record["record"] = after_record
                except SequenceError as exc:
                    return _sequence_error_response(exc)
            if isinstance(after_record, dict):
                last_updated_record = after_record
            changed = _changed_fields(before_record or {}, after_record or {})
            activity_cfg = _activity_view_config(found[2], entity_def.get("id"))
            if isinstance(after_record, dict) and isinstance(before_record, dict) and isinstance(activity_cfg, dict):
                show_changes = activity_cfg.get("show_changes", True) is not False
                tracked_fields = activity_cfg.get("tracked_fields") if isinstance(activity_cfg.get("tracked_fields"), list) else None
                if show_changes:
                    changes = _collect_activity_changes(entity_def, before_record, after_record, tracked_fields=tracked_fields)
                    if changes:
                        try:
                            activity_store.add_change(
                                entity_def.get("id"),
                                record_id,
                                changes,
                                actor=getattr(request.state, "user", None),
                            )
                        except Exception:
                            pass
            status_field = (workflow or {}).get("status_field")
            if isinstance(status_field, str) and isinstance(after_record, dict) and before_record.get(status_field) != after_record.get(status_field):
                _activity_add_status_change_event(
                    entity_def,
                    record_id,
                    status_field,
                    before_record.get(status_field),
                    after_record.get(status_field),
                    actor=getattr(request.state, "user", None),
                )
            _activity_add_action_event(
                entity_def.get("id"),
                record_id,
                action_id,
                action.get("label") if isinstance(action.get("label"), str) else None,
                kind,
                actor=getattr(request.state, "user", None),
                extra_payload={"changed_fields": changed, "bulk": True},
            )
            if isinstance(after_record, dict):
                before_snapshot = _automation_record_snapshot(before_record, entity_def)
                after_snapshot = _automation_record_snapshot(after_record, entity_def)
                _emit_triggers(
                    request,
                    module_id,
                    manifest,
                    "record.updated",
                    {
                        "entity_id": entity_def.get("id"),
                        "record_id": record_id,
                        "changed_fields": changed,
                        "before": before_snapshot,
                        "after": after_snapshot,
                        "user_id": (getattr(request.state, "actor", None) or {}).get("user_id"),
                        "timestamp": _now(),
                    },
                    entity_id=entity_def.get("id"),
                )
                status_field = (workflow or {}).get("status_field")
                if isinstance(status_field, str) and before_record and before_record.get(status_field) != after_record.get(status_field):
                    _emit_triggers(
                        request,
                        module_id,
                        manifest,
                        "workflow.status_changed",
                        {
                            "entity_id": entity_def.get("id"),
                            "record_id": record_id,
                            "changed_fields": [status_field],
                            "from": before_record.get(status_field),
                            "to": after_record.get(status_field),
                            "before": before_snapshot,
                            "after": after_snapshot,
                            "user_id": (getattr(request.state, "actor", None) or {}).get("user_id"),
                            "timestamp": _now(),
                        },
                        entity_id=entity_def.get("id"),
                        status_field=status_field,
                    )
        _resp_cache_invalidate_entity(entity_id)
        _resp_cache_invalidate_module_bootstrap(module_id)
        phase_ms["bulk_total"] = (time.perf_counter() - t0) * 1000
        phase_ms["total"] = (time.perf_counter() - action_start) * 1000
        _action_logger.info("action_perf=%s", {"action_id": action_id, "kind": kind, "ms": phase_ms, "updated": updated_count})
        _emit_triggers(
            request,
            module_id,
            manifest,
            "action.clicked",
            {
                "action_id": action_id,
                "kind": kind,
                "entity_id": entity_def.get("id"),
                "record_id": updated_ids[0] if len(updated_ids) == 1 else None,
                "record": _automation_record_snapshot(last_updated_record, entity_def) if len(updated_ids) == 1 and isinstance(last_updated_record, dict) else None,
                "record_ids": updated_ids,
                "changed_fields": list(patch.keys()) if isinstance(patch, dict) else [],
                "user_id": (getattr(request.state, "actor", None) or {}).get("user_id"),
                "timestamp": _now(),
            },
            action_id=action_id,
        )
        return _ok_response(
            {
                "result": {
                    "updated": updated_count,
                    "entity_id": entity_def.get("id"),
                    "record_id": updated_ids[0] if len(updated_ids) == 1 else None,
                    "record_ids": updated_ids,
                    "record": last_updated_record if len(updated_ids) == 1 and isinstance(last_updated_record, dict) else None,
                }
            }
        )

    return _error_response("ACTION_INVALID", "Unhandled action kind", "kind", status=400)


def run_action_internal(module_id: str, action_id: str, context: dict | None, actor: dict | None = None) -> dict:
    effective_actor = actor or {"user_id": "system", "workspace_role": "admin", "platform_role": "superadmin"}
    internal_req = SimpleNamespace(
        state=SimpleNamespace(cache={}, actor=effective_actor),
        headers={},
    )
    return _run_action_core(internal_req, module_id, action_id, context or {})


@app.get("/automations/meta")
async def automations_meta(request: Request) -> dict:
    actor = _resolve_actor(request)
    denied = _require_capability(actor, "automations.manage", "Admin role required")
    if denied:
        return denied
    org_id = actor.get("workspace_id") or "default"
    cache_key = f"automations_meta:{org_id}"
    cached = _resp_cache_get(cache_key)
    if cached is not None:
        logger.info("cache_hit=automations_meta key=%s", cache_key)
        return cached
    event_types = [
        "record.created",
        "record.updated",
        "workflow.status_changed",
        "action.clicked",
        "schedule.tick",
        "integration.webhook.received",
        "integration.sync.completed",
        "integration.sync.item",
        "integration.sync.failed",
    ]
    event_catalog: list[dict] = []
    system_actions = [
        {"id": "system.notify", "label": "Send notification"},
        {"id": "system.send_email", "label": "Send email"},
        {"id": "system.generate_document", "label": "Generate document"},
        {"id": "system.create_record", "label": "Create record"},
        {"id": "system.update_record", "label": "Update record"},
        {"id": "system.query_records", "label": "Query records"},
        {"id": "system.add_chatter", "label": "Add activity note"},
        {"id": "system.apply_integration_mapping", "label": "Apply integration mapping"},
        {"id": "system.integration_request", "label": "Call integration"},
        {"id": "system.integration_sync", "label": "Run integration sync"},
        {"id": "system.shopify_sync_product_media", "label": "Sync Shopify product media"},
        {"id": "system.noop", "label": "No-op (test)"},
    ]
    entities: list[dict] = []
    module_actions: list[dict] = []
    for mod in _get_registry_list(request):
        if not mod.get("enabled"):
            continue
        module_id = mod.get("module_id")
        manifest_hash = mod.get("current_hash")
        if not module_id or not manifest_hash:
            continue
        try:
            manifest = _get_snapshot(request, module_id, manifest_hash)
        except Exception:
            continue
        for ent in manifest.get("entities", []) if isinstance(manifest.get("entities"), list) else []:
            if not isinstance(ent, dict):
                continue
            ent_id = ent.get("id")
            if not isinstance(ent_id, str) or not ent_id:
                continue
            field_items: list[dict] = []
            fields = ent.get("fields")
            if isinstance(fields, list):
                for field in fields:
                    if not isinstance(field, dict):
                        continue
                    field_id = field.get("id")
                    if not isinstance(field_id, str) or not field_id:
                        continue
                    field_items.append(
                        {
                            "id": field_id,
                            "label": field.get("label") or field_id,
                            "type": field.get("type"),
                            "entity": field.get("entity"),
                            "display_field": field.get("display_field"),
                        }
                    )
            entities.append(
                {
                    "id": ent_id,
                    "label": ent.get("label") or ent.get("name") or ent_id,
                    "display_field": ent.get("display_field"),
                    "module_id": module_id,
                    "module_name": mod.get("name"),
                    "fields": field_items,
                }
            )
        actions = []
        module_slug = (manifest.get("module") or {}).get("id")
        if not isinstance(module_slug, str) or not module_slug:
            module_slug = module_id
        for trigger in manifest.get("triggers", []) if isinstance(manifest.get("triggers"), list) else []:
            if not isinstance(trigger, dict):
                continue
            trig_id = trigger.get("id")
            if not isinstance(trig_id, str) or not trig_id:
                continue
            event_types.append(trig_id)
            event = trigger.get("event")
            if event == "action.clicked":
                kind = "action_click"
            elif event == "workflow.status_changed":
                kind = "workflow_change"
            elif event in {"record.created", "record.updated"}:
                kind = "record_event"
            else:
                kind = "event"
            event_catalog.append(
                {
                    "id": trig_id,
                    "label": trigger.get("label") or trig_id,
                    "source_module_id": module_id,
                    "source_module_name": mod.get("name"),
                    "entity_id": trigger.get("entity_id"),
                    "kind": kind,
                    "payload_schema": {},
                }
            )
        for action in manifest.get("actions", []) if isinstance(manifest.get("actions"), list) else []:
            if not isinstance(action, dict):
                continue
            kind = action.get("kind")
            if kind not in {"create_record", "update_record", "bulk_update", "transform_record", "navigate", "open_form", "refresh"}:
                continue
            actions.append(
                {
                    "id": action.get("id"),
                    "label": action.get("label") or action.get("id"),
                    "kind": kind,
                    "entity_id": action.get("entity_id"),
                    "display_id": f"{module_slug}.{action.get('id')}",
                }
            )
        if actions:
            module_actions.append({"module_id": module_id, "module_name": mod.get("name"), "actions": actions})
    workspace_id = actor.get("workspace_id")
    members = _ai_workspace_members_for_request(request, workspace_id)
    connections = connection_store.list() if connection_store else []
    integration_mappings = integration_mapping_store.list() if integration_mapping_store else []
    if email_store:
        try:
            email_templates = email_store.list_templates()
        except TypeError:
            email_templates = email_store.list_templates(workspace_id or "default")
    else:
        email_templates = []
    if doc_template_store:
        try:
            doc_templates = doc_template_store.list()
        except TypeError:
            doc_templates = doc_template_store.list(workspace_id or "default")
    else:
        doc_templates = []
    response = _ok_response(
        {
            "event_types": list(dict.fromkeys(event_types)),
            "event_catalog": event_catalog,
            "system_actions": system_actions,
            "module_actions": module_actions,
            "entities": entities,
            "members": members,
            "connections": connections,
            "integration_mappings": integration_mappings,
            "email_templates": email_templates,
            "doc_templates": doc_templates,
        }
    )
    _resp_cache_set(cache_key, response)
    logger.info("cache_miss=automations_meta key=%s", cache_key)
    return response


@app.get("/automations/{automation_id}/export")
async def export_automation(request: Request, automation_id: str) -> dict:
    actor = _resolve_actor(request)
    denied = _require_capability(actor, "automations.manage", "Admin role required")
    if denied:
        return denied
    automation = automation_store.get(automation_id)
    if not automation:
        return _error_response("AUTOMATION_NOT_FOUND", "Automation not found", "automation_id", status=404)
    payload = {
        "name": automation.get("name"),
        "description": automation.get("description"),
        "trigger": automation.get("trigger") or {},
        "steps": automation.get("steps") or [],
    }
    return _ok_response({"automation": payload})


@app.post("/automations/import")
async def import_automation(request: Request) -> dict:
    actor = _resolve_actor(request)
    denied = _require_capability(actor, "automations.manage", "Admin role required")
    if denied:
        return denied
    body = await _safe_json(request)
    if not isinstance(body, dict):
        return _error_response("AUTOMATION_INVALID", "Invalid payload", "body", status=400)
    data = body.get("automation") if isinstance(body.get("automation"), dict) else body
    if not isinstance(data, dict):
        return _error_response("AUTOMATION_INVALID", "Invalid automation", "automation", status=400)
    name = data.get("name") or "Imported Automation"
    record = {
        "name": name,
        "description": data.get("description") or "",
        "status": "draft",
        "trigger": data.get("trigger") or {},
        "steps": data.get("steps") or [],
    }
    automation = automation_store.create(record)
    return _ok_response({"automation": automation})


