@app.post("/system/dashboard/query")
async def system_dashboard_query(request: Request) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_capability(actor, "records.read", "Read access required")
    if denied:
        return denied
    body = await _safe_json(request)
    source_key = body.get("source_key") if isinstance(body, dict) else None
    group_by = body.get("group_by") if isinstance(body, dict) else None
    measure = body.get("measure") if isinstance(body, dict) else None
    date_field = body.get("date_field") if isinstance(body, dict) else None
    start = body.get("start") if isinstance(body, dict) else None
    end = body.get("end") if isinstance(body, dict) else None
    limit = body.get("limit") if isinstance(body, dict) else 2000
    q = body.get("q") if isinstance(body, dict) else None
    source_filter = body.get("filter") if isinstance(body, dict) else None
    actor_ctx = _actor_domain_context(actor)
    sources = _collect_interface_sources(request, "dashboardable", actor)
    source = _find_source_by_key(sources, source_key)
    if not source:
        return _error_response("SOURCE_NOT_FOUND", "source_key not found", "source_key", status=404)
    cfg = source.get("config") if isinstance(source.get("config"), dict) else {}
    entity_id = source.get("entity_id")
    module_id = source.get("module_id")
    if not isinstance(entity_id, str):
        return _error_response("SOURCE_INVALID", "source entity missing", "source_key", status=400)
    found = _find_entity_def(request, entity_id)
    if not found:
        return _error_response("ENTITY_NOT_FOUND", "Entity not found or disabled", "source_key", status=404)
    entity_has_computed = has_computed_fields(found[1])
    limit_cap = max(1, min(int(limit or 2000), 5000))
    date_field_effective = date_field if isinstance(date_field, str) and date_field else (cfg.get("date_field") if isinstance(cfg.get("date_field"), str) else None)
    fields: list[str] = []
    if isinstance(group_by, str) and group_by:
        fields.append(group_by)
    if isinstance(measure, str) and (measure.startswith("sum:") or measure.startswith("count_distinct:")):
        fields.append(measure.split(":", 1)[1])
    if isinstance(date_field_effective, str):
        fields.append(date_field_effective)
    fields = list(dict.fromkeys([f for f in fields if isinstance(f, str) and f]))
    cache_key = (
        f"dashboard_query:{get_org_id()}:{entity_id}:{source_key or ''}:{group_by or ''}:{measure or 'count'}:"
        f"{date_field_effective or ''}:{start or ''}:{end or ''}:{limit_cap}:{q or ''}:"
        f"{_domain_hash(source_filter if isinstance(source_filter, dict) else None)}:{_context_hash(actor_ctx)}"
    )
    cached = _resp_cache_get(cache_key)
    if cached is not None:
        logger.info("cache_hit=dashboard_query key=%s", cache_key)
        return cached
    sql_result = None
    grouped_query = isinstance(group_by, str) and bool(group_by)
    if (
        not grouped_query
        and not entity_has_computed
        and _records_sql_fast_path_allowed(actor, entity_id, source_filter, allow_simple_domain=True)
    ):
        try:
            sql_result = _dashboard_query_sql_fast(
                entity_id=entity_id,
                source=source,
                group_by=group_by if isinstance(group_by, str) and group_by else None,
                measure=measure if isinstance(measure, str) and measure else "count",
                date_field=date_field_effective if isinstance(date_field_effective, str) and date_field_effective else None,
                start=start if isinstance(start, str) and start else None,
                end=end if isinstance(end, str) and end else None,
                limit=limit_cap,
                q=q if isinstance(q, str) and q else None,
                source_filter=source_filter if isinstance(source_filter, dict) else None,
            )
        except Exception:
            logger.exception("dashboard_query_fast_failed entity=%s source_key=%s", entity_id, source_key)
            sql_result = None
    if sql_result is not None:
        inconsistent_grouped_result = (
            isinstance(group_by, str)
            and bool(group_by)
            and isinstance(sql_result, dict)
            and int(sql_result.get("count") or 0) > 0
            and not (sql_result.get("groups") or [])
        )
        if not inconsistent_grouped_result:
            response = _ok_response(sql_result)
            _resp_cache_set(cache_key, response)
            logger.info("cache_miss=dashboard_query key=%s", cache_key)
            return response
        logger.warning(
            "dashboard_query_fast_inconsistent entity=%s source_key=%s group_by=%s count=%s; falling back to python aggregation",
            entity_id,
            source_key,
            group_by,
            sql_result.get("count"),
        )
    items = _records_list_page_all(
        entity_id,
        fields=None if entity_has_computed else (fields or None),
        q=q,
        cap=limit_cap,
    )
    items = _filter_record_items_for_actor(actor, module_id if isinstance(module_id, str) else found[0], found[1], items)
    start_dt = _to_datetime(start) if isinstance(start, str) and start else None
    end_dt = _to_datetime(end) if isinstance(end, str) and end else None
    filtered: list[dict] = []
    for item in items:
        record = item.get("record") if isinstance(item, dict) else None
        if not isinstance(record, dict):
            continue
        if start_dt and isinstance(date_field_effective, str):
            value_dt = _to_datetime(record.get(date_field_effective))
            if value_dt and value_dt < start_dt:
                continue
        if end_dt and isinstance(date_field_effective, str):
            value_dt = _to_datetime(record.get(date_field_effective))
            if value_dt and value_dt > end_dt:
                continue
        if isinstance(source_filter, dict):
            try:
                if not eval_condition(source_filter, {"record": record, "actor": actor_ctx}):
                    continue
            except Exception:
                continue
        filtered.append(item)
    effective_measure = measure if isinstance(measure, str) and measure else "count"
    measure_field = None
    measure_kind = "count"
    if effective_measure.startswith("sum:"):
        measure_kind = "sum"
        measure_field = effective_measure.split(":", 1)[1]
    elif effective_measure.startswith("count_distinct:"):
        measure_kind = "count_distinct"
        measure_field = effective_measure.split(":", 1)[1]
    if not isinstance(group_by, str) or not group_by:
        if measure_kind == "sum" and measure_field:
            total = 0.0
            for item in filtered:
                record = item.get("record") or {}
                try:
                    total += float(record.get(measure_field) or 0)
                except Exception:
                    continue
            response = _ok_response(
                {
                    "source": source,
                    "measure": effective_measure,
                    "value": total,
                    "count": len(filtered),
                }
            )
            _resp_cache_set(cache_key, response)
            logger.info("cache_miss=dashboard_query key=%s", cache_key)
            return response
        if measure_kind == "count_distinct" and measure_field:
            unique_values = {
                str((item.get("record") or {}).get(measure_field)).strip()
                for item in filtered
                if (item.get("record") or {}).get(measure_field) not in (None, "")
            }
            response = _ok_response(
                {
                    "source": source,
                    "measure": effective_measure,
                    "value": len(unique_values),
                    "count": len(filtered),
                }
            )
            _resp_cache_set(cache_key, response)
            logger.info("cache_miss=dashboard_query key=%s", cache_key)
            return response
        response = _ok_response(
            {
                "source": source,
                "measure": "count",
                "value": len(filtered),
            }
        )
        _resp_cache_set(cache_key, response)
        logger.info("cache_miss=dashboard_query key=%s", cache_key)
        return response
    groups: dict[str, float] = {}
    distinct_groups: dict[str, set[str]] = {}
    for item in filtered:
        record = item.get("record") or {}
        key = record.get(group_by)
        key_text = str(key) if key is not None else ""
        if measure_kind == "sum" and measure_field:
            try:
                value = float(record.get(measure_field) or 0)
            except Exception:
                value = 0.0
            groups[key_text] = groups.get(key_text, 0.0) + value
        elif measure_kind == "count_distinct" and measure_field:
            raw_value = record.get(measure_field)
            if raw_value not in (None, ""):
                distinct_groups.setdefault(key_text, set()).add(str(raw_value))
        else:
            groups[key_text] = groups.get(key_text, 0.0) + 1.0
    if measure_kind == "count_distinct":
        groups = {key: float(len(values)) for key, values in distinct_groups.items()}
    output = [{"key": key, "value": value} for key, value in groups.items()]
    output.sort(key=lambda row: row.get("value", 0), reverse=True)
    response = _ok_response(
        {
            "source": source,
            "group_by": group_by,
            "measure": effective_measure,
            "groups": output,
            "count": len(filtered),
        }
    )
    _resp_cache_set(cache_key, response)
    logger.info("cache_miss=dashboard_query key=%s", cache_key)
    return response


@app.get("/records/{entity_id}")
async def list_generic_records(
    request: Request,
    entity_id: str,
    q: str | None = None,
    limit: int = 50,
    offset: int = 0,
    cursor: str | None = None,
    search_fields: str | None = None,
    fields: str | None = None,
    domain: str | None = None,
) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_capability(actor, "records.read", "Read access required")
    if denied:
        return denied
    entity_id = _normalize_entity_id(entity_id)
    found = _find_entity_def(request, entity_id)
    if not found:
        return _error_response("ENTITY_NOT_FOUND", "Entity not found or disabled", "entity_id", status=404)
    denied = _entity_access_denied_response(actor, found[0], entity_id, write=False)
    if denied:
        return denied
    limit_cap = limit if isinstance(limit, int) and limit > 0 else 50
    if limit_cap > 200:
        limit_cap = 200
    offset_val = offset if isinstance(offset, int) and offset >= 0 else 0
    fields_list = [f.strip() for f in search_fields.split(",")] if isinstance(search_fields, str) and search_fields.strip() else None
    parsed_domain = None
    if isinstance(domain, str) and domain.strip():
        try:
            parsed_domain = json.loads(domain)
        except Exception as exc:
            return _error_response("DOMAIN_INVALID", "domain must be valid JSON", "domain", detail={"error": str(exc)}, status=400)
    actor_ctx = _actor_domain_context(actor)
    entity_has_computed = has_computed_fields(found[1])
    cache_key = (
        f"records:list:{get_org_id()}:{entity_id}:{limit_cap}:{offset_val}:{cursor or ''}:{fields or ''}:"
        f"{search_fields or ''}:{q or ''}:{_domain_hash(parsed_domain)}:{_context_hash(actor_ctx)}"
    )
    cached = _resp_cache_get(cache_key)
    if cached is not None:
        logger.info("cache_hit=records_list key=%s", cache_key)
        return cached
    field_ids = [f.strip() for f in fields.split(",") if f.strip()] if isinstance(fields, str) and fields.strip() else None
    use_cursor = isinstance(cursor, str) and cursor.strip()
    fast_page = None
    if (use_cursor or offset_val == 0) and parsed_domain and not entity_has_computed and _records_sql_fast_path_allowed(actor, entity_id, parsed_domain, allow_simple_domain=True):
        fast_page = _records_list_page_with_simple_domain(
            entity_id=entity_id,
            domain=parsed_domain,
            limit=limit_cap,
            cursor=cursor,
            q=q,
            search_fields=fields_list,
            fields=field_ids,
        )
    if fast_page is not None:
        items, next_cursor = fast_page
    elif use_cursor or offset_val == 0:
        items, next_cursor = generic_records.list_page(
            entity_id,
            limit=limit_cap,
            cursor=cursor,
            q=q,
            search_fields=fields_list,
            fields=None if (parsed_domain or entity_has_computed) else field_ids,
        )
    else:
        items = generic_records.list(entity_id, limit=limit_cap, offset=offset_val, q=q, search_fields=fields_list)
        next_cursor = None
    if parsed_domain and fast_page is None:
        items = _filter_records_by_domain(items, parsed_domain, {}, actor_ctx)
    if isinstance(limit_cap, int) and limit_cap > 0:
        items = items[:limit_cap]
    if isinstance(field_ids, list) and field_ids:
        trimmed = []
        for item in items:
            record = item.get("record") or {}
            slim = {fid: record.get(fid) for fid in field_ids if fid in record}
            if "id" in record:
                slim["id"] = record.get("id")
            trimmed.append({"record_id": item.get("record_id"), "record": slim})
        items = trimmed
    visible_items = _filter_record_items_for_actor(actor, found[0], found[1], items)
    payload = {
        "records": visible_items,
        "pagination": _ext_api_pagination_meta(limit=limit_cap, offset=offset_val, next_cursor=next_cursor),
    }
    if next_cursor:
        payload["next_cursor"] = next_cursor
    response = _ok_response(payload)
    _resp_cache_set(cache_key, response)
    logger.info("cache_miss=records_list key=%s", cache_key)
    return response


@app.get("/filters/{entity_id}")
async def list_saved_filters(request: Request, entity_id: str) -> dict:
    user_id = _require_user_id(request)
    if not user_id:
        if IS_DEV or os.getenv("OCTO_ALLOW_ANON_PREFS", "").strip() == "1":
            return _ok_response({"filters": []})
        return _error_response("AUTH_REQUIRED", "Authentication required", "user_id", status=401)
    entity_id = _normalize_entity_id(entity_id)
    with get_conn() as conn:
        rows = fetch_all(
            conn,
            """
            select id, name, domain, state, is_default, created_at
            from saved_filters
            where org_id=%s and user_id=%s and entity_id=%s
            order by created_at desc
            """,
            [get_org_id(), user_id, entity_id],
            query_name="saved_filters.list",
        )
        return _ok_response({"filters": rows})


@app.post("/filters/{entity_id}")
async def create_saved_filter(request: Request, entity_id: str) -> dict:
    user_id = _require_user_id(request)
    if not user_id:
        return _error_response("AUTH_REQUIRED", "Authentication required", "user_id", status=401)
    entity_id = _normalize_entity_id(entity_id)
    body = await _safe_json(request)
    name = body.get("name") if isinstance(body, dict) else None
    domain = body.get("domain") if isinstance(body, dict) else None
    state = body.get("state") if isinstance(body, dict) else None
    is_default = bool(body.get("is_default")) if isinstance(body, dict) else False
    if not isinstance(name, str) or not name.strip():
        return _error_response("FILTER_INVALID", "name required", "name", status=400)
    if not isinstance(domain, dict):
        return _error_response("FILTER_INVALID", "domain required", "domain", status=400)
    if state is not None and not isinstance(state, dict):
        return _error_response("FILTER_INVALID", "state must be object", "state", status=400)
    with get_conn() as conn:
        row = fetch_one(
            conn,
            """
            insert into saved_filters (org_id, user_id, entity_id, name, domain, state, is_default)
            values (%s, %s, %s, %s, %s, %s, %s)
            returning id, name, domain, state, is_default, created_at
            """,
            [get_org_id(), user_id, entity_id, name.strip(), json.dumps(domain), json.dumps(state) if state is not None else None, is_default],
            query_name="saved_filters.insert",
        )
        if is_default:
            execute(
                conn,
                """
                update saved_filters set is_default=false
                where org_id=%s and user_id=%s and entity_id=%s and id <> %s
                """,
                [get_org_id(), user_id, entity_id, row.get("id")],
                query_name="saved_filters.clear_default",
            )
            execute(
                conn,
                """
                insert into user_entity_prefs (org_id, user_id, entity_id, default_filter_id, updated_at)
                values (%s, %s, %s, %s, %s)
                on conflict (org_id, user_id, entity_id)
                do update set default_filter_id=excluded.default_filter_id, default_filter_key=null, updated_at=excluded.updated_at
                """,
                [get_org_id(), user_id, entity_id, row.get("id"), _now()],
                query_name="user_entity_prefs.set_default_filter",
            )
        return _ok_response({"filter": row})


@app.put("/filters/{filter_id}")
async def update_saved_filter(request: Request, filter_id: str) -> dict:
    user_id = _require_user_id(request)
    if not user_id:
        return _error_response("AUTH_REQUIRED", "Authentication required", "user_id", status=401)
    body = await _safe_json(request)
    with get_conn() as conn:
        existing = fetch_one(
            conn,
            "select id, entity_id, is_default from saved_filters where org_id=%s and user_id=%s and id=%s",
            [get_org_id(), user_id, filter_id],
            query_name="saved_filters.get",
        )
        if not existing:
            return _error_response("FILTER_NOT_FOUND", "Filter not found", "filter_id", status=404)
        name = body.get("name") if isinstance(body, dict) else None
        domain = body.get("domain") if isinstance(body, dict) else None
        state = body.get("state") if isinstance(body, dict) else None
        is_default = body.get("is_default") if isinstance(body, dict) else None
        updates = []
        params = []
        if isinstance(name, str) and name.strip():
            updates.append("name=%s")
            params.append(name.strip())
        if isinstance(domain, dict):
            updates.append("domain=%s")
            params.append(json.dumps(domain))
        if isinstance(state, dict):
            updates.append("state=%s")
            params.append(json.dumps(state))
        if isinstance(is_default, bool):
            updates.append("is_default=%s")
            params.append(is_default)
        if updates:
            params.extend([get_org_id(), user_id, filter_id])
            execute(
                conn,
                f"update saved_filters set {', '.join(updates)} where org_id=%s and user_id=%s and id=%s",
                params,
                query_name="saved_filters.update",
            )
        if isinstance(is_default, bool):
            entity_id = existing.get("entity_id")
            if is_default:
                execute(
                    conn,
                    """
                    update saved_filters set is_default=false
                    where org_id=%s and user_id=%s and entity_id=%s and id <> %s
                    """,
                    [get_org_id(), user_id, entity_id, filter_id],
                    query_name="saved_filters.clear_default",
                )
                execute(
                    conn,
                    """
                    insert into user_entity_prefs (org_id, user_id, entity_id, default_filter_id, updated_at)
                    values (%s, %s, %s, %s, %s)
                    on conflict (org_id, user_id, entity_id)
                    do update set default_filter_id=excluded.default_filter_id, default_filter_key=null, updated_at=excluded.updated_at
                    """,
                    [get_org_id(), user_id, entity_id, filter_id, _now()],
                    query_name="user_entity_prefs.set_default_filter",
                )
            else:
                if existing.get("is_default"):
                    execute(
                        conn,
                        "update user_entity_prefs set default_filter_id=null, updated_at=%s where org_id=%s and user_id=%s and entity_id=%s",
                        [_now(), get_org_id(), user_id, existing.get("entity_id")],
                        query_name="user_entity_prefs.clear_default_filter",
                    )
        row = fetch_one(
            conn,
            "select id, name, domain, state, is_default, created_at from saved_filters where org_id=%s and user_id=%s and id=%s",
            [get_org_id(), user_id, filter_id],
            query_name="saved_filters.get",
        )
        return _ok_response({"filter": row})


