# ---- Access / Users / Roles ----


def _list_workspace_members_enriched(workspace_id: str) -> list[dict]:
    members = list_workspace_members(workspace_id)
    assignments = list_workspace_access_assignments(workspace_id)
    profiles_by_user: dict[str, list[dict]] = {}
    for row in assignments:
        user_id = row.get("user_id")
        if not isinstance(user_id, str) or not user_id:
            continue
        profiles_by_user.setdefault(user_id, []).append(
            {
                "id": row.get("profile_id"),
                "profile_key": row.get("profile_key"),
                "name": row.get("name"),
                "description": row.get("description"),
            }
        )
    enriched = []
    for member in members:
        user_id = member.get("user_id")
        row = dict(member)
        row["managed_account_state"] = _normalize_managed_account_state(row.get("managed_account_state"))
        row["access_profiles"] = profiles_by_user.get(user_id, [])
        row["access_profile_ids"] = [profile.get("id") for profile in row["access_profiles"] if isinstance(profile.get("id"), str)]
        enriched.append(row)
    return enriched


@app.get("/access/context")
async def access_context(request: Request) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    workspace_id = str(actor.get("workspace_id") or "").strip()
    user_id = str(actor.get("user_id") or "").strip()
    workspace_role = str(actor.get("workspace_role") or actor.get("role") or "").strip()
    platform_role = str(actor.get("platform_role") or "").strip()
    managed_account_state = _managed_account_state_from_actor(actor) or ""
    cache_key = f"access_context:{workspace_id}:{user_id}:{workspace_role}:{platform_role}:{managed_account_state}"
    cached = _resp_cache_get(cache_key)
    if cached is not None:
        logger.info("cache_hit=access_context key=%s", cache_key)
        return cached
    workspaces = actor.get("workspaces") or []
    if actor.get("platform_role") == "superadmin":
        workspaces = list_all_workspaces()
    workspaces = _annotate_access_workspaces(workspaces, actor)
    policy = _access_policy_for_actor(actor)
    response = _ok_response(
        {
            "actor": {
                "user_id": actor.get("user_id"),
                "email": actor.get("email"),
                "workspace_id": actor.get("workspace_id"),
                "workspace_role": actor.get("workspace_role") or actor.get("role"),
                "platform_role": actor.get("platform_role") or "standard",
                "managed_account_state": managed_account_state or None,
                "password_handoff_required": _actor_requires_password_handoff(actor),
            },
            "workspaces": workspaces,
            "permissions": _actor_permissions(actor),
            "policy": {
                "profile_ids": policy.get("profile_ids", []),
                "profiles": policy.get("profiles", []),
                "module_access": policy.get("module_access", {}),
                "entity_access": policy.get("entity_access", {}),
                "entity_scope_rules": policy.get("entity_scope_rules", {}),
                "field_access": policy.get("field_access", {}),
                "action_access": policy.get("action_access", {}),
            },
        }
    )
    _resp_cache_set(cache_key, response)
    logger.info("cache_miss=access_context key=%s", cache_key)
    return response


@app.delete("/access/workspaces/{workspace_id}")
async def delete_access_workspace(request: Request, workspace_id: str) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_superadmin(actor, "Superadmin role required")
    if denied:
        return denied
    if not isinstance(workspace_id, str) or not workspace_id.strip():
        return _error_response("WORKSPACE_REQUIRED", "Workspace id required", "workspace_id", status=400)
    workspace_id = workspace_id.strip()
    if workspace_id == actor.get("workspace_id"):
        return _error_response("WORKSPACE_DELETE_FORBIDDEN", "Switch away before deleting the active workspace", "workspace_id", status=400)
    if not workspace_exists(workspace_id):
        return _error_response("WORKSPACE_NOT_FOUND", "Workspace not found", "workspace_id", status=404)
    ok = delete_workspace(workspace_id)
    if not ok:
        return _error_response("WORKSPACE_DELETE_FAILED", "Failed to delete workspace", "workspace_id", status=400)
    return _ok_response({"deleted": True, "workspace_id": workspace_id})


@app.patch("/access/workspace")
async def update_workspace_settings(request: Request) -> dict:
    actor = _resolve_actor(request)
    denied = _require_capability(actor, "workspace.manage_settings", "Admin role required")
    if denied:
        return denied
    body = await _safe_json(request)
    if not isinstance(body, dict):
        return _error_response("INVALID_BODY", "Expected JSON object", None, status=400)
    name = body.get("name")
    if not isinstance(name, str) or not name.strip():
        return _error_response("NAME_REQUIRED", "Workspace name is required", "name", status=400)
    if len(name.strip()) > 120:
        return _error_response("NAME_TOO_LONG", "Workspace name is too long", "name", status=400)
    updated = update_workspace_name(actor.get("workspace_id"), name)
    if not updated:
        return _error_response("WORKSPACE_NOT_FOUND", "Workspace not found", "workspace_id", status=404)
    workspaces = actor.get("workspaces") or []
    next_workspaces = []
    for item in workspaces:
        row = dict(item)
        if row.get("workspace_id") == updated.get("workspace_id"):
            row["workspace_name"] = updated.get("workspace_name")
        next_workspaces.append(row)
    return _ok_response({"workspace": updated, "workspaces": next_workspaces})


