@app.post("/access/members/create")
async def create_staged_workspace_member(request: Request) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_superadmin(actor, "Superadmin role required")
    if denied:
        return denied
    body = await _safe_json(request)
    if not isinstance(body, dict):
        return _error_response("INVALID_BODY", "Expected JSON object", None, status=400)
    email = (body.get("email") or "").strip().lower()
    password = body.get("password")
    role = _normalize_workspace_role(body.get("role") or "member")
    if "@" not in email:
        return _error_response("EMAIL_REQUIRED", "Valid email required", "email", status=400)
    if not isinstance(password, str) or len(password) < 8:
        return _error_response("PASSWORD_REQUIRED", "Temporary password must be at least 8 characters", "password", status=400)
    if not role:
        return _error_response("ROLE_INVALID", "Invalid role", "role", status=400)
    if _find_auth_user_id_by_email(email):
        return _error_response("USER_EXISTS", "A user with that email already exists", "email", status=400)

    workspace_id = actor.get("workspace_id")
    workspace_name = next(
        (
            item.get("workspace_name")
            for item in (actor.get("workspaces") or [])
            if isinstance(item, dict) and item.get("workspace_id") == workspace_id
        ),
        None,
    )
    created_user_id = ""
    try:
        created = _supabase_create_user(email, password, email_confirm=True)
        created_user = created.get("user") if isinstance(created, dict) else None
        created_user_id = created_user.get("id") if isinstance(created_user, dict) else ""
        if not isinstance(created_user_id, str) or not created_user_id:
            created_user_id = _find_auth_user_id_by_email(email) or ""
        if not created_user_id:
            raise RuntimeError("create_user_missing_id")
        _supabase_update_managed_account_state(
            created_user_id,
            state="staged",
            workspace_id=workspace_id,
            created_by_user_id=actor.get("user_id"),
            email_confirm=True,
        )
        _supabase_set_auto_workspace_creation(created_user_id, enabled=False)
        member = add_workspace_member(workspace_id, created_user_id, role)
    except Exception as exc:
        if created_user_id:
            with suppress(Exception):
                remove_workspace_member(workspace_id, created_user_id)
            with suppress(Exception):
                _supabase_delete_user(created_user_id)
        return _error_response("CREATE_USER_FAILED", str(exc), "email", status=400)

    _invalidate_access_runtime_caches(workspace_id, created_user_id)
    members = _list_workspace_members_enriched(workspace_id)
    return _ok_response(
        {
            "member": member,
            "members": members,
            "user_id": created_user_id,
            "managed_account_state": "staged",
            "workspace_id": workspace_id,
            "workspace_name": workspace_name,
        }
    )


@app.post("/access/members/invite")
async def invite_workspace_member(request: Request) -> dict:
    actor = _resolve_actor(request)
    denied = _require_capability(actor, "workspace.manage_members", "Admin role required")
    if denied:
        return denied
    body = await _safe_json(request)
    if not isinstance(body, dict):
        return _error_response("INVALID_BODY", "Expected JSON object", None, status=400)
    email = body.get("email")
    role = _normalize_workspace_role(body.get("role") or "member")
    if not isinstance(email, str) or "@" not in email:
        return _error_response("EMAIL_REQUIRED", "Valid email required", "email", status=400)
    if not role:
        return _error_response("ROLE_INVALID", "Invalid role", "role", status=400)
    # Force a single known-safe invite redirect so stale frontend payloads
    # cannot accidentally fall back to app root.
    redirect_to = _default_invite_redirect()
    normalized_email = email.strip().lower()
    existing_user_id = _find_auth_user_id_by_email(normalized_email)
    logger.info(
        "invite_workspace_member email=%s existing_user=%s redirect_to=%s",
        normalized_email,
        bool(existing_user_id),
        redirect_to,
    )
    try:
        if existing_user_id:
            invited = _supabase_send_recovery(normalized_email, redirect_to=redirect_to)
        else:
            invited = _supabase_invite_user(normalized_email, redirect_to=redirect_to)
    except Exception as exc:
        return _error_response("INVITE_FAILED", str(exc), "email", status=400)
    invited_user = invited.get("user") if isinstance(invited, dict) else None
    invited_user_id = invited_user.get("id") if isinstance(invited_user, dict) else None
    if not isinstance(invited_user_id, str) or not invited_user_id:
        invited_user_id = existing_user_id or _find_auth_user_id_by_email(normalized_email)
    invite_pending = False
    if isinstance(invited_user_id, str) and invited_user_id:
        member = add_workspace_member(actor.get("workspace_id"), invited_user_id, role)
        with suppress(Exception):
            _supabase_set_auto_workspace_creation(invited_user_id, enabled=False)
    else:
        member = create_workspace_invite(
            actor.get("workspace_id"),
            email=email,
            role=role,
            invited_by_user_id=actor.get("user_id"),
        )
        invite_pending = True
    members = _list_workspace_members_enriched(actor.get("workspace_id"))
    _invalidate_access_runtime_caches(actor.get("workspace_id"), invited_user_id if isinstance(invited_user_id, str) else None)
    return _ok_response(
        {
            "member": member,
            "members": members,
            "invited_email": email,
            "invite_pending": invite_pending,
            "existing_user": bool(existing_user_id),
            "email_flow": "recovery" if existing_user_id else "invite",
        }
    )


@app.post("/access/members/{user_id}/approve-handoff")
async def approve_staged_member_handoff(request: Request, user_id: str) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_superadmin(actor, "Superadmin role required")
    if denied:
        return denied
    workspace_id = actor.get("workspace_id")
    member = get_membership(user_id, workspace_id)
    if not member:
        return _error_response("MEMBER_NOT_FOUND", "Member not found", "user_id", status=404)
    auth_user = _find_auth_user_row_by_id(user_id)
    if not auth_user:
        return _error_response("AUTH_USER_NOT_FOUND", "Auth user not found", "user_id", status=404)
    if auth_user.get("managed_account_state") != "staged":
        return _error_response(
            "HANDOFF_INVALID",
            "Only staged users can be approved for handoff",
            "user_id",
            status=400,
        )
    body = await _safe_json(request)
    provided_password = (body or {}).get("password") if isinstance(body, dict) else None
    if provided_password not in (None, "") and (not isinstance(provided_password, str) or len(provided_password) < 8):
        return _error_response("PASSWORD_REQUIRED", "Temporary password must be at least 8 characters", "password", status=400)
    temporary_password = provided_password if isinstance(provided_password, str) and provided_password else _generate_temporary_password()
    try:
        _supabase_update_managed_account_state(
            user_id,
            state="handoff_required",
            workspace_id=workspace_id,
            password=temporary_password,
            email_confirm=True,
        )
    except Exception as exc:
        return _error_response("HANDOFF_FAILED", str(exc), "user_id", status=400)
    _invalidate_access_runtime_caches(workspace_id, user_id)
    return _ok_response(
        {
            "ok": True,
            "user_id": user_id,
            "managed_account_state": "handoff_required",
            "temporary_password": temporary_password,
            "members": _list_workspace_members_enriched(workspace_id),
        }
    )


@app.post("/access/platform-invite")
async def invite_platform_user(request: Request) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    if actor.get("platform_role") != "superadmin":
        return _error_response("FORBIDDEN", "Superadmin role required", status=403)
    body = await _safe_json(request)
    if not isinstance(body, dict):
        return _error_response("INVALID_BODY", "Expected JSON object", None, status=400)
    email = (body.get("email") or "").strip().lower()
    if "@" not in email:
        return _error_response("EMAIL_REQUIRED", "Valid email required", "email", status=400)
    requested_platform_role = (body.get("platform_role") or "standard").strip().lower()
    if requested_platform_role not in _PLATFORM_ROLES:
        return _error_response("ROLE_INVALID", "Invalid platform role", "platform_role", status=400)
    redirect_to = _default_invite_redirect()
    existing_user_id = _find_auth_user_id_by_email(email)
    logger.info(
        "invite_platform_user email=%s existing_user=%s redirect_to=%s requested_platform_role=%s",
        email,
        bool(existing_user_id),
        redirect_to,
        requested_platform_role,
    )
    try:
        if existing_user_id:
            invited = _supabase_send_recovery(email, redirect_to=redirect_to)
        else:
            invited = _supabase_invite_user(email, redirect_to=redirect_to)
    except Exception as exc:
        return _error_response("INVITE_FAILED", str(exc), "email", status=400)
    invited_user = invited.get("user") if isinstance(invited, dict) else None
    invited_user_id = invited_user.get("id") if isinstance(invited_user, dict) else None
    if not isinstance(invited_user_id, str) or not invited_user_id:
        invited_user_id = existing_user_id or _find_auth_user_id_by_email(email)
    platform_row = None
    if isinstance(invited_user_id, str) and invited_user_id and requested_platform_role != "standard":
        platform_row = set_platform_role(invited_user_id, requested_platform_role)
    return _ok_response(
        {
            "ok": True,
            "invited_email": email,
            "existing_user": bool(existing_user_id),
            "email_flow": "recovery" if existing_user_id else "invite",
            "platform_role": requested_platform_role,
            "user_id": invited_user_id,
            "platform_user": platform_row,
            "note": "No workspace membership assigned. Workspace is created on first login.",
        }
    )


@app.post("/access/password-handoff/complete")
async def complete_password_handoff(request: Request) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    user_id = actor.get("user_id")
    body = await _safe_json(request)
    new_password = body.get("password") if isinstance(body, dict) else None
    if new_password not in (None, "") and (not isinstance(new_password, str) or len(new_password) < 8):
        return _error_response("PASSWORD_REQUIRED", "Password must be at least 8 characters", "password", status=400)
    auth_user = _find_auth_user_row_by_id(user_id)
    if not auth_user:
        return _error_response("AUTH_USER_NOT_FOUND", "Auth user not found", "user_id", status=404)
    current_state = auth_user.get("managed_account_state")
    if current_state != "handoff_required":
        return _ok_response({"ok": True, "managed_account_state": current_state, "completed": False})
    try:
        app_metadata = _clear_managed_account_app_metadata(auth_user.get("app_metadata"))
        payload: dict[str, Any] = {"app_metadata": app_metadata}
        if isinstance(new_password, str) and new_password:
            payload["password"] = new_password
        _supabase_update_user(user_id, payload)
        _update_auth_user_app_metadata_direct(user_id, app_metadata)
    except Exception as exc:
        return _error_response("HANDOFF_COMPLETE_FAILED", str(exc), "user_id", status=400)
    _invalidate_access_runtime_caches(actor.get("workspace_id"), user_id)
    return _ok_response({"ok": True, "managed_account_state": None, "completed": True})


@app.patch("/access/members/{user_id}")
async def update_member_role(request: Request, user_id: str) -> dict:
    actor = _resolve_actor(request)
    denied = _require_capability(actor, "workspace.manage_members", "Admin role required")
    if denied:
        return denied
    body = await _safe_json(request)
    role = _normalize_workspace_role((body or {}).get("role"))
    if not role:
        return _error_response("ROLE_INVALID", "Invalid role", "role", status=400)
    workspace_id = actor.get("workspace_id")
    member = get_membership(user_id, workspace_id)
    if not member and actor.get("platform_role") != "superadmin":
        return _error_response("MEMBER_NOT_FOUND", "Member not found", "user_id", status=404)
    # Prevent lockout: a workspace must always have at least one admin member.
    if member and (member.get("role") or "") == "admin" and role != "admin":
        admins = [m for m in (list_workspace_members(workspace_id) or []) if (m.get("role") or "") == "admin"]
        if len(admins) <= 1:
            return _error_response(
                "LAST_ADMIN_REQUIRED",
                "At least one admin user is required in every workspace",
                "role",
                status=400,
            )
    updated = update_workspace_member_role(workspace_id, user_id, role)
    if not updated:
        updated = add_workspace_member(workspace_id, user_id, role)
    members = _list_workspace_members_enriched(workspace_id)
    _invalidate_access_runtime_caches(workspace_id, user_id)
    return _ok_response({"member": updated, "members": members})


@app.delete("/access/members/{user_id}")
async def delete_member(request: Request, user_id: str) -> dict:
    actor = _resolve_actor(request)
    denied = _require_capability(actor, "workspace.manage_members", "Admin role required")
    if denied:
        return denied
    workspace_id = actor.get("workspace_id")
    if user_id == actor.get("user_id") and actor.get("platform_role") != "superadmin":
        return _error_response("FORBIDDEN", "You cannot remove yourself from this workspace", status=400)
    member_before = get_membership(user_id, workspace_id)
    # Prevent lockout: a workspace must always have at least one admin member.
    if (member_before or {}).get("role") == "admin":
        admins = [m for m in (list_workspace_members(workspace_id) or []) if (m.get("role") or "") == "admin"]
        if len(admins) <= 1:
            return _error_response(
                "LAST_ADMIN_REQUIRED",
                "At least one admin user is required in every workspace",
                "user_id",
                status=400,
            )
    ok = remove_workspace_member(workspace_id, user_id)
    if not ok:
        return _error_response("MEMBER_NOT_FOUND", "Member not found", "user_id", status=404)
    user_workspaces = list_user_workspaces(user_id)
    if not user_workspaces:
        with suppress(Exception):
            _supabase_set_auto_workspace_creation(user_id, enabled=False)
    raw_delete_auth = request.query_params.get("delete_auth_user", "")
    delete_auth_user = str(raw_delete_auth).strip().lower() in {"1", "true", "yes", "on"}
    if delete_auth_user:
        if actor.get("platform_role") != "superadmin" and user_workspaces:
            return _error_response(
                "FORBIDDEN",
                "Only superadmin can delete auth users with workspace memberships",
                "delete_auth_user",
                status=403,
            )
        try:
            _supabase_delete_user(user_id)
        except Exception as exc:
            role = (member_before or {}).get("role") or "member"
            add_workspace_member(workspace_id, user_id, role)
            return _error_response("DELETE_AUTH_FAILED", str(exc), "delete_auth_user", status=400)
    members = _list_workspace_members_enriched(workspace_id)
    _invalidate_access_runtime_caches(workspace_id, user_id)
    return _ok_response({"ok": True, "members": members, "auth_deleted": delete_auth_user})


