def _artifact_ai_entity_field_items(entity_def: dict | None) -> list[dict]:
    fields: list[dict] = []
    raw_fields = entity_def.get("fields") if isinstance(entity_def, dict) else None
    if not isinstance(raw_fields, list):
        return fields
    for field in raw_fields:
        if not isinstance(field, dict):
            continue
        field_id = field.get("id")
        if not isinstance(field_id, str) or not field_id.strip():
            continue
        fields.append(
            {
                "id": field_id.strip(),
                "label": field.get("label") or field_id.strip(),
                "type": field.get("type"),
                "entity": field.get("entity"),
                "display_field": field.get("display_field"),
            }
        )
    return fields


def _artifact_ai_entities(request: Request) -> list[dict]:
    entities: list[dict] = []
    for mod in _get_registry_list(request):
        if not mod.get("enabled"):
            continue
        module_id = mod.get("module_id")
        manifest_hash = mod.get("current_hash")
        if not isinstance(module_id, str) or not module_id or not isinstance(manifest_hash, str) or not manifest_hash:
            continue
        try:
            manifest = _get_snapshot(request, module_id, manifest_hash)
        except Exception:
            continue
        module_meta = manifest.get("module") if isinstance(manifest.get("module"), dict) else {}
        for ent in manifest.get("entities", []) if isinstance(manifest.get("entities"), list) else []:
            if not isinstance(ent, dict):
                continue
            ent_id = ent.get("id")
            if not isinstance(ent_id, str) or not ent_id.strip():
                continue
            entities.append(
                {
                    "id": ent_id.strip(),
                    "label": ent.get("label") or ent.get("name") or ent_id.strip(),
                    "display_field": ent.get("display_field"),
                    "module_id": module_id,
                    "module_name": module_meta.get("name") if isinstance(module_meta.get("name"), str) else module_id,
                    "fields": _artifact_ai_entity_field_items(ent),
                }
            )
    return entities


_TEMPLATE_INVALID_KEY_RE = re.compile(r"""invalid\s+(?:record|line item)\s+key\s+'([^']+)'""", re.IGNORECASE)


def _artifact_ai_template_entity_aliases(entity: dict | None) -> set[str]:
    if not isinstance(entity, dict):
        return set()
    entity_id = entity.get("id") if isinstance(entity.get("id"), str) else ""
    short_id = entity_id.split(".")[-1] if entity_id else ""
    label = entity.get("label") if isinstance(entity.get("label"), str) else ""
    aliases = {
        _ai_norm_token(entity_id),
        _ai_norm_token(short_id),
        _ai_norm_token(_ai_humanize_identifier(short_id) or ""),
        _ai_norm_token(label),
    }
    return {alias for alias in aliases if alias}


def _artifact_ai_infer_template_prompt_entity(
    prompt: str | None,
    entities: list[dict],
    *,
    current_entity_id: str | None = None,
) -> str | None:
    if not isinstance(prompt, str) or not prompt.strip() or not isinstance(entities, list):
        return None
    normalized_prompt = _ai_norm_token(prompt)
    if not normalized_prompt:
        return None

    invalid_prefixes: list[str] = []
    for match in _TEMPLATE_INVALID_KEY_RE.finditer(prompt):
        raw_key = str(match.group(1) or "").strip()
        if not raw_key:
            continue
        prefix = str(raw_key.split(".", 1)[0] or "").strip()
        if not prefix:
            continue
        invalid_prefixes.append(_ai_norm_token(prefix))
        if prefix.endswith("_line"):
            invalid_prefixes.append(_ai_norm_token(prefix[: -len("_line")]))
    invalid_prefixes = [item for item in invalid_prefixes if item]

    scored: list[tuple[int, int, str]] = []
    for entity in entities:
        if not isinstance(entity, dict):
            continue
        entity_id = entity.get("id")
        if not isinstance(entity_id, str) or not entity_id.strip():
            continue
        aliases = _artifact_ai_template_entity_aliases(entity)
        if not aliases:
            continue
        short_norm = _ai_norm_token(entity_id.split(".")[-1])
        alias_score = 0
        prefix_score = 0
        for prefix in invalid_prefixes:
            if prefix == short_norm:
                prefix_score += 10
            elif short_norm and prefix.startswith(f"{short_norm} "):
                prefix_score += 6
        for alias in aliases:
            if not alias or len(alias) < 4:
                continue
            pattern = rf"(?<![a-z0-9]){re.escape(alias)}(?![a-z0-9])"
            alias_score += len(re.findall(pattern, normalized_prompt))
        total_score = alias_score + prefix_score
        if total_score > 0:
            scored.append((alias_score, prefix_score, entity_id.strip()))
    if not scored:
        return None
    alias_scored = [item for item in scored if item[0] > 0]
    if alias_scored:
        scored = alias_scored
    scored.sort(key=lambda item: (item[0], item[1]), reverse=True)
    top_alias_score, top_prefix_score, top_entity_id = scored[0]
    second_scores = (scored[1][0], scored[1][1]) if len(scored) > 1 else (-1, -1)
    if (top_alias_score + top_prefix_score) <= 0 or (top_alias_score, top_prefix_score) == second_scores:
        return None
    return top_entity_id


def _artifact_ai_selected_entity(entities: list[dict], selected_entity_id: str | None, current: dict | None = None) -> dict | None:
    selected_id = ""
    if isinstance(selected_entity_id, str) and selected_entity_id.strip():
        selected_id = selected_entity_id.strip()
    elif isinstance(current, dict):
        variables_schema = current.get("variables_schema")
        if isinstance(variables_schema, dict) and isinstance(variables_schema.get("entity_id"), str):
            selected_id = variables_schema.get("entity_id").strip()
    if not selected_id:
        return None
    for entity in entities:
        if isinstance(entity, dict) and entity.get("id") == selected_id:
            return copy.deepcopy(entity)
    return None


def _artifact_ai_template_helpers(selected_entity_id: str | None) -> dict:
    config = _template_related_line_config(selected_entity_id)
    if not isinstance(config, dict):
        return {}
    line_entity = _find_entity_def_global(config.get("line_entity_id"))
    line_summary = _artifact_ai_template_entity_summary(line_entity)
    accessible_line_item_keys = line_summary.get("accessible_record_keys") or []
    preferred_line_item_keys: list[str] = []
    preferred_token_groups = [
        (("product_name", "product_id_label", "product_id_name", "product_id"), "Product"),
        (("description",), "Description"),
        (("quantity",), "Quantity"),
        (("uom",), "UOM"),
        (("unit_price",), "Unit Price"),
        (("unit_cost",), "Unit Cost"),
        (("discount",), "Discount"),
        (("tax",), "Tax"),
        (("line_total",), "Line Total"),
        (("total",), "Total"),
    ]
    for tokens, _label in preferred_token_groups:
        match_key = None
        for token in tokens:
            for key in accessible_line_item_keys:
                text = str(key or "").strip()
                if not text or text in preferred_line_item_keys:
                    continue
                lowered = text.lower()
                if lowered.endswith(f".{token}") or lowered.endswith(f"_{token}") or token in lowered:
                    match_key = text
                    break
            if isinstance(match_key, str) and match_key:
                break
        if isinstance(match_key, str) and match_key:
            preferred_line_item_keys.append(match_key)
    if not preferred_line_item_keys:
        preferred_line_item_keys = [str(key).strip() for key in accessible_line_item_keys[:6] if isinstance(key, str) and str(key).strip()]
    example_row_columns: list[dict] = []
    display_label_map = {
        "product_name": "Product",
        "product_id_label": "Product",
        "product_id_name": "Product",
        "product_id": "Product",
        "description": "Description",
        "quantity": "Quantity",
        "uom": "UOM",
        "unit_price": "Unit Price",
        "unit_cost": "Unit Cost",
        "discount": "Discount",
        "tax": "Tax",
        "line_total": "Line Total",
        "total": "Total",
    }
    for key in preferred_line_item_keys[:6]:
        label = str(key.rsplit(".", 1)[-1] if "." in key else key).replace("_", " ").strip().title()
        lowered = key.lower()
        for token, display in display_label_map.items():
            if lowered.endswith(f".{token}") or lowered.endswith(f"_{token}") or token in lowered:
                label = display
                break
        example_row_columns.append({"field_id": key, "label": label})
    return {
        "supports_line_items": True,
        "preferred_collections": ["lines", "line_items", "formatted_line_items"],
        "record_collections": [alias for alias in (config.get("aliases") or []) if isinstance(alias, str) and alias],
        "related_entity_id": config.get("line_entity_id"),
        "related_entity_fields": _artifact_ai_entity_field_items(line_entity),
        "accessible_line_item_keys": accessible_line_item_keys,
        "lookup_alias_keys": line_summary.get("lookup_alias_keys") or [],
        "preferred_line_item_keys": preferred_line_item_keys,
        "example_row_columns": example_row_columns,
        "guidance": [
            "For repeating tables, prefer top-level lines or formatted_line_items.",
            "Do not invent record['lines'] unless context.template_helpers.supports_line_items is true.",
            "Use related_entity_fields and accessible_line_item_keys for line item field ids.",
            "Inside loops, use full field ids like line['module_line.quantity'] instead of bare keys like line['quantity'].",
            "When building tables, prefer the concrete field ids from preferred_line_item_keys and example_row_columns.",
        ],
    }


def _artifact_ai_template_validation_lines(validation: dict | None) -> tuple[list[str], list[str], list[str]]:
    if not isinstance(validation, dict):
        return [], [], []
    error_lines: list[str] = []
    warning_lines: list[str] = []
    undefined_lines: list[str] = []
    for item in validation.get("errors") or []:
        if isinstance(item, str) and item.strip():
            error_lines.append(item.strip())
            continue
        if isinstance(item, dict):
            message = item.get("message") or item.get("code")
            if not isinstance(message, str) or not message.strip():
                continue
            line = item.get("line")
            col = item.get("col")
            location = f" (line {line}{f', col {col}' if col else ''})" if line else ""
            error_lines.append(f"{message.strip()}{location}")
    for item in validation.get("warnings") or []:
        if isinstance(item, str) and item.strip():
            warning_lines.append(item.strip())
    undefined_items = validation.get("undefined") or validation.get("possible_undefined") or []
    for item in undefined_items:
        if isinstance(item, str) and item.strip():
            undefined_lines.append(item.strip())
    return error_lines, warning_lines, undefined_lines


def _artifact_ai_template_validation_snapshot(kind: str, current: dict | None) -> dict:
    source = current if isinstance(current, dict) else {}
    if kind == "email_template":
        validation = _artifact_ai_validate_email_template_draft(source)
    elif kind == "document_template":
        validation = _artifact_ai_validate_doc_template_draft(source)
    else:
        return {}
    error_lines, warning_lines, undefined_lines = _artifact_ai_template_validation_lines(validation)
    top_warnings = [*warning_lines, *[f"Undefined: {item}" for item in undefined_lines]]
    return {
        "compiled_ok": bool(validation.get("compiled_ok")),
        "error_count": len(error_lines),
        "warning_count": len(top_warnings),
        "top_errors": error_lines[:6],
        "top_warnings": top_warnings[:6],
        "undefined": undefined_lines[:12],
        "validated_at": validation.get("validated_at"),
    }


_TEMPLATE_RECORD_BRACKET_REF_RE = re.compile(r"""record\[\s*['"]([^'"]+)['"]\s*\]""")
_TEMPLATE_RECORD_DOT_REF_RE = re.compile(r"""(?<![\w.])record\.([A-Za-z_][A-Za-z0-9_]*(?:\.[A-Za-z_][A-Za-z0-9_]*)*)""")
_TEMPLATE_FOR_LOOP_RE = re.compile(r"""\{%\s*for\s+([A-Za-z_][A-Za-z0-9_]*)\s+in\s+(.+?)\s*%\}""", re.IGNORECASE | re.DOTALL)
_DOCUMENT_TEMPLATE_RUNTIME_TOKEN_RE = re.compile(r"""\{\{\s*(pageNumber|totalPages|date|title|url)\s*\}\}""")
_EMAIL_CTA_LINK_RE = re.compile(
    r"""<a\b(?P<attrs>[^>]*)\bhref\s*=\s*(?P<quote>["'])(?P<href>.*?)(?P=quote)(?P<tail>[^>]*)>(?P<label>.*?)</a>""",
    re.IGNORECASE | re.DOTALL,
)


def _artifact_ai_normalize_document_runtime_tokens(text: Any) -> Any:
    if not isinstance(text, str) or not text.strip():
        return text
    return _DOCUMENT_TEMPLATE_RUNTIME_TOKEN_RE.sub(
        lambda match: f'<span class="{str(match.group(1) or "").strip()}"></span>',
        text,
    )


def _artifact_ai_document_prompt_requests_logo(prompt: str | None, requested_focus: str | None = None) -> bool:
    prompt_text = _ai_norm_token(prompt) if isinstance(prompt, str) else ""
    focus_text = _ai_norm_token(requested_focus) if isinstance(requested_focus, str) else ""
    if _artifact_ai_prompt_avoids_logo(prompt):
        return False
    logo_signals = (
        "logo",
        "branding",
        "brand",
        "masthead",
        "letterhead",
        "headed paper",
    )
    if any(signal in prompt_text for signal in logo_signals):
        return True
    return focus_text == "branding"


