def _artifact_ai_text_lines(value: Any) -> list[str]:
    if isinstance(value, str):
        text = value.strip()
        return [text] if text else []
    if not isinstance(value, list):
        return []
    lines: list[str] = []
    for item in value:
        if isinstance(item, str):
            text = item.strip()
            if text:
                lines.append(text)
    return lines


def _artifact_ai_automation_validation_issue_lines(validation: dict | None) -> list[str]:
    issues: list[str] = []
    for item in (validation or {}).get("errors") or []:
        if not isinstance(item, dict):
            continue
        message = str(item.get("message") or "").strip()
        if not message:
            continue
        path = str(item.get("path") or "").strip()
        issue = f"{path}: {message}" if path else message
        if issue not in issues:
            issues.append(issue)
    return issues


def _artifact_ai_automation_repair_prompt(
    prompt: str,
    *,
    summary: str | None,
    validation: dict | None,
) -> str:
    subject = str(summary or prompt or "the current automation draft").strip()
    lines = [
        f"Fix the current automation draft for {subject}.",
        "",
        "Resolve these validation issues exactly:",
    ]
    issue_lines = _artifact_ai_automation_validation_issue_lines(validation)
    for issue in issue_lines:
        lines.append(f"- {issue}")
    if not issue_lines:
        lines.append("- Return a valid automation draft with the intended behavior preserved.")
    lines.extend(
        [
            "",
            "Keep the intended behavior and make the smallest change needed to return a valid automation draft.",
        ]
    )
    return "\n".join(lines)


def _artifact_ai_generate_plan(
    kind: str,
    request: Request,
    actor: dict | None,
    prompt: str,
    current: dict,
    selected_entity_id: str | None = None,
    requested_focus: str | None = None,
) -> dict:
    shared_context = _ai_build_shared_context(
        request,
        actor if isinstance(actor, dict) else None,
        message=prompt,
        answer_hints={"selected_entity_id": selected_entity_id} if isinstance(selected_entity_id, str) and selected_entity_id.strip() else None,
    )
    context_payload = _artifact_ai_prompt_context(
        kind,
        request,
        actor,
        current,
        selected_entity_id=selected_entity_id,
        requested_focus=requested_focus,
        shared_context=shared_context,
    )
    messages = [
        {"role": "system", "content": _artifact_ai_system_prompt(kind)},
        {"role": "user", "content": f"request.md\n{prompt.strip()}"},
        {"role": "user", "content": f"context.json\n```json\n{_json_prompt_payload(context_payload)}\n```"},
    ]
    response = _openai_chat_completion(
        messages,
        temperature=0.05,
        response_format={"type": "json_object"},
    )
    parsed = _artifact_ai_json_response(response)
    if not isinstance(parsed, dict):
        raise ValueError("AI response did not contain a valid JSON object")
    summary = parsed.get("summary")
    assumptions = _artifact_ai_text_lines(parsed.get("assumptions"))
    warnings = _artifact_ai_text_lines(parsed.get("warnings"))
    candidate_draft = parsed.get("draft") if isinstance(parsed.get("draft"), dict) else {}
    if kind == "automation":
        automation_meta = context_payload.get("meta") if isinstance(context_payload, dict) else None
        draft = _artifact_ai_normalize_automation_draft(current, candidate_draft, automation_meta)
        validation = _artifact_ai_validate_automation_draft(draft, automation_meta)
        last_serialized = json.dumps(draft, sort_keys=True, default=str)
        max_attempts = 5
        attempt = 1
        while validation.get("compiled_ok") is False and attempt < max_attempts:
            attempt += 1
            repair_context = copy.deepcopy(context_payload) if isinstance(context_payload, dict) else {}
            repair_context["current_draft"] = copy.deepcopy(draft)
            repair_context["current_validation"] = copy.deepcopy(validation)
            repair_context["repair_attempt"] = attempt - 1
            repair_messages = [
                {"role": "system", "content": _artifact_ai_system_prompt(kind)},
                {
                    "role": "user",
                    "content": f"request.md\n{_artifact_ai_automation_repair_prompt(prompt, summary=summary if isinstance(summary, str) else None, validation=validation)}",
                },
                {"role": "user", "content": f"context.json\n```json\n{_json_prompt_payload(repair_context)}\n```"},
            ]
            repair_response = _openai_chat_completion(
                repair_messages,
                temperature=0.05,
                response_format={"type": "json_object"},
            )
            repair_parsed = _artifact_ai_json_response(repair_response)
            if not isinstance(repair_parsed, dict):
                break
            repair_candidate_draft = repair_parsed.get("draft") if isinstance(repair_parsed.get("draft"), dict) else {}
            next_draft = _artifact_ai_normalize_automation_draft(draft, repair_candidate_draft, automation_meta)
            next_validation = _artifact_ai_validate_automation_draft(next_draft, automation_meta)
            next_serialized = json.dumps(next_draft, sort_keys=True, default=str)
            repair_summary = repair_parsed.get("summary")
            if isinstance(repair_summary, str) and repair_summary.strip():
                summary = repair_summary.strip()
            for item in _artifact_ai_text_lines(repair_parsed.get("assumptions")):
                if item not in assumptions:
                    assumptions.append(item)
            for item in _artifact_ai_text_lines(repair_parsed.get("warnings")):
                if item not in warnings:
                    warnings.append(item)
            if next_serialized == last_serialized:
                validation = next_validation
                break
            draft = next_draft
            validation = next_validation
            last_serialized = next_serialized
    elif kind == "email_template":
        draft = _artifact_ai_normalize_email_template_draft(current, candidate_draft)
        if isinstance(context_payload.get("selected_entity_id"), str) and context_payload.get("selected_entity_id").strip():
            variables_schema = draft.get("variables_schema") if isinstance(draft.get("variables_schema"), dict) else {}
            draft["variables_schema"] = {**variables_schema, "entity_id": context_payload.get("selected_entity_id").strip()}
        if _artifact_ai_email_prompt_implies_branded_transactional_layout(prompt, requested_focus) or _artifact_ai_prompt_requests_branding(prompt, requested_focus):
            updated_body_html, branding_assumptions = _artifact_ai_email_ensure_branding(
                draft.get("body_html"),
                context_payload,
                prompt,
                requested_focus,
                require_logo=_artifact_ai_branding_context_has_logo(context_payload) and not _artifact_ai_prompt_avoids_logo(prompt),
            )
            if isinstance(updated_body_html, str):
                draft["body_html"] = updated_body_html
            for item in branding_assumptions:
                if item not in assumptions:
                    assumptions.append(item)
        updated_body_html, cta_changed = _artifact_ai_email_strip_dead_quote_cta(draft.get("body_html"))
        if cta_changed and isinstance(updated_body_html, str):
            draft["body_html"] = updated_body_html
            assumptions.append("Replaced a placeholder quote CTA with an attachment note because no valid quote URL was available.")
            draft["body_text"] = _html_to_text(updated_body_html) or draft.get("body_text") or ""
        validation = _artifact_ai_validate_email_template_draft(draft)
    else:
        draft = _artifact_ai_normalize_doc_template_draft(current, candidate_draft)
        if isinstance(context_payload.get("selected_entity_id"), str) and context_payload.get("selected_entity_id").strip():
            variables_schema = draft.get("variables_schema") if isinstance(draft.get("variables_schema"), dict) else {}
            draft["variables_schema"] = {**variables_schema, "entity_id": context_payload.get("selected_entity_id").strip()}
        if _artifact_ai_document_prompt_requests_logo(prompt, requested_focus) and _artifact_ai_branding_context_has_logo(context_payload):
            draft, logo_injected = _artifact_ai_ensure_document_logo_masthead(draft)
            if logo_injected:
                assumptions.append("Inserted the workspace logo masthead because the request asked for branding or logo treatment.")
        updated_html, branding_assumptions = _artifact_ai_document_ensure_branding(
            draft.get("html"),
            context_payload,
            prompt,
            requested_focus,
        )
        if isinstance(updated_html, str):
            draft["html"] = updated_html
        for item in branding_assumptions:
            if item not in assumptions:
                assumptions.append(item)
        validation = _artifact_ai_validate_doc_template_draft(draft)
    return {
        "summary": summary.strip() if isinstance(summary, str) and summary.strip() else "Draft updated.",
        "draft": draft,
        "assumptions": assumptions,
        "warnings": warnings,
        "validation": validation,
    }


def _ai_scoped_artifact_current(selected_type: str | None, selected_key: str | None) -> dict | None:
    if not isinstance(selected_type, str) or not isinstance(selected_key, str) or not selected_key.strip():
        return None
    if selected_type == "automation":
        return automation_store.get(selected_key) if automation_store else None
    if selected_type == "email_template":
        return email_store.get_template(selected_key) if email_store else None
    if selected_type == "document_template":
        return doc_template_store.get(selected_key) if doc_template_store else None
    return None


def _ai_artifact_plan_result(
    kind: str,
    artifact_id: str,
    prompt: str,
    current: dict,
    request: Request,
    actor: dict | None,
    requested_focus: str | None = None,
) -> dict:
    normalized_focus = _artifact_ai_requested_focus(kind, requested_focus, prompt)
    plan = _artifact_ai_generate_plan(
        kind,
        request,
        actor if isinstance(actor, dict) else None,
        prompt,
        current,
        requested_focus=normalized_focus,
    )
    draft = plan.get("draft") if isinstance(plan.get("draft"), dict) else current
    payload_key = "automation"
    op_name = "update_automation_record"
    summary_line = None
    if kind == "email_template":
        payload_key = "email_template"
        op_name = "update_email_template_record"
        summary_line = _ai_email_template_summary_line({"op": op_name, "email_template": draft})
    elif kind == "document_template":
        payload_key = "document_template"
        op_name = "update_document_template_record"
        summary_line = _ai_document_template_summary_line({"op": op_name, "document_template": draft})
    else:
        summary_line = _ai_automation_summary_line({"op": op_name, "automation": draft})
    op = {
        "op": op_name,
        "artifact_type": kind,
        "artifact_id": artifact_id,
        payload_key: copy.deepcopy(draft),
    }
    requested_lines = _artifact_ai_requested_change_lines(kind, plan, summary_line)
    if kind in {"email_template", "document_template"}:
        requested_with_diffs: list[str] = []
        diff_lines = _artifact_ai_template_diff_requested_change_lines(kind, current, draft)
        for item in requested_lines[:1]:
            if isinstance(item, str) and item.strip() and item.strip() not in requested_with_diffs:
                requested_with_diffs.append(item.strip())
        for item in diff_lines:
            if isinstance(item, str) and item.strip() and item.strip() not in requested_with_diffs:
                requested_with_diffs.append(item.strip())
        for item in requested_lines[1:]:
            if isinstance(item, str) and item.strip() and item.strip() not in requested_with_diffs:
                requested_with_diffs.append(item.strip())
        requested_lines = requested_with_diffs
    elif kind == "automation":
        requested_with_diffs: list[str] = []
        diff_lines = _artifact_ai_automation_diff_requested_change_lines(current, draft)
        for item in requested_lines[:1]:
            if isinstance(item, str) and item.strip() and item.strip() not in requested_with_diffs:
                requested_with_diffs.append(item.strip())
        for item in diff_lines:
            if isinstance(item, str) and item.strip() and item.strip() not in requested_with_diffs:
                requested_with_diffs.append(item.strip())
        for item in requested_lines[1:]:
            if isinstance(item, str) and item.strip() and item.strip() not in requested_with_diffs:
                requested_with_diffs.append(item.strip())
        requested_lines = requested_with_diffs
    advisories = [item for item in (plan.get("warnings") or []) if isinstance(item, str) and item.strip()]
    validation = plan.get("validation") if isinstance(plan.get("validation"), dict) else {}
    risk_flags: list[str] = []
    if validation.get("compiled_ok") is False:
        risk_flags.append("The draft still has validation issues and needs review before apply.")
    return {
        "candidate_ops": [op],
        "questions": [],
        "question_meta": None,
        "assumptions": [item for item in (plan.get("assumptions") or []) if isinstance(item, str) and item.strip()],
        "risk_flags": risk_flags,
        "advisories": advisories,
        "requested_change_lines": requested_lines,
        "affected_modules": [],
        "affected_artifacts": [{"artifact_type": kind, "artifact_id": artifact_id, "artifact_key": artifact_id}],
        "planner_state": {
            "intent": f"{kind}_scoped_change",
            "artifact_type": kind,
            "artifact_id": artifact_id,
            "request_summary": prompt.strip(),
            "requested_focus": normalized_focus,
        },
        "resolved_without_changes": False,
    }


def _ai_artifact_match_labels(kind: str, item: dict) -> list[str]:
    labels: list[str] = []
    for key in ("name", "subject", "filename_pattern"):
        value = item.get(key)
        if isinstance(value, str) and value.strip() and value.strip() not in labels:
            labels.append(value.strip())
    artifact_id = item.get("id")
    if isinstance(artifact_id, str) and artifact_id.strip():
        humanized = _ai_humanize_identifier(artifact_id.strip()) or artifact_id.strip()
        if humanized not in labels:
            labels.append(humanized)
    return labels


def _ai_artifact_kind_hint_tokens(kind: str) -> set[str]:
    if kind == "automation":
        return {"automation", "workflow", "trigger"}
    if kind == "email_template":
        return {"email", "subject", "template"}
    if kind == "document_template":
        return {"document", "pdf", "template"}
    return set()


def _ai_artifact_prompt_match_score(prompt: str, kind: str, item: dict) -> tuple[int, str | None]:
    prompt_norm = _ai_norm_token(prompt)
    if not prompt_norm:
        return 0, None
    prompt_tokens = set(prompt_norm.split())
    best_score = 0
    best_label = None
    for label in _ai_artifact_match_labels(kind, item):
        label_norm = _ai_norm_token(label)
        if not label_norm:
            continue
        score = 0
        label_tokens = [token for token in label_norm.split() if len(token) > 2]
        exact_phrase = label_norm in prompt_norm
        if exact_phrase:
            score = 6 + min(3, len(label_tokens))
        elif len(label_tokens) >= 2 and all(token in prompt_tokens for token in label_tokens):
            score = 3 + min(3, len(label_tokens))
        if score <= 0:
            continue
        if prompt_tokens.intersection(_ai_artifact_kind_hint_tokens(kind)):
            score += 1
        if score > best_score:
            best_score = score
            best_label = label
    return best_score, best_label


def _ai_match_named_workspace_artifacts(prompt: str, actor: dict | None) -> list[dict]:
    matches: list[dict] = []
    catalog = _ai_workspace_artifact_catalog(actor if isinstance(actor, dict) else None)
    for item in catalog:
        if not isinstance(item, dict):
            continue
        kind = item.get("artifact_type")
        artifact_id = item.get("artifact_id")
        if not isinstance(kind, str) or not isinstance(artifact_id, str) or not artifact_id.strip():
            continue
        score, matched_label = _ai_artifact_prompt_match_score(prompt, kind, item)
        if score < 4:
            continue
        matches.append(
            {
                "artifact_type": kind,
                "artifact_id": artifact_id.strip(),
                "artifact_label": matched_label or artifact_id.strip(),
                "current": item,
                "score": score,
            }
        )
    matches.sort(
        key=lambda item: (
            -int(item.get("score") or 0),
            0 if item.get("artifact_type") == "automation" else 1 if item.get("artifact_type") == "email_template" else 2,
            str(item.get("artifact_label") or ""),
        )
    )
    unique_matches: list[dict] = []
    seen_keys: set[tuple[str, str]] = set()
    for item in matches:
        key = (str(item.get("artifact_type") or ""), str(item.get("artifact_id") or ""))
        if key in seen_keys:
            continue
        seen_keys.add(key)
        unique_matches.append(item)
        if len(unique_matches) >= 4:
            break
    return unique_matches


def _ai_named_artifact_plan(
    request: Request | None,
    session: dict,
    prompt: str,
) -> dict | None:
    selected_type = session.get("selected_artifact_type")
    if selected_type in {"automation", "email_template", "document_template"}:
        return None
    actor = getattr(request.state, "actor", None) if request is not None and hasattr(request, "state") else None
    unique_matches = _ai_match_named_workspace_artifacts(prompt, actor if isinstance(actor, dict) else None)
    if not unique_matches:
        return None
    aggregate = {
        "candidate_ops": [],
        "questions": [],
        "question_meta": None,
        "assumptions": [],
        "risk_flags": [],
        "advisories": [],
        "requested_change_lines": [],
        "affected_modules": [],
        "affected_artifacts": [],
        "planner_state": None,
        "resolved_without_changes": False,
    }
    for item in unique_matches:
        kind = item.get("artifact_type")
        artifact_id = item.get("artifact_id")
        if not isinstance(kind, str) or not isinstance(artifact_id, str):
            continue
        artifact_label = item.get("artifact_label") if isinstance(item.get("artifact_label"), str) and item.get("artifact_label").strip() else artifact_id
        focused_prompt = (
            f"{prompt.strip()}\n\n"
            f"Only update the existing {_ai_plan_artifact_type_label(kind)} named '{artifact_label}'. "
            "Ignore unrelated artifacts from the request."
        )
        try:
            artifact_plan = _ai_artifact_plan_result(kind, artifact_id, focused_prompt, item.get("current") or {}, request, actor if isinstance(actor, dict) else None)
        except Exception as exc:
            log_fn = logger.warning
            if _ai_named_artifact_plan_expected_failure(exc):
                log_fn = logger.debug
            log_fn(
                "named_artifact_plan_failed artifact_type=%s artifact_id=%s error=%s",
                kind,
                artifact_id,
                exc,
            )
            aggregate["advisories"].append(
                f"Skipped direct AI planning for existing {_ai_plan_artifact_type_label(kind)} '{artifact_label}' because that planner is unavailable right now."
            )
            continue
        aggregate["candidate_ops"].extend([op for op in (artifact_plan.get("candidate_ops") or []) if isinstance(op, dict)])
        aggregate["assumptions"].extend([entry for entry in (artifact_plan.get("assumptions") or []) if isinstance(entry, str) and entry.strip()])
        aggregate["risk_flags"].extend([entry for entry in (artifact_plan.get("risk_flags") or []) if isinstance(entry, str) and entry.strip()])
        aggregate["advisories"].extend([entry for entry in (artifact_plan.get("advisories") or []) if isinstance(entry, str) and entry.strip()])
        aggregate["requested_change_lines"].extend([entry for entry in (artifact_plan.get("requested_change_lines") or []) if isinstance(entry, str) and entry.strip()])
        aggregate["affected_artifacts"].extend([entry for entry in (artifact_plan.get("affected_artifacts") or []) if isinstance(entry, dict)])
        aggregate["assumptions"].append(f"Matched existing {_ai_plan_artifact_type_label(kind)} '{artifact_label}' from the request.")
    if not aggregate["candidate_ops"]:
        return None
    if len(unique_matches) == 1:
        only = unique_matches[0]
        aggregate["planner_state"] = {
            "intent": f"{only.get('artifact_type')}_named_change",
            "artifact_type": only.get("artifact_type"),
            "artifact_id": only.get("artifact_id"),
            "artifact_label": only.get("artifact_label"),
            "request_summary": prompt.strip(),
        }
    else:
        aggregate["planner_state"] = {
            "intent": "mixed_artifact_change",
            "request_summary": prompt.strip(),
            "artifact_matches": [
                {
                    "artifact_type": item.get("artifact_type"),
                    "artifact_id": item.get("artifact_id"),
                    "artifact_label": item.get("artifact_label"),
                }
                for item in unique_matches
            ],
        }
    aggregate["assumptions"] = list(dict.fromkeys(aggregate["assumptions"]))
    aggregate["risk_flags"] = list(dict.fromkeys(aggregate["risk_flags"]))
    aggregate["advisories"] = list(dict.fromkeys(aggregate["advisories"]))
    aggregate["requested_change_lines"] = _ai_strengthen_requested_change_lines(
        aggregate["requested_change_lines"],
        aggregate["candidate_ops"],
        aggregate["assumptions"],
    )
    return aggregate


def _ai_named_artifact_plan_expected_failure(exc: Exception) -> bool:
    if isinstance(exc, SecretStoreError):
        text = str(exc or "").strip().lower()
        if "openai api key is not configured" in text:
            return True
    if isinstance(exc, AssertionError):
        text = str(exc or "").strip().lower()
        if "semantic model should not be needed" in text:
            return True
    return False


def _ai_candidate_artifact_keys(ops: list[dict] | None) -> set[tuple[str, str]]:
    keys: set[tuple[str, str]] = set()
    for op in ops if isinstance(ops, list) else []:
        if not isinstance(op, dict):
            continue
        artifact_type = op.get("artifact_type")
        artifact_id = op.get("artifact_id")
        if not isinstance(artifact_type, str) or not artifact_type.strip():
            continue
        if not isinstance(artifact_id, str) or not artifact_id.strip():
            continue
        keys.add((artifact_type.strip(), artifact_id.strip()))
    return keys


def _ai_scoped_artifact_plan(
    request: Request,
    session: dict,
    prompt: str,
) -> dict | None:
    selected_type = session.get("selected_artifact_type")
    selected_key = session.get("selected_artifact_key")
    kind = selected_type if selected_type in {"automation", "email_template", "document_template"} else None
    current = _ai_scoped_artifact_current(selected_type, selected_key)
    if not isinstance(kind, str) or not isinstance(selected_key, str) or not selected_key.strip() or not isinstance(current, dict):
        return None
    actor = getattr(request.state, "actor", None)
    return _ai_artifact_plan_result(kind, selected_key, prompt, current, request, actor if isinstance(actor, dict) else None)


def _html_to_text(html: str | None) -> str:
    if not html:
        return ""
    import re
    text = re.sub(r"<[^>]+>", " ", html)
    return re.sub(r"\s+", " ", text).strip()


