@app.post("/documents/generate")
async def generate_document(request: Request) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    body = await _safe_json(request)
    if not isinstance(body, dict):
        return _error_response("INVALID_BODY", "Expected JSON object", None, status=400)
    template_id = body.get("template_id")
    entity_id = body.get("entity_id")
    record_id = body.get("record_id")
    if not (template_id and entity_id and record_id):
        return _error_response("DOC_INPUT_REQUIRED", "template_id, entity_id, record_id required", None, status=400)
    job = job_store.enqueue(
        {
            "type": "doc.generate",
            "payload": {
                "template_id": template_id,
                "entity_id": entity_id,
                "record_id": record_id,
                "purpose": body.get("purpose") or "default",
                "actor_user_id": actor.get("user_id"),
            },
        }
    )
    return _ok_response({"job": job})


# ---- Automations (Phase 2) ----


def _validate_automation_payload(data: dict, for_update: bool = False) -> list[dict]:
    errors: list[dict] = []
    if not for_update or "name" in data:
        if not isinstance(data.get("name"), str) or not data.get("name"):
            errors.append(_issue("AUTOMATION_NAME_REQUIRED", "name is required", "name"))
    if not for_update or "trigger" in data:
        trigger = data.get("trigger")
        if not isinstance(trigger, dict):
            errors.append(_issue("AUTOMATION_TRIGGER_INVALID", "trigger must be object", "trigger"))
        else:
            trigger_kind = trigger.get("kind")
            if trigger_kind not in {"event", "schedule"}:
                errors.append(_issue("AUTOMATION_TRIGGER_INVALID", "trigger.kind must be 'event' or 'schedule'", "trigger.kind"))
            if trigger_kind == "event":
                event_types = trigger.get("event_types")
                if not isinstance(event_types, list) or not all(isinstance(e, str) for e in event_types):
                    errors.append(_issue("AUTOMATION_TRIGGER_INVALID", "event_types must be list of strings", "trigger.event_types"))
                elif not [event for event in event_types if isinstance(event, str) and event.strip()]:
                    errors.append(_issue("AUTOMATION_TRIGGER_INVALID", "at least one event type is required", "trigger.event_types"))
                filters = trigger.get("filters", [])
                if filters is not None and not isinstance(filters, list):
                    errors.append(_issue("AUTOMATION_TRIGGER_INVALID", "filters must be list", "trigger.filters"))
                expr = trigger.get("expr")
                if expr is not None and not isinstance(expr, dict):
                    errors.append(_issue("AUTOMATION_TRIGGER_INVALID", "expr must be object", "trigger.expr"))
            if trigger_kind == "schedule":
                every_minutes = trigger.get("every_minutes")
                if not isinstance(every_minutes, int) or every_minutes <= 0:
                    errors.append(_issue("AUTOMATION_TRIGGER_INVALID", "every_minutes must be a positive integer", "trigger.every_minutes"))
    if not for_update or "steps" in data:
        steps = data.get("steps")
        if not isinstance(steps, list) or not steps:
            errors.append(_issue("AUTOMATION_STEPS_REQUIRED", "steps must be non-empty list", "steps"))
        else:
            def _validate_steps_list(items: list, base_path: str, *, allow_delay: bool = True) -> None:
                for idx, step in enumerate(items):
                    step_path = f"{base_path}[{idx}]"
                    if not isinstance(step, dict):
                        errors.append(_issue("AUTOMATION_STEP_INVALID", "step must be object", step_path))
                        continue
                    kind = step.get("kind")
                    if kind not in {"action", "condition", "delay", "foreach"}:
                        errors.append(_issue("AUTOMATION_STEP_INVALID", "unsupported step kind", f"{step_path}.kind"))
                        continue
                    if kind == "delay" and not allow_delay:
                        errors.append(_issue("AUTOMATION_STEP_INVALID", "delay is not supported inside nested branches yet", f"{step_path}.kind"))
                    action_id = step.get("action_id") if isinstance(step.get("action_id"), str) else None
                    if kind == "action" and not action_id:
                        errors.append(_issue("AUTOMATION_STEP_INVALID", "action_id required", f"{step_path}.action_id"))
                    inputs = step.get("inputs") if isinstance(step.get("inputs"), dict) else {}
                    if kind == "action" and action_id == "system.update_record":
                        if not isinstance(step.get("inputs"), dict):
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "inputs must be object", f"{step_path}.inputs"))
                        record_id = inputs.get("record_id")
                        if not isinstance(record_id, str) or not record_id.strip():
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "record_id required for update_record", f"{step_path}.inputs.record_id"))
                        patch = _automation_object_input(inputs.get("patch"))
                        if not isinstance(patch, dict):
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "patch must be object for update_record", f"{step_path}.inputs.patch"))
                        elif not patch:
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "patch must include at least one field change", f"{step_path}.inputs.patch"))
                    if kind == "action" and action_id == "system.notify":
                        recipients = inputs.get("recipient_user_ids")
                        has_recipient_list = isinstance(recipients, list) and len(recipients) > 0
                        has_single_recipient = isinstance(inputs.get("recipient_user_id"), str) and inputs.get("recipient_user_id").strip()
                        lookup_recipients = inputs.get("recipient_lookup_field_ids")
                        has_lookup_recipients = isinstance(lookup_recipients, list) and len([item for item in lookup_recipients if isinstance(item, str) and item.strip()]) > 0
                        has_single_lookup_recipient = isinstance(inputs.get("recipient_lookup_field_id"), str) and inputs.get("recipient_lookup_field_id").strip()
                        if not has_recipient_list and not has_single_recipient and not has_lookup_recipients and not has_single_lookup_recipient:
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "recipient_user_ids or recipient_user_id or recipient_lookup_field_ids required for notify", f"{step_path}.inputs"))
                        if not isinstance(inputs.get("title"), str) or not inputs.get("title").strip():
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "title required for notify", f"{step_path}.inputs.title"))
                        if not isinstance(inputs.get("body"), str) or not inputs.get("body").strip():
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "body required for notify", f"{step_path}.inputs.body"))
                    if kind == "action" and action_id == "system.send_email":
                        to_value = inputs.get("to")
                        has_direct_recipients = (
                            (isinstance(to_value, list) and len([item for item in to_value if isinstance(item, str) and item.strip()]) > 0)
                            or (isinstance(to_value, str) and bool(to_value.strip()))
                        )
                        has_expr_recipients = isinstance(inputs.get("to_expr"), str) and inputs.get("to_expr").strip()
                        has_field_recipients = isinstance(inputs.get("to_field_ids"), list) and len([item for item in inputs.get("to_field_ids") if isinstance(item, str) and item.strip()]) > 0
                        has_lookup_recipients = isinstance(inputs.get("to_lookup_field_ids"), list) and len([item for item in inputs.get("to_lookup_field_ids") if isinstance(item, str) and item.strip()]) > 0
                        has_internal_recipients = isinstance(inputs.get("to_internal_emails"), list) and len([item for item in inputs.get("to_internal_emails") if isinstance(item, str) and item.strip()]) > 0
                        if not any((has_direct_recipients, has_expr_recipients, has_field_recipients, has_lookup_recipients, has_internal_recipients)):
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "at least one recipient source is required for send_email", f"{step_path}.inputs"))
                        has_template = isinstance(inputs.get("template_id"), str) and inputs.get("template_id").strip()
                        has_inline_content = (
                            isinstance(inputs.get("subject"), str) and inputs.get("subject").strip()
                        ) or (
                            isinstance(inputs.get("body_html"), str) and inputs.get("body_html").strip()
                        ) or (
                            isinstance(inputs.get("body_text"), str) and inputs.get("body_text").strip()
                        )
                        if not has_template and not has_inline_content:
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "template_id or email content is required for send_email", f"{step_path}.inputs"))
                    if kind == "action" and action_id == "system.apply_integration_mapping":
                        mapping_id = inputs.get("mapping_id")
                        if not isinstance(mapping_id, str) or not mapping_id.strip():
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "mapping_id required for apply_integration_mapping", f"{step_path}.inputs.mapping_id"))
                        source_record = inputs.get("source_record")
                        has_source_record = (
                            (isinstance(source_record, str) and source_record.strip())
                            or isinstance(source_record, dict)
                            or isinstance(source_record, list)
                        )
                        if not has_source_record:
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "source_record required for apply_integration_mapping", f"{step_path}.inputs.source_record"))
                        elif isinstance(source_record, str) and source_record.strip() == "[object Object]":
                            errors.append(
                                _issue(
                                    "AUTOMATION_STEP_INVALID",
                                    "source_record must be a JSON object or raw context reference, not a stringified object placeholder",
                                    f"{step_path}.inputs.source_record",
                                )
                            )
                    if kind == "action" and action_id == "system.integration_request":
                        connection_id = inputs.get("connection_id")
                        if not isinstance(connection_id, str) or not connection_id.strip():
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "connection_id required for integration_request", f"{step_path}.inputs.connection_id"))
                        has_template = isinstance(inputs.get("template_id"), str) and inputs.get("template_id").strip()
                        has_target = (
                            (isinstance(inputs.get("path"), str) and inputs.get("path").strip())
                            or (isinstance(inputs.get("url"), str) and inputs.get("url").strip())
                        )
                        if not has_template and not has_target:
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "template_id or path/url required for integration_request", f"{step_path}.inputs"))
                    if kind == "condition":
                        if not isinstance(step.get("expr"), dict):
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "expr required", f"{step_path}.expr"))
                        if "stop_on_false" in step and not isinstance(step.get("stop_on_false"), bool):
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "stop_on_false must be boolean", f"{step_path}.stop_on_false"))
                        then_steps = step.get("then_steps")
                        else_steps = step.get("else_steps")
                        if then_steps is not None and not isinstance(then_steps, list):
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "then_steps must be list", f"{step_path}.then_steps"))
                        if else_steps is not None and not isinstance(else_steps, list):
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "else_steps must be list", f"{step_path}.else_steps"))
                        if isinstance(then_steps, list):
                            _validate_steps_list(then_steps, f"{step_path}.then_steps", allow_delay=False)
                        if isinstance(else_steps, list):
                            _validate_steps_list(else_steps, f"{step_path}.else_steps", allow_delay=False)
                        has_then = isinstance(then_steps, list) and len(then_steps) > 0
                        has_else = isinstance(else_steps, list) and len(else_steps) > 0
                        if not has_then and not has_else and step.get("stop_on_false") is not True:
                            errors.append(
                                _issue(
                                    "AUTOMATION_STEP_INVALID",
                                    "condition requires then_steps, else_steps, or stop_on_false",
                                    step_path,
                                )
                            )
                    if kind == "delay":
                        if "seconds" not in step and "until" not in step and "target_time" not in step:
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "seconds, until, or target_time required", step_path))
                    if kind == "foreach":
                        if "over" not in step:
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "over is required", f"{step_path}.over"))
                        child_steps = step.get("steps")
                        has_action = isinstance(step.get("action_id"), str)
                        has_steps = isinstance(child_steps, list) and len(child_steps) > 0
                        if not has_action and not has_steps:
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "foreach requires action_id or nested steps", step_path))
                        if child_steps is not None and not isinstance(child_steps, list):
                            errors.append(_issue("AUTOMATION_STEP_INVALID", "steps must be list", f"{step_path}.steps"))
                        if isinstance(child_steps, list):
                            _validate_steps_list(child_steps, f"{step_path}.steps", allow_delay=False)

            _validate_steps_list(steps, "steps")
    return errors


@app.get("/automations")
async def list_automations(request: Request, status: str | None = None) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_capability(actor, "automations.manage", "Admin role required")
    if denied:
        return denied
    items = automation_store.list(status=status)
    return _ok_response({"automations": items})


@app.post("/automations")
async def create_automation(request: Request) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_capability(actor, "automations.manage", "Admin role required")
    if denied:
        return denied
    body = await _safe_json(request)
    if not isinstance(body, dict):
        return _error_response("INVALID_BODY", "Expected JSON object", None, status=400)
    errors = _validate_automation_payload(body)
    if errors:
        return _error_response("AUTOMATION_INVALID", "Invalid automation", None, detail={"errors": errors}, status=400)
    item = automation_store.create(
        {
            "name": body.get("name"),
            "description": body.get("description"),
            "status": body.get("status", "draft"),
            "trigger": body.get("trigger"),
            "steps": body.get("steps"),
        }
    )
    return _ok_response({"automation": item})


