@app.post("/automations/{automation_id}/test-trigger")
async def test_automation_trigger(request: Request, automation_id: str) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_capability(actor, "automations.manage", "Admin role required")
    if denied:
        return denied
    automation = automation_store.get(automation_id)
    if not automation:
        return _error_response("AUTOMATION_NOT_FOUND", "Automation not found", "automation_id", status=404)
    body = await _safe_json(request)
    if body is None:
        body = {}
    if not isinstance(body, dict):
        return _error_response("INVALID_BODY", "Expected JSON object", None, status=400)

    trigger = automation.get("trigger") or {}
    if (trigger.get("kind") or "event") != "event":
        return _error_response("AUTOMATION_TEST_UNSUPPORTED", "Only event-triggered automations can be tested this way", "trigger.kind", status=400)

    event_types = trigger.get("event_types") if isinstance(trigger.get("event_types"), list) else []
    requested_event_type = body.get("event_type")
    if requested_event_type not in (None, "") and not isinstance(requested_event_type, str):
        return _error_response("EVENT_TYPE_INVALID", "event_type must be a string", "event_type", status=400)
    event_type = requested_event_type.strip() if isinstance(requested_event_type, str) and requested_event_type.strip() else (
        event_types[0] if event_types else None
    )
    if not isinstance(event_type, str) or not event_type:
        return _error_response("EVENT_TYPE_REQUIRED", "event_type is required", "event_type", status=400)

    payload_in = body.get("payload")
    if payload_in is not None and not isinstance(payload_in, dict):
        return _error_response("PAYLOAD_INVALID", "payload must be an object", "payload", status=400)
    payload = dict(payload_in or {})
    trigger_payload: dict[str, Any] = {"event": event_type}

    if event_type == "integration.webhook.received" or event_type.startswith("integration.webhook."):
        headers = body.get("headers")
        if headers is not None and not isinstance(headers, dict):
            return _error_response("HEADERS_INVALID", "headers must be an object", "headers", status=400)
        if headers is not None:
            trigger_payload["headers"] = headers
        if "connection_id" in body:
            if body.get("connection_id") not in (None, "") and not isinstance(body.get("connection_id"), str):
                return _error_response("CONNECTION_INVALID", "connection_id must be a string", "connection_id", status=400)
            if isinstance(body.get("connection_id"), str) and body.get("connection_id").strip():
                trigger_payload["connection_id"] = body.get("connection_id").strip()
        if "webhook_id" in body:
            if body.get("webhook_id") not in (None, "") and not isinstance(body.get("webhook_id"), str):
                return _error_response("WEBHOOK_ID_INVALID", "webhook_id must be a string", "webhook_id", status=400)
            if isinstance(body.get("webhook_id"), str) and body.get("webhook_id").strip():
                trigger_payload["webhook_id"] = body.get("webhook_id").strip()
        if "provider_event_id" in body:
            if body.get("provider_event_id") not in (None, "") and not isinstance(body.get("provider_event_id"), str):
                return _error_response("PROVIDER_EVENT_ID_INVALID", "provider_event_id must be a string", "provider_event_id", status=400)
            if isinstance(body.get("provider_event_id"), str) and body.get("provider_event_id").strip():
                trigger_payload["provider_event_id"] = body.get("provider_event_id").strip()
        if "event_key" in body:
            if body.get("event_key") not in (None, "") and not isinstance(body.get("event_key"), str):
                return _error_response("EVENT_KEY_INVALID", "event_key must be a string", "event_key", status=400)
            if isinstance(body.get("event_key"), str) and body.get("event_key").strip():
                trigger_payload["event_key"] = body.get("event_key").strip()
        trigger_payload["payload"] = payload
    else:
        trigger_payload.update(payload)

    run = automation_store.create_run(
        {
            "automation_id": automation_id,
            "status": "queued",
            "trigger_event_id": None,
            "trigger_type": event_type,
            "trigger_payload": {
                **trigger_payload,
                "source": "test_trigger",
                "tested_by": (actor or {}).get("user_id"),
                "tested_at": _now(),
            },
            "current_step_index": 0,
        }
    )
    job = job_store.enqueue({"type": "automation.run", "payload": {"run_id": run.get("id")}})
    return _ok_response({"run": run, "job": job}, status=202)


@app.delete("/automations/{automation_id}")
async def delete_automation(request: Request, automation_id: str) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_capability(actor, "automations.manage", "Admin role required")
    if denied:
        return denied
    existing = automation_store.get(automation_id)
    if not existing:
        return _error_response("AUTOMATION_NOT_FOUND", "Automation not found", "automation_id", status=404)
    if existing.get("status") not in {"draft", "disabled"}:
        return _error_response("AUTOMATION_DELETE_FORBIDDEN", "Only draft/disabled automations can be deleted", "status", status=400)
    automation_store.delete(automation_id)
    return _ok_response({"deleted": True})


def _ext_openapi_schema() -> dict:
    if hasattr(app.state, "ext_openapi_schema") and isinstance(app.state.ext_openapi_schema, dict):
        return app.state.ext_openapi_schema
    routes = []
    excluded = _PUBLIC_EXT_DOC_PATHS
    for route in app.routes:
        path = getattr(route, "path", None)
        if not isinstance(path, str):
            continue
        if path.startswith("/ext/v1") and path not in excluded:
            routes.append(route)
    schema = get_openapi(
        title="Octodrop External API",
        version="v1",
        description=(
            "Public Octodrop API for external systems. "
            "Authenticate with `X-Api-Key` and use these routes for metadata, records, "
            "published automation execution, and signed webhook-driven integrations.\n\n"
            "Keys are workspace-scoped and should be issued per external system with least-privilege scopes. "
            "The default rate limit is 300 requests per 60 seconds per API credential; 429 responses include "
            "`Retry-After` and `X-RateLimit-*` headers. List endpoints use `limit`, `offset`, and `cursor`; "
            "the current hard cap is 200 items per page. Outbound webhooks should be verified with "
            "`X-Octo-Timestamp` and `X-Octo-Signature`.\n\n"
            "Guide: [/ext/v1/guide.md](/ext/v1/guide.md)\n\n"
            "Event Catalog: [/ext/v1/events.md](/ext/v1/events.md)"
        ),
        routes=routes,
    )
    schema["servers"] = [{"url": "/"}]
    components = schema.setdefault("components", {})
    security_schemes = components.setdefault("securitySchemes", {})
    security_schemes["ApiKeyAuth"] = {
        "type": "apiKey",
        "in": "header",
        "name": "X-Api-Key",
        "description": "Scoped Octodrop API credential created in Settings -> Developer -> API Credentials.",
    }
    for path_item in (schema.get("paths") or {}).values():
        if not isinstance(path_item, dict):
            continue
        for operation in path_item.values():
            if isinstance(operation, dict):
                operation.setdefault("security", [{"ApiKeyAuth": []}])
    app.state.ext_openapi_schema = schema
    return schema


@app.get("/ext/v1/openapi.json", include_in_schema=False)
async def ext_openapi_json() -> dict:
    return _ext_openapi_schema()


@app.get("/ext/v1/guide.md", include_in_schema=False)
async def ext_external_api_guide() -> Response:
    guide_path = ROOT / "OCTODROP_EXTERNAL_API_GUIDE.md"
    if not guide_path.exists():
        return Response("# External API Guide\n\nGuide file not found.\n", media_type="text/markdown", status_code=404)
    return Response(guide_path.read_text(encoding="utf-8"), media_type="text/markdown; charset=utf-8")


@app.get("/ext/v1/events.md", include_in_schema=False)
async def ext_external_event_catalog() -> Response:
    catalog_path = ROOT / "OCTODROP_EXTERNAL_EVENT_CATALOG.md"
    if not catalog_path.exists():
        return Response("# External Event Catalog\n\nCatalog file not found.\n", media_type="text/markdown", status_code=404)
    return Response(catalog_path.read_text(encoding="utf-8"), media_type="text/markdown; charset=utf-8")


