@app.post("/attachments/upload")
async def upload_attachment(request: Request, file: UploadFile = File(...)) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_capability(actor, "records.write", "Write access required")
    if denied:
        return denied
    data = await file.read()
    if _uploaded_file_too_large(data):
        return _error_response(
            "ATTACHMENT_TOO_LARGE",
            f"Attachment exceeds the configured {int(_MAX_UPLOAD_BYTES / (1024 * 1024))}MB limit",
            "file",
            status=413,
        )
    try:
        stored = store_bytes(get_org_id(), file.filename, data, mime_type=file.content_type or "application/octet-stream")
    except Exception as exc:
        logger.exception("attachment_store_failed filename=%s", file.filename)
        return _error_response("ATTACHMENT_UPLOAD_FAILED", str(exc), "file", status=400)
    attachment = attachment_store.create_attachment(
        {
            "filename": file.filename,
            "mime_type": file.content_type or "application/octet-stream",
            "size": stored["size"],
            "storage_key": stored["storage_key"],
            "sha256": stored["sha256"],
            "created_by": actor.get("user_id"),
        }
    )
    return _ok_response({"attachment": attachment})


@app.post("/prefs/ui/logo/upload")
async def upload_workspace_logo(request: Request, file: UploadFile = File(...)) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    if not using_supabase_storage():
        return _error_response(
            "SUPABASE_STORAGE_NOT_CONFIGURED",
            "Supabase storage is not configured. Set SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY.",
            None,
            status=400,
        )
    org_id = get_org_id()
    data = await file.read()
    if _uploaded_file_too_large(data):
        return _error_response(
            "ATTACHMENT_TOO_LARGE",
            f"Logo exceeds the configured {int(_MAX_UPLOAD_BYTES / (1024 * 1024))}MB limit",
            "file",
            status=413,
        )
    stored = store_bytes(
        org_id,
        file.filename,
        data,
        mime_type=file.content_type or "application/octet-stream",
        bucket=branding_bucket(),
    )
    logo_url = public_url(branding_bucket(), stored["storage_key"])
    with get_conn() as conn:
        current = fetch_one(
            conn,
            "select theme, colors, layout_prefs from workspace_ui_prefs where org_id=%s",
            [org_id],
            query_name="workspace_ui_prefs.current_for_logo",
        ) or {}
        execute(
            conn,
            """
            insert into workspace_ui_prefs (org_id, theme, colors, logo_url, layout_prefs, updated_at)
            values (%s, %s, %s, %s, %s, %s)
            on conflict (org_id)
            do update set theme=excluded.theme, colors=excluded.colors, logo_url=excluded.logo_url, layout_prefs=excluded.layout_prefs, updated_at=excluded.updated_at
            """,
            [
                org_id,
                current.get("theme"),
                json.dumps(current.get("colors")) if current.get("colors") is not None else None,
                logo_url,
                json.dumps(current.get("layout_prefs")) if current.get("layout_prefs") is not None else None,
                _now(),
            ],
            query_name="workspace_ui_prefs.upsert_logo",
    )
    _invalidate_prefs_ui_runtime_caches(org_id)
    return _ok_response({"logo_url": logo_url})


@app.post("/prefs/branding/assets/upload")
async def upload_branding_asset(
    request: Request,
    file: UploadFile = File(...),
    name: str = Form(""),
    reference_key: str = Form(""),
    type: str = Form("other"),
    alt_text: str = Form(""),
    notes: str = Form(""),
    sort_order: int = Form(0),
    is_active: bool = Form(True),
) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_admin(actor)
    if denied:
        return denied
    if not using_supabase_storage():
        return _error_response(
            "SUPABASE_STORAGE_NOT_CONFIGURED",
            "Supabase storage is not configured. Set SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY.",
            None,
            status=400,
        )
    org_id = get_org_id()
    data = await file.read()
    if _uploaded_file_too_large(data):
        return _error_response(
            "ATTACHMENT_TOO_LARGE",
            f"Asset exceeds the configured {int(_MAX_UPLOAD_BYTES / (1024 * 1024))}MB limit",
            "file",
            status=413,
        )
    asset_name = _trimmed_text(name) or Path(str(file.filename or "asset")).stem or "Branding asset"
    asset_reference_key = _branding_reference_key(reference_key or asset_name or file.filename or "asset")
    if not asset_reference_key:
        return _error_response("BRANDING_ASSET_REFERENCE_KEY_REQUIRED", "reference_key is required", "reference_key", status=400)
    asset_type = _branding_asset_type(type)
    with get_conn() as conn:
        duplicate = fetch_one(
            conn,
            "select id from branding_assets where workspace_id=%s and lower(reference_key)=lower(%s)",
            [org_id, asset_reference_key],
            query_name="branding_assets.duplicate_check",
        )
        if duplicate:
            return _error_response(
                "BRANDING_ASSET_REFERENCE_KEY_TAKEN",
                "reference_key must be unique within the workspace",
                "reference_key",
                status=409,
            )
        stored = store_bytes(
            org_id,
            file.filename or f"{asset_reference_key}.bin",
            data,
            mime_type=file.content_type or "application/octet-stream",
            bucket=branding_bucket(),
        )
        row = fetch_one(
            conn,
            """
            insert into branding_assets (
                workspace_id, name, reference_key, type, storage_key, mime_type, alt_text, notes, is_active, sort_order, created_at, updated_at
            )
            values (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s)
            returning id, workspace_id, name, reference_key, type, storage_key, mime_type, alt_text, notes, is_active, sort_order, created_at, updated_at
            """,
            [
                org_id,
                asset_name,
                asset_reference_key,
                asset_type,
                stored["storage_key"],
                file.content_type or "application/octet-stream",
                _trimmed_text(alt_text) or None,
                _trimmed_text(notes) or None,
                bool(is_active),
                int(sort_order or 0),
                _now(),
                _now(),
            ],
            query_name="branding_assets.insert",
        ) or {}
    _invalidate_prefs_ui_runtime_caches(org_id)
    return _ok_response({"asset": _branding_asset_payload(row)})


@app.patch("/prefs/branding/assets/{asset_id}")
async def update_branding_asset(request: Request, asset_id: str) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_admin(actor)
    if denied:
        return denied
    body = await _safe_json(request)
    if not isinstance(body, dict):
        return _error_response("BRANDING_ASSET_INVALID", "asset body required", "body", status=400)
    org_id = get_org_id()
    with get_conn() as conn:
        current = fetch_one(
            conn,
            """
            select id, workspace_id, name, reference_key, type, storage_key, mime_type, alt_text, notes, is_active, sort_order, created_at, updated_at
            from branding_assets
            where id=%s and workspace_id=%s
            """,
            [asset_id, org_id],
            query_name="branding_assets.current",
        ) or {}
        if not current:
            return _error_response("BRANDING_ASSET_NOT_FOUND", "branding asset not found", "asset_id", status=404)
        next_name = _trimmed_text(body.get("name")) if "name" in body else _trimmed_text(current.get("name"))
        next_name = next_name or _trimmed_text(current.get("name")) or "Branding asset"
        next_reference_key = (
            _branding_reference_key(body.get("reference_key"))
            if "reference_key" in body
            else _trimmed_text(current.get("reference_key"))
        )
        if not next_reference_key:
            return _error_response("BRANDING_ASSET_REFERENCE_KEY_REQUIRED", "reference_key is required", "reference_key", status=400)
        duplicate = fetch_one(
            conn,
            "select id from branding_assets where workspace_id=%s and lower(reference_key)=lower(%s) and id<>%s",
            [org_id, next_reference_key, asset_id],
            query_name="branding_assets.duplicate_update_check",
        )
        if duplicate:
            return _error_response(
                "BRANDING_ASSET_REFERENCE_KEY_TAKEN",
                "reference_key must be unique within the workspace",
                "reference_key",
                status=409,
            )
        next_type = _branding_asset_type(body.get("type")) if "type" in body else _branding_asset_type(current.get("type"))
        next_alt_text = _trimmed_text(body.get("alt_text")) if "alt_text" in body else _trimmed_text(current.get("alt_text"))
        next_notes = _trimmed_text(body.get("notes")) if "notes" in body else _trimmed_text(current.get("notes"))
        next_is_active = bool(body.get("is_active")) if "is_active" in body else bool(current.get("is_active", True))
        next_sort_order = int(body.get("sort_order") or 0) if "sort_order" in body else int(current.get("sort_order") or 0)
        row = fetch_one(
            conn,
            """
            update branding_assets
            set name=%s,
                reference_key=%s,
                type=%s,
                alt_text=%s,
                notes=%s,
                is_active=%s,
                sort_order=%s,
                updated_at=%s
            where id=%s and workspace_id=%s
            returning id, workspace_id, name, reference_key, type, storage_key, mime_type, alt_text, notes, is_active, sort_order, created_at, updated_at
            """,
            [
                next_name,
                next_reference_key,
                next_type,
                next_alt_text or None,
                next_notes or None,
                next_is_active,
                next_sort_order,
                _now(),
                asset_id,
                org_id,
            ],
            query_name="branding_assets.update",
        ) or {}
    _invalidate_prefs_ui_runtime_caches(org_id)
    return _ok_response({"asset": _branding_asset_payload(row)})


@app.delete("/prefs/branding/assets/{asset_id}")
async def delete_branding_asset(request: Request, asset_id: str) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_admin(actor)
    if denied:
        return denied
    org_id = get_org_id()
    storage_key = ""
    with get_conn() as conn:
        current = fetch_one(
            conn,
            """
            select id, workspace_id, storage_key
            from branding_assets
            where id=%s and workspace_id=%s
            """,
            [asset_id, org_id],
            query_name="branding_assets.delete_current",
        ) or {}
        if not current:
            return _error_response("BRANDING_ASSET_NOT_FOUND", "branding asset not found", "asset_id", status=404)
        storage_key = _trimmed_text(current.get("storage_key"))
        execute(
            conn,
            """
            update workspace_ui_prefs
            set app_logo_asset_id = case when app_logo_asset_id=%s then null else app_logo_asset_id end,
                app_icon_asset_id = case when app_icon_asset_id=%s then null else app_icon_asset_id end,
                favicon_asset_id = case when favicon_asset_id=%s then null else favicon_asset_id end,
                pwa_icon_asset_id = case when pwa_icon_asset_id=%s then null else pwa_icon_asset_id end,
                nav_logo_asset_id = case when nav_logo_asset_id=%s then null else nav_logo_asset_id end,
                homepage_brand_asset_id = case when homepage_brand_asset_id=%s then null else homepage_brand_asset_id end,
                logo_url = case when app_logo_asset_id=%s then null else logo_url end,
                updated_at=%s
            where org_id=%s
            """,
            [asset_id, asset_id, asset_id, asset_id, asset_id, asset_id, asset_id, _now(), org_id],
            query_name="workspace_ui_prefs.clear_deleted_branding_asset",
        )
        execute(
            conn,
            """
            update workspace_template_branding
            set primary_logo_asset_id = case when primary_logo_asset_id=%s then null else primary_logo_asset_id end,
                secondary_logo_asset_id = case when secondary_logo_asset_id=%s then null else secondary_logo_asset_id end,
                header_graphic_asset_id = case when header_graphic_asset_id=%s then null else header_graphic_asset_id end,
                footer_graphic_asset_id = case when footer_graphic_asset_id=%s then null else footer_graphic_asset_id end,
                default_background_graphic_asset_id = case when default_background_graphic_asset_id=%s then null else default_background_graphic_asset_id end,
                default_email_banner_asset_id = case when default_email_banner_asset_id=%s then null else default_email_banner_asset_id end,
                default_watermark_asset_id = case when default_watermark_asset_id=%s then null else default_watermark_asset_id end,
                updated_at=%s
            where org_id=%s
            """,
            [asset_id, asset_id, asset_id, asset_id, asset_id, asset_id, asset_id, _now(), org_id],
            query_name="workspace_template_branding.clear_deleted_branding_asset",
        )
        execute(
            conn,
            "delete from branding_assets where id=%s and workspace_id=%s",
            [asset_id, org_id],
            query_name="branding_assets.delete",
        )
    if storage_key:
        deleted = delete_storage(org_id, storage_key, bucket=branding_bucket())
        if not deleted:
            logger.warning("branding_asset_storage_delete_failed asset_id=%s storage_key=%s", asset_id, storage_key)
    _invalidate_prefs_ui_runtime_caches(org_id)
    branding = _branding_domains_for_org(org_id)
    user_id = actor.get("user_id") if isinstance(actor, dict) else None
    workspace, user = _load_ui_pref_settings(org_id, user_id if isinstance(user_id, str) else None)
    if isinstance(workspace, dict):
        workspace = {
            **workspace,
            "logo_url": branding.get("app_branding", {}).get("app_logo_url") or workspace.get("logo_url") or "",
            "app_logo_url": branding.get("app_branding", {}).get("app_logo_url") or workspace.get("logo_url") or "",
            "app_icon_url": branding.get("app_branding", {}).get("app_icon_url") or "",
            "favicon_url": branding.get("app_branding", {}).get("favicon_url") or "",
            "pwa_icon_url": branding.get("app_branding", {}).get("pwa_icon_url") or "",
            "nav_logo_url": branding.get("app_branding", {}).get("nav_logo_url") or "",
            "colors": branding.get("app_branding", {}).get("colors")
            if isinstance(branding.get("app_branding", {}).get("colors"), dict)
            else workspace.get("colors") or {},
            "workspace_name": branding.get("workspace_name") or workspace.get("workspace_name") or "",
            "app_logo_asset_id": branding.get("app_branding", {}).get("app_logo_asset_id") or workspace.get("app_logo_asset_id") or "",
            "app_icon_asset_id": branding.get("app_branding", {}).get("app_icon_asset_id") or workspace.get("app_icon_asset_id") or "",
            "favicon_asset_id": branding.get("app_branding", {}).get("favicon_asset_id") or workspace.get("favicon_asset_id") or "",
            "pwa_icon_asset_id": branding.get("app_branding", {}).get("pwa_icon_asset_id") or workspace.get("pwa_icon_asset_id") or "",
            "nav_logo_asset_id": branding.get("app_branding", {}).get("nav_logo_asset_id") or workspace.get("nav_logo_asset_id") or "",
            "homepage_brand_asset_id": branding.get("app_branding", {}).get("homepage_brand_asset_id") or workspace.get("homepage_brand_asset_id") or "",
        }
    return _ok_response(
        {
            "ok": True,
            "deleted_asset_id": asset_id,
            "app_branding": branding.get("app_branding") or {},
            "template_branding": branding.get("template_branding") or {},
            "branding_assets": branding.get("branding_assets") or [],
            "workspace": workspace or {},
            "user": user or {},
            "resolved": build_locale_context(workspace=workspace, user=user),
        }
    )


@app.post("/ops/attachments/cleanup")
async def cleanup_preview_attachments(request: Request) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    admin = _require_admin(actor)
    if admin:
        return admin
    body = await _safe_json(request)
    source = "preview"
    hours = 24
    limit = 200
    if isinstance(body, dict):
        source = body.get("source") or source
        hours = body.get("older_than_hours") or hours
        limit = body.get("limit") or limit
    job = job_store.enqueue(
        {
            "type": "attachments.cleanup",
            "payload": {"source": source, "older_than_hours": hours, "limit": limit},
        }
    )
    return _ok_response({"job": job})


@app.get("/attachments/{attachment_id}/download")
async def download_attachment(request: Request, attachment_id: str):
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    attachment, attachment_org_id = _get_attachment_for_actor(actor, attachment_id)
    if not attachment:
        return _error_response("ATTACHMENT_NOT_FOUND", "Attachment not found", "attachment_id", status=404)
    can_read_attachment = _has_capability(actor, "records.read")
    can_read_preview_attachment = (
        attachment.get("source") == "preview"
        and _has_capability(actor, "templates.manage")
    )
    if not can_read_attachment and not can_read_preview_attachment:
        return _error_response("FORBIDDEN", "Read access required", status=403)
    storage_key = attachment.get("storage_key")
    org_id = attachment_org_id or get_org_id()
    try:
        data = read_bytes(org_id, storage_key)
    except FileNotFoundError:
        return _error_response("ATTACHMENT_MISSING", "Attachment file missing", "storage_key", status=404)
    except RuntimeError:
        path = resolve_path(org_id, storage_key)
        if not path.exists():
            return _error_response("ATTACHMENT_MISSING", "Attachment file missing", "storage_key", status=404)
        from fastapi.responses import FileResponse

        return FileResponse(path, media_type=attachment.get("mime_type"), filename=attachment.get("filename"))
    filename = str(attachment.get("filename") or "attachment")
    safe_ascii = filename.encode("ascii", "ignore").decode("ascii").strip() or "attachment"
    encoded_name = urllib.parse.quote(filename, safe="")
    headers = {
        "Content-Disposition": f'attachment; filename="{safe_ascii}"; filename*=UTF-8\'\'{encoded_name}'
    }
    return Response(content=data, media_type=attachment.get("mime_type") or "application/octet-stream", headers=headers)


@app.post("/attachments/link")
async def link_attachment(request: Request) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_capability(actor, "records.write", "Write access required")
    if denied:
        return denied
    body = await _safe_json(request)
    if not isinstance(body, dict):
        return _error_response("INVALID_BODY", "Expected JSON object", None, status=400)
    if not (body.get("attachment_id") and body.get("entity_id") and body.get("record_id")):
        return _error_response("ATTACHMENT_LINK_REQUIRED", "attachment_id, entity_id, record_id required", None, status=400)
    record_denied = _record_access_denied_response(
        request,
        actor,
        str(body.get("entity_id")),
        str(body.get("record_id")),
        write=True,
    )
    if record_denied:
        return record_denied
    purpose = body.get("purpose")
    if purpose is not None:
        body["purpose"] = str(purpose).strip() or "default"
    link = attachment_store.link(body)
    try:
        attachment = attachment_store.get_attachment(body.get("attachment_id"))
        if attachment:
            _activity_add_attachment_event(
                body.get("entity_id"),
                body.get("record_id"),
                attachment,
                action="added",
                purpose=body.get("purpose"),
                actor=getattr(request.state, "user", None),
            )
    except Exception:
        pass
    return _ok_response({"link": link})


@app.get("/records/{entity_id}/{record_id}/attachments")
async def list_record_attachments(request: Request, entity_id: str, record_id: str) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_capability(actor, "records.read", "Read access required")
    if denied:
        return denied
    record_denied = _record_access_denied_response(request, actor, entity_id, record_id, write=False)
    if record_denied:
        return record_denied
    purpose = (request.query_params.get("purpose") or "").strip() or None
    try:
        links = attachment_store.list_links(entity_id, record_id, purpose)
    except TypeError:
        links = attachment_store.list_links(get_org_id(), entity_id, record_id, purpose)
    attachments = []
    unique_links = []
    seen_attachment_ids: set[str] = set()
    for link in links:
        attachment_id = link.get("attachment_id") if isinstance(link, dict) else None
        if not isinstance(attachment_id, str) or not attachment_id:
            continue
        if attachment_id in seen_attachment_ids:
            continue
        att = attachment_store.get_attachment(attachment_id)
        if not att:
            continue
        seen_attachment_ids.add(attachment_id)
        unique_links.append(link)
        attachments.append(att)
    return _ok_response({"links": unique_links, "attachments": attachments})


@app.delete("/records/{entity_id}/{record_id}/attachments/{attachment_id}")
async def delete_record_attachment(request: Request, entity_id: str, record_id: str, attachment_id: str) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_capability(actor, "records.write", "Records write permission required")
    if denied:
        return denied
    record_denied = _record_access_denied_response(request, actor, entity_id, record_id, write=True)
    if record_denied:
        return record_denied
    if not attachment_store or not hasattr(attachment_store, "unlink"):
        return _error_response("NOT_SUPPORTED", "Attachment deletion is not supported", None, status=400)
    attachment = attachment_store.get_attachment(attachment_id)

    purpose = (request.query_params.get("purpose") or "").strip() or None
    try:
        removed_links = int(attachment_store.unlink(entity_id, record_id, attachment_id, purpose))
    except TypeError:
        removed_links = int(attachment_store.unlink(get_org_id(), entity_id, record_id, attachment_id, purpose))
    if removed_links <= 0:
        return _error_response("ATTACHMENT_NOT_FOUND", "Attachment not linked to this record", "attachment_id", status=404)

    if attachment:
        _activity_add_attachment_event(
            entity_id,
            record_id,
            attachment,
            action="removed",
            purpose=purpose or "default",
            actor=getattr(request.state, "user", None),
        )

    try:
        remaining_links = int(attachment_store.count_links(attachment_id))
    except TypeError:
        remaining_links = int(attachment_store.count_links(get_org_id(), attachment_id))
    deleted_attachment = False
    if remaining_links <= 0 and hasattr(attachment_store, "delete_attachment"):
        try:
            removed = attachment_store.delete_attachment(attachment_id)
        except TypeError:
            removed = attachment_store.delete_attachment(get_org_id(), attachment_id)
        if removed:
            deleted_attachment = True
            storage_key = (removed or {}).get("storage_key")
            if storage_key:
                try:
                    delete_storage(get_org_id(), storage_key)
                except Exception:
                    logger.exception("attachment_storage_delete_failed attachment_id=%s storage_key=%s", attachment_id, storage_key)

    return _ok_response(
        {
            "deleted": True,
            "attachment_id": attachment_id,
            "removed_links": removed_links,
            "deleted_attachment": deleted_attachment,
        }
    )


# ---- System actions (Phase 1) ----


@app.post("/system/notify")
async def system_notify(request: Request) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    body = await _safe_json(request)
    if not isinstance(body, dict):
        return _error_response("INVALID_BODY", "Expected JSON object", None, status=400)
    recipients: list[str] = []
    if isinstance(body.get("recipient_user_ids"), list):
        recipients.extend(
            item.strip()
            for item in body.get("recipient_user_ids")
            if isinstance(item, str) and item.strip()
        )
    if isinstance(body.get("recipient_user_id"), str) and body.get("recipient_user_id").strip():
        recipients.append(body.get("recipient_user_id").strip())
    deduped: list[str] = []
    seen: set[str] = set()
    for recipient in recipients:
        if recipient in seen:
            continue
        seen.add(recipient)
        deduped.append(recipient)
    if not deduped:
        return _error_response("RECIPIENT_REQUIRED", "recipient_user_id or recipient_user_ids required", "recipient_user_ids", status=400)
    notifications = [
        notification_store.create({**body, "recipient_user_id": recipient})
        for recipient in deduped
    ]
    return _ok_response({"notification": notifications[0], "notifications": notifications})


